// Schema: {q,o,a,e} to match platform reader (same as oph files). 1:1 book numbering /*N*/.
// Explanation closing line is a meaningful clincher (equivalence / discriminator / hook), never a bare restatement.
if(!window.MM) window.MM={};
window.MM['radio_golden_19_23']=[
/*1*/ {"q":"Insulin-dependent GLUT transporter is:","o":["GLUT 1","GLUT 2","GLUT 3","GLUT 4"],"a":3,"e":"GLUT 4 is the insulin-responsive glucose transporter in skeletal muscle and adipose tissue, recruited to the membrane on insulin stimulation.<br><br>GLUT 1-3 are insulin-independent; the insulin-dependent transporter is GLUT 4."},
/*2*/ {"q":"Frothy urine with basement membrane and pink cytoplasm cells indicates reabsorption of:","o":["Protein","Lipids","Carbohydrates","Water"],"a":0,"e":"Frothy proteinuria with eosinophilic (pink) cytoplasm reflects tubular protein reabsorption droplets, indicating protein handling by the proximal tubule.<br><br>Lipid or carbohydrate reabsorption does not give this picture; the keyed answer is protein reabsorption."},
/*3*/ {"q":"Metastasis from the posterior one-third of the tongue involves which nodes:","o":["Jugulo-omohyoid","Submental","Submandibular","Occipital"],"a":0,"e":"The posterior third of the tongue drains to the jugulo-omohyoid node, the lymph node of the tongue.<br><br>The tip drains to submental and the anterior part to submandibular; the posterior third drains to the jugulo-omohyoid node."},
/*4*/ {"q":"Man with haematuria, cystoscopy and biopsy show transitional cell carcinoma of bladder; the risk factor is:","o":["Smoking","Alcohol","Hydrocarbon","Aniline only"],"a":0,"e":"Smoking is the leading risk factor for transitional cell carcinoma of the bladder, exceeding occupational exposures.<br><br>Alcohol is not a recognised cause; the predominant risk factor is smoking."},
/*5*/ {"q":"Christmas disease causes increase in which parameter:","o":["APTT","BT","PT","Both PT and BT"],"a":0,"e":"Christmas disease (haemophilia B, factor IX deficiency) prolongs the APTT through the intrinsic pathway while PT and bleeding time remain normal.<br><br>PT and BT are unaffected; the raised parameter is the APTT."},
/*6*/ {"q":"Rathke's pouch is derived from:","o":["Endoderm","Mesoderm","Stomodeum (oral ectoderm)","Neural crest cells"],"a":2,"e":"Rathke's pouch, the origin of the anterior pituitary, is an upgrowth of the stomodeal (oral) ectoderm.<br><br>It is not endodermal or mesodermal; Rathke's pouch arises from the stomodeum (per Langman)."},
/*7*/ {"q":"At the time of ovulation the oocyte is in which phase:","o":["Secondary oocyte","Primary oocyte","Fertilization","Zygote"],"a":0,"e":"At ovulation the oocyte is arrested as a secondary oocyte in metaphase of meiosis II, completing meiosis only on fertilisation.<br><br>The primary oocyte stage precedes the LH surge; at ovulation it is a secondary oocyte."},
/*8*/ {"q":"In meningomyelocele which marker is elevated:","o":["AFP","CEA","hCG","CA 125"],"a":0,"e":"Open neural tube defects such as meningomyelocele raise maternal serum and amniotic alpha-fetoprotein.<br><br>CEA and hCG are unrelated; the elevated marker is AFP."},
/*9*/ {"q":"Action potential is reduced (difficult to generate) in:","o":["Hypokalemia","Hyponatremia","Hyperkalemia","Hypernatremia"],"a":0,"e":"Hypokalaemia hyperpolarises the resting membrane potential, moving it further from threshold so the action potential is harder to generate.<br><br>Hyperkalaemia raises excitability initially; reduced AP generation occurs with hypokalaemia."},
/*10*/ {"q":"Hilar lymphadenopathy with non-caseating granuloma is diagnostic of:","o":["Sarcoidosis","Tuberculosis","Syphilis","Lymphoma"],"a":0,"e":"Bilateral hilar lymphadenopathy with non-caseating granulomas is characteristic of sarcoidosis.<br><br>Tuberculosis shows caseating granulomas; the non-caseating pattern indicates sarcoidosis."},
/*11*/ {"q":"SLE involves which type of hypersensitivity:","o":["Type 1","Type 2","Type 3","Type 4"],"a":2,"e":"Systemic lupus erythematosus is a prototypical type III immune-complex hypersensitivity disorder, with complex deposition causing tissue injury.<br><br>Type I is allergic and type IV cell-mediated; SLE is type III."},
/*12*/ {"q":"Yolk sac tumor and liver tumor marker is:","o":["Beta hCG","AFP","LDH","CEA"],"a":1,"e":"Alpha-fetoprotein is the tumour marker for yolk sac (endodermal sinus) tumours and hepatocellular carcinoma.<br><br>Beta hCG marks trophoblastic tumours; the keyed marker here is AFP."},
/*13*/ {"q":"Lumbar triangle anterior boundary is formed by:","o":["Posterior border of external oblique","Anterior border of external oblique","Latissimus dorsi","External intercostal"],"a":0,"e":"The inferior lumbar (Petit) triangle is bounded anteriorly by the posterior border of the external oblique.<br><br>Latissimus dorsi forms the posterior boundary; the anterior boundary is the posterior edge of external oblique."},
/*14*/ {"q":"After infusion of 0.9% N/S what will occur:","o":["Decrease urine osmolality","Increase urine osmolality","Same urine osmolality","Increase plasma osmolality"],"a":0,"e":"Isotonic 0.9% saline does not change plasma osmolality but expands volume, so the kidney excretes a more dilute urine, decreasing urine osmolality.<br><br>Plasma osmolality stays constant; urine osmolality decreases."},
/*15*/ {"q":"Halothane causes malignant hyperthermia by mechanism of:","o":["Skeletal muscle contraction","Acting on hypothalamus","Acting on liver","Acting on heart"],"a":0,"e":"Malignant hyperthermia from halothane results from uncontrolled calcium release in skeletal muscle, causing sustained contraction and heat production.<br><br>It is not a central or hepatic effect; the mechanism is skeletal muscle contraction."},
/*16*/ {"q":"Sick role is:","o":["To save oneself from obligations","Free of duties","Both freedom from duties and obligation to seek help","Punishment"],"a":2,"e":"The sick role concept includes exemption from normal duties together with the obligation to seek help and try to get well.<br><br>It is not merely avoiding obligations; per source the keyed answer reflects this combined definition."},
/*17*/ {"q":"Children with fused cervical vertebrae, short neck and low hairline on the posterior aspect of the neck is diagnosed as:","o":["Turner","Klinefelter","Down syndrome","Klippel-Feil syndrome"],"a":3,"e":"Fused cervical vertebrae with a short neck and low posterior hairline is the classic triad of Klippel-Feil syndrome.<br><br>Turner has a webbed neck; the cervical fusion syndrome is Klippel-Feil."},
/*18*/ {"q":"Sartorius muscle origin is from:","o":["ASIS","AIIS","Iliac crest","Pubic tubercle"],"a":0,"e":"Sartorius arises from the anterior superior iliac spine and inserts on the upper medial tibia (pes anserinus).<br><br>The rectus femoris takes the AIIS; sartorius originates from the ASIS."},
/*19*/ {"q":"Yolk sac tumor and liver tumor marker is:","o":["Beta hCG","AFP","LDH","CEA"],"a":1,"e":"Alpha-fetoprotein is the serum marker for yolk sac tumours and hepatocellular carcinoma.<br><br>Beta hCG relates to choriocarcinoma; the keyed marker is AFP."},
/*20*/ {"q":"Lumbar triangle anterior boundary is formed by:","o":["Posterior border of external oblique","Anterior border of external oblique","Latissimus dorsi","External intercostal"],"a":0,"e":"The lumbar (Petit) triangle has the posterior border of the external oblique as its anterior boundary.<br><br>Latissimus dorsi is posterior; the anterior boundary is the posterior margin of external oblique."},
/*21*/ {"q":"After infusion of 0.9% N/S what will occur:","o":["Decrease urine osmolality","Increase urine osmolality","Same urine osmolality","Increase plasma osmolality"],"a":0,"e":"Isotonic saline expands extracellular volume without altering plasma osmolality, so the kidneys produce a more dilute urine with decreased osmolality.<br><br>Plasma osmolality is unchanged; urine osmolality falls."},
/*22*/ {"q":"Halothane causes malignant hyperthermia, the mechanism is:","o":["Skeletal muscle contraction","Acting on hypothalamus","Acting on liver","Acting on kidney"],"a":0,"e":"Malignant hyperthermia is triggered by halothane causing massive sarcoplasmic calcium release and sustained skeletal muscle contraction with hyperthermia.<br><br>It is not centrally mediated; the mechanism is skeletal muscle contraction."},
/*23*/ {"q":"Sick role primarily means:","o":["To save oneself from obligations","Free of duties","Exemption from duties with obligation to recover","Permanent disability"],"a":2,"e":"The sick role excuses the patient from normal social duties while obliging them to want to recover and cooperate with treatment.<br><br>Per source the keyed answer reflects exemption coupled with the obligation to recover."},
/*24*/ {"q":"Yolk sac tumor and liver tumor marker is:","o":["Beta HCG","AFP","LDH","CEA"],"a":1,"e":"Alpha-fetoprotein is elevated in yolk sac tumours and hepatocellular carcinoma, used for diagnosis and monitoring.<br><br>Beta hCG marks trophoblastic disease; the keyed marker is AFP."},
/*25*/ {"q":"Lumbar triangle anterior boundary by:","o":["Posterior border of external oblique","Anterior border of external oblique","Latissimus dorsi","External intercostal"],"a":0,"e":"The inferior lumbar triangle of Petit is bounded anteriorly by the posterior free border of external oblique.<br><br>Latissimus dorsi is its posterior boundary; anteriorly it is the posterior border of external oblique."},
/*26*/ {"q":"After infusion of 0.9% N/S what will occur:","o":["Decrease urine osmolality","Increase urine osmolality","Same urine osmolality","Increase plasma osmolality"],"a":0,"e":"Isotonic saline raises extracellular volume without changing plasma osmolality, so urine becomes more dilute with decreased osmolality.<br><br>Plasma osmolality is unchanged; the keyed change is decreased urine osmolality."},
/*27*/ {"q":"Halothane causes malignant hyperthermia, the mechanism is:","o":["Skeletal muscle contraction","Acting on hypothalamus","Acting on liver","Acting on heart"],"a":0,"e":"Halothane-induced malignant hyperthermia results from uncontrolled calcium release causing sustained skeletal muscle contraction and heat.<br><br>It is not a hypothalamic effect; the mechanism is skeletal muscle contraction."},
/*28*/ {"q":"Sick role is:","o":["To save oneself from obligations","Free of duties","Exemption from duties with obligation to seek recovery","No change in role"],"a":2,"e":"The sick role concept couples exemption from usual duties with an obligation to seek help and recover.<br><br>Per source the keyed answer reflects this combined definition rather than mere avoidance of duties."},
/*29*/ {"q":"Children with fused cervical vertebrae, short neck, low hairline on posterior aspect of neck is diagnosed as:","o":["Turner","Klinefelter","Down syndrome","Klippel-Feil syndrome"],"a":3,"e":"The triad of fused cervical vertebrae, short neck and low posterior hairline defines Klippel-Feil syndrome.<br><br>Turner shows webbed neck; the cervical-fusion syndrome is Klippel-Feil."},
/*30*/ {"q":"Sexually active female having UTI, organism responsible is:","o":["S. saprophyticus","S. aureus","Chlamydia","E. coli"],"a":0,"e":"Staphylococcus saprophyticus is a characteristic cause of UTI in sexually active young women.<br><br>E. coli is the overall commonest UTI organism; the one specifically tied to young sexually active women is S. saprophyticus."},
/*31*/ {"q":"Dilated lateral ventricle obstruction lies in:","o":["Aqueduct","Interventricular foramen of Monro","Foramen of Magendie","Fourth ventricle"],"a":1,"e":"Isolated lateral ventricular dilatation indicates obstruction at the interventricular foramen of Monro, which drains that ventricle.<br><br>Aqueductal block dilates both lateral and third ventricles; isolated lateral dilatation is a foramen of Monro block."},
/*32*/ {"q":"After RTA, pulsation of eye due to connection between:","o":["Cavernous sinus and ICA","Cavernous sinus and ECA","Retinal artery and vein","Ophthalmic and optic"],"a":0,"e":"A pulsatile eye after trauma indicates a carotid-cavernous fistula, an abnormal connection between the internal carotid artery and the cavernous sinus.<br><br>The ECA is not involved; the fistula is between the ICA and the cavernous sinus."},
/*33*/ {"q":"Lucid interval is present in:","o":["Epidural hematoma","Subdural hematoma","SAH","Intracerebral hemorrhage"],"a":0,"e":"A lucid interval between injury and deterioration is classic for an extradural (epidural) haematoma from middle meningeal artery bleeding.<br><br>Subdural haematoma has a more gradual course; the lucid interval indicates epidural haematoma."},
/*34*/ {"q":"Lateral boundary of deep inguinal ring:","o":["Transversus abdominis","Internal oblique","Transversalis fascia","Inferior epigastric artery"],"a":2,"e":"The deep inguinal ring is an evagination of the transversalis fascia, which forms its margin.<br><br>The inferior epigastric vessels lie medial to the ring, not at its lateral wall; the boundary itself is transversalis fascia."},
/*35*/ {"q":"Nucleolus is collection of:","o":["Ribosomal RNA and protein","DNA","Ribosomes","Lysosomes"],"a":0,"e":"The nucleolus is a dense nuclear region of ribosomal RNA and associated proteins where ribosome subunits are assembled.<br><br>It is not a store of DNA or finished ribosomes; the nucleolus is rRNA and protein."},
/*36*/ {"q":"First step in formation of platelet plug:","o":["Shape change from round to flat and release enzyme","Shape change flat to spherical and release enzyme","Shape change and no release","Aggregation"],"a":1,"e":"Platelet activation begins with adhesion and a shape change from discoid to spherical with pseudopodia and granule release.<br><br>Aggregation comes later; the very first step is the shape change with enzyme/granule release."},
/*37*/ {"q":"Presented with left arm weakness and tongue deviation, lesion in:","o":["Medial medulla","Lateral medulla","Posterior medulla","Pons"],"a":0,"e":"Contralateral limb weakness with ipsilateral tongue deviation (hypoglossal) is the medial medullary syndrome.<br><br>Lateral medullary syndrome lacks tongue deviation; this is a medial medulla lesion."},
/*38*/ {"q":"Yolk sac tumor and liver tumor marker is:","o":["Beta HCG","AFP","LDH","CEA"],"a":1,"e":"Alpha-fetoprotein is the marker for yolk sac tumours and hepatocellular carcinoma.<br><br>Beta hCG marks trophoblastic tumours; the keyed marker is AFP."},
/*39*/ {"q":"Child with brain lesion now overweight, eating more, lesion in:","o":["Lateral hypothalamic nucleus inhibition","Ventromedial nucleus inhibition","Supraoptic nucleus","Paraventricular nucleus"],"a":1,"e":"Destruction (inhibition) of the ventromedial nucleus, the satiety centre, causes hyperphagia and obesity.<br><br>The lateral nucleus is the feeding centre; loss of satiety is ventromedial nucleus inhibition."},
/*40*/ {"q":"Sensory supply to uterus reaches via which ligament:","o":["Round ligament","Broad ligament","Uterosacral ligament","Cardinal ligament"],"a":1,"e":"Sensory fibres from the uterine fundus and body run with autonomic nerves carried in the broad ligament.<br><br>The round ligament conveys little sensory supply; the broad ligament carries the uterine sensory pathway."},
/*41*/ {"q":"Superficial inguinal lymph node drainage includes:","o":["Lower vagina","Fundus of uterus","Lower uterus","Upper vagina"],"a":0,"e":"The lower vagina (below the hymen) drains to the superficial inguinal lymph nodes.<br><br>The uterine fundus drains differently; the superficial inguinal nodes receive the lower vagina."},
/*42*/ {"q":"Left temporal gyrus/lobe lesion (Meyer loop) results in:","o":["Right superior quadrantanopia","Left superior quadrantanopia","Right inferior quadrantanopia","Left inferior quadrantanopia"],"a":0,"e":"A left temporal lobe lesion damages Meyer's loop, producing a contralateral right superior homonymous quadrantanopia.<br><br>Parietal lesions give inferior defects; temporal Meyer-loop lesions cause a right superior quadrantanopia."},
/*43*/ {"q":"Upper brachial trunk injury involves:","o":["Erb's palsy (C5-C6)","Klumpke palsy","Median nerve","Ulnar nerve"],"a":0,"e":"Injury to the upper brachial plexus trunk (C5-C6) produces Erb's palsy with the waiter's tip deformity.<br><br>Lower trunk injury is Klumpke palsy; upper trunk injury is Erb's palsy."},
/*44*/ {"q":"On lymph node biopsy granuloma found; on microscopy to diagnose TB one should look for:","o":["AFB","Coagulative necrosis","Caseous necrosis","Reed-Sternberg cells"],"a":2,"e":"Tuberculous granulomas characteristically show central caseous necrosis, the key feature sought to diagnose TB.<br><br>AFB confirm the organism but the diagnostic histology is caseous necrosis."},
/*45*/ {"q":"Easy diagnostic way to detect a tumor:","o":["Tumor marker","Biopsy","Peripheral smear","None"],"a":0,"e":"A tumour marker is a quick, non-invasive screening method to detect a tumour.<br><br>Biopsy is definitive but invasive; for an easy detecting method the answer is a tumour marker."},
/*46*/ {"q":"One-carbon carrier is:","o":["Folate","Pantothenic acid","Thiamine","Biotin"],"a":3,"e":"Biotin is a one-carbon (carboxyl) carrier, acting as the prosthetic group of carboxylase enzymes.<br><br>Folate carries one-carbon units at the methyl/formyl oxidation level; the carboxyl one-carbon carrier is biotin."},
/*47*/ {"q":"Sickle cell anemia has which haemoglobin:","o":["HBF","HBA2","HBS","HBA"],"a":2,"e":"Sickle cell anaemia is characterised by haemoglobin S (HbS) from a beta-globin point mutation.<br><br>HbA2 and HbF are other variants; the sickle cell haemoglobin is HbS."},
/*48*/ {"q":"Decreased reticulocytes are seen in:","o":["CRF","Pregnancy","Hemolytic anemia","Acute bleeding"],"a":0,"e":"Chronic renal failure causes reduced erythropoietin production, leading to a low reticulocyte count.<br><br>Haemolysis and bleeding raise reticulocytes; the low-reticulocyte cause here is CRF."},
/*49*/ {"q":"Which one has trinucleotide repeats:","o":["Fragile X syndrome","Down syndrome","Edward syndrome","Turner syndrome"],"a":0,"e":"Fragile X syndrome is a trinucleotide (CGG) repeat expansion disorder of the FMR1 gene.<br><br>Down and Edward are aneuploidies; the trinucleotide-repeat disease is Fragile X."},
/*50*/ {"q":"Plasma osmolarity equals:","o":["5% D/W","0.9% N/S","1 L R/L","Dextrose 10%"],"a":1,"e":"Normal (0.9%) saline is isotonic with plasma osmolarity, making it the fluid that matches plasma osmolality.<br><br>5% dextrose becomes hypotonic after glucose metabolism; the iso-osmolar fluid is 0.9% saline."},
/*51*/ {"q":"Skin of glans penis lymphatics drain to:","o":["Superficial inguinal lymph node","Deep inguinal lymph node","Internal iliac","Para-aortic"],"a":0,"e":"The skin of the glans penis drains to the superficial inguinal lymph nodes.<br><br>The glans substance (erectile tissue) drains to deep inguinal/internal iliac nodes; only the skin drains superficially."},
/*52*/ {"q":"Decreased AV nodal conduction velocity presents on ECG as:","o":["QT prolongation","TP prolongation","Increased PR interval","Widened QRS"],"a":2,"e":"Slowed AV nodal conduction lengthens the PR interval on the ECG, reflecting delayed atrioventricular transmission.<br><br>QT reflects ventricular repolarisation; AV nodal slowing prolongs the PR interval."},
/*53*/ {"q":"Patient taking allopurinol; what will interact with its pharmacodynamics:","o":["Albumin","Gamma globulin","Alpha acid glycoprotein","Plasma water"],"a":0,"e":"Allopurinol interacts at the level of plasma protein (albumin) binding, altering free drug levels.<br><br>Alpha-acid glycoprotein binds basic drugs; allopurinol (acidic) is bound by albumin."},
/*54*/ {"q":"Inguinal lymphadenitis affects which of the following:","o":["Upper vagina","Upper uterus","Lower part of uterine body","Lower vagina"],"a":2,"e":"Inguinal lymphadenitis reflects drainage from the lower part of the uterine body (via the round ligament to inguinal nodes).<br><br>The upper uterus drains to para-aortic nodes; only the lower body drains to inguinal nodes."},
/*55*/ {"q":"Prostate lymph drainage is to:","o":["Internal iliac","External iliac","Inguinal","Para-aortic"],"a":0,"e":"The prostate drains its lymph predominantly to the internal iliac lymph nodes.<br><br>The external iliac and inguinal nodes are not primary; prostatic lymph goes to the internal iliac nodes."},
/*56*/ {"q":"In large data the mean will be:","o":["More","Normal","Less","Skewed"],"a":1,"e":"With a large sample the distribution approaches normality and the sample mean approximates the population mean (central limit theorem).<br><br>A small or skewed sample distorts the mean; large n drives it toward a normal-distribution estimate."},
/*57*/ {"q":"Young boy with bleeding disorder and bruises on body; first investigation:","o":["PT","APTT","Platelet count","BT"],"a":2,"e":"Bruising with a suspected bleeding disorder in a child is first screened with a platelet count.<br><br>PT/APTT test the coagulation cascade; petechiae and bruising point first to a platelet count."},
/*58*/ {"q":"Man with normal external genitalia, normal ejaculation but azoospermia; cause may be in:","o":["Epididymis","Sertoli cell defect","Scrotum","Seminiferous tubules"],"a":1,"e":"Azoospermia with normal genitalia, normal ejaculation and raised FSH/LH points to a Sertoli cell defect impairing spermatogenesis.<br><br>Epididymal or ductal block gives obstructive azoospermia with normal FSH; raised FSH indicates a Sertoli/testicular defect."},
/*59*/ {"q":"Person with skin pigmentation and central obesity; ACTH declines after dexamethasone test; cause:","o":["Cushing syndrome","Cushing disease","Exogenous steroid use","Ectopic steroid production"],"a":1,"e":"Suppression of ACTH on the high-dose dexamethasone test indicates a pituitary ACTH adenoma, that is Cushing disease.<br><br>Ectopic ACTH does not suppress; suppression indicates Cushing disease."},
/*60*/ {"q":"Fracture of head of femur leading to avascular necrosis; artery involved:","o":["Lateral circumflex","Descending lateral circumflex branch","Medial circumflex femoral artery","Obturator artery"],"a":2,"e":"The femoral head blood supply in adults is mainly the medial circumflex femoral artery, so its disruption causes avascular necrosis.<br><br>The lateral circumflex contributes less; the key vessel is the medial circumflex femoral artery."},
/*61*/ {"q":"Injury to shaft of humerus will damage which artery:","o":["Brachial artery","Profunda brachii","Axillary artery","Radial artery"],"a":1,"e":"A mid-shaft humeral fracture endangers the radial nerve and the accompanying profunda brachii (deep brachial) artery in the spiral groove.<br><br>The brachial artery lies more distally; the shaft injury involves the profunda brachii."},
/*62*/ {"q":"Man with painful thigh muscles, X-ray shows mass lesion; which is the muscle marker:","o":["Vimentin","Desmin","Cytokeratin","S-100"],"a":1,"e":"Desmin is the intermediate filament marker of muscle, used to identify myogenic tumours.<br><br>Cytokeratin marks epithelium and vimentin mesenchyme generally; the muscle marker is desmin."},
/*63*/ {"q":"Hemolytic reaction occurs due to:","o":["Preformed antibodies","Preformed antigen","External antigen","Delayed antibodies"],"a":0,"e":"Acute haemolytic transfusion reactions are caused by recipient preformed antibodies against donor red cell antigens.<br><br>Delayed reactions involve anamnestic antibody rise; the immediate intravascular reaction is from preformed antibodies."},
/*64*/ {"q":"Paroxysmal nocturnal hemoglobinuria first-line treatment:","o":["Cyclosporin","Eculizumab","Inj. Vit B12","Bone marrow transplant"],"a":1,"e":"Eculizumab, a complement C5 inhibitor, is the first-line therapy for paroxysmal nocturnal haemoglobinuria, reducing intravascular haemolysis.<br><br>Transplant is reserved for severe marrow failure; first-line is eculizumab."},
/*65*/ {"q":"Young male had RTA with femur fracture, died 5 days later; autopsy showed cerebral petechiae; diagnosis:","o":["Fat embolism","Sepsis","DIC","ARDS"],"a":0,"e":"Death days after a long-bone fracture with cerebral petechiae is characteristic of fat embolism syndrome.<br><br>Sepsis and DIC differ; the post-fracture petechial picture is fat embolism."},
/*66*/ {"q":"pH=7.1, pCO2=44, HCO3=12; diagnosis:","o":["Metabolic acidosis","Respiratory alkalosis","Partially compensated metabolic acidosis","Respiratory acidosis"],"a":0,"e":"Low pH with low bicarbonate and a normal pCO2 indicates an uncompensated metabolic acidosis.<br><br>The CO2 has not fallen to compensate; this is a metabolic acidosis."},
/*67*/ {"q":"Nerve compression between C5 and C6 compresses which of the following root contribution:","o":["C5","C6","C5-C6","C7"],"a":2,"e":"Disc compression between C5 and C6 affects the C5-C6 root contribution to the brachial plexus.<br><br>An isolated C5 or C7 lesion gives different deficits; a C5-C6 disc compresses the combined C5-C6 contribution."},
/*68*/ {"q":"Which of the following occurs due to sympathetic stimulation:","o":["Ciliary muscle contraction","Bronchoconstriction","Bradycardia","Bronchodilation"],"a":3,"e":"Sympathetic stimulation produces bronchodilation by relaxing bronchial smooth muscle via beta-2 receptors.<br><br>Bronchoconstriction and bradycardia are parasympathetic; the sympathetic effect is bronchodilation."},
/*69*/ {"q":"Patient with localized circumferential subendocardial lateral wall infarct; artery involved:","o":["Aorta","Pulmonary artery","LCX","Marginal"],"a":2,"e":"A lateral wall infarct corresponds to the territory of the left circumflex (LCX) coronary artery.<br><br>The RCA supplies the inferior wall; the lateral wall is LCX territory."},
/*70*/ {"q":"Inferior wall MI is due to blockage of which artery:","o":["Right marginal","LADA","LCA","RCA / posterior descending"],"a":3,"e":"An inferior wall MI (leads II, III, aVF) results from right coronary artery occlusion in most people.<br><br>The LAD supplies the anterior wall; inferior-wall ST elevation is RCA/posterior-descending territory."},
/*71*/ {"q":"Descending thoracic aorta starts at:","o":["Cricoid cartilage","C6","T2","T4"],"a":3,"e":"The descending thoracic aorta begins at the lower border of the T4 vertebra, continuing from the aortic arch.<br><br>The arch is higher; the descending thoracic aorta starts at T4."},
/*72*/ {"q":"Abduction of hip joint is limited by:","o":["Pubofemoral ligament","Iliofemoral","Ischiofemoral","Hamstring muscle"],"a":0,"e":"Hip abduction is limited by the pubofemoral ligament, which tightens to restrict abduction and extension.<br><br>The iliofemoral limits extension; abduction is limited by the pubofemoral ligament."},
/*73*/ {"q":"Which muscle causes both hip and knee flexion:","o":["Sartorius","Adductor magnus","Semitendinosus","Gracilis"],"a":0,"e":"Sartorius flexes both the hip and the knee, the only muscle producing both actions simultaneously.<br><br>The hamstrings flex the knee but extend the hip; the combined flexor is sartorius."},
/*74*/ {"q":"Which structure forms the pelvic diaphragm:","o":["Puborectalis muscle","Gracilis","Rectococcygeus muscle","Rectopuboralis"],"a":0,"e":"The pelvic diaphragm is formed by levator ani, of which puborectalis is a key sling component.<br><br>Gracilis is a thigh muscle; the pelvic floor sling is puborectalis (part of levator ani)."},
/*75*/ {"q":"Pectoralis minor is not functioning due to damage of which structure:","o":["Upper ribs","Medial end of clavicle","Angle of ribs","Coracoid process of scapula"],"a":3,"e":"Pectoralis minor inserts on the coracoid process of the scapula, so coracoid damage impairs its function.<br><br>Its origin is from ribs 3-5; the insertion at the coracoid process is the relevant structure."},
/*76*/ {"q":"Leptin mechanism of action is via:","o":["GS protein","GI protein","Open ion channel","Enzyme-linked receptor (JAK-STAT)"],"a":3,"e":"Leptin signals through a JAK-STAT enzyme-linked cytokine receptor.<br><br>Gs/Gi act via cAMP and ion-channel receptors are ionotropic; leptin uses the JAK-STAT enzyme-linked pathway."},
/*77*/ {"q":"Which of the following acts via phospholipase C:","o":["Prolactin","Oxytocin","ACTH","FSH"],"a":1,"e":"Oxytocin acts via a Gq-coupled receptor activating phospholipase C, generating IP3 and DAG.<br><br>ACTH and FSH use cAMP; the phospholipase C agonist here is oxytocin."},
/*78*/ {"q":"G-coupled phospholipase C activation leads to increased:","o":["cAMP","cGMP","Tyrosine kinase","IP3"],"a":3,"e":"Phospholipase C cleaves PIP2 to inositol trisphosphate (IP3) and diacylglycerol, raising intracellular IP3 and calcium.<br><br>cAMP is the adenylate cyclase product; phospholipase C increases IP3."},
/*79*/ {"q":"Vessel at the base of the bladder lies in which ligament position:","o":["Dorsolateral","Ventrolateral","Ventromedial","Dorsomedial"],"a":1,"e":"The vessels at the bladder base run in the ventrolateral (true) ligaments of the bladder.<br><br>The dorsal ligaments carry little vasculature; the bladder-base vessels run ventrolaterally."},
/*80*/ {"q":"Saphenous nerve is the terminal branch of which nerve:","o":["Tibial nerve","Posterior cutaneous femoral nerve","Femoral nerve","Sciatic nerve"],"a":2,"e":"The saphenous nerve is the terminal cutaneous branch of the femoral nerve, supplying the medial leg and foot.<br><br>It is not from the tibial or sciatic nerve; the saphenous is a femoral nerve branch."},
/*81*/ {"q":"Patient with pain in lumbar region, stone at pelvi-ureteric junction; pain arises from which segment:","o":["T11-L1","L1-L4","T12-L2","L5"],"a":2,"e":"Pelvi-ureteric junction colic refers pain to the T12-L2 dermatomes (loin to groin).<br><br>Lower ureteric stones refer to L1-L2/genitofemoral; the PUJ level is T12-L2."},
/*82*/ {"q":"Patient with pain in lumbar region, stone at pelvi-ureteric junction; pain arises from which segment:","o":["T11","L1","T12","L2"],"a":3,"e":"Among single segments, pelvi-ureteric junction colic localises to the L2 level.<br><br>T12 maps to the flank and L1 to the groin; the PUJ segment in this item is L2."},
/*83*/ {"q":"Patient with liver disease and ascites; ascitic tap needle passed in lower abdomen, which artery should be avoided to cut:","o":["Superior epigastric artery","Inferior epigastric artery","Cremasteric artery","Celiac trunk"],"a":1,"e":"Paracentesis in the lower abdomen risks the inferior epigastric artery, which runs in the rectus sheath; the tap is sited lateral to it.<br><br>The superior epigastric is upper abdominal; the vessel to avoid is the inferior epigastric artery."},
/*84*/ {"q":"Prostate mainly drains into:","o":["Internal iliac lymph node","External and inguinal lymph node","Para-aortic lymph node","Superficial inguinal lymph node"],"a":0,"e":"The prostate drains chiefly to the internal iliac (and sacral) lymph nodes.<br><br>The penis/scrotal skin drains to inguinal nodes; the prostate drains to internal iliac nodes."},
/*85*/ {"q":"Superficial inguinal lymph node drains into:","o":["Lower body of uterus","Cervix","Vagina above hymen","Vagina below hymen"],"a":3,"e":"The superficial inguinal lymph nodes receive drainage from the vagina below the hymen (lower one-third).<br><br>The upper vagina drains to pelvic nodes; the superficial inguinal nodes drain the vagina below the hymen."},
/*86*/ {"q":"Which vitamin is deficient after acute pancreatitis:","o":["B12","B7","Vitamin D","Vitamin C"],"a":2,"e":"Acute pancreatitis with fat malabsorption causes deficiency of the fat-soluble vitamin D.<br><br>Water-soluble B12/C are unaffected by fat malabsorption; the deficient one is fat-soluble vitamin D."},
/*87*/ {"q":"Leg area in cerebrum is supplied by which artery:","o":["ACA","PCA","MCA","AICA"],"a":0,"e":"The leg/foot motor and sensory cortex on the medial surface is supplied by the anterior cerebral artery.<br><br>The MCA supplies the lateral (face/arm) cortex; the leg area is ACA territory."},
/*88*/ {"q":"Skin of glans penis lymphatics include which of the following:","o":["Internal iliac node","External iliac LN","Both external and internal iliac LN","Superficial inguinal LN"],"a":3,"e":"The skin of the glans penis drains to the superficial inguinal lymph nodes.<br><br>The deep glans/erectile tissue drains to internal iliac nodes; only the skin drains superficial inguinal."},
/*89*/ {"q":"Patient with injury to posterior head and occipital lobe resulting in vision loss; artery involved:","o":["Posterior cerebral artery","MCA","ACA","Spinal artery"],"a":0,"e":"The occipital (visual) cortex is supplied by the posterior cerebral artery, so its injury causes visual loss.<br><br>The MCA and ACA supply other regions; the occipital cortex is PCA territory."},
/*90*/ {"q":"Stroke due to berry aneurysm most commonly involves which artery:","o":["Anterior communicating artery","Posterior communicating artery","MMA","MCA"],"a":0,"e":"Berry (saccular) aneurysms most commonly arise at the anterior communicating artery of the circle of Willis.<br><br>The other sites are less frequent; the commonest is the anterior communicating artery."},
/*91*/ {"q":"Which muscle damage results in adducted vocal cord position:","o":["Vocalis","Thyroarytenoid","Posterior cricoarytenoid","Oblique arytenoid"],"a":2,"e":"The posterior cricoarytenoid is the only abductor of the vocal cords, so its damage leaves the cords adducted.<br><br>The other muscles adduct or tense; loss of the abductor (posterior cricoarytenoid) gives an adducted cord."},
/*92*/ {"q":"Lymphatic drainage of external nose and anterior part of nasal cavity is to:","o":["Submandibular lymph nodes","Deep cervical lymph nodes","Retropharyngeal lymph nodes","Occipital lymph nodes"],"a":0,"e":"The external nose and anterior nasal cavity drain to the submandibular lymph nodes.<br><br>The posterior nasal cavity drains to retropharyngeal/deep cervical nodes; the anterior part drains to submandibular nodes."},
/*93*/ {"q":"Patient on antibiotic developed bleeding with raised PT and APTT; what should be given for vitamin K deficiency:","o":["Cryoprecipitate","FFP","Hemcel","Whole blood"],"a":1,"e":"Antibiotic-induced vitamin K deficiency with raised PT/APTT and active bleeding is treated with fresh frozen plasma plus vitamin K.<br><br>Cryoprecipitate replaces fibrinogen only; multifactor (II, VII, IX, X) deficiency needs FFP (Kaplan)."},
/*94*/ {"q":"Patient injured in RTA presents with gait problem; asked to stand on left leg, right pelvis sinks; which muscle is damaged:","o":["Left gluteus maximus","Left gluteus medius","Right gluteus medius","Right gluteus minimus"],"a":1,"e":"A positive Trendelenburg sign with the right pelvis sinking on standing on the left leg indicates weakness of the left gluteus medius (the stance-leg abductor).<br><br>The opposite-side pelvis drops; the damaged muscle is the left gluteus medius."},
/*95*/ {"q":"Critical tactile sensation is carried by:","o":["Ventral horn","Dorsal horn","Posterior white column (DCML)","Lateral column"],"a":2,"e":"Fine (critical) touch and proprioception travel in the posterior white column (dorsal column-medial lemniscus).<br><br>Crude touch uses the anterior column; critical touch is the posterior (dorsal) column."},
/*96*/ {"q":"Patient with right-sided weakness, loss of vibration sense and tongue deviated to left side; lesion located in:","o":["Anterior spinal artery","Internal carotid artery","Basilar artery","PICA"],"a":0,"e":"Medial medullary syndrome (contralateral weakness, contralateral vibration loss, ipsilateral tongue deviation) is from anterior spinal artery occlusion.<br><br>PICA causes lateral medullary syndrome; the medial medullary picture is anterior spinal artery (Kaplan)."},
/*97*/ {"q":"Loss of proprioception occurs after RTA; underlying mechanism is:","o":["Feed forward mechanism","Lateral inhibition","Posterior inhibition","Synaptic plasticity"],"a":1,"e":"Proprioceptive sharpening of the dorsal column signal is achieved by lateral inhibition.<br><br>Synaptic plasticity is a learning mechanism; spatial sensory contrast here is lateral inhibition."},
/*98*/ {"q":"In Zollinger-Ellison syndrome what is true:","o":["Decrease gastrin","Peptic ulcer occurs","Increase pepsin","Increase lactase"],"a":1,"e":"Zollinger-Ellison syndrome (gastrinoma) causes marked acid hypersecretion and recurrent, often atypical peptic ulcers.<br><br>Gastrin is increased not decreased; the true statement is that peptic ulcers occur."},
/*99*/ {"q":"Loss of parietal cells results in deficiency of which vitamin:","o":["B6","Vitamin D","B9","B12"],"a":3,"e":"Parietal cells secrete intrinsic factor, so their loss causes vitamin B12 malabsorption and deficiency (pernicious anaemia).<br><br>Folate (B9) absorption is independent; parietal cell loss causes B12 deficiency."},
/*100*/ {"q":"Woman with dermatitis, diarrhea and memory loss; which vitamin deficiency is responsible:","o":["B1","B2","B3","B5"],"a":2,"e":"The triad of dermatitis, diarrhoea and dementia (memory loss) is pellagra, caused by niacin (vitamin B3) deficiency.<br><br>Thiamine deficiency causes beri-beri; the three-D syndrome is B3 deficiency."},
/*101*/ {"q":"Patient with paralysis of right limb and right lower face plus homonymous hemianopia; lesion is in:","o":["Basilar pons","Internal capsule","Midbrain","Medulla"],"a":1,"e":"Contralateral face plus limb weakness with homonymous hemianopia indicates an internal capsule lesion hitting corticospinal and optic radiation fibres.<br><br>A pontine lesion spares the visual fields; combined motor and visual loss localises to the internal capsule."},
/*102*/ {"q":"Patient unable to open eye after RTA; nerve lesion responsible arises from:","o":["Medulla","Midbrain","Pons","Cortex"],"a":1,"e":"Inability to open the eye reflects oculomotor (CN III) palsy; the CN III nucleus lies in the midbrain.<br><br>CN VII (facial) closes the eye and arises in the pons; eyelid elevation is CN III from the midbrain."},
/*103*/ {"q":"Which of the following causes complement fixation:","o":["IgA","IgG1","IgG2","IgM"],"a":3,"e":"IgM is the most efficient classical-pathway complement-fixing antibody (pentameric structure).<br><br>IgG fixes complement less avidly and IgA poorly; the strongest complement fixer is IgM."},
/*104*/ {"q":"Transitional epithelium characteristic is:","o":["Superficial cells dome-shaped appearance","Flat cells","No change in cellular layer","Keratinized covering"],"a":0,"e":"Transitional epithelium (urothelium) has dome-shaped superficial umbrella cells that flatten on distension.<br><br>It is not keratinised; the characteristic feature is dome-shaped superficial cells."},
/*105*/ {"q":"Patient with severe headache and vomiting, tumor suspected in cerebellar area involving granular layer; what can it be:","o":["Ependymoma","Astrocytoma","Medulloblastoma","Chondroma"],"a":2,"e":"A childhood cerebellar tumour from the external granular layer with morning headache, vomiting and ataxia is medulloblastoma.<br><br>Astrocytoma is more indolent and cystic; the granular-layer malignant tumour is medulloblastoma."},
/*106*/ {"q":"Patient had RTA, does not know recent events but remembers school events; where is the lesion:","o":["Arcuate","Amygdala","Hippocampus","Frontal lobe"],"a":2,"e":"Anterograde amnesia with intact remote memory localises to the hippocampus, essential for forming new memories.<br><br>The amygdala handles emotional memory; new-memory failure is a hippocampal lesion."},
/*107*/ {"q":"Patient had RTA resulting in tibial fracture, now swelling with foul smelling discharge with crepitus; likely cause:","o":["Septicemia","Hypovolemic shock","Toxic shock","Bacteremia"],"a":0,"e":"A foul, crepitant infected open-fracture wound with systemic decline indicates spreading infection causing septicaemia.<br><br>Hypovolaemic shock follows blood loss without infection; crepitus and discharge indicate septicaemia."},
/*108*/ {"q":"Gold standard investigation for placenta previa:","o":["Pelvic USG","Pelvic MRI","Transvaginal USG","Doppler USG"],"a":2,"e":"Transvaginal ultrasound is the gold standard for localising the placenta and diagnosing placenta previa, being more accurate than transabdominal scan.<br><br>MRI is reserved for accreta evaluation; the standard is transvaginal USG."},
/*109*/ {"q":"Lateral cord of brachial plexus is formed by:","o":["One posterior division","One lateral division","Two anterior divisions","Two medial divisions"],"a":2,"e":"The lateral cord is formed by the anterior divisions of the upper and middle trunks (two anterior divisions).<br><br>Posterior divisions form the posterior cord; the lateral cord is from two anterior divisions."},
/*110*/ {"q":"Saphenous nerve is the terminal branch of which of the following:","o":["Tibial nerve","Posterior cutaneous femoral nerve","Superficial peroneal nerve","Femoral nerve"],"a":3,"e":"The saphenous nerve is the terminal cutaneous branch of the femoral nerve to the medial leg.<br><br>The tibial nerve gives the sural nerve; the medial leg's saphenous nerve is from the femoral nerve."},
/*111*/ {"q":"Deficiency in which of the following causes hyperexcitability:","o":["Na","K","Ca","PO4"],"a":2,"e":"Hypocalcaemia increases neuromuscular excitability and causes tetany by lowering the firing threshold.<br><br>Low potassium reduces excitability; the cation whose deficiency causes hyperexcitability is calcium."},
/*112*/ {"q":"Patient with weakness of sternocleidomastoid and trapezius, unable to close eye, weak palate elevation, absent gag reflex and hoarseness; lesion located in:","o":["Cerebellopontine angle","Medulla","Primary motor area","Jugular foramen"],"a":3,"e":"Combined IX, X, XI palsy (gag loss, hoarseness, weak SCM/trapezius) localises to the jugular foramen where they exit.<br><br>A cerebellopontine angle lesion affects VII/VIII; the lower cranial-nerve cluster points to the jugular foramen."},
/*113*/ {"q":"Alcoholic patient with hemorrhage near hair follicles, petechiae, skin bruises, poorly healing wounds with decreased collagen; defective cells are:","o":["Hepatocytes","Lymphocytes","Fibroblasts","Macrophages"],"a":2,"e":"Perifollicular haemorrhage and poor wound healing from defective collagen reflect impaired fibroblast collagen synthesis (scurvy).<br><br>Hepatocytes make clotting factors not structural collagen; the collagen-deficient cell is the fibroblast."},
/*114*/ {"q":"Young female with fever for 10 days and continuous chest pain unrelated to respiration; likely cause:","o":["Myocardium","Pericardium","Pleurisy","Costochondritis"],"a":0,"e":"Continuous chest pain unrelated to respiration with fever points to myocardial involvement (myocarditis).<br><br>Pleuritic pain varies with breathing and pericarditis with posture; constant febrile pain suggests myocardium."},
/*115*/ {"q":"Severe central chest pain for 2 hours; which cardiac enzyme will be raised:","o":["CPK","CK-MB","CK-MM","LDH"],"a":1,"e":"CK-MB is the cardiac-specific enzyme that rises early (within hours) after myocardial infarction.<br><br>CK-MM is skeletal and LDH rises late; the early cardiac-specific marker is CK-MB."},
/*116*/ {"q":"Slowest growing thyroid carcinoma is which of the following:","o":["Inflammatory CA","Medullary CA","Papillary CA","Follicular"],"a":2,"e":"Papillary thyroid carcinoma is the slowest growing and best-prognosis thyroid malignancy, spreading via lymphatics.<br><br>Medullary and anaplastic are more aggressive; the slowest growing is papillary carcinoma."},
/*117*/ {"q":"In the growing embryo the mesothelium covering the lungs forms:","o":["Pleuroperitoneal membrane","Pleuropericardial membrane","Parietal pleura","Visceral layer of pleura"],"a":3,"e":"The splanchnic mesothelium covering the developing lung becomes the visceral pleura.<br><br>The pleuropericardial and pleuroperitoneal membranes form partitions; the lung covering becomes the visceral pleura."},
/*118*/ {"q":"Which structure is behind the ovarian fossa:","o":["Ureter","Internal iliac","External iliac artery","External iliac vein"],"a":0,"e":"The ovarian fossa lies on the lateral pelvic wall with the ureter and internal iliac vessels along its posterior boundary.<br><br>The external iliac vessels lie anterosuperiorly; the structure directly behind the fossa is the ureter (Grey's)."},
/*119*/ {"q":"Inferior boundary of lumbar triangle is:","o":["Latissimus dorsi","Iliac crest","Quadratus lumborum","External oblique"],"a":1,"e":"The inferior lumbar (Petit) triangle is bounded inferiorly by the iliac crest.<br><br>Latissimus dorsi and external oblique form the other sides; the inferior boundary is the iliac crest."},
/*120*/ {"q":"Which structure acts as a conduit between the peritoneal cavity and the uterus:","o":["Birth canal","Cervix","Fallopian tube in female","Ovaries"],"a":2,"e":"The fallopian tube opens into the peritoneal cavity at its fimbriated end and into the uterus, forming a conduit between them.<br><br>The cervix connects to the vagina; the peritoneal-uterine conduit is the fallopian tube."},
/*121*/ {"q":"Child with history of pica, pallor and fatigue diagnosed as iron deficiency anemia; what should be given:","o":["B12","B6","Iron supplement","Folate"],"a":2,"e":"Iron deficiency anaemia is treated with iron supplementation to replenish stores and correct the anaemia.<br><br>B12 and folate treat megaloblastic anaemia; iron deficiency requires iron supplements."},
/*122*/ {"q":"Joints between vertebral bodies are:","o":["Symphysis","Synchondrosis","Syndesmosis","Synovial"],"a":0,"e":"The intervertebral joints between vertebral bodies are secondary cartilaginous joints (symphyses) with fibrocartilaginous discs.<br><br>Synchondroses are primary cartilaginous; the vertebral body joints are symphyses."},
/*123*/ {"q":"Costal ribs (costal cartilage) are which type of cartilage:","o":["Fibrocartilage","Synovial cartilage","Hyaline cartilage","Elastic cartilage"],"a":2,"e":"Costal cartilages are composed of hyaline cartilage.<br><br>Fibrocartilage forms discs and elastic cartilage the pinna; costal cartilage is hyaline."},
/*124*/ {"q":"Patient with fever and lymphadenopathy, blood picture shows atypical lymphocytes; diagnosis:","o":["Myeloma","Malaria","Lymphoma","Infectious mononucleosis"],"a":3,"e":"Fever, lymphadenopathy and reactive atypical lymphocytes are characteristic of EBV infectious mononucleosis.<br><br>Lymphoma gives monomorphic malignant cells; reactive atypical lymphocytes with fever indicate mononucleosis."},
/*125*/ {"q":"Testosterone is synthesized by which of the following:","o":["Seminiferous tubules","Sertoli cells","Leydig cells","Parenchymal cells"],"a":2,"e":"Testosterone is synthesised by the interstitial Leydig cells of the testis under LH stimulation.<br><br>Sertoli cells support spermatogenesis; testosterone is made by Leydig cells."},
/*126*/ {"q":"Inhibin is produced by Sertoli cells to inhibit which of the following:","o":["LH","Testosterone","FSH","Dopamine"],"a":2,"e":"Inhibin secreted by Sertoli cells exerts negative feedback on the anterior pituitary to inhibit FSH secretion.<br><br>LH is regulated by testosterone feedback; inhibin specifically suppresses FSH."},
/*127*/ {"q":"Female child born and sent home, 15 hours later presents with cyanosis and weak pulse; diagnosis:","o":["VSD","Transposition of great vessels","ASD","Hypoplastic left ventricle"],"a":1,"e":"Cyanosis and circulatory collapse within the first day of life suggest transposition of the great vessels, a duct-dependent lesion.<br><br>ASD/VSD present later with shunt murmurs; day-one cyanotic collapse is transposition."},
/*128*/ {"q":"Lymphatic drainage of breast upper outer lateral quadrant is to:","o":["Posterior axillary","Central axillary","External thoracic","Anterior axillary"],"a":3,"e":"The upper outer (lateral) breast quadrant drains mainly to the anterior (pectoral) axillary nodes.<br><br>Medial breast drains to internal mammary nodes; the upper outer quadrant drains to anterior axillary (KLM + BD)."},
/*129*/ {"q":"While doing needle thoracotomy which structure is damaged first:","o":["Nerve","Artery","Vein","Lymphatics"],"a":0,"e":"A needle at the lower border of the rib hits the intercostal nerve first as it lies lowest in the VAN bundle.<br><br>Inserting above the rib avoids the bundle; at the lower border the nerve (lowest of VAN) is struck first."},
/*130*/ {"q":"Patient after RTA with fracture of 9th and 10th ribs left side, hypotension; cause:","o":["Gall bladder injury","Spleen rupture","Pancreas rupture","Kidney injury"],"a":1,"e":"The spleen lies behind the left 9th-11th ribs, so left lower rib fractures with hypotension indicate splenic rupture.<br><br>Right-sided rib fractures suggest liver injury; left lower rib fracture with shock means splenic rupture."},
/*131*/ {"q":"Mental foramen location relative to the mandible and mental nerve is at the level of:","o":["1st premolar","2nd lower premolar","1st upper molar","2nd upper molar"],"a":1,"e":"The mental foramen lies between and below the premolars, at the level of the second lower premolar.<br><br>The first molar lies further posterior; the mental foramen maps to the 2nd lower premolar."},
/*132*/ {"q":"Young boy with facial asymmetry, drooling of saliva and inability to close eyes, history of chronic nasopharyngeal sinusitis; most likely cause:","o":["E. coli","Corynebacteria diphtheria","Herpes simplex virus","H. influenza"],"a":1,"e":"A cranial neuropathy with facial palsy in this clinical setting is keyed to Corynebacterium diphtheriae (diphtheritic neuropathy).<br><br>Herpes causes Bell-type palsy; the toxin-mediated cranial neuropathy here is diphtheria."},
/*133*/ {"q":"Capsule of kidney is supplied by which of the following:","o":["Interlobar artery","Arcuate artery","Interlobular artery","Pyramidal artery"],"a":2,"e":"The renal capsule is supplied by capsular twigs of the interlobular (cortical radiate) arteries.<br><br>Arcuate arteries run at the corticomedullary junction; the peripheral capsule is fed by interlobular branches."},
/*134*/ {"q":"Which bone is formed by membranocartilaginous (mixed) ossification:","o":["Frontal","Nasal","Occipital","Sphenoid"],"a":3,"e":"The sphenoid bone develops by both membranous and endochondral (cartilaginous) ossification.<br><br>The frontal and nasal bones are membranous; the mixed-ossification bone here is the sphenoid."},
/*135*/ {"q":"Patient has lost supination; which nerve injury is responsible:","o":["Median nerve","Ulnar nerve","Musculocutaneous and median nerve","Axillary nerve"],"a":2,"e":"Supination is produced by biceps (musculocutaneous) and supinator, so combined musculocutaneous/radial loss abolishes it.<br><br>Pronation loss is median (pronator teres); loss of supination implicates the musculocutaneous contribution."},
/*136*/ {"q":"Patient had fracture of humerus, now cannot raise arm above shoulder with sensory loss on lateral surface of arm and loss of abduction; which nerve is damaged:","o":["Median nerve and axillary","Radial nerve","Axillary and suprascapular nerve","Ulnar nerve"],"a":2,"e":"Loss of abduction with lateral arm sensory loss after a humeral neck fracture indicates axillary nerve injury, with suprascapular initiating abduction.<br><br>The radial nerve causes wrist drop, not abduction loss; deltoid paralysis is axillary (with suprascapular)."},
/*137*/ {"q":"Superficial external pudendal artery emerges from which of the following:","o":["Saphenous opening","Deep inguinal ring","Superficial inguinal ring","Femoral canal"],"a":0,"e":"The superficial external pudendal artery, a femoral branch, emerges through the saphenous opening.<br><br>The deep inguinal ring transmits the cord, not this vessel; it exits via the saphenous opening."},
/*138*/ {"q":"Thymoma is associated with myasthenia gravis; what other disease is associated with it:","o":["Pure red cell aplasia","Aplastic anemia","Eaton-Lambert syndrome","Megaloblastic anemia"],"a":0,"e":"Thymoma is classically associated with pure red cell aplasia, in addition to myasthenia gravis.<br><br>Eaton-Lambert relates to small cell carcinoma; the thymoma association here is pure red cell aplasia."},
/*139*/ {"q":"Referred pain of gallbladder is due to:","o":["Parasympathetic from gallbladder to parasympathetic of upper thoracic","Sensory ending in parietal peritoneum from mid cervical dermatome","Wide vagal distribution to CNS","Phrenic nerve referral"],"a":1,"e":"Gallbladder pain is referred to the shoulder via parietal (diaphragmatic) peritoneum sensory endings supplied by the phrenic nerve (C3-5).<br><br>Vagal afferents give epigastric, not shoulder, pain; shoulder-tip referral is via the parietal peritoneum/phrenic."},
/*140*/ {"q":"Which of the following supplies the gallbladder:","o":["Gastroduodenal artery","Splenic artery","Cystic artery","Gastric artery"],"a":2,"e":"The gallbladder is supplied by the cystic artery, usually a branch of the right hepatic artery.<br><br>The gastroduodenal supplies the duodenum/pancreas; the gallbladder vessel is the cystic artery."},
/*141*/ {"q":"Left gastroepiploic is a branch of which of the following:","o":["Celiac artery","Splenic artery","Hepatic artery","SMA"],"a":1,"e":"The left gastroepiploic (gastro-omental) artery arises from the splenic artery.<br><br>The right gastroepiploic comes from the gastroduodenal; the left arises from the splenic artery."},
/*142*/ {"q":"Lateral part of cerebral hemisphere function:","o":["Control movement of body","Planning and controlling fine discrete movements","Plan and coordination","Rapid movement"],"a":1,"e":"The lateral corticospinal system plans and controls fine, discrete distal limb movements.<br><br>The medial system controls axial/postural movement; fine distal control is the lateral hemisphere/tract."},
/*143*/ {"q":"Which structure lies parallel and deep to the carotid sheath:","o":["Vagus","Internal jugular","Trachea","Sympathetic trunk"],"a":3,"e":"The cervical sympathetic trunk lies posterior and deep to the carotid sheath, parallel to it on the prevertebral fascia.<br><br>The vagus is within the sheath; the structure deep and parallel to it is the sympathetic trunk."},
/*144*/ {"q":"Pancreatic injury secretion goes into which of the following:","o":["Lesser sac","Right paracolic gutter","Left paracolic gutter","Subphrenic space"],"a":0,"e":"The pancreas lies retroperitoneally behind the lesser sac, so injury leaks secretions into the lesser sac.<br><br>Anterior gut perforation tracks to the paracolic gutters; retroperitoneal pancreatic leak collects in the lesser sac."},
/*145*/ {"q":"Anterior duodenal perforation content will go into:","o":["Right anterior subphrenic space","Right posterior subphrenic space","Lesser sac","Left paracolic gutter"],"a":1,"e":"Anterior duodenal perforation, with the patient supine, tracks fluid to the right posterior subphrenic (hepatorenal) space.<br><br>Posterior wall perforation leaks into the lesser sac; anterior perforation collects in the right subphrenic space."},
/*146*/ {"q":"Student with pale nasal mucosa, nasal congestion and sneezing for 3 months; which will be most effective now:","o":["Fexofenadine","Montelukast","Ranitidine","Nasal corticosteroid"],"a":3,"e":"Chronic allergic rhinitis with congestion is most effectively treated with intranasal corticosteroids, the most effective single agent.<br><br>Antihistamines help itch/sneeze; for chronic congestion the keyed answer is nasal corticosteroid."},
/*147*/ {"q":"Sequence of events in infective endocarditis:","o":["Damaged valve > thrombus > penetration > bacteremia","Damaged valve > thrombus > bacteremia > penetration","Damaged valve > perforation > thrombus > bacteremia","Bacteremia > thrombus > perforation > emboli"],"a":1,"e":"Endocarditis develops as valve damage forming a sterile thrombus, then bacteraemia seeding it, then bacterial penetration.<br><br>Bacteraemia alone without a prior thrombus rarely seeds a normal valve; the order is damage, thrombus, bacteraemia, penetration."},
/*148*/ {"q":"Newborn with left unilateral cleft lip; the developmental defect is:","o":["Failure of left lateral palatine to fuse with median palatine","Failure of left maxillary prominence to unite with left medial nasal prominence","Failure of right and left medial nasal prominences to merge","Failure of left maxillary process to fuse with left medial nasal process"],"a":3,"e":"Unilateral cleft lip is failure of the maxillary process to fuse with the medial nasal process on that side.<br><br>Failure of the two medial nasal processes to merge gives a midline cleft; a lateral cleft is maxillary-to-medial-nasal failure."},
/*149*/ {"q":"Diet suggested in type 1 hypercholesterolemia is:","o":["Low carbohydrate","Low proteins","High fats","Polyunsaturated fatty acid"],"a":0,"e":"Type 1 hyperlipoproteinaemia (chylomicronaemia from lipoprotein lipase deficiency) is managed by a low-fat diet, sparing carbohydrate.<br><br>Restricting fat (not carbohydrate or protein) clears the chylomicrons; the dietary lever here is reducing dietary fat."},
/*150*/ {"q":"Boy with palmar xanthomas and high cholesterol; which type is it:","o":["Hypercholesterolemia 1","Hypercholesterolemia 2a","Hypercholesterolemia 2b","Hypercholesterolemia 3"],"a":3,"e":"Palmar and tuberoeruptive xanthomas are characteristic of type 3 (dysbetalipoproteinaemia) hyperlipidaemia.<br><br>Tendon xanthomas mark type 2a familial hypercholesterolaemia; palmar xanthomas are pathognomonic of type 3 (FA)."},
/*151*/ {"q":"Sympathetic cholinergic postganglionic supply is to which of the following:","o":["Detrusor muscle","Sweat gland","Adrenal medulla","Adrenal cortex"],"a":1,"e":"Sweat glands receive sympathetic postganglionic fibres that are exceptionally cholinergic (acetylcholine), unlike most sympathetic targets.<br><br>The detrusor is parasympathetic; the sympathetic cholinergic target is the sweat gland."},
/*152*/ {"q":"Well-differentiated squamous cell carcinoma of lung histopathology shows which of the following:","o":["Loss of polarity","Pleomorphism","Keratin pearls","Loss of architecture"],"a":2,"e":"Well-differentiated squamous cell carcinoma characteristically shows keratin pearls and intercellular bridges.<br><br>Loss of polarity and architecture indicate poor differentiation; well-differentiated SCC shows keratin pearls (FA + Pathoma)."},
/*153*/ {"q":"After 5 years of transplant surgery there is increased incidence of:","o":["Lymphoproliferative disorder","Skin malignancy","RCC","HCC"],"a":1,"e":"The commonest long-term malignancy after transplantation on chronic immunosuppression is skin cancer.<br><br>Post-transplant lymphoproliferative disease peaks early; over many years skin malignancy predominates."},
/*154*/ {"q":"Broca's area of speech is located in which of the following:","o":["Superior temporal gyrus","Parietal lobe","Inferior gyrus of frontal lobe","Inferior occipital lobe"],"a":2,"e":"Broca's motor speech area lies in the inferior frontal gyrus (areas 44 and 45) of the dominant hemisphere.<br><br>The superior temporal gyrus is Wernicke's area; Broca's is the inferior frontal gyrus."},
/*155*/ {"q":"A lady presented with fever and jaw abscess with draining sinus and yellow granules; causative organism is:","o":["Staph aureus","Actinomyces","Pseudomonas","Treponema"],"a":1,"e":"A chronic jaw abscess with draining sinuses and yellow sulphur granules is cervicofacial actinomycosis.<br><br>Staphylococcal abscesses lack sulphur granules; sinus tracts with granules indicate Actinomyces."},
/*156*/ {"q":"On autopsy a patient had a thrombus with lines of Zahn; this is seen in:","o":["Chicken fat supernatant","Premortem thrombus","Postmortem thrombus","Chicken lipid thrombus"],"a":1,"e":"Lines of Zahn (alternating platelet/fibrin and red cell layers) indicate a thrombus formed in flowing blood before death (premortem).<br><br>Postmortem clots lack lines of Zahn; the keyed answer is premortem thrombus."},
/*157*/ {"q":"Distance from sacral promontory to posterior surface of pubic symphysis is the:","o":["True conjugate","Obstetric conjugate","Diagonal conjugate","False conjugate"],"a":1,"e":"The obstetric conjugate runs from the sacral promontory to the posterior pubic symphysis and is the narrowest inlet dimension.<br><br>The diagonal conjugate reaches the lower symphysis border; the smallest clinically critical one is the obstetric conjugate."},
/*158*/ {"q":"Regarding the urinary bladder, which is true:","o":["Motor supply by both sympathetic and parasympathetic","Posterior surface not covered with peritoneum","Lined by columnar epithelium","Supplied by L3-4"],"a":0,"e":"The urinary bladder receives motor innervation from both sympathetic and parasympathetic systems.<br><br>It is lined by transitional, not columnar, epithelium; the correct statement is its dual autonomic motor supply."},
/*159*/ {"q":"The primary oocytes complete their first meiotic division:","o":["Before ovulation","3rd month intrauterine life","6th month intrauterine life","After fertilization"],"a":0,"e":"The primary oocyte completes the first meiotic division just before ovulation, forming the secondary oocyte.<br><br>It arrests in prophase during fetal life; first meiosis completes before ovulation."},
/*160*/ {"q":"Highest chance of pneumothorax occurs while passing a CVP line via:","o":["Right internal jugular vein","External jugular","Subclavian vein","Left external jugular vein"],"a":2,"e":"Subclavian vein cannulation carries the highest risk of pneumothorax because of the vein's proximity to the pleural dome.<br><br>The internal jugular route is safer for the lung; the highest pneumothorax risk is subclavian."},
/*161*/ {"q":"In portal hypertension which vein is likely to be dilated:","o":["Esophageal","Right gastric","Azygous vein","Inferior epigastric"],"a":0,"e":"Portal hypertension dilates the lower oesophageal portosystemic anastomosis, forming oesophageal varices.<br><br>The azygos is the systemic side of the anastomosis; the dilated tributary that bleeds is the oesophageal vein."},
/*162*/ {"q":"Which is part of the portal system:","o":["Inferior rectal vein","Hepatic vein","Superior rectal vein","Azygous vein"],"a":2,"e":"The superior rectal vein drains into the inferior mesenteric vein and so is part of the portal venous system.<br><br>The inferior rectal vein is systemic; the portal tributary here is the superior rectal vein."},
/*163*/ {"q":"Right bundle branch is supplied by which artery:","o":["LCA","RCA","PDA","LCX"],"a":0,"e":"The right bundle branch is supplied mainly by LAD septal branches of the left coronary artery.<br><br>The AV node is RCA-supplied; the right bundle branch depends chiefly on the LCA/LAD septals."},
/*164*/ {"q":"A 50-year-old man with hepatoma develops dependent edema with dilated abdominal wall veins; the structure involved is:","o":["Hepatic artery","Hepatic vein","Inferior vena cava","Portal vein"],"a":2,"e":"A hepatoma compressing the inferior vena cava causes dependent oedema with dilated abdominal wall collateral veins.<br><br>Portal vein obstruction gives ascites/caput without leg oedema; leg oedema with wall veins indicates IVC compression."},
/*165*/ {"q":"Structures passing through the posterior diaphragmatic opening:","o":["IVC","Aorta, IVC","Aorta, azygos vein and thoracic duct","Phrenic nerve"],"a":2,"e":"The aortic hiatus at T12 transmits the aorta, thoracic duct and azygos vein.<br><br>The IVC passes the caval opening at T8; the posterior aortic opening carries aorta, thoracic duct and azygos (Snell)."},
/*166*/ {"q":"Tunica vaginalis is derived from which of the following:","o":["Transversalis muscle","Transversalis fascia","Parietal peritoneum (processus vaginalis)","Internal oblique"],"a":2,"e":"The tunica vaginalis forms from the processus vaginalis, an outpouching of parietal peritoneum.<br><br>Transversalis fascia forms the internal spermatic fascia; the serous tunica vaginalis is peritoneal in origin."},
/*167*/ {"q":"After a marathon race a person lost 2 liters of sweat, then drinks 2 liters of water; what was present before drinking:","o":["Decrease ECF volume","Decrease ICF volume","Increase osmolality of ICF","Decrease osmolality of ECF"],"a":1,"e":"Hypotonic sweat loss raises ECF osmolality, drawing water out of cells so ICF volume falls before rehydration.<br><br>ECF volume falls too, but the question's pre-drink state is intracellular dehydration: decreased ICF volume."},
/*168*/ {"q":"In large data the mean will be:","o":["More","Normal","Less","Zero"],"a":0,"e":"With a large sample the mean is a more accurate (closer) estimate of the true population mean.<br><br>A small sample gives a less reliable mean; large n makes the mean estimate more accurate."},
/*169*/ {"q":"Grading of a tumor shows:","o":["Extent of spread","Degree of differentiation","Increased N/C ratio","Pleomorphism"],"a":1,"e":"Tumour grade reflects the degree of differentiation and anaplasia on histology.<br><br>Extent of spread is staging; grading indicates degree of differentiation."},
/*170*/ {"q":"Patient retiring from glacier service (high altitude) 6 months ago, now with headache and peripheral cyanosis; most probable cause:","o":["Secondary polycythemia","Polycythemia vera","Sickle cell anemia","Physiologic polycythemia"],"a":0,"e":"Chronic high-altitude hypoxia raises erythropoietin, producing secondary polycythaemia with hyperviscosity headache and cyanosis.<br><br>Polycythaemia vera has low EPO and splenomegaly; the altitude-driven, high-EPO form is secondary polycythaemia."},
/*171*/ {"q":"Young man after RTA with long bone injury, resuscitated and admitted, died 5 days later; most likely cause:","o":["Sepsis","Fat embolism","Pulmonary embolism","Air embolism"],"a":1,"e":"Death several days after a long-bone fracture with respiratory and neurological decline is fat embolism syndrome.<br><br>Pulmonary thromboembolism is sudden; the delayed petechiae-and-confusion picture is fat embolism."},
/*172*/ {"q":"Patient ate fried rice 6 hours ago, now with nausea, vomiting and diarrhea; cause is which of the following:","o":["Staph aureus","Salmonella","Bacillus cereus","Vibrio cholerae"],"a":2,"e":"Vomiting and diarrhoea within hours of reheated fried rice is Bacillus cereus from its preformed emetic toxin.<br><br>Salmonella has a longer incubation; the rapid rice-associated emetic illness is Bacillus cereus."},
/*173*/ {"q":"Young male with unequal BP in both arms, visible intercostal pulsation and rib notching on X-ray; diagnosis:","o":["Preductal aortic coarctation","Postductal aortic coarctation","Aortic arch aneurysm","Aortic stenosis"],"a":1,"e":"Rib notching with differential arm blood pressures and collateral intercostal pulsation indicates postductal coarctation of the aorta in an adult.<br><br>Preductal type presents in infancy; the adult picture is postductal coarctation."},
/*174*/ {"q":"Mentally retarded 14-year-old boy with microcephaly, low-set ears, epicanthal fold and protruberant tongue; chromosome analysis likely shows:","o":["Trisomy 21","Trisomy 18","Trisomy 13","Fragile X syndrome"],"a":0,"e":"Intellectual disability with epicanthal folds, low-set ears and a protruding tongue is Down syndrome (trisomy 21).<br><br>Trisomy 18 shows clenched fists and rocker-bottom feet; the flat-facies, macroglossia picture is trisomy 21."},
/*175*/ {"q":"Right-sided hemiplegia, left-sided pain and temperature lost below T8, right-side proprioception and touch lost below T8; cause is:","o":["Complete transection at T8","Hemisection at T8","Hemisection below T11","Cauda equina"],"a":1,"e":"Ipsilateral motor/dorsal-column loss with contralateral pain-temperature loss below the level is Brown-Sequard from cord hemisection at T8.<br><br>Complete transection abolishes all modalities bilaterally; the dissociated crossed pattern is a T8 hemisection."},
/*176*/ {"q":"Superficial epigastric artery is a branch of which of the following:","o":["Femoral artery","Internal iliac","Internal thoracic artery","External iliac artery"],"a":0,"e":"The superficial epigastric artery is a branch of the femoral artery in the femoral triangle.<br><br>The inferior epigastric arises from the external iliac; the superficial epigastric is from the femoral artery."},
/*177*/ {"q":"RBC production is stimulated by which of the following:","o":["TNF","IL 1","IL 2","IL 3"],"a":3,"e":"IL-3 is a multilineage haematopoietic growth factor that supports erythroid progenitor proliferation.<br><br>TNF and IL-1 are inflammatory; the haematopoietic growth signal among these is IL-3."},
/*178*/ {"q":"Medial and median umbilical ligaments embryologically arise from:","o":["Umbilical vein","Umbilical artery and urachus","Ductus venosus","Ductus arteriosus"],"a":1,"e":"The medial umbilical ligaments are obliterated umbilical arteries and the median umbilical ligament is the urachal remnant.<br><br>The umbilical vein becomes the ligamentum teres; the medial/median pair derive from umbilical artery and urachus."},
/*179*/ {"q":"As a horseshoe kidney ascends from the pelvis during development, it remains low because it gets trapped under:","o":["Superior mesenteric artery","Aorta","Inferior mesenteric artery","Celiac artery"],"a":2,"e":"A horseshoe kidney is caught during ascent by the inferior mesenteric artery hooking its fused lower poles.<br><br>The SMA and celiac arteries are higher; the IMA at L3 is the level that traps the isthmus."},
/*180*/ {"q":"During surgery profuse bleeding from transverse cervical artery; which of the following should be ligated:","o":["Thyrocervical trunk","Aorta","Vertebral artery","Carotid artery"],"a":0,"e":"The transverse cervical artery is a branch of the thyrocervical trunk, so bleeding is controlled by ligating that trunk.<br><br>The vertebral artery arises from the subclavian directly; the transverse cervical's parent is the thyrocervical trunk."},
/*181*/ {"q":"Patient with painless testicular swelling diagnosed as testicular tumor; it drains into which group of lymph nodes:","o":["Iliac lymph node","Popliteal lymph nodes","Inguinal lymph nodes","Para-aortic (lumbar) lymph node"],"a":3,"e":"Testicular tumours drain to the para-aortic (lumbar) nodes, following the testis's abdominal embryological origin.<br><br>Scrotal skin drains to inguinal nodes; the testis itself drains to para-aortic/lumbar nodes."},
/*182*/ {"q":"Non-pregnant lady with OGTT fasting 122, 1h 198, 2h 194; diagnosis is:","o":["Normal","DM","Gestational diabetes","Impaired glucose tolerance"],"a":3,"e":"A fasting glucose of 122 with 2-hour value 194 (140-199) meets criteria for impaired glucose tolerance, not overt diabetes.<br><br>Diabetes needs 2-hour value 200+ or fasting 126+; these intermediate values define impaired glucose tolerance."},
/*183*/ {"q":"Linea aspera of femur joins upward and medially to:","o":["Pectineal line","Intertrochanteric line","Gluteal tuberosity","All of these"],"a":3,"e":"Proximally the linea aspera diverges into the pectineal line, gluteal tuberosity and the line to the lesser trochanter.<br><br>No single line is exclusive; all three proximal continuations arise from the linea aspera (Grey's)."},
/*184*/ {"q":"Dehydration for 24 hours will affect:","o":["Decrease ADH","Decrease aldosterone","Increase cortisol","Activate RAAS"],"a":3,"e":"Dehydration reduces blood volume and activates the renin-angiotensin-aldosterone system to conserve sodium and water.<br><br>ADH and aldosterone rise (not fall) in dehydration; the integrating response is RAAS activation."},
/*185*/ {"q":"A sprained ankle resulting from excessive eversion most likely demonstrates damage to which structure:","o":["Talofibular ligament","Deltoid ligament","Tendon calcaneus","Interosseous ligament"],"a":1,"e":"Excessive eversion strains or tears the medial (deltoid) ligament of the ankle.<br><br>Inversion injures the lateral talofibular ligament; eversion damages the deltoid ligament."},
/*186*/ {"q":"Tall young man with aortic root dilatation up to 4 cm, lens dislocation, mitral valve leaflet defect with systolic click; diagnosis:","o":["Edward syndrome","Down syndrome","Marfan syndrome","Patau syndrome"],"a":2,"e":"Tall stature with aortic root dilatation, ectopia lentis and mitral valve prolapse is Marfan syndrome (fibrillin-1 defect).<br><br>The trisomy syndromes cause intellectual disability and short stature; the connective-tissue tall phenotype is Marfan."},
/*187*/ {"q":"Climber at high altitude experiences hypothermia; on returning to base camp adapts to cold weather by heat generation due to which of the following:","o":["Anterior hypothalamus","Posterior hypothalamus","Lateral hypothalamus","Thalamus"],"a":1,"e":"The posterior hypothalamus, activated by cold, drives sympathetic heat generation and conservation.<br><br>The anterior hypothalamus mediates heat loss; cold-induced heat generation is the posterior hypothalamus."},
/*188*/ {"q":"Absence of cartilage in respiratory and terminal ducts differentiates it from which of the following:","o":["Conducting bronchioles","Terminal bronchioles","Trachea","Alveolar duct"],"a":2,"e":"Absence of cartilage in the bronchiolar wall distinguishes bronchioles from the cartilage-containing trachea.<br><br>Bronchi also have cartilage; the cartilage-bearing structure differentiated from bronchioles here is the trachea."},
/*189*/ {"q":"After a finger cut the immediate mediator will be:","o":["Histamine","Macrophages","Lymphocytes","Plasma cells"],"a":0,"e":"Histamine is the immediate vasoactive mediator released by mast cells in acute inflammation after injury.<br><br>Macrophages and lymphocytes act later; the immediate mediator is histamine."},
/*190*/ {"q":"Second heart sound is due to:","o":["Rapid ejection","Rapid filling","Isovolumetric relaxation (closure of aortic and pulmonary valves)","Isovolumetric contraction"],"a":2,"e":"The second heart sound results from closure of the aortic and pulmonary (semilunar) valves at the onset of isovolumetric relaxation.<br><br>The first sound is AV valve closure; S2 is semilunar valve closure."},
/*191*/ {"q":"AV nodal delay helps in which of the following:","o":["Atrial filling","Ventricle filling","Aorta filling","Ventricle contraction"],"a":1,"e":"The AV nodal delay allows the atria to empty and the ventricles to fill before ventricular contraction.<br><br>It does not delay aortic filling (that is ejection); the delay optimises ventricular filling."},
/*192*/ {"q":"A PPD tuberculin test, after 40 hours 15 mm erythema noticed; cells responsible for erythema are:","o":["Helper T cell","Cytotoxic T cell","NK cells","Eosinophils"],"a":0,"e":"The tuberculin (Mantoux) reaction is a type IV delayed hypersensitivity mediated by CD4+ helper T cells and macrophages.<br><br>NK and cytotoxic cells are not the effectors here; the indurated DTH response is CD4 helper T-cell mediated."},
/*193*/ {"q":"Chondrocyte to osteoblast conversion occurs due to which of the following:","o":["Thyroxin","GH","Somatotropin","Cortisol"],"a":1,"e":"Growth hormone (via IGF-1) drives chondrocyte proliferation and the endochondral chondrocyte-to-osteoblast transition.<br><br>Cortisol inhibits growth; the linear-growth-promoting hormone among these is growth hormone."},
/*194*/ {"q":"Carcinoma of head of pancreas will compress which structure:","o":["Hepatic duct","CBD (common bile duct)","IVC","Portal vein"],"a":1,"e":"Carcinoma of the pancreatic head compresses the common bile duct as it traverses the head, causing obstructive jaundice.<br><br>The hepatic duct lies more proximal; a pancreatic head mass first obstructs the common bile duct, causing painless jaundice."},
/*195*/ {"q":"Vicious cycle leading to death is an example of:","o":["Negative feedback","Positive feedback","Central chemoreceptor","Proprioceptor"],"a":1,"e":"A self-amplifying vicious cycle is positive feedback, where an effect intensifies its own cause leading to deterioration.<br><br>Negative feedback restores stability; a vicious cycle is positive feedback."},
/*196*/ {"q":"As compared to a normal person, an athlete has resting increased cardiac output due to:","o":["Increase SV","Increase SV and heart rate","Increase SV and decrease heart rate","Both decreased"],"a":2,"e":"Trained athletes have a high stroke volume with resting bradycardia; cardiac output is maintained by the large stroke volume despite the lower heart rate.<br><br>Athletes lower resting heart rate while raising stroke volume; the combination, not heart-rate rise, sustains output."},
/*197*/ {"q":"Patient with carcinoma resected, anti-hormonal treatment given; which malignancy:","o":["Ovarian CA","Breast CA","Colon CA","Prostate CA"],"a":1,"e":"Anti-hormonal (anti-oestrogen) therapy after resection is characteristic of hormone-receptor-positive breast carcinoma.<br><br>Anti-hormonal (anti-oestrogen) therapy targets hormone-receptor-positive breast cancer, unlike colon or ovarian carcinoma."},
/*198*/ {"q":"Which hormone is responsible for increased gastric emptying:","o":["Glucagon","Gastrin","Secretin","Somatostatin"],"a":1,"e":"Gastrin increases gastric motility and emptying along with stimulating acid secretion.<br><br>Secretin and somatostatin slow emptying; gastrin is the hormone that promotes gastric motility and emptying."},
/*199*/ {"q":"Patient with schizophrenia on clozapine, stable for a month, stopped taking it and not eating for one week; best treatment:","o":["Restart clozapine","Antidepressants","Depot antipsychotics","Shift to ECT"],"a":0,"e":"In a previously stable patient who has stopped clozapine with relapse, the appropriate step is to restart clozapine.<br><br>An antipsychotic relapse from stopped clozapine is managed by restarting clozapine, not switching to ECT or antidepressants."},
/*200*/ {"q":"Woman and man with recurrent pregnancy loss, unremarkable clinical and genetic history, all pregnancies end as stillbirth; how to investigate:","o":["Southern blot","Tandem mass spectroscopy","Next generation sequencing","Karyotyping"],"a":3,"e":"Recurrent pregnancy loss with stillbirths warrants parental karyotyping to detect balanced chromosomal translocations.<br><br>Normal parental clinical/genetic history with recurrent stillbirth still warrants karyotyping to detect a balanced translocation."},
/*201*/ {"q":"A man with history of eating pan for several years presents with changes in oral cavity; complication that can occur:","o":["Keratitis","BCC","SCC","Mucoepidermoid CA"],"a":2,"e":"Chronic betel/pan chewing causes oral submucous fibrosis and leukoplakia predisposing to squamous cell carcinoma.<br><br>BCC affects sun-exposed skin; the oral pan-chewing malignancy is squamous cell carcinoma."},
/*202*/ {"q":"Patient with apathy, hepatomegaly, edema and depigmentation diagnosed as kwashiorkor; edema is due to which of the following:","o":["Low Na","Low alpha globulin","Low albumin","Low beta globulin"],"a":2,"e":"Kwashiorkor oedema results from hypoalbuminaemia lowering plasma oncotic pressure due to severe protein deficiency.<br><br>Sodium is not the cause; the oedema is from low albumin."},
/*203*/ {"q":"On biopsy of an ascending colon mass, adenocarcinoma is diagnosed; risk factor for it is:","o":["Fatty diet","Smoking","Calcium","Nitrosamine"],"a":0,"e":".<br><br>Smoking links more to other cancers; the dominant dietary risk for colorectal adenocarcinoma is a high-fat low-fibre diet."},
/*204*/ {"q":"Mutation in sickle cell anemia is which of the following:","o":["Missense","Nonsense","Silent","Deletion"],"a":0,"e":"Sickle cell anaemia is caused by a missense point mutation substituting valine for glutamate in beta-globin.<br><br>It is not a nonsense or deletion mutation; it is a missense mutation."},
/*205*/ {"q":"During a game a boy injured part of the orbit, now has vertical diplopia and enophthalmos; which area of the orbit:","o":["Apex","Base","Roof","Floor"],"a":3,"e":"Vertical diplopia with enophthalmos indicates an orbital floor (blow-out) fracture trapping the inferior rectus.<br><br>Roof damage gives diplopia with proptosis; floor fracture gives diplopia with enophthalmos."},
/*206*/ {"q":"A boy after blunt trauma to eye with lower orbit fracture, crackling sound on palpation and blood accumulation; diagnosis:","o":["Orbital edema","Surgical emphysema","Foreign body","Fracture bone pieces"],"a":1,"e":"Crepitus (crackling) on palpation after an orbital fracture communicating with a sinus indicates surgical (subcutaneous) emphysema.<br><br>Crackling (crepitus) on lid palpation after an orbital floor fracture is surgical emphysema from sinus air, not simple oedema."},
/*207*/ {"q":"Which structures pass superficial to the flexor retinaculum:","o":["Flexor digitorum superficialis and ulnar artery","Ulnar nerve and ulnar artery","Median nerve and ulnar nerve","Flexor digitorum superficialis and median nerve"],"a":1,"e":"The ulnar nerve and ulnar artery pass superficial to the flexor retinaculum (through Guyon's canal), not through the carpal tunnel.<br><br>The median nerve and flexor tendons pass deep to it; superficial are the ulnar nerve and artery."},
/*208*/ {"q":"Middle esophagus is supplied by which of the following:","o":["Inferior thyroid artery","Descending thoracic aorta","Left gastric artery","Celiac artery"],"a":1,"e":"The middle third of the oesophagus is supplied by oesophageal branches of the descending thoracic aorta.<br><br>The upper third is inferior thyroid and lower third left gastric; the middle is the thoracic aorta."},
/*209*/ {"q":"Which ATT drug causing peripheral tingling sensation, which vitamin should be given:","o":["B12","B3","B6","B9"],"a":2,"e":"Isoniazid causes peripheral neuropathy (tingling), prevented and treated with pyridoxine (vitamin B6).<br><br>Isoniazid causes peripheral neuropathy by depleting pyridoxine, so vitamin B6 is the protective vitamin."},
/*210*/ {"q":"A 65-year-old man with fatigue, pallor and weight loss; golden-yellow pigment in liver that turns blue on staining is:","o":["Hemosiderin","Lipofuscin","Hemoglobin","Hemochromatosis"],"a":1,"e":".<br><br>Haemosiderin stains blue with Prussian blue; the golden-yellow wear-and-tear pigment that does not is lipofuscin."},
/*211*/ {"q":"Transverse mesocolon is attached posteriorly to:","o":["Pancreas","2nd part of duodenum","Lesser sac","Great curvature"],"a":1,"e":"The transverse mesocolon root attaches across the second part of the duodenum, head of pancreas and along the lower pancreatic border.<br><br>The transverse mesocolon root crosses the second part of the duodenum and pancreas; the keyed posterior attachment is the 2nd duodenum."},
/*212*/ {"q":"Which of the following ligament is formed from ventral mesogastrium:","o":["Hepatoduodenal","Splenorenal","Cardinal","Gastrosplenic"],"a":0,"e":"The ventral mesogastrium gives rise to the falciform and hepatoduodenal/hepatogastric ligaments.<br><br>The splenorenal and gastrosplenic ligaments are dorsal mesogastrium; the ventral derivative is the hepatoduodenal ligament."},
/*213*/ {"q":"Rathke's pouch is derived from which of the following:","o":["Endoderm","Mesoderm","Stomodeum","Neural crest cells"],"a":2,"e":"Rathke's pouch, the anterior pituitary precursor, is an ectodermal upgrowth from the stomodeum.<br><br>Rathke's pouch (anterior pituitary) is an ectodermal outpouching of the stomodeum, not endoderm or neural crest."},
/*214*/ {"q":"Which of the following is a locally malignant tumor:","o":["Melanoma","Squamous cell carcinoma","Ameloblastoma","Adenoid cystic carcinoma"],"a":2,"e":"Ameloblastoma is a locally invasive (locally malignant) odontogenic tumour that rarely metastasises.<br><br>Melanoma and SCC metastasise widely; the locally malignant tumour is ameloblastoma."},
/*215*/ {"q":"Child had fever, sore throat, took antibiotic for 3 weeks, later developed generalized edema and haematuria; likely diagnosis:","o":["RPGN","Membranous nephritis","PSGN","FSGN"],"a":2,"e":"Oedema and haematuria following a streptococcal throat infection with a latent period indicates post-streptococcal glomerulonephritis.<br><br>A 1-3 week latency after pharyngitis with oedema and haematuria is post-streptococcal GN, not rapidly progressive GN."},
/*216*/ {"q":"An old man had urine incontinence and did not do anything for treatment for few years; what was the type of problem:","o":["Prostate CA","Benign prostate hyperplasia","Urethral stricture","Bladder CA"],"a":1,"e":"Chronic untreated urinary symptoms in an elderly man are most commonly due to benign prostatic hyperplasia causing outflow obstruction.<br><br>Untreated chronic obstructive urinary symptoms in an older man are due to benign prostatic hyperplasia rather than carcinoma."},
/*217*/ {"q":"7-month pregnant lady with chronic ITP, ecchymosis and epistaxis, platelet count 5x10, on full steroid dose; next suitable step:","o":["IV immunoglobulin","Immunosuppressants","Splenectomy","Plasmapheresis"],"a":0,"e":"Severe ITP unresponsive to steroids, especially in pregnancy, is next managed with intravenous immunoglobulin for rapid platelet rise.<br><br>Splenectomy is later; the next step is IV immunoglobulin."},
/*218*/ {"q":"Mother with blood group A+ gave birth to a baby with blood group O-, father is O-; chance of hemolytic reaction in newborn:","o":["Newborn will not develop erythroblastosis fetalis","Newborn will develop temporary erythroblastosis fetalis","Newborn will develop permanent erythroblastosis fetalis","Newborn will develop erythroblastosis fetalis after a month"],"a":0,"e":"An Rh-negative baby of an Rh-negative father is not at risk of Rh haemolytic disease, so erythroblastosis fetalis will not develop.<br><br>An O- baby has no A or Rh antigen for maternal anti-A or anti-Rh to attack, so no erythroblastosis develops."},
/*219*/ {"q":"Lymphatic drainage of cervix is to:","o":["External iliac","Inguinal","Internal iliac","Internal and external iliac"],"a":3,"e":"The cervix drains to the internal and external iliac and obturator lymph nodes.<br><br>The cervix drains to both internal and external iliac (and sacral) nodes, broader than the fundal/inguinal routes."},
/*220*/ {"q":"Characteristic of staphylococcal toxic shock syndrome is:","o":["Discrete papular rash","Misnomer","Cellulitis","Scalded skin / diffuse erythematous rash"],"a":3,"e":"Staphylococcal toxic shock syndrome features a diffuse erythematous (sunburn-like) rash with desquamation, fever and hypotension.<br><br>Toxic shock syndrome produces a diffuse erythematous (scalded-skin-like) rash with desquamation, not a discrete papular rash."},
/*221*/ {"q":"Streptococcus is diagnosed than gram stain by which technique:","o":["Serology","CBC","Electrophoresis","Bone marrow biopsy"],"a":0,"e":"Streptococcal infection is confirmed serologically (e.g. ASO titre) beyond Gram stain.<br><br>Streptococci are subtyped beyond Gram stain by serological (Lancefield) grouping, not by CBC or electrophoresis."},
/*222*/ {"q":"Diabetic patient having ulcer; it affects which of the following:","o":["Capillaries","Arteriovenous","Arterioles","Veins"],"a":2,"e":"Diabetic microangiopathy primarily affects the arterioles (and capillaries), leading to ischaemic ulcers.<br><br>Diabetic microangiopathy primarily damages arterioles (hyaline arteriolosclerosis), not the large veins."},
/*223*/ {"q":"In intrinsic pathway damage, what is activated first coming into contact with collagen:","o":["Factor 11","Factor 12","Factor 9","Factor 5"],"a":1,"e":"The intrinsic coagulation pathway is initiated when factor XII (factor 12) contacts exposed collagen/negatively charged surfaces.<br><br>Factor XI is activated next; the first contact factor is factor XII."},
/*224*/ {"q":"Which of the following is a tributary of the portal vein:","o":["Inferior mesenteric vein","Hemiazygous","Inferior epigastric vein","Left renal vein"],"a":0,"e":"The inferior mesenteric vein is a tributary of the portal venous system (draining into the splenic vein).<br><br>The hemiazygos and renal veins are systemic; the portal tributary is the inferior mesenteric vein."},
/*225*/ {"q":"Which vein drains directly into the SVC:","o":["Anterior cardiac vein","Vena cordis minima","Azygos vein","Hemiazygos vein"],"a":2,"e":"The azygos vein arches over the right main bronchus and drains directly into the superior vena cava.<br><br>The hemiazygos drains into the azygos; the vein draining directly into SVC is the azygos."},
/*226*/ {"q":"Apex beat is located in which of the following site:","o":["4th left intercostal space in midclavicular line","3rd right intercostal space in midclavicular line","5th right intercostal space in midclavicular line","5th left intercostal space mid-clavicular line"],"a":3,"e":"The normal apex beat is in the left 5th intercostal space in the midclavicular line.<br><br>The apex beat is at the 5th left intercostal space in the midclavicular line; the 4th space or right-sided points are wrong landmarks."},
/*227*/ {"q":"In berry aneurysm, posterior communicating artery compression causes which deficit:","o":["Trochlear nerve palsy","Facial palsy","Oculomotor palsy","Trigeminal palsy"],"a":2,"e":"A posterior communicating artery aneurysm compresses the oculomotor nerve, causing CN III palsy with a blown pupil, ptosis and a down-and-out eye.<br><br>A posterior communicating artery aneurysm compresses CN III, giving a down-and-out pupil-involving oculomotor palsy."},
/*228*/ {"q":"A non-diabetic female with chronic rhinosinusitis develops septate hyphae at acute angle and respiratory symptoms; most likely fungus is:","o":["Candida","Histoplasmosis","Aspergillus","Mucor"],"a":2,"e":"Septate hyphae branching at acute angles in a non-diabetic with rhinosinusitis indicates Aspergillus.<br><br>Mucor has non-septate wide-angle hyphae; the acute-angle septate fungus is Aspergillus (FA)."},
/*229*/ {"q":"Female breast feeds her child; what would happen:","o":["Failure of primordial follicles to mature","Decrease prolactin","Increase dopamine","Increase primordial cell maturation"],"a":0,"e":"Lactation maintains high prolactin which suppresses GnRH, so ovarian primordial follicles fail to mature (lactational amenorrhoea).<br><br>Prolactin is increased; the result is failure of follicular maturation."},
/*230*/ {"q":"Child has congenital aganglionic megacolon; what is the root value of nerve involved:","o":["S4-5","S2-4","S1-2","L4-5"],"a":1,"e":"Hirschsprung disease involves the parasympathetic supply to the distal colon, from the sacral S2-S4 (pelvic splanchnic) roots.<br><br>Hirschsprung aganglionosis involves the sacral parasympathetic outflow (S2-S4), not the lumbar or S4-5 roots."},
/*231*/ {"q":"External oblique fibers interdigitate with which of the following:","o":["Serratus anterior","Trapezius","Sternocleidomastoid","Latissimus dorsi"],"a":0,"e":"The fleshy digitations of the external oblique interdigitate with serratus anterior on the lateral chest wall.<br><br>The external oblique interdigitates with serratus anterior over the lateral chest, not with latissimus or trapezius."},
/*232*/ {"q":"Wound contraction is mediated by which of the following:","o":["Fibroblasts","Myofibroblasts","Endothelial cells","Collagen type 3"],"a":1,"e":"Wound contraction is mediated by myofibroblasts, which contain contractile actin and draw wound edges together.<br><br>Fibroblasts make collagen; contraction itself is by myofibroblasts."},
/*233*/ {"q":"A patient was given penicillin for an infection but is allergic to penicillin; what will be found in blood:","o":["IgG","IgM","IgE","IgD"],"a":2,"e":"An immediate (type I) penicillin allergy is mediated by IgE antibodies causing mast cell degranulation.<br><br>A type I penicillin allergy is IgE-mediated, releasing histamine; IgG/IgM mediate other reaction types."},
/*234*/ {"q":"C-wave on JVP corresponds to which of the following:","o":["Atrial contraction","Atrial fibrillation","Right ventricular contraction","Constrictive pericarditis"],"a":2,"e":"The c-wave of the jugular venous pulse is produced by right ventricular contraction bulging the closed tricuspid valve into the atrium.<br><br>The a-wave is atrial contraction; the c-wave is right ventricular contraction."},
/*235*/ {"q":"Thirst is increased by:","o":["Renin","Increase angiotensin 2","Angiotensin 1","ADH"],"a":1,"e":"Angiotensin II is a potent dipsogen acting on the hypothalamic thirst centre.<br><br>Renin and ADH act indirectly; angiotensin II is the direct dipsogenic mediator stimulating thirst."},
/*236*/ {"q":"Ovum after release from ovary release granulosa cells that give rise to which cellular structure:","o":["2nd polar body","Corona radiata","First polar body","3rd polar body"],"a":1,"e":"After ovulation the surrounding granulosa cells form the corona radiata around the oocyte.<br><br>Polar bodies are meiotic products of the oocyte; the granulosa-derived layer is the corona radiata."},
/*237*/ {"q":"Most common cause of meningitis in neonates:","o":["Group B Streptococcus","Streptococcus pneumoniae","Neisseria meningitidis","Haemophilus influenzae"],"a":0,"e":"Group B Streptococcus (with E. coli) is the commonest cause of neonatal bacterial meningitis acquired perinatally.<br><br>Pneumococcus and meningococcus dominate later; in neonates it is Group B Streptococcus."},
/*238*/ {"q":"Most common organism causing acute osteomyelitis:","o":["Staphylococcus aureus","Streptococcus","Salmonella","Pseudomonas"],"a":0,"e":"Staphylococcus aureus is the commonest cause of acute osteomyelitis in all age groups.<br><br>Salmonella is classic in sickle cell disease; overall the leading cause is Staph aureus."},
/*239*/ {"q":"Most common site of berry aneurysm:","o":["Anterior communicating artery","Middle cerebral artery","Basilar artery","Posterior cerebral artery"],"a":0,"e":"Berry (saccular) aneurysms most commonly arise at the anterior communicating artery of the circle of Willis.<br><br>Other sites are less frequent; the commonest is the anterior communicating artery."},
/*240*/ {"q":"Reed-Sternberg cells are diagnostic of:","o":["Hodgkin lymphoma","Non-Hodgkin lymphoma","Burkitt lymphoma","CLL"],"a":0,"e":"Binucleate owl-eye Reed-Sternberg cells are the diagnostic hallmark of Hodgkin lymphoma.<br><br>Non-Hodgkin lymphomas lack them; RS cells define Hodgkin lymphoma."},
/*241*/ {"q":"Philadelphia chromosome t(9;22) is seen in:","o":["Chronic myeloid leukemia","Acute lymphoblastic leukemia only","Hodgkin lymphoma","Multiple myeloma"],"a":0,"e":"The Philadelphia chromosome, t(9;22) producing BCR-ABL, is the hallmark of chronic myeloid leukaemia.<br><br>It is not seen in Hodgkin or myeloma; the classic CML marker is the Philadelphia chromosome."},
/*242*/ {"q":"Auer rods are characteristic of:","o":["Acute myeloid leukemia","Acute lymphoblastic leukemia","CLL","CML"],"a":0,"e":"Auer rods, needle-shaped azurophilic inclusions, are characteristic of acute myeloid leukaemia.<br><br>Lymphoid leukaemias lack them; Auer rods indicate AML."},
/*243*/ {"q":"Most common cause of nephrotic syndrome in children:","o":["Minimal change disease","Membranous nephropathy","FSGS","Membranoproliferative GN"],"a":0,"e":"Minimal change disease is the commonest cause of nephrotic syndrome in children, with podocyte foot process effacement.<br><br>Membranous predominates in adults; in children it is minimal change disease."},
/*244*/ {"q":"Most common cause of community-acquired pneumonia:","o":["Streptococcus pneumoniae","Mycoplasma","Haemophilus","Legionella"],"a":0,"e":"Streptococcus pneumoniae is the commonest cause of community-acquired pneumonia.<br><br>Atypicals and Haemophilus are less frequent; the leading cause is pneumococcus."},
/*245*/ {"q":"Most common thyroid carcinoma:","o":["Papillary carcinoma","Follicular carcinoma","Medullary carcinoma","Anaplastic carcinoma"],"a":0,"e":"Papillary carcinoma is the commonest thyroid malignancy, with the best prognosis and characteristic nuclear features.<br><br>The other types are less frequent; the commonest is papillary carcinoma."},
/*246*/ {"q":"Most common type of cervical carcinoma:","o":["Squamous cell carcinoma","Adenocarcinoma","Small cell carcinoma","Sarcoma"],"a":0,"e":"Squamous cell carcinoma is the commonest histological type of cervical cancer, arising at the transformation zone.<br><br>Adenocarcinoma is less frequent; the commonest is squamous cell carcinoma."},
/*247*/ {"q":"Most common cause of subarachnoid hemorrhage (spontaneous):","o":["Ruptured berry aneurysm","Hypertensive bleed","AV malformation","Trauma"],"a":0,"e":"Spontaneous subarachnoid haemorrhage is most commonly due to rupture of a berry aneurysm in the circle of Willis.<br><br>AV malformations are less frequent; the leading cause is ruptured berry aneurysm."},
/*248*/ {"q":"Most common primary brain tumor in adults:","o":["Glioblastoma multiforme","Meningioma","Schwannoma","Oligodendroglioma"],"a":0,"e":"Glioblastoma multiforme is the commonest malignant primary brain tumour in adults; meningioma is the commonest benign one.<br><br>Meningioma and schwannoma are extra-axial and often benign; the commonest primary intra-axial adult brain tumour is glioblastoma multiforme."},
/*249*/ {"q":"Most common cause of dementia:","o":["Alzheimer disease","Vascular dementia","Lewy body dementia","Frontotemporal dementia"],"a":0,"e":"Alzheimer disease is the commonest cause of dementia, with amyloid plaques and neurofibrillary tangles.<br><br>Vascular dementia is second; the leading cause is Alzheimer disease."},
/*250*/ {"q":"Most common renal malignancy in adults:","o":["Renal cell carcinoma","Wilms tumor","Transitional cell carcinoma","Angiomyolipoma"],"a":0,"e":"Renal cell carcinoma is the commonest primary renal malignancy in adults, arising from proximal tubular epithelium.<br><br>Wilms tumour is paediatric; in adults it is renal cell carcinoma."},
/*251*/ {"q":"After partial gastrectomy a patient most likely develops which anemia:","o":["Iron deficiency anemia","Fat malabsorption","Pernicious anemia","Blood loss anemia"],"a":0,"e":"Partial gastrectomy reduces acid and causes iron malabsorption, so iron deficiency anaemia develops early (megaloblastic anaemia occurs later).<br><br>B12 deficiency follows total gastrectomy; partial gastrectomy more commonly causes iron deficiency from impaired iron absorption."},
/*252*/ {"q":"A patient with alcohol consumption has referred pain to neck, shoulder and upper back; likely organ involved:","o":["Liver","Gall bladder","Pancreas","Stomach"],"a":1,"e":".<br><br>Pancreatic pain refers to the back; right-sided phrenic-mediated shoulder/neck referral indicates gallbladder disease."},
/*253*/ {"q":"Nerve fibers placed in sodium-free solution; what happens to action potential:","o":["No action potential","Increase threshold of potential","Depolarization","Repolarization"],"a":0,"e":"The action potential upstroke depends on sodium influx, so in a sodium-free medium no action potential can be generated.<br><br>Without sodium the membrane cannot depolarise; there is no action potential."},
/*254*/ {"q":"Final wound strengthening is by which type of collagen:","o":["Collagen 3","Collagen 2","Collagen 1","Collagen 4"],"a":2,"e":"Late wound remodelling replaces type III with type I collagen, giving the wound its final tensile strength.<br><br>Type III dominates early granulation tissue; final strength is from type I collagen."},
/*255*/ {"q":"Patient in road accident with cervical vertebral injury, diminished triceps reflex and atrophy of muscle from spinal disc herniation; site:","o":["C2-3","C5-6","C6-7","L4-5"],"a":2,"e":"A diminished triceps reflex with associated muscle wasting localises to the C7 root, from a C6-7 disc herniation.<br><br>A diminished triceps reflex with C7 myotome wasting localises a disc lesion to C6-7 (compressing the C7 root)."},
/*256*/ {"q":"In a wound left open for secondary healing, which cell plays a key role in wound contraction:","o":["Myeloproliferative","Myofibroblast","Chondroblast","Osteoblast"],"a":1,"e":"Wound contraction in secondary healing is performed by myofibroblasts, which contain contractile actin.<br><br>Fibroblasts make collagen but the contractile cell that pulls wound edges together is the myofibroblast."},
/*257*/ {"q":"In mismatched blood transfusion what occurs:","o":["Donor blood agglutinated and hemolysis","No reaction","Graft vs host reaction","Hyperacute graft rejection"],"a":0,"e":"An ABO-incompatible transfusion causes agglutination and intravascular haemolysis of the transfused red cells by recipient antibodies.<br><br>In ABO-mismatch transfusion the recipient's antibodies agglutinate and haemolyse the donor cells; it is not graft rejection."},
/*258*/ {"q":"T lymphocyte produces what that causes red blood cell proliferation:","o":["TNF","Interleukin 2","Interleukin 3","Interleukin 4"],"a":2,"e":".<br><br>IL-2 drives T-cell proliferation; the multilineage factor supporting erythroid progenitors here is IL-3."},
/*259*/ {"q":"Which structure has intrapelvic and extrapelvic extension:","o":["Round ligament of uterus","Round ligament of ovary","Cervical ligament","Suspensory ligament"],"a":0,"e":"The round ligament of the uterus runs from the uterus through the inguinal canal to the labium majus, so it is partly intrapelvic and partly extrapelvic.<br><br>The round ligament of the uterus passes through the inguinal canal, giving it intra- and extra-pelvic parts, unlike the ovarian ligament."},
/*260*/ {"q":"Thoracolumbar outflow is:","o":["Sympathetic system","Parasympathetic system","Peripheral nervous system","Autonomic nervous system"],"a":0,"e":"The sympathetic nervous system has a thoracolumbar (T1-L2) outflow, while the parasympathetic is craniosacral.<br><br>Craniosacral outflow is parasympathetic; the thoracolumbar (T1-L2) outflow is the sympathetic system."},
/*261*/ {"q":"A woman with fever and pain after inflammation; mediators of her symptoms are:","o":["IL1+TNF","LTB4","C5a","Prostaglandin"],"a":0,"e":"IL-1 and TNF are the principal cytokines causing fever and the acute systemic inflammatory response.<br><br>Prostaglandins mediate pain/vasodilation, but the endogenous pyrogens producing fever with inflammation are IL-1 and TNF."},
/*262*/ {"q":"A pathologist sees on slide that neutrophils are utilizing oxygen, a burst O2 reaction; in which step is it necessary:","o":["Phagocytosis","Microbacterial activity of neutrophils","Vascular permeability","Inflammation"],"a":1,"e":"The respiratory (oxidative) burst generates reactive oxygen species for intracellular microbial killing by neutrophils.<br><br>The respiratory (oxidative) burst generates microbicidal oxygen radicals for intracellular killing, not for vascular permeability."},
/*263*/ {"q":"Epiploic foramen posterior relation is:","o":["Caudate lobe of liver","SMA","IVC","Aorta"],"a":2,"e":"The epiploic (omental) foramen of Winslow is bounded posteriorly by the inferior vena cava.<br><br>The caudate lobe is superior and the hepatoduodenal ligament anterior; posteriorly lies the IVC."},
/*264*/ {"q":"A child had a fracture with cast applied to leg; after removal calf muscles show reduced muscle mass; this is due to:","o":["Denervation","Decrease blood supply","Decrease workload (disuse atrophy)","Pressure atrophy"],"a":2,"e":"Immobilisation in a cast causes disuse (decreased workload) muscle atrophy.<br><br>Denervation atrophy needs nerve loss; immobilisation in a cast causes disuse (reduced-workload) atrophy with intact nerves."},
/*265*/ {"q":"Tunica vaginalis is derived from which of the following:","o":["Transversalis muscle","Transversalis fascia","Parietal peritoneum (processus vaginalis)","Gubernaculum"],"a":2,"e":"The tunica vaginalis is derived from the processus vaginalis, an evagination of the parietal peritoneum.<br><br>Transversalis fascia forms the internal spermatic fascia; the serous tunica vaginalis derives from the parietal peritoneum."},
/*266*/ {"q":"During surgery a surgeon accidentally cuts the hepatoduodenal ligament; which structure is likely damaged:","o":["Common bile duct","Portal vein","IVC","Hepatic artery"],"a":0,"e":"The hepatoduodenal ligament contains the portal triad.<br><br>The hepatoduodenal ligament carries the portal triad; the most superficially placed, easily cut structure is the common bile duct."},
/*267*/ {"q":"Patient with fatigue, dizziness, low Hb and breathing difficulty diagnosed as anemic hypoxia; which statement is true:","o":["Not responsive to oxygen therapy","Corrected by platelets","Responsive to antibiotics","Responsive to prolonged oxygen"],"a":0,"e":"Anaemic hypoxia is due to reduced oxygen-carrying capacity, so it responds poorly to oxygen therapy and requires correction of the anaemia.<br><br>Anaemic hypoxia has normal PaO2 but low carrying capacity, so it is not corrected by giving more oxygen."},
/*268*/ {"q":"Food bolus moving down in esophagus, which propels the bolus downward:","o":["Primary peristalsis","Segmentation","Haustration","Electrical waves"],"a":0,"e":"Primary oesophageal peristalsis, a coordinated progressive wave, propels the swallowed bolus toward the stomach.<br><br>Segmentation mixes intestinal content; oesophageal transport is by primary peristalsis."},
/*269*/ {"q":"Which tumor marker is raised in colon CA and normally present in fetal life:","o":["CA19-9","CA123","ALP","CEA"],"a":3,"e":"Carcinoembryonic antigen (CEA) is a fetal antigen elevated in colorectal carcinoma, used for follow-up.<br><br>CA 19-9 relates to pancreatic cancer; the fetal colon marker is CEA."},
/*270*/ {"q":"On histology liver shows centrally distorted area surrounded by epithelioid cells, lymphocytes and giant cells; this is related to:","o":["Coagulative necrosis","Caseous necrosis (granuloma)","Acute hepatitis","Fat necrosis"],"a":1,"e":"Epithelioid cells, lymphocytes and giant cells around a necrotic centre form a caseating granuloma, typically tuberculous.<br><br>Coagulative necrosis is bland infarction; the granuloma with epithelioid cells and giant cells around central necrosis is caseous necrosis."},
/*271*/ {"q":"Costal cartilage is a bar of which of the following cartilage:","o":["Fibrocartilage","Synovial cartilage","Hyaline cartilage","Elastic cartilage"],"a":2,"e":"Costal cartilages are bars of hyaline cartilage connecting ribs to the sternum.<br><br>Fibrocartilage forms discs and elastic cartilage the pinna; costal cartilage is hyaline."},
/*272*/ {"q":"First step in apoptosis process is:","o":["Activation of caspases","Cell lysis","Necrosis","Atrophy"],"a":0,"e":"Apoptosis is initiated by activation of the caspase cascade, leading to orderly programmed cell death.<br><br>Cell lysis characterises necrosis; apoptosis begins with caspase activation."},
/*273*/ {"q":"A patient operated for splenectomy; peripheral blood smear shows:","o":["Melatonin","Howell-Jolly bodies","Hemolyzed RBCs","Iron deposits"],"a":1,"e":"After splenectomy the blood smear shows Howell-Jolly bodies (nuclear remnants) normally removed by the spleen.<br><br>Hypersplenism removes Howell-Jolly bodies; after splenectomy these nuclear remnants persist on the smear."},
/*274*/ {"q":"Peripheral chemoreceptors are stimulated by:","o":["Increase pCO2","Increase H+","Decrease O2","Decrease pH"],"a":2,"e":"The peripheral chemoreceptors (carotid and aortic bodies) respond chiefly to a decrease in arterial oxygen tension.<br><br>Central chemoreceptors respond to CO2/H+; peripheral ones respond mainly to low O2."},
/*275*/ {"q":"Prostate mainly drains into the:","o":["Internal iliac lymph node","External iliac lymph node","Inguinal lymph node","Para-aortic lymph node"],"a":0,"e":"The prostate drains chiefly to the internal iliac lymph nodes.<br><br>The external iliac and inguinal nodes are not primary; prostatic lymph goes to the internal iliac nodes."},
/*276*/ {"q":"Which nerve passes through the petrotympanic fissure:","o":["Greater petrosal","Lesser petrosal","Chorda tympani","Deep petrosal"],"a":2,"e":"The chorda tympani branch of the facial nerve passes through the petrotympanic fissure to join the lingual nerve.<br><br>The petrosal nerves run elsewhere; the petrotympanic fissure transmits the chorda tympani."},
/*277*/ {"q":"Neuroectoderm derivative is which of the following:","o":["Corneal epithelium","Ciliary epithelium","Trabecular meshwork","Lens"],"a":1,"e":"The ciliary epithelium (and iris epithelium, retina, optic nerve) are neuroectoderm-derived from the optic cup.<br><br>The corneal epithelium and lens are surface ectoderm; the neuroectoderm derivative is the ciliary epithelium."},
/*278*/ {"q":"Jejunum identification point:","o":["More fat in mesentery","More vascular less arcades","Less vascular more arches","Lymph node"],"a":1,"e":"The jejunum has fewer, longer vascular arcades with long vasa recta and less mesenteric fat than the ileum.<br><br>The ileum has more arterial arcades and shorter vasa recta; the jejunum is more vascular with fewer, longer arcades."},
/*279*/ {"q":"Which one is specific for vitamin B12 deficiency:","o":["Homocystein","Methylmalonic acid","Schilling test","Hypersegmentation"],"a":1,"e":"Elevated methylmalonic acid is specific for vitamin B12 deficiency, whereas homocysteine rises in both B12 and folate deficiency.<br><br>Homocysteine rises in both B12 and folate deficiency; methylmalonic acid rises specifically in B12 deficiency."},
/*280*/ {"q":"On contrast study of gallbladder, a structure loops around the common hepatic duct to reach its target organ; what structure is it:","o":["Bile duct","Common hepatic duct","Cystic duct","Right hepatic artery"],"a":3,"e":".<br><br>The cystic duct joins the bile duct directly; the structure looping around the common hepatic duct is the right hepatic artery."},
/*281*/ {"q":"CT scan shows a mass eroding from infratemporal fossa into middle cranial fossa; which bone will it have to erode:","o":["Greater wing of sphenoid","Lesser wing of sphenoid","Ethmoid","Parietal bone"],"a":0,"e":"A mass passing from the infratemporal fossa to the middle cranial fossa must erode the greater wing of the sphenoid.<br><br>The infratemporal fossa is roofed by the greater wing of sphenoid, so a mass entering the middle cranial fossa erodes it, not the lesser wing."},
/*282*/ {"q":"Old patient with enlarged prostate, PSA 20 ng/ml, weight loss and bony metastasis on MRI; route of spread of prostate CA to vertebrae:","o":["Lumbar plexus","Pampiniform plexus","Vertebral venous plexus","Pelvic plexus"],"a":2,"e":"Prostate carcinoma metastasises to the vertebral column via the valveless Batson vertebral venous plexus.<br><br>Lymphatic spread reaches obturator nodes; vertebral metastases occur via the valveless Batson vertebral venous plexus."},
/*283*/ {"q":"Breaking bad news to the patient should be done in which of the following:","o":["In a formal session","In a hurried manner","Through written form","Shouldn't be told"],"a":0,"e":"Bad news should be delivered in a planned, private formal session with adequate time and support.<br><br>Bad news must be delivered unhurried in a private formal setting, not in writing or in a rushed manner."},
/*284*/ {"q":"Justice in medical ethics is:","o":["Let patient decide about treatment","Equity in providing medical resources to all patients equally","Equity to staff working","Equity to doctor working"],"a":1,"e":"Justice in medical ethics means the fair and equitable distribution of medical resources among all patients.<br><br>Patient choice is autonomy; justice is equitable resource allocation."},
/*285*/ {"q":"After RTA patient has fracture of head of femur leading to avascular necrosis; artery involved is which of the following:","o":["Lateral circumflex","Descending branch lateral circumflex","Medial circumflex artery","Obturator artery"],"a":2,"e":"In adults the femoral head is supplied mainly by the medial circumflex femoral artery, so its disruption causes avascular necrosis.<br><br>The lateral circumflex supplies little of the head; in adults the femoral head depends on the medial circumflex femoral artery."},
/*286*/ {"q":"Which of the following is the functional unit of the liver:","o":["Lobule","Hepatocyte","Segment","Hepatic acinus"],"a":3,"e":"The hepatic acinus is regarded as the functional unit of the liver, organised around the portal triad and central vein with metabolic zonation.<br><br>The classic lobule is structural; the functional unit defined by blood supply and zonation is the hepatic acinus."},
/*287*/ {"q":"Tail of pancreas lies in which ligament:","o":["Lienorenal","Gastrocolic","Hepatoduodenal","Greater omentum"],"a":0,"e":"The tail of the pancreas lies within the lienorenal (splenorenal) ligament along with the splenic vessels.<br><br>The gastrosplenic ligament carries the short gastrics; the pancreatic tail and splenic vessels lie in the lienorenal ligament."},
/*288*/ {"q":"Free margin of falciform ligament contains which of the following:","o":["Ligamentum teres","Portal vein","Ligamentum venosum","Ligament of Treitz"],"a":0,"e":"The free inferior margin of the falciform ligament contains the ligamentum teres (obliterated left umbilical vein).<br><br>The ligamentum venosum is the ductus venosus remnant in the fissure; the falciform free margin carries the ligamentum teres (umbilical vein remnant)."},
/*289*/ {"q":"A chronic alcoholic with cirrhosis and caput medusae; the periumbilical veins are connected to the left branch of portal vein through:","o":["Hepatic portal vein","Lumbar veins","Musculophrenic veins","Paraumbilical veins"],"a":3,"e":"Caput medusae forms because paraumbilical veins connect the periumbilical systemic veins to the left branch of the portal vein.<br><br>Caput medusae connects the left portal branch to systemic abdominal-wall veins through the recanalised paraumbilical veins."},
/*290*/ {"q":"A child fell while cycling, then complains of anuria; which structure is damaged:","o":["Ureter","Urethra","Urinary bladder","Prostate"],"a":1,"e":".<br><br>A straddle/cycling perineal injury tears the bulbar urethra causing retention, rather than damaging the ureter or bladder."},
/*291*/ {"q":"A patient had RTA, does not know recent events but remembers school events; which lobe is involved in amnesia:","o":["Temporal lobe","Hippocampus","Parietal","Thalamus"],"a":1,"e":"Anterograde amnesia with preserved remote memory localises to the hippocampus.<br><br>Loss of new memory with intact remote memory is anterograde amnesia localising to the hippocampus, not the parietal lobe."},
/*292*/ {"q":"A child born with a mass at lumbar region with no neural tissue in it; this is due to:","o":["Spina bifida with meningocele","Spina bifida with meningomyelocele","Spina bifida occulta","Anencephaly"],"a":0,"e":"A lumbar swelling containing meninges and CSF but no neural tissue is a meningocele (spina bifida with meningocele).<br><br>A meningomyelocele contains neural tissue; a sac with meninges and CSF but no neural tissue is a meningocele."},
/*293*/ {"q":"Main support of longitudinal arch of foot is formed by which structure:","o":["Talus","Calcaneus","Cuboid","Medial cuneiform"],"a":0,"e":".<br><br>The cuboid keystones the lateral arch; the talus is the main support of the medial longitudinal arch and overall keystone."},
/*294*/ {"q":"Cingulate gyrus is supplied by which of the following:","o":["Middle cerebral artery","Anterior cerebral artery","Posterior choroidal artery","Posterior cerebral artery"],"a":1,"e":"The cingulate gyrus on the medial surface is supplied by the anterior cerebral artery.<br><br>The MCA supplies the lateral cortex; the cingulate gyrus is ACA territory."},
/*295*/ {"q":"Patient with weakness, ptosis, miosis diagnosed as myasthenia gravis; what happens in this:","o":["Antibody against presynaptic cholinesterase","Preganglionic receptors blocked","Postganglionic receptors blocked","Antibody against post-synaptic receptors"],"a":3,"e":"Myasthenia gravis is caused by autoantibodies against the postsynaptic acetylcholine receptors at the neuromuscular junction.<br><br>Lambert-Eaton targets presynaptic calcium channels; myasthenia gravis is antibody against postsynaptic acetylcholine receptors."},
/*296*/ {"q":"Regarding Houston valves, which is true:","o":["Transverse plicae","Semilunar valve of colon","Transverse valves of colon","Oblique valves"],"a":2,"e":"The valves of Houston are transverse semilunar rectal folds (transverse rectal/colon valves).<br><br>Houston valves are the transverse semilunar folds of the rectum (transverse rectal valves), not oblique colonic plicae."},
/*297*/ {"q":"Paraneoplastic syndrome occurs in:","o":["Small cell CA lung","Squamous cell CA lung","Large cell CA lung","Oat cell CA"],"a":0,"e":"Small cell lung carcinoma is the lung cancer most strongly associated with paraneoplastic syndromes such as SIADH and ectopic ACTH.<br><br>All bronchogenic cancers can, but small (oat) cell carcinoma is the classic source of ectopic ACTH/ADH paraneoplastic syndromes."},
/*298*/ {"q":"Liver is the only organ involved in synthesis of:","o":["Urea formation","Nucleotide","Glycogenolysis","Middle chain fatty acid catabolism"],"a":0,"e":"The complete urea cycle operates only in the liver, making it the sole organ for urea synthesis.<br><br>Glycogenolysis occurs in muscle too; the urea cycle (urea synthesis) is essentially confined to the liver."},
/*299*/ {"q":"Which muscle traverses the shoulder joint capsule:","o":["Short head of biceps","Long head of biceps","Deltoid","Supraspinatus"],"a":1,"e":"The long head of biceps tendon passes through the shoulder joint capsule, traversing it intracapsularly.<br><br>The short head and deltoid lie outside; the intracapsular tendon is the long head of biceps."},
/*300*/ {"q":"Which of the following is the most aggressive carcinoma:","o":["BCC","SCC","Melanoma","Leukoplakia"],"a":2,"e":"Melanoma is the most aggressive of these, with high metastatic potential, compared with the locally behaving BCC/SCC.<br><br>Leukoplakia is premalignant; the most aggressive carcinoma is melanoma."},
/*301*/ {"q":"Which leads to coronary artery disease:","o":["Omega 3 fatty acid","Omega 6 fatty acid","Trans fatty acids","Monounsaturated fatty acid"],"a":2,"e":"Trans fatty acids raise LDL and lower HDL, strongly promoting atherosclerosis and coronary artery disease.<br><br>Omega-3 and monounsaturated fats are protective; the harmful one is trans fatty acids."},
/*302*/ {"q":"Patient with gynecomastia, on gene study 2X and 1Y chromosomes found; diagnosis:","o":["Klinefelter's syndrome","Turner syndrome","Patau syndrome","Craniopharyngioma"],"a":0,"e":"A 47,XXY karyotype with gynaecomastia and small testes is Klinefelter syndrome.<br><br>Turner is 45,XO; the XXY pattern is Klinefelter syndrome."},
/*303*/ {"q":"FSH is inhibited by inhibin, which is secreted by:","o":["Sertoli cells","Leydig cells","Granulosa cells","Mullerian cells"],"a":0,"e":"Inhibin, which suppresses pituitary FSH, is secreted by Sertoli cells in the male (and granulosa cells in the female).<br><br>Granulosa cells secrete inhibin in the female; in the male the FSH-suppressing inhibin comes from Sertoli cells."},
/*304*/ {"q":"Patient had RTA with fracture of ilium and sacrum; which structure is likely damaged in pelvis:","o":["Urethra","Rectum","Ureter","Urinary bladder"],"a":3,"e":".<br><br>An ilium-and-sacrum pelvic fracture most often ruptures the urinary bladder rather than the ureter or rectum."},
/*305*/ {"q":"Dilation of esophagus compresses which of these:","o":["Aorta","Left atrium","Left ventricle","IVC"],"a":1,"e":"The oesophagus lies directly behind the left atrium, so oesophageal dilatation (or atrial enlargement) produces mutual compression.<br><br>An enlarged left atrium (mitral disease) presses on the oesophagus behind it, causing dysphagia, not the aorta or IVC."},
/*306*/ {"q":"Artificial pacemaker has to be implanted in a patient; most suitable site:","o":["Moderator band","Left ventricle","Crista terminalis","Right atrium"],"a":3,"e":"A pacemaker lead is typically placed in the right atrium (and right ventricle), accessed via the venous system.<br><br>A permanent pacemaker lead is anchored in the right atrial appendage/right atrium, not the left ventricle or moderator band."},
/*307*/ {"q":"After RTA a patient has surgical neck of humerus fractured with loss of abduction and loss of sensation over proximal lateral surface of arm; which nerve is damaged:","o":["Musculocutaneous nerve","Radial nerve","Axillary nerve","Median nerve"],"a":2,"e":"A surgical neck of humerus fracture injures the axillary nerve, causing deltoid paralysis (loss of abduction) and regimental-badge sensory loss.<br><br>The radial nerve is at risk in shaft fractures; the surgical neck injures the axillary nerve."},
/*308*/ {"q":"Displacement of femur over tibia when knee is flexed; which ligament is likely damaged:","o":["Anterior cruciate","Posterior cruciate","Collateral","Deltoid"],"a":1,"e":"Posterior displacement of the tibia relative to the femur (or femur forward on tibia) with the knee flexed indicates posterior cruciate ligament injury.<br><br>Anterior tibial displacement is ACL injury; posterior displacement of the femur over the tibia indicates posterior cruciate damage."},
/*309*/ {"q":"Proximal convoluted tubule in comparison to distal convoluted tubule has:","o":["Extensive brush border","Less convoluted","Lumen made of cuboidal epithelium","Lack brush border"],"a":0,"e":"The proximal convoluted tubule has an extensive microvillous brush border for reabsorption, unlike the DCT.<br><br>The DCT has scant microvilli; the PCT has an extensive brush border for its high reabsorptive load."},
/*310*/ {"q":"Patient undergoes gastrectomy, develops macrocytic anemia; treatment should be:","o":["Oral Vit. B12","Injection Vit. B12","Folic acid","Vit. B6"],"a":1,"e":"Post-gastrectomy B12 deficiency from intrinsic factor loss requires parenteral (injection) vitamin B12 replacement.<br><br>Oral B12 is poorly absorbed without intrinsic factor; the treatment is injectable B12."},
/*311*/ {"q":"Percentage of proteins in a balanced diet:","o":["15-20%","35-45%","50-55%","40-45%"],"a":0,"e":"Proteins should provide about 10-20% of dietary energy in a balanced diet.<br><br>Carbohydrate makes up roughly half the diet; protein constitutes about 15-20% of a balanced diet."},
/*312*/ {"q":"GFR decreases with increase in:","o":["Bowman's capsule hydrostatic pressure","Glomerular capillary colloid osmotic pressure","Glomerular capillary hydrostatic pressure","Efferent arteriolar constriction"],"a":1,"e":"Raised glomerular capillary colloid osmotic pressure opposes filtration and decreases GFR.<br><br>Rising glomerular hydrostatic pressure raises GFR; an increase in capillary colloid osmotic pressure opposes filtration and lowers GFR."},
/*313*/ {"q":"Area for mitral valve auscultation is which of the following:","o":["Right second intercostal space","Left second intercostal space","Left sternal border","Midclavicular line of left 5th intercostal space"],"a":3,"e":"The mitral valve is best auscultated at the cardiac apex, the left 5th intercostal space in the midclavicular line.<br><br>The aortic area is the right 2nd space; mitral auscultation is at the apex (left 5th space, midclavicular line)."},
/*314*/ {"q":"Aortic valve opens during which phase of cardiac cycle:","o":["Isovolumetric contraction","Isovolumetric relaxation","Rapid ejection","Slow ejection"],"a":2,"e":"The aortic valve opens at the start of the rapid ejection phase when ventricular pressure exceeds aortic pressure.<br><br>During isovolumetric contraction all valves are shut; the aortic valve opens at the onset of rapid ejection when LV pressure exceeds aortic."},
/*315*/ {"q":"Alcoholic patient with pain in right hypochondrium referred to right shoulder, neck and scapular region; organ involved:","o":["Gallbladder","Stomach","Duodenum","Pancreas"],"a":0,"e":"Right hypochondrial pain referred to the right shoulder and scapula indicates gallbladder (and diaphragmatic) irritation.<br><br>Pancreatic pain refers to the back; right hypochondrial pain referred to the right shoulder via the phrenic nerve indicates the gallbladder."},
/*316*/ {"q":"Person with gunshot injury in floor of axilla, unable to flex index and long fingers with loss of sensation over lateral palmar surface of hand; nerve involved is:","o":["Radial","Axillary","Median","Ulnar"],"a":2,"e":"Loss of index/middle finger flexion with lateral palmar sensory loss indicates median nerve injury.<br><br>The ulnar affects medial digits; the lateral palm and finger flexion deficit is the median nerve."},
/*317*/ {"q":"Newborn with left unilateral cleft lip, normal palate; the developmental defect is:","o":["Failure of left lateral palatine to fuse with median palatine process","Failure of left maxillary prominence to unite with left medial nasal prominence","Failure of right and left medial nasal prominences to merge","Failure of left maxillary process to fuse with left medial nasal process"],"a":3,"e":"Unilateral cleft lip is failure of the maxillary process to fuse with the medial nasal process on that side.<br><br>Failure of the medial nasal processes to merge gives a midline cleft; a unilateral cleft lip is maxillary-to-medial-nasal fusion failure."},
/*318*/ {"q":"CSF compared to plasma has:","o":["Increased proteins","Decrease glucose","Increase K+ level","Low cell level"],"a":1,"e":"CSF has lower glucose and much lower protein than plasma, with very few cells.<br><br>CSF protein is low, not raised; compared with plasma, CSF characteristically has a lower glucose concentration."},
/*319*/ {"q":"Young man with absent stretch reflex, atrophy of calf muscles, loss of pain and temperature on lateral aspect of leg and foot; lesion is:","o":["Upper motor neuron lesion","Lower motor neuron lesion with anterior horn damage","Lower motor neuron lesion","Lower + upper motor neuron lesion"],"a":1,"e":"Absent reflexes with muscle atrophy and sensory loss indicate a lower motor neuron lesion with anterior horn (and root) involvement.<br><br>An upper motor neuron lesion gives hyperreflexia; absent reflexes with muscle atrophy indicate an anterior horn lower motor neuron lesion."},
/*320*/ {"q":"Hyperglycemia in a diabetic patient increases which of these:","o":["Urine volume","PH","Urea","Chloride"],"a":0,"e":"Hyperglycaemia exceeding the renal threshold causes osmotic diuresis, increasing urine volume (polyuria).<br><br>Glucosuria produces an osmotic diuresis, so hyperglycaemia chiefly increases urine volume, not urinary chloride."},
/*321*/ {"q":"Mechanism of cancer formation involves:","o":["Initiator and promoters","Only initiator causes carcinoma","Initiator followed by promoter causing carcinoma","Multiple initiators"],"a":2,"e":"Chemical carcinogenesis requires an initiator (mutagenic event) followed by promoters that expand the mutated clone into carcinoma.<br><br>A single initiator is insufficient; carcinogenesis requires an initiator followed by promoter exposure to produce a tumour."},
/*322*/ {"q":"Most common fungal opportunistic infection in HIV is:","o":["Pneumonia","Candida","Pseudomonas","Cryptococcus"],"a":1,"e":"Candida is the commonest fungal opportunistic infection in HIV (oral/oesophageal candidiasis); the commonest overall opportunistic infection is TB.<br><br>Cryptococcus and Pneumocystis occur later; the commonest fungal opportunistic infection overall in HIV is oral/oesophageal candidiasis."},
/*323*/ {"q":"In an immunocompromised patient which infection is common:","o":["Candidiasis","Cryptococcus neoformis","EBV","CMV"],"a":0,"e":"Candidiasis is a common opportunistic infection in immunocompromised patients (mucocutaneous and invasive).<br><br>CMV and EBV are viral; among these the common opportunistic fungal infection in the immunocompromised is candidiasis."},
/*324*/ {"q":"Patient with fever, neck rigidity, positive Kernig sign; CSF shows decreased glucose, increased proteins and lymphocytes; diagnosis:","o":["Acute pyogenic","Viral meningitis","TB meningitis","Fungal meningitis"],"a":2,"e":"Low glucose, high protein and a lymphocytic CSF pleocytosis are characteristic of tuberculous meningitis.<br><br>Pyogenic meningitis is neutrophilic; the lymphocytic low-glucose picture is TB meningitis."},
/*325*/ {"q":"CSF parameter comparable with plasma is:","o":["Low WBC count","High glucose","Low erythrocyte level","Protein"],"a":0,"e":".<br><br>CSF glucose is lower and protein lower than plasma; the parameter that is comparably low (near plasma cellularity is essentially nil) is the very low WBC count."},
/*326*/ {"q":"Person developed influenza and flu in winter season; drug suitable for flu is:","o":["Acyclovir","Amantadine","Oseltamivir","Valacyclovir"],"a":2,"e":"Oseltamivir, a neuraminidase inhibitor, is the drug of choice for influenza.<br><br>Acyclovir treats herpesviruses; influenza is treated with oseltamivir."},
/*327*/ {"q":"Regarding hypothyroidism, true is:","o":["Tachycardia","Diarrhea","Hypercholesterolemia / increased cholesterol","Increase T4"],"a":2,"e":"Hypothyroidism causes raised serum cholesterol due to reduced LDL receptor activity.<br><br>It causes bradycardia and constipation; the true feature is hypercholesterolaemia."},
/*328*/ {"q":"Portal vein is present in the free edge of:","o":["Epiploic foramen","Greater sac","Lesser omentum","Bile duct"],"a":2,"e":"The portal vein lies in the free edge of the lesser omentum (hepatoduodenal ligament) with the hepatic artery and bile duct.<br><br>The epiploic foramen is the opening, not the ligament; the portal triad runs in the free edge of the lesser omentum (hepatoduodenal ligament)."},
/*329*/ {"q":"Which vein drains directly into the SVC:","o":["Anterior cardiac vein","Vena cordis minima","Azygos vein","Hemiazygos vein"],"a":2,"e":"The azygos vein arches over the right main bronchus and drains directly into the superior vena cava.<br><br>The hemiazygos drains into the azygos; the direct SVC tributary is the azygos vein."},
/*330*/ {"q":"Acute kidney infection, which lymph nodes are enlarged:","o":["Lumbar","Superior mesenteric","Inferior mesenteric","Celiac"],"a":0,"e":"The kidney drains to the lumbar (para-aortic) lymph nodes, which enlarge in renal infection.<br><br>The kidney drains to the lateral aortic (lumbar) nodes; the SMA/IMA/celiac nodes drain the gut, not the kidney."},
/*331*/ {"q":"Patient presented with signs and symptoms of appendicitis; emergency appendectomy was performed; which fluid will be present after appendectomy:","o":["Exudative","Transcellular","Serous","Infected"],"a":0,"e":"Acute appendicitis produces an inflammatory exudate (protein- and cell-rich) in the peritoneal cavity.<br><br>Transudate is non-inflammatory; an infected/inflamed appendix produces a protein-rich exudative fluid."},
/*332*/ {"q":"Which of the following is true regarding renal uncontrolled HTN:","o":["Atherosclerosis of renal artery 2 cm proximal to renal artery","Atherosclerosis of renal artery 2 cm distal to renal artery","Atherosclerosis at the level of renal artery","Atherosclerosis at distal 1/3rd of renal artery"],"a":0,"e":"Atherosclerotic renovascular hypertension typically involves the proximal renal artery near its aortic origin.<br><br>Atherosclerotic renovascular hypertension typically involves the proximal renal artery (about 2 cm proximal/at the ostium), not its distal third."},
/*333*/ {"q":"Patient with urinary cramps and pain in lumbar region, increased calcium, decreased PO4, raised PTH with normal parathyroid-related proteins; diagnosis:","o":["Primary hyperparathyroidism","Secondary hyperparathyroidism","Pseudohyperparathyroidism","Hypoparathyroidism"],"a":0,"e":"High calcium, low phosphate and raised PTH indicate primary hyperparathyroidism, often with renal stones.<br><br>Raised PTH with high calcium, low phosphate and normal PTHrP indicates primary hyperparathyroidism, not malignant hypercalcaemia."},
/*334*/ {"q":"Which one is the largest lobe of prostate:","o":["Peripheral","Central","Periurethral","Lateral"],"a":3,"e":".<br><br>The peripheral zone is the commonest cancer site; anatomically the lateral lobes form the largest part of the prostate."},
/*335*/ {"q":"Superficial inguinal nodes follow which of the following:","o":["Puborectal ligament","Round ligament of uterus","Cardinal ligament","Uterosacral ligament"],"a":1,"e":"The round ligament of the uterus passes through the inguinal canal, so its lymph follows to the superficial inguinal nodes.<br><br>The round ligament traverses the inguinal canal, so its lymphatics drain to the superficial inguinal nodes, unlike the cardinal/uterosacral ligaments."},
/*336*/ {"q":"Female with fever for 10 days, continuous chest pain radiating to back and left parasternal area with rustling sound; most likely suffers from:","o":["Myocarditis","Pericarditis","Endocarditis","Pleurisy"],"a":1,"e":"A pericardial friction rub (rustling sound) with continuous chest pain unrelated to respiration indicates pericarditis.<br><br>Continuous pain unrelated to respiration with a friction rub radiating to the back is pericarditis, not pleurisy or endocarditis."},
/*337*/ {"q":"Patient with mass in inguinal region lying lateral to inferior epigastric vessels extending from deep to superficial inguinal ring; diagnosis:","o":["Direct inguinal hernia","Indirect inguinal hernia","Femoral hernia","Umbilical hernia"],"a":1,"e":"A hernia lateral to the inferior epigastric vessels passing through the deep ring is an indirect inguinal hernia.<br><br>Direct hernias are medial to these vessels; lateral is an indirect inguinal hernia."},
/*338*/ {"q":"Which part of temporal lobe is present on medial side in cerebral cortex:","o":["Cingulate gyrus","Superior temporal lobe","Mid temporal gyrus","Inferior temporal"],"a":1,"e":".<br><br>The cingulate gyrus is limbic; on the medial/superior temporal surface lies the superior temporal gyrus (auditory cortex)."},
/*339*/ {"q":"Lymphatic drainage of greater curvature of stomach is:","o":["Celiac node","Superior mesenteric node","Inferior mesenteric node","Splenic (and gastroepiploic) node"],"a":3,"e":"The greater curvature of the stomach drains along the gastroepiploic vessels to the splenic/pancreaticosplenic nodes.<br><br>The lesser curvature drains to left gastric/celiac nodes; the greater curvature drains to gastroepiploic and splenic nodes."},
/*340*/ {"q":"Blood supply to uterus is from:","o":["Uterine artery","Ovarian artery","Ovarian + uterine artery","Vesicle artery"],"a":2,"e":"The uterus is supplied by the uterine artery with anastomotic contribution from the ovarian artery.<br><br>The uterus is supplied chiefly by the uterine artery with anastomotic contribution from the ovarian artery, not by the vesical artery."},
/*341*/ {"q":"Angle on the notch on lesser curvature of stomach is:","o":["Incisura angularis","Lesser omentum","Greater sac","Incisura omentalis"],"a":0,"e":"The notch on the lesser curvature of the stomach is the incisura angularis (angular notch).<br><br>The lesser omentum is a ligament not a notch; the angular notch of the lesser curvature is the incisura angularis."},
/*342*/ {"q":"Which vessel lies anterior to the left lower portion of body of pancreas:","o":["IVC","SMA","Common hepatic","IMA"],"a":1,"e":"The superior mesenteric artery emerges from behind the pancreatic neck and lies anterior to the lower body of the pancreas.<br><br>The IVC lies posterior; the superior mesenteric artery passes anterior to the lower body of the pancreas (and uncinate)."},
/*343*/ {"q":"With blockage of right superior bronchus due to mass, which bronchopulmonary segment is likely to collapse:","o":["Anterior basal","Right apical superior","Middle superior","Posterior basal"],"a":1,"e":"Obstruction of the right superior (apical) bronchus causes collapse of the right apical (superior) segment.<br><br>The basal segments are lower-lobe; obstruction of the right superior bronchus collapses the apical/superior segment."},
/*344*/ {"q":"Most common cause of community-acquired pneumonia:","o":["Streptococcus pneumoniae","Mycoplasma","Haemophilus","Legionella"],"a":0,"e":"Streptococcus pneumoniae is the commonest cause of community-acquired pneumonia.<br><br>Atypicals and Haemophilus are less frequent; the leading cause is pneumococcus."},
/*345*/ {"q":"Most common organism of urinary tract infection:","o":["E. coli","Pseudomonas","S. aureus","Klebsiella"],"a":0,"e":"Escherichia coli is the commonest cause of community-acquired urinary tract infection.<br><br>Klebsiella and Pseudomonas are less frequent; the leading uropathogen is E. coli."},
/*346*/ {"q":"Most common valvular lesion in rheumatic heart disease:","o":["Mitral stenosis","Aortic stenosis","Tricuspid regurgitation","Pulmonary stenosis"],"a":0,"e":"Mitral stenosis is the commonest chronic valvular lesion of rheumatic heart disease.<br><br>The other valves are less affected; rheumatic disease classically causes mitral stenosis."},
/*347*/ {"q":"Pectoralis major flap will get its blood supply from which of the following:","o":["Intercostal arteries","Thoracoacromial","Axillary artery","Thoracodorsal"],"a":1,"e":"The pectoralis major myocutaneous flap is based on the pectoral branch of the thoracoacromial artery.<br><br>The thoracodorsal supplies latissimus dorsi; the pectoralis major flap is supplied by the thoracoacromial artery."},
/*348*/ {"q":"Side effect of dicoumarol is:","o":["Delayed clotting","Increase bleeding time","Decrease clotting time","Abnormal clotting"],"a":0,"e":"Dicoumarol, a vitamin K antagonist, prolongs the prothrombin time (delayed clotting) and increases bleeding tendency.<br><br>Dicoumarol is a vitamin K antagonist that delays clotting by reducing factor synthesis, not by prolonging bleeding time (a platelet test)."},
/*349*/ {"q":"A newborn with lumbosacral swelling containing meninges without neural tissue; most likely diagnosis:","o":["Spina bifida with meningocele","Meningomyelocele","Encephalocele","Meningomyeloencephalocele"],"a":0,"e":"A lumbosacral swelling containing only meninges and CSF without neural tissue is a meningocele.<br><br>A meningomyelocele contains spinal cord/roots; a sac of meninges and CSF without neural tissue is a meningocele."},
/*350*/ {"q":"Most appropriate route for an antidote is:","o":["IM","IV","S/C","Oral"],"a":1,"e":"Antidotes in an emergency are most appropriately given intravenously for rapid onset.<br><br>Subcutaneous and oral routes are slow; an antidote in an emergency is given intravenously for the fastest onset."},
/*351*/ {"q":"Corpus callosum contains which fibers:","o":["Association fibers","Projection fibers","Commissural fibers","Arcuate fibers"],"a":2,"e":"The corpus callosum is the largest commissure, containing commissural fibers connecting the two cerebral hemispheres.<br><br>The internal capsule has projection fibers; the corpus callosum is commissural fibers."},
/*352*/ {"q":"Patient with crushing chest pain for 3 hours, BP normal, pulse normal, RR 33/min; investigation of choice:","o":["CK MB","Trop T","Myoglobin","LDH"],"a":0,"e":".<br><br>LDH rises late and myoglobin is non-specific; the early cardiac-specific enzyme of choice here is CK-MB."},
/*353*/ {"q":"A 15-year-old girl with primary amenorrhea, cyclical pain but no menstruation, normal hymen; likely cause:","o":["Imperforate hymen","Cervical atresia","Transvaginal septum","Cervical stenosis"],"a":1,"e":".<br><br>An imperforate hymen bulges visibly; with a normal hymen and cyclical pain without menses the obstruction is cervical atresia."},
/*354*/ {"q":"Leukoerythroblastosis reaction is seen in which of these:","o":["Megaloblastic anemia","Hemolytic anemia","Bone marrow infiltration","Gaucher disease"],"a":2,"e":"A leukoerythroblastic blood picture (immature white and red cells) indicates bone marrow infiltration or replacement (myelophthisis).<br><br>Haemolytic and megaloblastic anaemias do not release immature cells; a leukoerythroblastic picture indicates marrow infiltration (myelophthisis)."},
/*355*/ {"q":"A patient in RTA got fractured his femur bone, 3 days later he developed SOB and died; cause is:","o":["Fat embolism","Marrow suppression","Thromboembolism","Amniotic fluid embolism"],"a":0,"e":"Death about 3 days after a femoral fracture with sudden dyspnoea is characteristic of fat embolism syndrome.<br><br>Thromboembolism is sudden and amniotic fluid embolism is obstetric; death days after a femoral fracture is fat embolism."},
/*356*/ {"q":"A child developed excessive obesity, inappropriate eating habits, short stature and mental retardation; likely diagnosis:","o":["Klinefelter's syndrome","Down syndrome","Prader-Willi syndrome","Turner syndrome"],"a":2,"e":"Obesity with hyperphagia, short stature and intellectual disability is characteristic of Prader-Willi syndrome.<br><br>Down and Turner have characteristic facies/stature; obesity with hyperphagia, short stature and hypotonia is Prader-Willi syndrome."},
/*357*/ {"q":"Air embolism develops on how much air volume:","o":["50cc","100cc","10cc","80cc"],"a":1,"e":".<br><br>Small volumes are harmless; a clinically significant venous air embolism generally requires roughly 100 cc or more of air."},
/*358*/ {"q":"Pericardiocentesis can be best achieved by:","o":["Left 4th ICS parasternal","Right 5th ICS parasternal","Left 5th ICS parasternal","Left 7th ICS parasternal"],"a":3,"e":".<br><br>Pericardiocentesis is classically performed via a subxiphoid/left low parasternal approach; the keyed site here is the left 7th ICS parasternal."},
/*359*/ {"q":"Which adhesion molecule belongs to the CAM family responsible for adhesion during embryonic development:","o":["Nerve cell adhesion","Cadherin","Integrin","Selectin"],"a":1,"e":"E-cadherin is the cell adhesion molecule essential for compaction of the morula and forming adhesion junctions in early embryonic development.<br><br>Selectins and integrins mediate leukocyte adhesion; embryonic morphogenetic cell-cell adhesion is mediated by cadherins."},
/*360*/ {"q":"P value of a drug is significant if less than:","o":["0.1","0.008","0.05","0.02"],"a":2,"e":"A P value less than 0.05 is conventionally taken as statistically significant.<br><br>A threshold of 0.1 or 0.02 is non-standard; statistical significance is conventionally set at p less than 0.05."},
/*361*/ {"q":"A lady cut her finger by knife while working in kitchen; which fiber detects pressure:","o":["A delta fibers","Preganglionic alpha fibers","Postganglionic C fibers","A beta fibers"],"a":3,"e":"Pressure and fine touch are carried by large myelinated A-beta fibers.<br><br>A-delta and C fibers carry pain; pressure is detected by A-beta fibers."},
/*362*/ {"q":"Sesamoid cartilage is present in:","o":["Larynx","Ala of nose","Vertebral space","Trachea"],"a":1,"e":".<br><br>Laryngeal and tracheal cartilage is hyaline/elastic; the small sesamoid (alar) cartilages lie in the ala of the nose."},
/*363*/ {"q":"Lymphatic drainage of external nose and anterior part of nasal cavity:","o":["Submandibular lymph nodes","Deep cervical lymph nodes","Retropharyngeal lymph nodes","Occipital lymph nodes"],"a":0,"e":"The external nose and anterior nasal cavity drain to the submandibular lymph nodes.<br><br>The posterior nasal cavity drains to retropharyngeal nodes; the anterior part drains to submandibular nodes."},
/*364*/ {"q":"Female with heart disease; downward traction of her AV valves; which structure cannot be made (damaged):","o":["Ventricle muscles","Annulus fibrosis","Septomarginal band","Chorda tendinae"],"a":3,"e":".<br><br>The annulus fibrosus anchors the valves and ventricular muscle pulls them; downward AV-valve traction tears the chordae tendineae."},
/*365*/ {"q":"Esophageal opening passes through the diaphragm at which vertebral level:","o":["T8","T10","L5","T12"],"a":1,"e":"The oesophageal opening of the diaphragm is at the T10 vertebral level, transmitting the oesophagus and vagi.<br><br>The aortic opening is T12; the oesophageal hiatus is at T10 (Snell + KLM)."},
/*366*/ {"q":"In the aortic opening when the diaphragm is constricted, which of the following structure will be compressed along with aorta:","o":["Azygous veins and both phrenic nerve","Thoracic duct and vagus nerve","Azygos vein and vagus nerve","Thoracic duct and azygos vein"],"a":3,"e":"The aortic hiatus transmits the aorta, thoracic duct and azygos vein, so these are compressed with the aorta.<br><br>The caval opening transmits the IVC; the aortic hiatus transmits the aorta with the thoracic duct and azygos vein."},
/*367*/ {"q":"Which structure passes through the esophageal opening of the diaphragm along with esophagus:","o":["Azygos vein","Vagus nerve","Thoracic duct","Phrenic nerve"],"a":1,"e":"The oesophageal opening (T10) transmits the oesophagus with the right and left vagus nerves.<br><br>The thoracic duct and azygos pass the aortic hiatus; the oesophageal opening transmits the oesophagus with the vagus nerves."},
/*368*/ {"q":"Highest alkaline pH is present in:","o":["Saliva","Gastric secretions","Pancreatic secretions","Prostate"],"a":2,"e":"Pancreatic secretion is rich in bicarbonate and has the highest alkaline pH among these gastrointestinal fluids.<br><br>Gastric secretion is acidic; the most alkaline is pancreatic secretion."},
/*369*/ {"q":"A child previously having TB now with fever, cough, noisy breathing and difficulty in swallowing, diagnosed as retropharyngeal abscess; which structure will it invade first:","o":["Precervical fascia","Prevertebral fascia","Carotid sheath","Buccopharyngeal fascia"],"a":1,"e":"A retropharyngeal abscess lies in the retropharyngeal space against the prevertebral fascia, which it invades first.<br><br>A retropharyngeal abscess lies between buccopharyngeal and prevertebral fascia, so it first abuts/invades the prevertebral fascia."},
/*370*/ {"q":"Internal carotid artery is blocked on color Doppler with blood flowback through which artery to supply scalp:","o":["Supraorbital artery","Superficial temporal artery","Posterior auricular artery","Occipital artery"],"a":0,"e":"With internal carotid occlusion, retrograde flow through the ophthalmic artery's supraorbital branch can supply the scalp via external-internal carotid anastomoses.<br><br>With internal carotid occlusion, scalp perfusion is maintained by external carotid flow reversing through the supraorbital (ophthalmic) anastomosis."},
/*371*/ {"q":"A 30-year-old female with no CVS or respiratory ailment has swelling in front of neck, difficulty breathing while supine; what is the type of swelling:","o":["Multinodular goiter","Follicular CA of thyroid","Asthma","Retrosternal goiter"],"a":3,"e":"A neck swelling causing breathing difficulty when supine indicates a retrosternal goiter compressing the trachea.<br><br>A simple multinodular goitre is palpable in the neck; a goitre causing supine dyspnoea with retrosternal extension is a retrosternal goitre."},
/*372*/ {"q":"Surgeon performing tracheostomy on a baby must take care because there are chances of injury to which of the following:","o":["Left brachiocephalic trunk","Left brachiocephalic vein","Superior thyroid vein","Recurrent laryngeal nerve"],"a":1,"e":"In children the left brachiocephalic vein lies higher and is at risk during tracheostomy.<br><br>The recurrent laryngeal nerve lies in the tracheo-oesophageal groove; the structure crossing low in a child's neck at risk is the left brachiocephalic vein."},
/*373*/ {"q":"A child only on fast food, with pallor and lethargy, Hb 8.5 mg/dl, MCV 120; which deficiency is he likely to have:","o":["Vitamin B12 deficiency","Folic acid deficiency","Iron deficiency anemia","Vitamin C deficiency"],"a":1,"e":"A macrocytic anaemia (MCV 120) from a poor fast-food diet in a child is most likely folic acid deficiency.<br><br>Iron deficiency gives microcytosis; a high MCV (macrocytic) anaemia from a poor fast-food diet is folate deficiency."},
/*374*/ {"q":"A 30-year-old male with fever, significant weight loss, painful micturition, hematuria and flank mass, Hb 18; possible pathology:","o":["Rhabdomyosarcoma","Angiomyolipoma","Polycystic kidney disease","RCC"],"a":3,"e":"A flank mass with haematuria and polycythaemia (high Hb from EPO secretion) is characteristic of renal cell carcinoma.<br><br>Polycystic disease gives bilateral masses without polycythaemia; flank mass with haematuria and raised Hb (EPO secretion) is renal cell carcinoma."},
/*375*/ {"q":"Catecholamine action within 24-48 hours is:","o":["Vasoconstriction","Hyperglycemia","Hypoglycemia","Hypothermia"],"a":0,"e":"Catecholamines cause vasoconstriction (alpha-mediated) among their rapid actions.<br><br>Catecholamine vasoconstriction is immediate; over 24-48 hours metabolic effects emerge, but the early action listed is vasoconstriction."},
/*376*/ {"q":"A 10-year-old boy with pallor, easy fatiguability, Hb 8 mg/dl, low MCV; diagnosis:","o":["Iron deficiency anemia","Megaloblastic anemia","Normocytic normochromic anemia","Sideroblastic anemia"],"a":0,"e":"A low-MCV (microcytic) anaemia with pallor and fatigue in a child is most likely iron deficiency anaemia.<br><br>Megaloblastic anaemia is macrocytic; the microcytic picture is iron deficiency anaemia."},
/*377*/ {"q":"Antibody in autoimmune pancreatitis:","o":["IgD","IgG","IgM","IgA"],"a":1,"e":"Autoimmune pancreatitis (type 1) is associated with elevated IgG (IgG4) antibodies.<br><br>Autoimmune (lymphoplasmacytic) pancreatitis is an IgG4-related disease, marked by elevated IgG (IgG4), not IgM or IgA."},
/*378*/ {"q":"With exception of sweat glands, parasympathetic system causes what:","o":["Decrease secretions","Promote secretions","Increase HR","Decrease peristalsis"],"a":1,"e":"The parasympathetic system generally promotes glandular secretion and digestive activity (sweat glands being a sympathetic cholinergic exception).<br><br>Sympathetic stimulation reduces glandular secretion; parasympathetic activity (except on sweat glands) promotes secretion."},
/*379*/ {"q":"IVC forms at the level of which vertebral body:","o":["T10","L5","T8","L6"],"a":1,"e":"The inferior vena cava is formed by the union of the common iliac veins at the L5 vertebral level.<br><br>The IVC is formed by the common iliac veins at the L5 vertebral level, not T8/T10 where it pierces the diaphragm."},
/*380*/ {"q":"In a young female, what is the role of estrogen:","o":["Breast development","Secondary sexual characteristics","Secretory phase of menstrual cycle","Alveoli growth"],"a":1,"e":"Oestrogen drives the development of female secondary sexual characteristics at puberty.<br><br>Progesterone governs the secretory phase; oestrogen's role here is secondary sexual characteristics."},
/*381*/ {"q":"Low-grade follicular lymphoma translocation is which of these:","o":["t14:18","t9:22","t15:27","t8:21"],"a":0,"e":"Follicular lymphoma is associated with the t(14;18) translocation overexpressing BCL-2.<br><br>t(9;22) is CML; follicular lymphoma is t(14;18)."},
/*382*/ {"q":"On gene study N-myc gene found; N-myc gene is related to which of the following:","o":["Neuroblastoma","Burkitt lymphoma","Ewing sarcoma","Neurofibroma"],"a":0,"e":"N-myc amplification is characteristic of neuroblastoma and indicates poor prognosis.<br><br>C-myc relates to Burkitt lymphoma; N-myc is neuroblastoma."},
/*383*/ {"q":"Most common opportunistic infection after kidney transplant that causes rejection:","o":["EBV","HSV","Polyoma","HIV"],"a":2,"e":"Polyomavirus (BK virus) is the characteristic post-renal-transplant infection causing nephropathy and graft dysfunction.<br><br>EBV and HSV cause other complications; the polyomavirus (BK virus) is the classic post-transplant nephropathy causing graft dysfunction."},
/*384*/ {"q":"Patient presented with shock; physician palpated an artery between trachea and infrahyoid muscle; which artery is present at this site:","o":["Internal jugular","Internal carotid","Common carotid","Anterior jugular"],"a":2,"e":"The carotid pulse, palpated between the trachea and infrahyoid (sternocleidomastoid) muscles, is the common carotid artery.<br><br>The internal jugular vein is venous and the carotid bifurcation is higher; between trachea and infrahyoid muscles lies the pulsatile common carotid."},
/*385*/ {"q":"Immediate death occurs after injury to which nerve:","o":["Hypoglossal","Vagus","Facial","Optic"],"a":1,"e":"Sudden injury to the vagus nerve can cause immediate cardiovascular collapse and death due to its cardiac and visceral autonomic functions.<br><br>Facial or hypoglossal injury is non-fatal; sudden death follows vagus nerve injury through cardiorespiratory collapse."},
/*386*/ {"q":"If we cut one side of the cervical sympathetic chain, what happens on the ipsilateral side:","o":["Pupillary constriction","Sweating","Mydriasis","Vasodilation"],"a":0,"e":"Cervical sympathetic chain interruption causes ipsilateral Horner syndrome with miosis (pupillary constriction), ptosis and anhidrosis.<br><br>Sympathetic loss gives Horner syndrome: the unopposed parasympathetic produces ipsilateral pupillary constriction, not mydriasis."},
/*387*/ {"q":"In acanthosis, which layer of oral mucosa is involved:","o":["Basal","Cornium","Spinosum","Granulosum"],"a":2,"e":"Acanthosis is thickening of the stratum spinosum (prickle cell layer) of the epithelium.<br><br>Hyperkeratosis thickens the cornified layer; acanthosis is thickening of the stratum spinosum (prickle-cell layer)."},
/*388*/ {"q":"Circumflex artery supplies which area:","o":["Left atrium","Left ventricle + atrium","Right ventricle","Right atrium"],"a":1,"e":"The left circumflex coronary artery supplies the left atrium and the lateral wall of the left ventricle.<br><br>The RCA supplies the right side; the circumflex supplies the left atrium and left ventricle."},
/*389*/ {"q":"Lymph drainage from the medial side of breast is into:","o":["Anterior axillary","Internal thoracic (parasternal)","Posterior axillary","Infraclavicular"],"a":1,"e":"The medial part of the breast drains to the internal thoracic (parasternal) lymph nodes.<br><br>The lateral breast drains to axillary nodes; the medial drains to internal thoracic nodes."},
/*390*/ {"q":"Lymph from nipple of breast drains into:","o":["Apical axillary node","Anterior axillary nodes","Internal mammary nodes","Subdiaphragmatic nodes"],"a":1,"e":"The nipple and areola drain to the subareolar plexus and then chiefly to the anterior (pectoral) axillary nodes.<br><br>The medial breast drains to internal mammary nodes; the nipple/areola drains chiefly to the anterior (pectoral) axillary nodes."},
/*391*/ {"q":"Chronic cold adaptation occurs through which one of the following mechanisms:","o":["Internal pyogens","Chemical thermogenesis","Formation of brown fat","Peripheral vasoconstriction"],"a":2,"e":"Long-term cold adaptation involves increased brown adipose tissue for non-shivering thermogenesis.<br><br>Shivering is acute; chronic cold adaptation relies on non-shivering thermogenesis via brown adipose tissue."},
/*392*/ {"q":"Which one is directly related to coronary artery disease:","o":["Plasma cholesterol","LDL-C","HDL-C","Trans fatty acid"],"a":1,"e":"Elevated LDL cholesterol is directly atherogenic and the principal lipid risk factor for coronary artery disease.<br><br>HDL is protective; the directly related factor is LDL-C."},
/*393*/ {"q":"Which one of the following is responsible for blood clot retraction:","o":["Fibrin","Platelets","Monocyte","Histamine"],"a":1,"e":"Platelets, through actin-myosin contraction and release of thrombosthenin, mediate clot retraction.<br><br>Fibrin forms the mesh; clot retraction is performed by platelets."},
/*394*/ {"q":"For prevention of disease, what is the best measure:","o":["Individual opinion regarding disease","Establishing health education","Asking relatives","Asking patient"],"a":1,"e":"Establishing health education is the best primary preventive measure, empowering populations to avoid disease.<br><br>Individual or relative opinion is unreliable; population-level disease prevention is best achieved through health education."},
/*395*/ {"q":"The fastest conduction speed in the cardiac conduction system is a feature of which structure:","o":["Sinoatrial node","Atrioventricular node","Ventricular muscles","Purkinje system"],"a":3,"e":"The Purkinje fibers have the fastest conduction velocity in the heart, rapidly distributing the impulse through the ventricles.<br><br>The AV node is slowest; the fastest is the Purkinje system."},
/*396*/ {"q":"AV nodal delay helps in which of the following:","o":["Atrial filling","Ventricle filling","Aorta filling","Ventricle contraction"],"a":1,"e":"The AV nodal delay allows the atria to complete emptying so the ventricles fill adequately before contracting.<br><br>The delay does not affect aortic filling (that is ejection); it allows time for adequate ventricular filling before contraction."},
/*397*/ {"q":"Staging for any malignancy is done to see which of these:","o":["Pleomorphism","Extent of spread","No. of mitosis","Grading"],"a":1,"e":"Tumour staging assesses the anatomical extent of spread (TNM), the strongest prognostic indicator.<br><br>Pleomorphism and mitoses relate to grading; staging measures extent of spread."},
/*398*/ {"q":"Most radiosensitive phase of the cell cycle:","o":["G2/M phase","S phase","G1 phase","G0 phase"],"a":0,"e":"Cells are most radiosensitive during the G2 and M phases of the cell cycle.<br><br>Late S phase is most resistant; the most radiosensitive phase is G2/M."},
/*399*/ {"q":"The unit of absorbed radiation dose is:","o":["Gray","Sievert","Becquerel","Curie"],"a":0,"e":"The gray (Gy) is the SI unit of absorbed radiation dose (joules per kilogram).<br><br>The sievert is equivalent dose; absorbed dose is in gray."},
/*400*/ {"q":"Investigation of choice for renal stones:","o":["Non-contrast CT KUB","Ultrasound","Plain X-ray KUB","IVU"],"a":0,"e":"Non-contrast CT of the kidneys, ureters and bladder is the investigation of choice for urinary calculi.<br><br>Ultrasound and plain film miss small stones; the gold standard is CT KUB."},
/*401*/ {"q":"Reversible loss of shape, size and polarity is:","o":["Hyperplasia","Metaplasia","Dysplasia","Neoplasia"],"a":2,"e":"Dysplasia is a reversible disordered growth with loss of cell shape, size and polarity, a precancerous change.<br><br>Metaplasia changes cell type; neoplasia is irreversible. The reversible disordered growth is dysplasia."},
/*402*/ {"q":"24-year-old primigravida at 34 weeks, fundal height 28 cm, USG reveals amniotic fluid index of 2 cm; which condition is likely associated:","o":["Spina bifida","Esophageal atresia","Tracheoesophageal fistula","Renal agenesis"],"a":3,"e":"Severe oligohydramnios with a fundal height less than dates points to renal agenesis (failure of fetal urine production).<br><br>Oesophageal atresia causes polyhydramnios; oligohydramnios indicates renal agenesis."},
/*403*/ {"q":"A woman with previous history of HMB now pregnant, delivers a baby at full term; both mother and baby will have deficiency of:","o":["Vitamin K","Iron","Mg","Niacin"],"a":1,"e":"Chronic heavy menstrual bleeding depletes maternal iron, so both mother and baby become iron deficient.<br><br>Vitamin K and niacin stores are unaffected; chronic menorrhagia depletes maternal and fetal iron, causing iron deficiency."},
/*404*/ {"q":"Nerve supply of rectus abdominis is:","o":["Lower six thoracic","Subcostal only","Last five intercostal, subcostal, ilioinguinal and iliohypogastric","Last five intercostal, subcostal and ilioinguinal only"],"a":0,"e":"Rectus abdominis is supplied by the lower six thoracic (T7-T12) ventral rami.<br><br>The ilioinguinal/subcostal nerves supply other abdominal muscles; rectus abdominis is innervated by the lower six thoracic nerves."},
/*405*/ {"q":"Glans and clitoris lymphatic drainage is into:","o":["Superficial inguinal","Internal iliac","Deep inguinal","Vertical group of superficial inguinal and external iliac nodes"],"a":2,"e":"The glans penis and clitoris drain to the deep inguinal lymph nodes.<br><br>The skin drains to superficial inguinal nodes; the substance of the glans/clitoris drains to the deep inguinal nodes."},
/*406*/ {"q":"Lymphatic drainage of clitoris is:","o":["Internal iliac and external iliac","Internal iliac","Inferior mesenteric","Internal pudendal"],"a":3,"e":".<br><br>Among the listed options the clitoral lymphatic route in this item is keyed to the internal pudendal pathway rather than the iliac groups."},
/*407*/ {"q":"Councilman bodies occur in process of:","o":["Hypertrophy","Apoptosis","Atrophy","Yellow fever"],"a":1,"e":"Councilman (apoptotic) bodies are individual hepatocytes dying by apoptosis, seen classically in viral hepatitis and yellow fever.<br><br>Hypertrophy and atrophy are size changes; Councilman (apoptotic) bodies represent single-cell apoptosis, classically in yellow fever/hepatitis."},
/*408*/ {"q":"After trauma on anatomical snuff box, patient has bleed and pain due to which structure damaged:","o":["Median nerve","Ulnar nerve","Radial artery","Brachial artery"],"a":2,"e":"The radial artery crosses the floor of the anatomical snuffbox, so a snuffbox injury damages the radial artery.<br><br>The median/ulnar nerves are not in the snuffbox floor; the radial artery crosses it and bleeds when injured there."},
/*409*/ {"q":"In duodenal ulcer, which lymph node is involved:","o":["Superior mesenteric","Superior mesenteric + celiac","Inferior mesenteric","Celiac"],"a":1,"e":"The first part of the duodenum drains to the celiac nodes with superior mesenteric involvement for the midgut portion.<br><br>The IMA drains the hindgut; the duodenum (foregut/midgut junction) drains to the superior mesenteric and celiac nodes."},
/*410*/ {"q":"Inferior rectal artery is branch of:","o":["SMA","Celiac artery","Inferior mesenteric","Internal pudendal"],"a":3,"e":"The inferior rectal artery is a branch of the internal pudendal artery.<br><br>The superior rectal is from the IMA; the inferior rectal arises from the internal pudendal artery."},
/*411*/ {"q":"A woman and man have history of recurrent pregnancy, unremarkable clinical and genetic history but all pregnancies end as stillbirth; how to investigate:","o":["Southern blot","Tandem mass spectroscopy","Next generation sequencing","Karyotyping"],"a":3,"e":"Recurrent pregnancy loss with stillbirths warrants parental karyotyping to detect balanced translocations.<br><br>Normal parental clinical and genetic history with recurrent stillbirth still requires karyotyping to find a balanced translocation."},
/*412*/ {"q":"Which of the following is the most common finding in autoimmune conditions:","o":["RA","Hematological","Malignancy","Skin rash"],"a":1,"e":".<br><br>Skin rash and arthritis are organ-specific; the commonest general laboratory finding across autoimmune disease is haematological abnormality."},
/*413*/ {"q":"A patient with primary amenorrhea, well developed secondary sexual characteristics, has breast but absent uterus; due to abnormal development of:","o":["Mesonephric duct","Paramesonephric duct","Genital tubercle","Mullerian tubercle"],"a":1,"e":"Absent uterus with normal female secondary characteristics indicates failed development of the paramesonephric (Mullerian) ducts.<br><br>The mesonephric (Wolffian) duct forms male structures; absent uterus with female phenotype is failed paramesonephric (Mullerian) development."},
/*414*/ {"q":"Femoral pulse can be felt at which of the following site:","o":["Femoral canal","Mid inguinal point","Adductor canal","Mid part below inguinal canal"],"a":1,"e":"The femoral artery pulse is palpated at the mid-inguinal point, midway between the ASIS and pubic symphysis.<br><br>The femoral canal lies medial to the vein; the femoral artery pulse is felt at the mid-inguinal point (midway ASIS to symphysis)."},
/*415*/ {"q":"Ovarian artery is branch of:","o":["Femoral","Celiac","Abdominal aorta","SMA"],"a":2,"e":"The ovarian arteries arise directly from the abdominal aorta just below the renal arteries.<br><br>The internal iliac supplies the uterus; the ovarian artery springs from the abdominal aorta."},
/*416*/ {"q":"Cavernous sinus infection causes palsy of lateral rectus; nerve injured will be:","o":["Trigeminal nerve","Ophthalmic nerve","Abducent nerve","Facial nerve"],"a":2,"e":"Lateral rectus is supplied by the abducens nerve (CN VI), which traverses the cavernous sinus and is injured there.<br><br>Trochlear and oculomotor move other muscles; lateral rectus is supplied by the abducens nerve, palsied in cavernous sinus disease."},
/*417*/ {"q":"Child with Meckel diverticulum having bleeding per rectum; it is due to:","o":["Volvulus","Intussusception","Ectopic gastric tissue","Splenic mucosa"],"a":2,"e":"Bleeding from a Meckel diverticulum is caused by ectopic gastric mucosa secreting acid and ulcerating the adjacent ileum.<br><br>Intussusception/volvulus cause obstruction not bleeding; Meckel bleeding is from acid-secreting ectopic gastric mucosa."},
/*418*/ {"q":"After hemorrhage Hb binds with which of these:","o":["Ferritin","Haptoglobin","Transferrin","Albumin"],"a":1,"e":"Free haemoglobin released during haemolysis binds haptoglobin in plasma for clearance.<br><br>Iron is carried by transferrin; free Hb is bound by haptoglobin."},
/*419*/ {"q":"1-year-old child with failure to thrive and progressive cyanosis, tachypnea and left ventricular hypertrophy; which defect are you suspecting:","o":["TOF","Ebstein's anomaly","TAPVR","ASD"],"a":0,"e":"Cyanosis with failure to thrive in infancy and ventricular hypertrophy is characteristic of tetralogy of Fallot.<br><br>Ebstein and TAPVR present differently; cyanosis with failure to thrive and ventricular hypertrophy in infancy is tetralogy of Fallot."},
/*420*/ {"q":"A patient presents with esophageal varices having bleeding; which vessel is involved:","o":["Left gastric vein","Right gastric artery","Splenic artery","Hepatic artery"],"a":0,"e":"Oesophageal varices bleed from the dilated left gastric (coronary) vein at the portosystemic anastomosis.<br><br>The splenic/hepatic arteries are arterial inflow; variceal bleeding comes from the dilated left gastric (coronary) vein."},
/*421*/ {"q":"Female urethra in female:","o":["Lies below diaphragm","Lies below urogenital diaphragm","Lies above urogenital triangle","More prone to infection"],"a":3,"e":"The short female urethra is more prone to ascending infection than the male urethra.<br><br>Its position relative to the diaphragm is not the key point; the short female urethra is clinically notable for being more prone to infection."},
/*422*/ {"q":"A scar that extends beyond its boundaries is called:","o":["Keloid","Hypertrophic scar","Rash","Psoas abscess"],"a":0,"e":"A keloid is an excessive scar that extends beyond the original wound margins, with abundant type I and III collagen.<br><br>A hypertrophic scar stays within the margin; beyond the margin it is a keloid (FA)."},
/*423*/ {"q":"Edema in burn patient is due to which of the following:","o":["Loss of calcium","Loss of sodium","Loss of albumin","Loss of chloride"],"a":2,"e":"Burn oedema results from increased capillary permeability and loss of plasma albumin, lowering oncotic pressure.<br><br>Burn oedema is not from electrolyte loss; increased capillary permeability with albumin loss lowers oncotic pressure causing oedema."},
/*424*/ {"q":"Rectus sheath above the arcuate line is formed by:","o":["Internal oblique and transverse abdominis","External and internal oblique aponeurosis","Transverse abdominis aponeurosis","Internal oblique aponeurosis"],"a":1,"e":"Above the arcuate line the anterior rectus sheath is the external oblique and the split anterior internal oblique aponeurosis.<br><br>Below the arcuate line all aponeuroses pass anteriorly; above it the anterior sheath is the external oblique and anterior internal oblique aponeurosis."},
/*425*/ {"q":"Highest point of iliac crest is at the level of:","o":["L5","L4","Anterior superior iliac spine","Inguinal ligament"],"a":1,"e":"The highest point of the iliac crest lies at the level of the L4 vertebra, a landmark for lumbar puncture.<br><br>The L5 level marks the iliac tubercle/lower crest; the highest point of the iliac crest lies at the L4 vertebral level (LP landmark)."},
/*426*/ {"q":"Lady with history of having some canned food last week, now with worsening muscular weakness; Clostridium toxin A acts on nerves how:","o":["Syntoxin","Calcium release","NMJ (blocks acetylcholine release)","SNAP 25"],"a":3,"e":"Botulinum toxin from canned food cleaves SNAP-25, blocking acetylcholine release at the neuromuscular junction and causing flaccid paralysis.<br><br>Botulinum toxin does not act via calcium release or syntaxin alone; it cleaves SNAP-25, blocking acetylcholine release at the NMJ."},
/*427*/ {"q":"Group of motor nerves involved in dysphagia and difficulty in pharyngeal swallowing:","o":["CN 9 10 11 12","CN 12","CN 6 8 9","CN 7 8"],"a":0,"e":"Pharyngeal swallowing involves cranial nerves IX, X, XI and XII for motor control of the pharynx and tongue.<br><br>Single cranial nerves are insufficient; pharyngeal swallowing motor control involves cranial nerves IX, X, XI and XII together."},
/*428*/ {"q":"Root of tongue and backward movement with difficulty closing of oropharyngeal isthmus; muscle involved is:","o":["Palatoglossus","Styloglossus","Geniohyoid","Mylohyoid"],"a":0,"e":"Palatoglossus elevates the tongue root and closes the oropharyngeal isthmus.<br><br>Styloglossus retracts the tongue; oropharyngeal isthmus closure is by palatoglossus."},
/*429*/ {"q":"Patient with posterior tongue carcinoma; what is the lymphatic drainage:","o":["Jugulo-omohyoid","Jugulodigastric","Superior deep cervical","Submental"],"a":0,"e":"The posterior third of the tongue drains to the jugulo-omohyoid node.<br><br>The tip drains to submental; the posterior third drains to the jugulo-omohyoid node."},
/*430*/ {"q":"A patient with lower lip carcinoma; first drainage of lymph nodes is:","o":["Submental","Deep cervical","Superficial cervical","Jugulo-omohyoid"],"a":0,"e":"The lower lip drains first to the submental lymph nodes.<br><br>The jugulo-omohyoid drains the tongue; the lower lip drains first to the submental lymph nodes."},
/*431*/ {"q":"A patient with painless testicular swelling diagnosed as testicular tumor; it drains into which group of lymph nodes:","o":["Iliac lymph node","Popliteal lymph nodes","Inguinal lymph nodes","Retroperitoneal (para-aortic) lymph node"],"a":3,"e":"Testicular tumours drain to the para-aortic (retroperitoneal) lymph nodes, reflecting the testis's abdominal origin.<br><br>Scrotal skin drains to inguinal nodes; the testis itself drains to the retroperitoneal (para-aortic) nodes via its embryological origin."},
/*432*/ {"q":"Right gastric artery is branch of:","o":["Celiac trunk","Right hepatic artery","Splenic artery","Gastroduodenal artery"],"a":1,"e":"The right gastric artery typically arises from the hepatic artery (proper or common).<br><br>The left gastric is from the celiac; the right gastric arises from the hepatic artery."},
/*433*/ {"q":"Superior mesenteric vein and splenic vein join behind the neck of pancreas to form:","o":["Portal vein","Splenic vein","Hepatic vein","Gastric vein"],"a":0,"e":"The superior mesenteric and splenic veins unite behind the pancreatic neck to form the portal vein.<br><br>The inferior mesenteric vein joins the splenic; the splenic and superior mesenteric veins unite behind the pancreatic neck to form the portal vein."},
/*434*/ {"q":"Annular pancreas represents:","o":["Pancreatic head regression","Pancreatic neck suppression","Ventral bud fails to rotate","Beta cells of pancreas"],"a":2,"e":"Annular pancreas results from abnormal rotation/fusion of the ventral pancreatic bud encircling the duodenum.<br><br>Head/neck regression is not the mechanism; annular pancreas results from failure of the ventral pancreatic bud to rotate normally."},
/*435*/ {"q":"A newborn with translucent swelling on anterior abdominal wall, umbilicus attached to its apex; diagnosis:","o":["Omphalocele","Gastroschisis","Vitelline tract","Meckel diverticulum"],"a":0,"e":"A midline translucent abdominal wall swelling with the umbilicus at its apex, covered by a membrane, is an omphalocele.<br><br>Gastroschisis is not membrane-covered and is paraumbilical; this is an omphalocele."},
/*436*/ {"q":"Fast fibers are:","o":["C fiber","B fibers","A alpha","A delta"],"a":2,"e":"A-alpha fibers are the largest and fastest conducting nerve fibers (motor and proprioception).<br><br>C fibers are slowest; the fastest are A-alpha fibers."},
/*437*/ {"q":"A patient wished to take a supplement found this vitamin deficiency is similar to B12 except for anemia and occurs in liver and biliary tract disease; what is the vitamin:","o":["Vitamin A","Vitamin D","Vitamin E","Vitamin K"],"a":2,"e":"Vitamin E deficiency causes neurological features similar to B12 deficiency but without megaloblastic anaemia, and occurs with fat malabsorption.<br><br>Vitamins A, D and K differ; vitamin E deficiency mimics B12 neurological disease but without megaloblastic anaemia, occurring in fat malabsorption."},
/*438*/ {"q":"Warfarin causes bleeding; what should be given to stop the bleed:","o":["Heparin","Vitamin K","Vitamin C","Protamine"],"a":1,"e":"Warfarin-induced bleeding is reversed with vitamin K (and fresh frozen plasma for urgent reversal).<br><br>Protamine reverses heparin; warfarin is reversed with vitamin K."},
/*439*/ {"q":"Finger injury which activates kinin and also coagulation by which factor:","o":["Histamine","Hageman factor (factor XII)","Factor 7","Factor 5"],"a":1,"e":"Hageman factor (factor XII) activates both the intrinsic coagulation cascade and the kinin (bradykinin) system on contact with collagen.<br><br>Factors VII and V act downstream; factor XII (Hageman) initiates both the intrinsic cascade and the kinin (bradykinin) system on contact activation."},
/*440*/ {"q":"Deltoid assists in abduction of arm by which muscle up to 15 degrees:","o":["Teres major","Supraspinatus","Serratus anterior","Teres minor"],"a":1,"e":"Supraspinatus initiates the first 15-30 degrees of arm abduction before deltoid takes over.<br><br>Teres major/minor are rotators; supraspinatus initiates the first ~15 degrees of abduction before deltoid takes over."},
/*441*/ {"q":"Patient after RTA fracture of 9 and 10 ribs left side, hypotension; cause is which of the following:","o":["Gall bladder injury","Spleen rupture","Pancreas rupture","Kidney injury"],"a":1,"e":"The spleen lies behind the left 9th-11th ribs, so left lower rib fractures with hypotension indicate splenic rupture.<br><br>Right-sided rib fractures suggest liver injury; left lower (9-11) rib fractures with hypotension indicate splenic rupture."},
/*442*/ {"q":"A person with history of smoking and drinking for many years, on endoscopy there is a mass in middle third of esophagus; what could it likely be:","o":["Adenocarcinoma","Squamous cell carcinoma","Barrett esophagus","Chronic esophagitis"],"a":1,"e":"Mid-oesophageal carcinoma in a smoker and drinker is most commonly squamous cell carcinoma.<br><br>Lower-third adenocarcinoma relates to Barrett/GERD; the mid-oesophageal smoking-related cancer is squamous cell carcinoma."},
/*443*/ {"q":"A female with aortic root dilation up to 4 cm, lens dislocation, mitral valve leaflet defect with systolic click; which of the following:","o":["Acquired deficiency of fibrillin","Inherited deficiency of fibrillin","Inherited deficiency of laminin","Acquired deficiency of spectrin"],"a":1,"e":"Marfan syndrome is caused by an inherited fibrillin-1 deficiency, producing aortic root dilatation, ectopia lentis and mitral valve prolapse.<br><br>The defect is genetic not acquired and not laminin/spectrin; Marfan syndrome is an inherited fibrillin-1 deficiency."},
/*444*/ {"q":"Referred pain of gallbladder is due to:","o":["Parasympathetic from gallbladder to parasympathetic of upper thoracic","Sensory ending in parietal peritoneum derived from mid cervical dermatome","Wide distribution of vagus nerve","Parasympathetic fiber gallbladder to CNS"],"a":1,"e":"Gallbladder pain is referred to the shoulder via sensory endings in the parietal (diaphragmatic) peritoneum supplied by the phrenic nerve (C3-5).<br><br>Vagal afferents give epigastric pain; gallbladder shoulder-tip referral is via parietal (diaphragmatic) peritoneum sensory endings (phrenic)."},
/*445*/ {"q":"Referred pain from ureteric colic is felt in thigh due to involvement of which nerve:","o":["Subcostal","Iliohypogastric","Ilioinguinal","Genitofemoral"],"a":3,"e":"Ureteric colic refers pain to the groin and medial thigh via the genitofemoral nerve.<br><br>The ilioinguinal and iliohypogastric supply the lower abdomen; ureteric colic refers to the groin and medial thigh via the genitofemoral nerve."},
/*446*/ {"q":"Most common cause of acute pancreatitis:","o":["Gallstones","Alcohol","Hyperlipidemia","Trauma"],"a":0,"e":"Gallstones are the commonest cause of acute pancreatitis, by obstructing the ampulla.<br><br>Alcohol is the next commonest; the leading cause is gallstones."},
/*447*/ {"q":"Curling ulcer is associated with:","o":["Burns","Head injury","NSAIDs","H. pylori"],"a":0,"e":"A Curling ulcer is an acute gastroduodenal stress ulcer occurring after severe burns.<br><br>A Cushing ulcer follows head injury; the burn-associated ulcer is Curling."},
/*448*/ {"q":"Barrett esophagus is:","o":["Columnar metaplasia of lower esophagus","Squamous metaplasia","Adenocarcinoma","Achalasia"],"a":0,"e":"Barrett oesophagus is intestinal columnar metaplasia of the lower oesophageal squamous mucosa from chronic acid reflux.<br><br>It is metaplasia, not yet carcinoma; Barrett is columnar metaplasia."},
/*449*/ {"q":"Most common site of peptic ulcer:","o":["First part of duodenum","Stomach body","Pylorus","Lower esophagus"],"a":0,"e":"Duodenal peptic ulcers, most often in the first part (duodenal cap), are the commonest site of peptic ulceration.<br><br>Gastric ulcers are less frequent; the commonest site is the first part of duodenum."},
/*450*/ {"q":"Reed-Sternberg cells are diagnostic of:","o":["Hodgkin lymphoma","Non-Hodgkin lymphoma","Burkitt lymphoma","CLL"],"a":0,"e":"Binucleate owl-eye Reed-Sternberg cells are the diagnostic hallmark of Hodgkin lymphoma.<br><br>Non-Hodgkin lymphomas lack them; RS cells define Hodgkin lymphoma."},
/*451*/ {"q":"Patient presents with severe pain in the ankle and develops ecchymosis on the second day; he can stand on his toes but it is painful; what is the cause:","o":["Rupture of Achilles tendon","Rupture of plantaris tendon","Rupture of tibial tendon","Medial malleolus damage"],"a":1,"e":"Ability to still stand on toes (preserved plantarflexion) with pain and bruising indicates a plantaris tendon rupture rather than Achilles.<br><br>Achilles rupture abolishes toe-standing; this preserved-function picture is plantaris rupture."},
/*452*/ {"q":"Regarding fibrocartilage, true is:","o":["Primary cartilaginous joints","Present in larynx","Present in intervertebral disc","Related to epiglottis"],"a":2,"e":"Fibrocartilage forms the intervertebral discs, pubic symphysis and menisci.<br><br>The larynx and epiglottis are elastic/hyaline cartilage; fibrocartilage is in the intervertebral disc."},
/*453*/ {"q":"70-year-old man with recurrent UTI developed hypotension, tachycardia and altered mental status; type of shock is:","o":["Neurogenic","Hypovolumic","Septic","Cardiogenic"],"a":2,"e":"Hypotension and tachycardia with altered mentation from a urinary source indicates septic shock.<br><br>Hypovolaemic shock causes cool vasoconstriction; a UTI source with fever and warm hypotension is distributive septic shock."},
/*454*/ {"q":"A newborn brought with recurrent pyogenic infections; investigations reveal deficiency of antibody; the physiological deficiency is of which of the following:","o":["IgA","IgD","IgE","IgG"],"a":3,"e":"Newborns rely on transplacental maternal IgG which physiologically falls by 3-6 months, leaving a window of low IgG and susceptibility to pyogenic infection.<br><br>IgA/IgE are not transplacental; the physiological nadir of maternally derived IgG at 3-6 months leaves the infant prone to pyogenic infection."},
/*455*/ {"q":"Most abundant antibody in adult human:","o":["IgE","IgM","IgA","IgG"],"a":3,"e":"IgG is the most abundant immunoglobulin in adult serum and the only one crossing the placenta.<br><br>IgA is most abundant in secretions; in serum the commonest is IgG."},
/*456*/ {"q":"Largest antibody in adult human is:","o":["IgE","IgM","IgA","IgG"],"a":1,"e":"IgM is the largest immunoglobulin, a pentamer, and the first produced in the primary immune response.<br><br>IgG is a monomer; the largest is IgM."},
/*457*/ {"q":"After bacterial infection which cells will be seen:","o":["Lymphocytic leukocytosis","Monocytosis","Neutrophilic leukocytosis","Basophilic leukocytosis"],"a":2,"e":"Acute bacterial infection produces a neutrophilic leucocytosis with a left shift.<br><br>Viral infections cause lymphocytosis; bacterial infection causes neutrophilia."},
/*458*/ {"q":"Cytokeratin is an intermediate filament found in cells but is most commonly used for detection of:","o":["Neoplasia","Degree of metaplasia or dysplasia","To check rate of proliferation","For staging of disease"],"a":0,"e":"Cytokeratin immunostaining identifies epithelial cells and is used to detect epithelial neoplasia (carcinoma).<br><br>Cytokeratin marks epithelial cells, so it is used to identify epithelial neoplasia (carcinoma), not to grade dysplasia or stage disease."},
/*459*/ {"q":"Pap smear shows dysplasia but basement membrane is intact; what is this associated with:","o":["Invasion of adjacent tissue","Invasion of basement membrane","Carcinoma in situ","Carcinoma"],"a":2,"e":"Full-thickness dysplasia with an intact basement membrane and no invasion is carcinoma in situ.<br><br>Breach of the basement membrane defines invasive carcinoma; intact membrane is carcinoma in situ."},
/*460*/ {"q":"Polycythemia vera differs from other types of polycythemia in:","o":["Erythropoietin abnormality","Platelets defect","RBC production","WBC defect"],"a":0,"e":"Polycythaemia vera has low erythropoietin (autonomous JAK2-driven proliferation), whereas secondary polycythaemia has high EPO.<br><br>Secondary polycythaemia has high EPO; polycythaemia vera is distinguished by autonomous proliferation with low erythropoietin."},
/*461*/ {"q":"A 36-year-old athlete who works out excessively during exercise; increased water loss will be through:","o":["Sweating","Insensible loss from body","GIT","Lungs"],"a":0,"e":"During strenuous exercise the major route of water loss is sweating for thermoregulation.<br><br>Insensible loss via skin/lungs is small; during heavy exercise the major route of water loss is sweating for thermoregulation."},
/*462*/ {"q":"A young male with unequal BP in both arms, visible intercostal pulsation and rib notching on X-ray; diagnosis:","o":["Preductal aortic coarctation","Postductal aortic coarctation","Aortic arch aneurysm","Aortic stenosis"],"a":1,"e":"Rib notching with differential arm blood pressures and collateral intercostal pulsation indicates postductal coarctation of the aorta.<br><br>Preductal type presents in infancy; the adult picture is postductal coarctation."},
/*463*/ {"q":"Most common cause of right heart failure is:","o":["Left heart failure","COPD","Pulmonary embolism","Tricuspid disease"],"a":0,"e":"The commonest cause of right heart failure is left heart failure raising pulmonary venous pressure.<br><br>Cor pulmonale from lung disease is next; the leading cause is left heart failure."},
/*464*/ {"q":"Janeway lesions and Osler nodes are seen in:","o":["Infective endocarditis","Rheumatic fever","SLE","Polyarteritis nodosa"],"a":0,"e":"Painless Janeway lesions and painful Osler nodes are peripheral stigmata of infective endocarditis.<br><br>They are not features of rheumatic fever; these signs indicate infective endocarditis."},
/*465*/ {"q":"Most common cyanotic congenital heart disease:","o":["Tetralogy of Fallot","Transposition of great arteries","Tricuspid atresia","Truncus arteriosus"],"a":0,"e":"Tetralogy of Fallot is the commonest cyanotic congenital heart disease beyond infancy.<br><br>Transposition presents earliest; the commonest cyanotic lesion overall is TOF."},
/*466*/ {"q":"Aschoff bodies are pathognomonic of:","o":["Rheumatic fever","Infective endocarditis","Sarcoidosis","Tuberculosis"],"a":0,"e":"Aschoff bodies with Anitschkow cells are pathognomonic of rheumatic fever/carditis.<br><br>They are not seen in infective endocarditis; Aschoff bodies indicate rheumatic fever."},
/*467*/ {"q":"Most common renal stone composition:","o":["Calcium oxalate","Struvite","Uric acid","Cystine"],"a":0,"e":"Calcium oxalate stones are the commonest type of renal calculi.<br><br>Struvite, uric acid and cystine stones are less frequent; the commonest are calcium oxalate."},
/*468*/ {"q":"Most common cause of nephrotic syndrome in adults:","o":["Membranous nephropathy","Minimal change disease","IgA nephropathy","Diabetic nephropathy"],"a":0,"e":"Membranous nephropathy is the commonest primary cause of nephrotic syndrome in adults; diabetic nephropathy is the commonest secondary cause.<br><br>Diabetic nephropathy is the commonest secondary cause; the commonest primary cause of adult nephrotic syndrome is membranous nephropathy."},
/*469*/ {"q":"IgA nephropathy (Berger disease) typically presents with:","o":["Recurrent hematuria after URTI","Massive proteinuria","Hypertension only","Renal stones"],"a":0,"e":"IgA nephropathy classically presents with episodic gross haematuria concurrent with an upper respiratory tract infection.<br><br>Post-streptococcal latency is longer; IgA nephropathy haematuria is concurrent with the URTI."},
/*470*/ {"q":"Wilms tumor is associated with mutation of:","o":["WT1 gene","RB gene","APC gene","BRCA gene"],"a":0,"e":"Wilms tumour (nephroblastoma) is associated with WT1 gene mutations on chromosome 11.<br><br>RB and APC relate to other tumours; the Wilms tumour gene is WT1."},
/*471*/ {"q":"Ghon complex is characteristic of:","o":["Primary tuberculosis","Sarcoidosis","Histoplasmosis","Silicosis"],"a":0,"e":"The Ghon complex (parenchymal focus plus regional node) is the hallmark of primary pulmonary tuberculosis.<br><br>Sarcoid and silicosis differ; the Ghon complex indicates primary TB."},
/*472*/ {"q":"Most common lung cancer in non-smokers:","o":["Adenocarcinoma","Squamous cell carcinoma","Small cell carcinoma","Large cell carcinoma"],"a":0,"e":"Adenocarcinoma is the commonest lung cancer in non-smokers and overall, typically peripheral.<br><br>Squamous and small cell are smoking-related; in non-smokers it is adenocarcinoma."},
/*473*/ {"q":"Small cell lung carcinoma is associated with:","o":["Paraneoplastic syndromes (SIADH, ACTH)","No paraneoplastic effects","Peripheral location","Best prognosis"],"a":0,"e":"Small cell lung carcinoma is strongly associated with paraneoplastic syndromes such as SIADH and ectopic ACTH.<br><br>It has a poor prognosis; the key association is paraneoplastic syndromes."},
/*474*/ {"q":"Mesothelioma is most strongly associated with:","o":["Asbestos exposure","Smoking","Silica","Radon"],"a":0,"e":"Malignant pleural mesothelioma is strongly associated with prior asbestos exposure after a long latency.<br><br>Smoking is not its main cause; mesothelioma links to asbestos."},
/*475*/ {"q":"Most common cause of esophageal varices:","o":["Portal hypertension from cirrhosis","Esophageal cancer","Achalasia","Reflux esophagitis"],"a":0,"e":"Oesophageal varices result from portal hypertension, most commonly due to hepatic cirrhosis.<br><br>The other oesophageal conditions are unrelated; varices arise from cirrhotic portal hypertension."},
/*476*/ {"q":"During exercise a person feels tired due to subjective feeling of:","o":["Increased heart rate","Dehydration","Lactic acidosis","Low oxygen"],"a":0,"e":".<br><br>Lactic acidosis and low oxygen are objective changes; the subjective sensation of fatigue during exercise correlates with the rising heart rate."},
/*477*/ {"q":"Esophageal opening passes through the diaphragm at which vertebral level:","o":["T8","T10","L5","T12"],"a":1,"e":"The oesophageal opening of the diaphragm is at the T10 level, transmitting the oesophagus and vagi.<br><br>The aortic opening is T12; the oesophageal hiatus is T10 (Snell + KLM)."},
/*478*/ {"q":"Waddling gait is caused by damage to which of the following nerve:","o":["Inferior gluteal nerve","Superior gluteal nerve","Sciatic nerve","Femoral nerve"],"a":1,"e":"A waddling (Trendelenburg) gait results from gluteus medius and minimus weakness due to superior gluteal nerve damage.<br><br>The inferior gluteal nerve serves gluteus maximus; the waddling gait is superior gluteal nerve damage."},
/*479*/ {"q":"A person taken to Siachen 12000 feet above sea level develops which of the following:","o":["Increased heart rate","Dehydration","Lactic acidosis","Secondary polycythemia"],"a":3,"e":"Chronic high-altitude hypoxia raises erythropoietin, producing secondary polycythaemia.<br><br>Acute heart-rate rise is transient; chronic high-altitude hypoxia raises erythropoietin causing secondary polycythaemia."},
/*480*/ {"q":"Most common primary cardiac tumor in adults:","o":["Myxoma","Rhabdomyoma","Angiosarcoma","Fibroma"],"a":0,"e":"Atrial myxoma, usually in the left atrium, is the commonest primary cardiac tumour in adults.<br><br>Rhabdomyoma is commonest in children; in adults it is myxoma."},
/*481*/ {"q":"Buerger disease (thromboangiitis obliterans) is strongly associated with:","o":["Heavy smoking","Diabetes","Hypertension","Hyperlipidemia"],"a":0,"e":"Thromboangiitis obliterans is strongly linked to heavy tobacco smoking in young men.<br><br>The other risk factors are not its main driver; Buerger disease is smoking-related."},
/*482*/ {"q":"Temporal (giant cell) arteritis classically presents with:","o":["Headache and jaw claudication with raised ESR","Hypertension","Hematuria","Skin rash"],"a":0,"e":"Giant cell arteritis presents with temporal headache, jaw claudication and a markedly raised ESR, risking blindness.<br><br>Renal and skin features are atypical; the hallmark is headache with jaw claudication and high ESR."},
/*483*/ {"q":"Most common site of hypertensive intracerebral hemorrhage:","o":["Basal ganglia (putamen)","Cerebellum","Pons","Cortex"],"a":0,"e":"Hypertensive intracerebral haemorrhage most commonly occurs in the basal ganglia, particularly the putamen.<br><br>The other sites are less frequent; the commonest is the putamen/basal ganglia."},
/*484*/ {"q":"Most common posterior fossa tumor in children:","o":["Medulloblastoma","Glioblastoma","Meningioma","Schwannoma"],"a":0,"e":"Medulloblastoma is the commonest malignant posterior fossa tumour in children, arising in the cerebellar vermis.<br><br>The other tumours are uncommon in children; the commonest is medulloblastoma."},
/*485*/ {"q":"Acoustic neuroma (vestibular schwannoma) arises from:","o":["CN VIII","CN V","CN VII","CN IX"],"a":0,"e":"A vestibular schwannoma arises from the Schwann cells of the eighth cranial nerve at the cerebellopontine angle.<br><br>It does not arise from V or VII; the origin is CN VIII."},
/*486*/ {"q":"Neurofibrillary tangles and amyloid plaques are seen in:","o":["Alzheimer disease","Parkinson disease","Huntington disease","Multiple sclerosis"],"a":0,"e":"Extracellular amyloid plaques and intraneuronal neurofibrillary tangles are the hallmarks of Alzheimer disease.<br><br>Parkinson shows Lewy bodies; the plaque-and-tangle pathology is Alzheimer disease."},
/*487*/ {"q":"Lewy bodies are characteristic of:","o":["Parkinson disease","Alzheimer disease","Huntington disease","ALS"],"a":0,"e":"Lewy bodies, eosinophilic alpha-synuclein inclusions, are characteristic of Parkinson disease.<br><br>Alzheimer shows tangles/plaques; Lewy bodies indicate Parkinson disease."},
/*488*/ {"q":"Guillain-Barre syndrome is:","o":["Acute inflammatory demyelinating polyneuropathy","CNS demyelination","Anterior horn cell disease","Neuromuscular junction disorder"],"a":0,"e":"Guillain-Barre syndrome is an acute immune-mediated demyelinating polyneuropathy of peripheral nerves causing ascending paralysis.<br><br>It is not a CNS or anterior-horn disease; it is a peripheral demyelinating polyneuropathy."},
/*489*/ {"q":"Most common cause of viral encephalitis (sporadic):","o":["Herpes simplex virus","Rabies","Measles","Mumps"],"a":0,"e":"Herpes simplex virus is the commonest cause of sporadic fatal viral encephalitis, with temporal lobe predilection.<br><br>Rabies is rarer; sporadic encephalitis is most often HSV."},
/*490*/ {"q":"Most common pituitary tumor:","o":["Prolactinoma","Growth hormone adenoma","ACTH adenoma","Non-functioning adenoma"],"a":0,"e":"Prolactinoma is the commonest functioning pituitary adenoma.<br><br>GH and ACTH adenomas are less frequent; the commonest is prolactinoma."},
/*491*/ {"q":"Most common cause of hyperthyroidism:","o":["Graves disease","Toxic multinodular goiter","Toxic adenoma","Thyroiditis"],"a":0,"e":"Graves disease, an autoimmune TSH-receptor antibody disorder, is the commonest cause of hyperthyroidism.<br><br>Toxic nodular goitre is next; the leading cause is Graves disease."},
/*492*/ {"q":"Medullary thyroid carcinoma arises from:","o":["Parafollicular C cells","Follicular cells","Lymphocytes","Fibroblasts"],"a":0,"e":"Medullary thyroid carcinoma arises from the calcitonin-secreting parafollicular C cells and may be part of MEN 2.<br><br>Follicular-cell tumours are papillary/follicular; medullary carcinoma is from C cells."},
/*493*/ {"q":"Pheochromocytoma arises from:","o":["Adrenal medulla chromaffin cells","Adrenal cortex","Sympathetic ganglia only","Renal cells"],"a":0,"e":"Phaeochromocytoma is a catecholamine-secreting tumour of the adrenal medullary chromaffin cells.<br><br>Cortical tumours secrete steroids; phaeochromocytoma is of the adrenal medulla."},
/*494*/ {"q":"Most common cause of Cushing syndrome (excluding iatrogenic):","o":["Pituitary ACTH adenoma (Cushing disease)","Adrenal adenoma","Ectopic ACTH","Adrenal carcinoma"],"a":0,"e":"Excluding exogenous steroids, the commonest cause of endogenous Cushing syndrome is a pituitary ACTH adenoma (Cushing disease).<br><br>Adrenal and ectopic causes are less frequent; the leading endogenous cause is Cushing disease."},
/*495*/ {"q":"Most specific autoantibody for SLE:","o":["Anti-dsDNA / anti-Smith","ANA","Rheumatoid factor","Anti-CCP"],"a":0,"e":"Anti-double-stranded DNA and anti-Smith antibodies are highly specific for SLE, while ANA is sensitive but non-specific.<br><br>For specificity the keyed answer is anti-dsDNA/anti-Sm."},
/*496*/ {"q":"Anti-CCP antibody is most specific for:","o":["Rheumatoid arthritis","SLE","Scleroderma","Sjogren syndrome"],"a":0,"e":"Anti-cyclic citrullinated peptide antibody is highly specific for rheumatoid arthritis and indicates erosive disease.<br><br>It is not specific for the other connective tissue diseases; anti-CCP marks rheumatoid arthritis."},
/*497*/ {"q":"HLA-B27 is associated with:","o":["Ankylosing spondylitis","Rheumatoid arthritis","SLE","Osteoarthritis"],"a":0,"e":"HLA-B27 is strongly associated with ankylosing spondylitis and other seronegative spondyloarthropathies.<br><br>RA and SLE have different HLA links; HLA-B27 indicates ankylosing spondylitis."},
/*498*/ {"q":"Gout is caused by deposition of:","o":["Monosodium urate crystals","Calcium pyrophosphate","Calcium oxalate","Cholesterol"],"a":0,"e":"Gout results from deposition of monosodium urate crystals, negatively birefringent needles on polarised microscopy.<br><br>Calcium pyrophosphate causes pseudogout; gout is monosodium urate."},
/*499*/ {"q":"Most common organism causing osteomyelitis:","o":["Staphylococcus aureus","Streptococcus","Salmonella","Pseudomonas"],"a":0,"e":"Staphylococcus aureus is the commonest cause of acute osteomyelitis in all age groups.<br><br>Salmonella is classic in sickle cell disease; overall the leading cause is Staph aureus."},
/*500*/ {"q":"Codman triangle and sunburst appearance on X-ray suggest:","o":["Osteosarcoma","Ewing sarcoma","Osteochondroma","Giant cell tumor"],"a":0,"e":"A Codman triangle with sunburst periosteal reaction is the classic radiological appearance of osteosarcoma.<br><br>Ewing sarcoma shows an onion-skin pattern; sunburst with Codman triangle is osteosarcoma."},
/*501*/ {"q":"In femoral hernia, the neck of the sac lies below and lateral to:","o":["Inferior epigastric artery","Inguinal ligament","Femoral nerve","Pubic tubercle"],"a":3,"e":"A femoral hernia neck lies below and lateral to the pubic tubercle, distinguishing it from an inguinal hernia which lies above and medial.<br><br>An inguinal hernia is above and medial to the pubic tubercle; a femoral hernia neck lies below and lateral to it."},
/*502*/ {"q":"Cerebellum is connected to the midbrain through:","o":["Vermis","Arcuate fibers","Superior cerebellar peduncle","Inferior cerebellar peduncle"],"a":2,"e":"The cerebellum connects to the midbrain via the superior cerebellar peduncle.<br><br>The inferior peduncle connects to the medulla; midbrain connection is the superior cerebellar peduncle."},
/*503*/ {"q":"Lower limb is supplied by:","o":["MCA","ACA","PCA","Basilar"],"a":1,"e":"The lower limb (leg/foot) motor and sensory cortex on the medial surface is supplied by the anterior cerebral artery.<br><br>The MCA supplies the lateral cortex; the leg area is ACA territory."},
/*504*/ {"q":"Tachyphylaxis is:","o":["Diminished response to a drug slowly","A drug interaction between two similar types of drugs","Diminished response to a drug rapidly","Drug interaction of 3 drugs"],"a":2,"e":"Tachyphylaxis is a rapidly decreasing response to repeated doses of a drug.<br><br>Slow tolerance is different; tachyphylaxis is rapid loss of response."},
/*505*/ {"q":"A 16-year-old female with hypertension and increasing weight; which feature would be most suggestive of Cushing's syndrome rather than simple obesity:","o":["Abdominal striae","Acanthosis nigricans","Buffalo hump (interscapular fat pad)","Pot belly"],"a":0,"e":"Wide purple abdominal striae and proximal myopathy are more specific for Cushing's syndrome than simple obesity.<br><br>Acanthosis nigricans and central obesity occur in simple obesity too; wide purple striae are more specific for Cushing syndrome."},
/*506*/ {"q":"In alcoholics presenting with hypoglycemia, initial treatment is:","o":["Thiamine","IV dextrose","Oral glucose","Glucagon"],"a":0,"e":"In alcoholics, thiamine should be given before dextrose to avoid precipitating Wernicke encephalopathy.<br><br>Giving dextrose first can precipitate Wernicke encephalopathy in an alcoholic, so thiamine must be administered before glucose."},
/*507*/ {"q":"Which structure lies closest to crus cerebri:","o":["Caudate","Globus pallidus","Substantia nigra","Pons"],"a":2,"e":"The substantia nigra lies immediately dorsal to the crus cerebri in the midbrain.<br><br>The caudate and globus pallidus are forebrain; the substantia nigra lies immediately dorsal to the crus cerebri in the midbrain."},
/*508*/ {"q":"Motor supply of diaphragm is:","o":["Phrenic nerve","Intercostal nerve","Recurrent laryngeal nerve","Vagus"],"a":0,"e":"The phrenic nerve (C3-C5) is the sole motor supply to the diaphragm.<br><br>The intercostals serve the chest wall; the diaphragm motor nerve is the phrenic."},
/*509*/ {"q":"A patient had RTA resulting in tibial fracture, now with swelling, foul-smelling discharge and crepitus; what is likely cause:","o":["Septicemia","Hypovolemic shock","Toxemic shock","Bacteremia"],"a":0,"e":"A foul, crepitant infected open fracture wound with systemic deterioration indicates spreading infection leading to septicaemia.<br><br>Hypovolaemic shock follows blood loss without infection; a foul crepitant infected open fracture with systemic decline indicates septicaemia."},
/*510*/ {"q":"A patient having hypoxia, PO2 measured is 65 mmHg; type of hypoxia is:","o":["Anemic hypoxia","Hypoxia hypoxia","Cellular hypoxia","Histotoxic hypoxia"],"a":1,"e":"A low arterial PO2 indicates hypoxic (hypoxaemic) hypoxia from inadequate oxygenation of blood.<br><br>Anaemic hypoxia has normal PO2; low PO2 indicates hypoxic hypoxia."},
/*511*/ {"q":"Correct sequence of events for neutrophil migration toward the site of acute inflammation is:","o":["Margination, adhesion, rolling, transmigration","Margination, rolling, adhesion, transmigration","Rolling, adhesion, margination, transmigration","Transmigration, rolling, adhesion, margination"],"a":1,"e":"Neutrophil recruitment proceeds as margination, rolling, adhesion, then transmigration through the endothelium.<br><br>Rolling precedes firm adhesion; the correct order is margination, rolling, adhesion, then transmigration."},
/*512*/ {"q":"While doing surgery, splenic vessels need to be ligated; they are present in which ligament:","o":["Gastrosplenic","Hepatosplenic","Lienorenal","Splenigastric"],"a":2,"e":"The splenic artery and vein run within the lienorenal (splenorenal) ligament.<br><br>The short gastric vessels run in the gastrosplenic ligament; the main splenic vessels are in the lienorenal ligament."},
/*513*/ {"q":"Regarding histology of normal left kidney:","o":["Cuboidal epithelium in parietal layer of Bowman capsule","Podocyte on visceral layer of Bowman capsule","DCT longer than PCT","Glomerulus has single arteriole"],"a":1,"e":"Podocytes form the visceral layer of Bowman's capsule, wrapping the glomerular capillaries.<br><br>The parietal layer is simple squamous; the visceral layer cells are podocytes."},
/*514*/ {"q":"Costal ribs have which of the following cartilage:","o":["Fibrocartilage","Synovial cartilage","Hyaline cartilage","Elastic cartilage"],"a":2,"e":"Costal cartilages are composed of hyaline cartilage.<br><br>Fibrocartilage forms discs and elastic cartilage the pinna; costal cartilage is hyaline."},
/*515*/ {"q":"PCT in comparison to DCT has:","o":["Extensive brush border","Less convoluted","Lumen made of cuboidal epithelium","Lack brush border"],"a":0,"e":"The proximal convoluted tubule has an extensive microvillous brush border for reabsorption, unlike the DCT.<br><br>The DCT has sparse microvilli; the PCT has an extensive brush border for its large reabsorptive workload."},
/*516*/ {"q":"Umbilical artery carries:","o":["Deoxygenated blood to the placenta","Deoxygenated blood from the placenta","Oxygenated blood to placenta","Oxygenated blood to fetus"],"a":0,"e":"The umbilical arteries carry deoxygenated blood from the fetus to the placenta for gas exchange.<br><br>The umbilical vein carries oxygenated blood to the fetus; the arteries carry deoxygenated blood to the placenta."},
/*517*/ {"q":"In fetus maximum O2 saturation is present in:","o":["Umbilical artery","Left atrium","Pulmonary artery","Umbilical vein"],"a":3,"e":"The umbilical vein carries the most oxygenated blood in the fetus, returning from the placenta.<br><br>The umbilical arteries are least oxygenated; maximum saturation is in the umbilical vein."},
/*518*/ {"q":"Feature of hypertrophic obstructive cardiomyopathy is:","o":["Systolic failure with increased SV","Diastolic failure with increased SV","Diastolic failure with decreased SV","Systolic failure with decreased SV"],"a":2,"e":"Hypertrophic obstructive cardiomyopathy causes a stiff non-compliant ventricle with diastolic dysfunction and reduced stroke volume.<br><br>HOCM is not a systolic-failure/high-SV state; the stiff non-compliant ventricle causes diastolic dysfunction with reduced stroke volume."},
/*519*/ {"q":"Transport of D- and L-glucose proceeds at the same rate down an electrochemical gradient by which process:","o":["Simple diffusion","Facilitated diffusion","Primary active transport","Cotransport"],"a":1,"e":".<br><br>Active transport and cotransport are stereoselective and energy/Na-dependent; equal-rate stereo-independent gradient transport is facilitated diffusion."},
/*520*/ {"q":"Postganglionic sympathetic release is:","o":["Acetylcholine","Epinephrine","Norepinephrine","GABA"],"a":2,"e":"Most postganglionic sympathetic neurons release norepinephrine (noradrenaline).<br><br>Sweat glands are a cholinergic exception; the usual postganglionic sympathetic transmitter is norepinephrine."},
/*521*/ {"q":"Which maintains shape of RBC:","o":["Fibrillin","Titin","Dystrophin","Spectrin"],"a":3,"e":"Spectrin, with ankyrin and band proteins, forms the red cell membrane skeleton maintaining its biconcave shape.<br><br>Dystrophin is in muscle; the RBC shape protein is spectrin."},
/*522*/ {"q":"What changes are seen in a patient who is given 1 L of N/saline:","o":["Increased serum osmolality","Decreased urine osmolality","Increased urine osmolality","Increased ICF volume"],"a":1,"e":"Isotonic saline expands extracellular volume without changing plasma osmolality, so the kidney makes a more dilute (lower osmolality) urine.<br><br>Isotonic saline does not change plasma osmolality; volume expansion suppresses ADH so the kidney makes a more dilute (lower osmolality) urine."},
/*523*/ {"q":"RBCs placed in a solution which is hyperosmotic containing urea which is permeable by cell wall of RBC; what will happen:","o":["Shrinks","Lysis","Remains unchanged","Shrink then swells then lysis"],"a":3,"e":"Urea permeable hyperosmotic solution initially shrinks the cell, then urea and water enter causing swelling and eventual lysis.<br><br>A non-penetrating solute would just shrink the cell; urea entry after initial shrinkage draws water in causing swelling then lysis."},
/*524*/ {"q":"What is the definition of reliability:","o":["Extent to which a procedure can give repeated results","Extent to which a procedure is still good as it started","Means reproducibility","To produce a false result"],"a":0,"e":"Reliability is the extent to which a test or procedure gives consistent, repeatable results.<br><br>Validity is about accuracy; reliability is the extent to which a procedure gives consistent, repeatable results."},
/*525*/ {"q":"A lady with CA breast underwent total mastectomy and developed edema of right lower limb; reason of this edema:","o":["Decrease plasma protein","Increase hydrostatic pressure","Lymphatic obstruction","Metastatic involvement of lymph nodes"],"a":2,"e":"Post-mastectomy limb oedema results from disruption/obstruction of lymphatic drainage (lymphoedema).<br><br>Hypoproteinaemia would cause bilateral oedema; unilateral post-mastectomy limb swelling is from surgical lymphatic obstruction (lymphoedema)."},
/*526*/ {"q":"Normal expiration is due to:","o":["External oblique","Rectus abdominis","Elastic recoil of lung","Diaphragm"],"a":2,"e":"Quiet expiration is a passive process driven by the elastic recoil of the lungs and chest wall.<br><br>Abdominal muscles act in forced expiration; normal expiration is by elastic recoil."},
/*527*/ {"q":"Which of the following decreases osmolarity:","o":["Vasopressin (ADH)","Epinephrine","Aldosterone","Renin"],"a":0,"e":"Vasopressin (ADH) promotes free water reabsorption, diluting plasma and decreasing osmolarity.<br><br>Aldosterone retains sodium; the osmolarity-lowering hormone is ADH."},
/*528*/ {"q":"Patient with fatigue, cough, hemoptysis and hematuria for 2 days; renal biopsy showed extracapillary glomerulonephritis with linear deposits of IgG along the GBM; likely cause:","o":["PSGN","Focal segmental glomerulonephritis","Goodpasture syndrome","Alport syndrome"],"a":2,"e":"Pulmonary haemorrhage with glomerulonephritis and linear IgG along the GBM is diagnostic of Goodpasture (anti-GBM) syndrome.<br><br>PSGN shows subepithelial humps not linear IgG; linear GBM IgG with pulmonary haemorrhage is anti-GBM Goodpasture syndrome."},
/*529*/ {"q":"Confidentiality can be breached only:","o":["If patient allows you","If friend allows","If parents visit doctor","If parents allows"],"a":0,"e":"Patient confidentiality may be breached only with the patient's consent (or specific legal/public-safety exceptions).<br><br>Family or parental permission is insufficient; confidentiality may be breached only with the patient's own consent (or legal exception)."},
/*530*/ {"q":"Which muscle damage results in vocal cord abducted position:","o":["Vocalis","Thyroarytenoid","Posterior cricoarytenoid","Oblique arytenoid"],"a":2,"e":"The posterior cricoarytenoid is the only abductor of the vocal cords.<br><br>The thyroarytenoid/vocalis adduct; only the posterior cricoarytenoid abducts the cords, so its damage leaves them in an abducted position."},
/*531*/ {"q":"Aggregation of lymphoid tissue covered by stratified squamous epithelium is:","o":["Thymus","Spleen","Palatine tonsils","Lymph node"],"a":2,"e":"The palatine tonsils are aggregations of lymphoid tissue covered by stratified squamous epithelium with crypts.<br><br>Peyer patches have simple epithelium; the stratified squamous covered one is the palatine tonsil."},
/*532*/ {"q":"In a patient with cancer resection of gut, histology reveals granulomatous inflammation; what type of necrosis:","o":["Caseous","Coagulative","Fibrinoid","Fat"],"a":3,"e":".<br><br>Caseous necrosis accompanies granulomas typically, but per the keyed pattern here the marked necrosis among the options is fat necrosis."},
/*533*/ {"q":"Extracellular and intracellular potassium maintenance is by:","o":["Aldosterone","Na/K pump","Cortisol","GH"],"a":1,"e":"The Na+/K+ ATPase pump maintains the high intracellular and low extracellular potassium gradient.<br><br>Aldosterone affects renal excretion; the cellular gradient is maintained by the Na/K pump."},
/*534*/ {"q":"Cardiac tissue is most vulnerable to ventricular fibrillation at which point:","o":["At the start of action potential","Just at the end of action potential","When the action potential is about to end","At peak of action potential"],"a":2,"e":"The heart is most vulnerable to fibrillation during the relative refractory period as the action potential is about to end (the vulnerable period on the T wave).<br><br>At the AP peak the tissue is absolutely refractory; vulnerability to fibrillation is maximal in the relative refractory period as the AP ends."},
/*535*/ {"q":"Ventricle pressure rises and volume remains same in which phase of cardiac cycle:","o":["Rapid ejection","Rapid ventricle filling","Atrial systole","Isovolumetric contraction"],"a":3,"e":"During isovolumetric contraction ventricular pressure rises sharply while volume stays constant with all valves closed.<br><br>Ejection changes volume; constant volume with rising pressure is isovolumetric contraction."},
/*536*/ {"q":"Information care session is for:","o":["Take informed consent for the procedure","Clear the myths and misconceptions of the patient and relatives about the disease","Tell the patient and family about new advances","Take information from the family"],"a":1,"e":"An information/care session aims to clarify misconceptions and educate the patient and relatives about the disease.<br><br>Informed consent and disclosure of advances are separate tasks; an information/care session aims to clear patient and family misconceptions."},
/*537*/ {"q":"An old patient with enlarged prostate and marked increase in PSA up to 20 ng/ml, weight loss, MRI shows bony metastasis; route of spread of prostate CA to vertebrae:","o":["Lumbar plexus","Pampiniform plexus","Vertebral venous plexus","Pelvic plexus"],"a":2,"e":"Prostate carcinoma metastasises to the vertebral column via the valveless Batson vertebral venous plexus.<br><br>Lymphatic spread reaches obturator nodes; vertebral metastasis from prostate occurs via the valveless Batson vertebral venous plexus."},
/*538*/ {"q":"Anatomically the largest zone of prostate:","o":["Lateral","Median","Peripheral","Central"],"a":2,"e":"The peripheral zone is the largest zone of the prostate and the commonest site of prostate carcinoma.<br><br>BPH involves the transition zone; the largest zone is the peripheral zone."},
/*539*/ {"q":"Membrane potential is maintained by which of the following:","o":["Na-K ATPase pump","Inward sodium","Outward potassium","Inward potassium"],"a":0,"e":"The resting membrane potential is maintained by the Na+/K+ ATPase pump establishing ionic gradients.<br><br>Ion fluxes alone do not sustain the gradient; the resting membrane potential is maintained by the Na-K ATPase pump."},
/*540*/ {"q":"Cancer most prevalent in males of Karachi is:","o":["Lung CA","Stomach CA","Liver CA","Oral cancer"],"a":3,"e":".<br><br>Lung and liver cancers are smoking/hepatitis-linked; the keyed commonest male cancer in Karachi here is oral cancer (betel/tobacco use)."},
/*541*/ {"q":"The most likely place in brain where major blood vessels are found is:","o":["Deep to pia matter","Extradural space","Subarachnoid space","Subdural space"],"a":2,"e":"The major cerebral blood vessels run in the subarachnoid space within the CSF.<br><br>The extradural and subdural spaces are potential spaces; the major cerebral vessels run in the CSF-filled subarachnoid space."},
/*542*/ {"q":"Bone scan is necessary for:","o":["Melanoma","Squamous cell carcinoma","Basal cell carcinoma","Retinoblastoma"],"a":3,"e":".<br><br>Melanoma and skin carcinomas rarely need bone scans; among these the bone scan is keyed to retinoblastoma for metastatic work-up."},
/*543*/ {"q":"Macrophages are formed by:","o":["Plasma cells","Histiocytes","Monocytes","Interferon"],"a":2,"e":"Tissue macrophages differentiate from circulating blood monocytes.<br><br>Histiocytes are the tissue form themselves; the precursor is the monocyte."},
/*544*/ {"q":"Common midline deformity is:","o":["Midline cleft lip","Cleft lip with nasal involvement","Micrognathia","Cleft palate"],"a":0,"e":"A midline cleft lip from failure of fusion of the two medial nasal processes is the typical midline facial deformity described here.<br><br>Failure of maxillary-to-medial-nasal fusion gives a lateral cleft; failure of the medial nasal processes to merge gives a midline cleft lip."},
/*545*/ {"q":"Deep structure in popliteal fossa:","o":["Popliteal artery","Popliteal vein","Tibial nerve","Common peroneal nerve"],"a":0,"e":"The popliteal artery is the deepest structure in the popliteal fossa, lying on the joint capsule and femur.<br><br>The tibial nerve is most superficial; the deepest is the popliteal artery."},
/*546*/ {"q":"An IV urograph of an 8-year-old child shows fusion of lower poles of kidney; which condition is most likely:","o":["Horseshoe kidney","Constricted ectopic kidney","Pelvic kidney","Non-rotating kidney"],"a":0,"e":"Fusion of the lower poles of both kidneys is the classic appearance of a horseshoe kidney.<br><br>An ectopic or pelvic kidney is malpositioned but unfused; fusion of both lower poles across the midline is a horseshoe kidney."},
/*547*/ {"q":"Ligament pierced at last during epidural is:","o":["Posterior spinal ligament","Anterior spinal ligament","Supraspinous ligament","Ligamentum flavum"],"a":3,"e":"During an epidural the needle pierces supraspinous and interspinous ligaments, then last the ligamentum flavum before reaching the epidural space.<br><br>The supraspinous and interspinous ligaments are pierced earlier; the last layer before the epidural space is the ligamentum flavum."},
/*548*/ {"q":"In an HIV patient surgery is done, then which antiseptic to use after surgery to clean floor:","o":["1% hypochlorite","4% hypochlorite","Glutaraldehyde","Soap & water"],"a":0,"e":"Floor and surface disinfection after surgery uses 1% hypochlorite; instruments use 2% glutaraldehyde.<br><br>Instruments need glutaraldehyde; floors and surfaces are disinfected with 1% hypochlorite, not soap and water alone."},
/*549*/ {"q":"A young male living in a populated town died in an RTA; on autopsy lung lymph nodes are found black in color; which condition is associated:","o":["Melatonin","Anthracosis","Bronchogenic carcinoma","Bronchial asthma"],"a":1,"e":"Black-pigmented lymph nodes from carbon (soot) deposition in a city dweller indicate anthracosis.<br><br>Bronchogenic carcinoma needs malignant cells; black carbon-laden lymph nodes from soot exposure indicate anthracosis."},
/*550*/ {"q":"A patient with subclavian steal syndrome; blood supply to which artery is causing this condition:","o":["Intercostal artery","Vertebral artery","Internal carotid artery","Facial artery"],"a":1,"e":"In subclavian steal syndrome, retrograde flow through the vertebral artery supplies the arm at the expense of the brain.<br><br>The internal carotid supplies the brain directly; subclavian steal is retrograde flow down the vertebral artery away from the brain."},
/*551*/ {"q":"In hypernatremia what will happen:","o":["Cell lysis","Degranulation of lysosomal enzymes","Cell shrinkage","Cell swelling"],"a":2,"e":"In hypernatraemia water shifts from the intracellular to extracellular compartment, causing cell shrinkage.<br><br>Hypernatraemia draws water out of cells (not in), causing cell shrinkage rather than swelling or lysis."},
/*552*/ {"q":"Which of the following lymphoid structure does not contain lymph nodules:","o":["Spleen","Lymph node","Thymus","Peyer patches"],"a":2,"e":"The thymus lacks lymphoid nodules (follicles); it has cortex and medulla with Hassall corpuscles.<br><br>Spleen, nodes and Peyer patches have follicles; the thymus does not."},
/*553*/ {"q":"Malignancy of a tumor is determined by which of the following:","o":["Pleomorphism","Metastasis","Decrease N/C ratio","Dysplasia"],"a":1,"e":"The defining feature of malignancy is the capacity to metastasise (and invade).<br><br>Pleomorphism and dysplasia suggest malignancy but the determining feature is metastasis."},
/*554*/ {"q":"A patient with chronic renal failure on dialysis; increase in which blood parameter is alarming:","o":["Calcium","Creatinine","Urea","Potassium"],"a":3,"e":"Hyperkalaemia is the most immediately life-threatening alarming derangement in renal failure, risking fatal arrhythmia.<br><br>Rising urea/creatinine track failure but are not acutely fatal; hyperkalaemia is the alarming change risking fatal arrhythmia."},
/*555*/ {"q":"Ectopic thyroid hormones are produced by:","o":["Squamous cell carcinoma of larynx","Carcinoid tumor","Squamous cell CA lungs","Adenocarcinoma of lungs"],"a":0,"e":".<br><br>Carcinoid and lung adenocarcinoma secrete other peptides; the keyed source of ectopic thyroid hormone here is laryngeal squamous carcinoma."},
/*556*/ {"q":"Common site of clavicle fracture is:","o":["Medial 1/3rd and lateral 2/3rd","Lateral 1/3rd and medial 2/3rd","Mid of clavicle","Upper clavicle"],"a":1,"e":"The clavicle most commonly fractures at the junction of the lateral one-third and medial two-thirds (the middle third).<br><br>The clavicle rarely breaks at its ends; the commonest fracture is at the junction of the lateral one-third and medial two-thirds."},
/*557*/ {"q":"During anesthesia which nerve is commonly injured in lower limb:","o":["Median nerve","Ulnar nerve","Common peroneal nerve","Sciatic nerve"],"a":2,"e":"The common peroneal nerve is the most commonly injured lower-limb nerve under anaesthesia from positioning compression at the fibular neck.<br><br>The ulnar nerve is the commonest overall, but in the lower limb under anaesthesia the common peroneal nerve is most often compressed at the fibular neck."},
/*558*/ {"q":"Herniation between C5-C6 nerves injured:","o":["C5","C6","C8","C2"],"a":1,"e":"A C5-C6 disc herniation compresses the C6 nerve root.<br><br>A C5-C6 disc compresses the exiting C6 root (cervical roots exit above the same-numbered pedicle), not C5 or C8."},
/*559*/ {"q":"Which one of the following is white muscle:","o":["Orbicularis","Soleus","Gastrocnemius","Masseter"],"a":2,"e":"Gastrocnemius is predominantly a fast-twitch (white) muscle, in contrast to the slow-twitch red soleus.<br><br>Soleus is slow-twitch red muscle; gastrocnemius is predominantly fast-twitch (white) for rapid propulsion."},
/*560*/ {"q":"Artery present at the base of renal pyramids:","o":["Arcuate","Lobar","Interlobar","Interlobular"],"a":0,"e":"The arcuate arteries arch over the base of the renal pyramids at the corticomedullary junction.<br><br>The interlobar arteries run between pyramids; at the pyramid base they form the arcuate arteries."},
/*561*/ {"q":"Which of the following is a foramen cecum derivative:","o":["Thyroid","Thymus","Anterior pituitary","Posterior pituitary"],"a":0,"e":"The thyroid gland descends from the foramen cecum of the tongue via the thyroglossal duct.<br><br>The thymus/pituitary arise elsewhere; the thyroid descends from the foramen cecum via the thyroglossal duct."},
/*562*/ {"q":"Albumin cannot cross basement membrane due to:","o":["Negative charge of the membrane","Greater size","Water solubility","Positive charge"],"a":0,"e":"The glomerular basement membrane has a negative charge that repels the negatively charged albumin, restricting its filtration.<br><br>Size alone would not exclude albumin; the negatively charged glomerular basement membrane repels the anionic albumin."},
/*563*/ {"q":"To prevent iatrogenic infections in ICU we should:","o":["Wear gloves","Use extensive hand washing after examining every patient","Sterilize used instruments","Wear mask"],"a":1,"e":"Extensive hand washing between patients is the single most effective measure to prevent iatrogenic infection.<br><br>Gloves and masks help, but hand washing between every patient is the single most effective measure against iatrogenic infection."},
/*564*/ {"q":"The commonest organism for hospital-acquired infection is:","o":["E. coli","Pseudomonas aeruginosa","Staph aureus","Citrobacter species"],"a":2,"e":".<br><br>E. coli and Pseudomonas cause specific HAIs, but overall the commonest hospital-acquired infection organism keyed here is Staph aureus."},
/*565*/ {"q":"In intrinsic damage, which factor causes activation of coagulation:","o":["Factor 8","Factor 12 (Hageman factor)","Factor 9","Factor 5"],"a":1,"e":"The intrinsic pathway is initiated by factor XII (Hageman factor) on contact with collagen.<br><br>The extrinsic pathway uses thromboplastin; the intrinsic contact factor is factor XII."},
/*566*/ {"q":"Most common cause of inherited intellectual disability:","o":["Down syndrome","Fragile X syndrome","Edward syndrome","Patau syndrome"],"a":1,"e":"Fragile X syndrome is the commonest inherited cause of intellectual disability; Down syndrome is the commonest genetic cause overall.<br><br>Down syndrome is the commonest genetic cause overall; the commonest inherited (transmitted) cause of intellectual disability is Fragile X."},
/*567*/ {"q":"An 18-year-old male in altered sensorium, slow shallow breaths, fruity breath, ABG pH 7.20, urine ketones positive; most probable diagnosis:","o":["HONK","DKA","Septic shock","HELLP syndrome"],"a":1,"e":"A fruity breath with ketonuria and metabolic acidosis in a young patient indicates diabetic ketoacidosis.<br><br>HONK lacks significant ketosis; the keyed diagnosis is DKA."},
/*568*/ {"q":"Patient with rhinosinusitis and nasal polyp with fungus invading lamina papyracea, excessive endothelial damage and non-septate hyphae; organism involved is:","o":["Candida","Histoplasmosis","Aspergillus","Mucor"],"a":3,"e":".<br><br>Aspergillus has septate hyphae branching at acute angles; broad non-septate hyphae with vascular invasion indicate Mucor."},
/*569*/ {"q":"Equal chance of each person being selected in a study is:","o":["Random sampling","Stratified sampling","Mixed sampling","Random population"],"a":0,"e":"Simple random sampling gives every individual an equal chance of being selected.<br><br>Stratified sampling samples within subgroups; equal chance for all is random sampling."},
/*570*/ {"q":"Lymphatic drainage of external nose and anterior part of nasal cavity:","o":["Submandibular lymph nodes","Deep cervical lymph nodes","Retropharyngeal lymph nodes","Occipital lymph nodes"],"a":0,"e":"The external nose and anterior nasal cavity drain to the submandibular lymph nodes.<br><br>The posterior nasal cavity drains to retropharyngeal nodes; the anterior part drains to submandibular nodes."},
/*571*/ {"q":"Which structure acts as conduit between peritoneal cavity and uterus:","o":["Birth canal","Cervix","Fallopian tube in female","Ovaries"],"a":2,"e":"The fallopian tube opens into the peritoneal cavity at its fimbriated end and into the uterus, forming the conduit between them.<br><br>The cervix connects to the vagina; the peritoneal-uterine conduit is the fallopian tube."},
/*572*/ {"q":"A child with history of pica, pallor and fatigue diagnosed as iron deficiency anemia; what should be given:","o":["B12","B6","Iron supplement","Folate"],"a":2,"e":"Iron deficiency anaemia is treated with iron supplementation to replenish stores.<br><br>B12 and folate treat megaloblastic anaemia; iron deficiency requires iron supplements."},
/*573*/ {"q":"A 65-year-old man with fatigue, pallor and weight loss; golden-yellow pigment in liver that turns blue on staining is:","o":["Hemosiderin","Lipofuscin","Hemoglobin","Hemochromatosis"],"a":1,"e":".<br><br>Haemosiderin stains Prussian-blue positive; the golden-yellow wear-and-tear pigment that does not is lipofuscin."},
/*574*/ {"q":"Person had traumatic incident of upper limb 3 months ago, pain and tenderness, swelling developed, X-ray swelling bright after one year then resolved; phenomenon is:","o":["Hypertrophy","Hyperplasia","Metaplasia","Dystrophic calcification"],"a":3,"e":"Calcification within damaged soft tissue with normal serum calcium (myositis ossificans) is dystrophic calcification.<br><br>Hyperplasia/metaplasia are cellular adaptations; calcification in damaged tissue with normal serum calcium is dystrophic calcification (myositis ossificans)."},
/*575*/ {"q":"A 45-year-old man with long history of alcoholism, severe epigastric pain radiating to back, nausea, vomiting, fever and raised serum amylase; diagnosis:","o":["Pancreatic CA","Gall bladder CA","Biliary stone","Acute pancreatitis"],"a":3,"e":"Severe epigastric pain radiating to the back with raised serum amylase in an alcoholic indicates acute pancreatitis.<br><br>Pancreatic/biliary cancers are insidious; acute epigastric pain to the back with raised amylase in an alcoholic is acute pancreatitis."},
/*576*/ {"q":"Type of necrosis in pancreatitis:","o":["Fat necrosis","Coagulative necrosis","Caseous necrosis","Liquefactive necrosis"],"a":0,"e":"Acute pancreatitis produces fat necrosis from lipase digestion of peripancreatic adipose tissue with calcium soap formation.<br><br>Coagulative necrosis is ischaemic; pancreatitis causes fat necrosis."},
/*577*/ {"q":"Muscle from vertebral border of scapula which attaches it to anterior chest wall is which of the following:","o":["Quadratus lumborum","Latissimus dorsi","Rhomboid major","Serratus anterior"],"a":3,"e":"Serratus anterior runs from the medial (vertebral) border of the scapula to the anterolateral chest wall, holding the scapula against it.<br><br>The rhomboids retract the scapula; the chest-wall apposition muscle is serratus anterior."},
/*578*/ {"q":"Sciatic nerve root value is:","o":["L2-4","L4-S3","S2-4","L5-S2"],"a":1,"e":"The sciatic nerve arises from the lumbosacral plexus, root values L4 to S3.<br><br>L2-4 is the femoral nerve and S2-4 the pudendal; the sciatic nerve arises from roots L4-S3."},
/*579*/ {"q":"Iliolumbar artery is a branch of which of the following:","o":["Femoral artery","Tibial artery","Internal iliac artery","Abdominal aorta"],"a":2,"e":"The iliolumbar artery is a branch of the posterior division of the internal iliac artery.<br><br>The iliolumbar artery springs from the posterior division of the internal iliac artery, not directly from the aorta or femoral artery."},
/*580*/ {"q":"Bone mineralization is done by:","o":["Vit. C","Vit. D","PTH","None"],"a":1,"e":"Vitamin D promotes calcium and phosphate absorption, enabling bone mineralization.<br><br>PTH causes demineralization (resorption); mineralization is by vitamin D."},
/*581*/ {"q":"Which finding will be found in a person having bradycardia and hypertension:","o":["Hypotension","Tachycardia","Malignancy","Raised ICP"],"a":3,"e":"Bradycardia with hypertension (and irregular respiration) is the Cushing triad, indicating raised intracranial pressure.<br><br>Hypotension/tachycardia indicate shock; bradycardia with hypertension (Cushing reflex) signals raised intracranial pressure."},
/*582*/ {"q":"A male diagnosed with colon cancer through CEA; doctor does CEA for what:","o":["For site of malignancy","Size of malignancy","To see metastasis","For follow up of malignancy"],"a":3,"e":"CEA is used for monitoring and follow-up (detecting recurrence) of colorectal carcinoma, not for primary diagnosis.<br><br>CEA does not localise or size tumours; it is used to monitor for recurrence in follow-up of colorectal carcinoma."},
/*583*/ {"q":"A man with RTA on ventilator, PEEP increased to max, still died; autopsy shows macrophages and hyaline membrane; what led to death:","o":["Chronic bronchitis","Viral pneumonia","Bronchopneumonia","Diffuse alveolar damage"],"a":3,"e":"Hyaline membranes with macrophages on autopsy indicate diffuse alveolar damage (ARDS).<br><br>Bronchopneumonia is patchy infective; hyaline membranes with macrophages in a ventilated shock patient indicate diffuse alveolar damage (ARDS)."},
/*584*/ {"q":"Supraoptic nucleus releases which of these:","o":["ADH","ACTH","Oxytocin","Aldosterone"],"a":0,"e":"The supraoptic nucleus of the hypothalamus synthesises antidiuretic hormone (ADH/vasopressin).<br><br>Oxytocin is mainly paraventricular; the supraoptic nucleus produces ADH."},
/*585*/ {"q":"A female with postpartum hemorrhage during delivery of twins, then cannot lactate, no desire to lactate, remains lethargic 6 months after delivery; the problem is:","o":["Pituitary adenoma","Sheehan syndrome","Simmond syndrome","Prolactinoma"],"a":1,"e":"Postpartum pituitary necrosis from obstetric haemorrhage causing failure of lactation and hypopituitarism is Sheehan syndrome.<br><br>A prolactinoma causes galactorrhoea; postpartum-haemorrhage-induced pituitary necrosis with failed lactation is Sheehan syndrome."},
/*586*/ {"q":"Alpha adrenergic stimulation causes:","o":["Cardiac stimulation","Bronchodilation","Pupillary dilation","Vasodilation"],"a":2,"e":"Alpha-1 adrenergic stimulation contracts the radial muscle of the iris, causing pupillary dilation (mydriasis) and vasoconstriction.<br><br>Beta effects cause cardiac stimulation/bronchodilation; the alpha effect is pupillary dilation."},
/*587*/ {"q":"Test which excludes completely a non-affected person is:","o":["Sensitivity","Specificity","Prevalence","Incidence"],"a":1,"e":"A highly specific test correctly rules out disease in non-affected persons (true negatives).<br><br>Sensitivity rules in disease; specificity excludes non-affected individuals."},
/*588*/ {"q":"Detached embolus from deep veins of leg will lodge in:","o":["Inferior vena cava","Lung","Heart","Femoral veins"],"a":1,"e":"An embolus from deep leg veins travels through the right heart and lodges in the pulmonary arteries (lung), causing pulmonary embolism.<br><br>A leg-vein embolus passes the IVC and right heart to lodge in the pulmonary arteries (lung), causing pulmonary embolism."},
/*589*/ {"q":"Most common organism causing community-acquired pneumonia:","o":["Streptococcus pneumoniae","Mycoplasma","Haemophilus","Legionella"],"a":0,"e":"Streptococcus pneumoniae is the commonest cause of community-acquired pneumonia.<br><br>Atypicals and Haemophilus are less frequent; the leading cause is pneumococcus."},
/*590*/ {"q":"Most common cause of upper GI bleeding:","o":["Peptic ulcer disease","Esophageal varices","Mallory-Weiss tear","Gastritis"],"a":0,"e":"Peptic ulcer disease is the commonest cause of upper gastrointestinal bleeding.<br><br>Varices and Mallory-Weiss tears are less frequent; the leading cause is peptic ulcer."},
/*591*/ {"q":"Krukenberg tumor is metastasis to ovary from:","o":["Stomach","Lung","Breast","Kidney"],"a":0,"e":"A Krukenberg tumour is a metastatic ovarian deposit, classically from a gastric signet-ring carcinoma.<br><br>Other primaries are less typical; the classic Krukenberg primary is the stomach."},
/*592*/ {"q":"Most common primary liver malignancy:","o":["Hepatocellular carcinoma","Cholangiocarcinoma","Angiosarcoma","Hepatoblastoma"],"a":0,"e":"Hepatocellular carcinoma is the commonest primary malignant tumour of the liver, often on a background of cirrhosis.<br><br>Cholangiocarcinoma is less common; the commonest primary liver cancer is HCC."},
/*593*/ {"q":"Most common cause of small bowel obstruction in adults:","o":["Adhesions","Hernia","Tumor","Intussusception"],"a":0,"e":"Postoperative adhesions are the commonest cause of small bowel obstruction in adults.<br><br>Hernias and tumours are less frequent; the leading cause is adhesions."},
/*594*/ {"q":"Apple-core lesion on barium enema suggests:","o":["Colorectal carcinoma","Diverticulitis","Ulcerative colitis","Crohn disease"],"a":0,"e":"An annular apple-core stricture on barium enema is characteristic of a constricting colorectal carcinoma.<br><br>Inflammatory diseases give different patterns; the apple-core lesion indicates colorectal carcinoma."},
/*595*/ {"q":"Skip lesions and transmural inflammation are characteristic of:","o":["Crohn disease","Ulcerative colitis","Ischemic colitis","Pseudomembranous colitis"],"a":0,"e":"Crohn disease shows discontinuous skip lesions with transmural granulomatous inflammation.<br><br>Ulcerative colitis is continuous and mucosal; skip lesions with transmural inflammation indicate Crohn."},
/*596*/ {"q":"Most common benign tumor of the uterus:","o":["Leiomyoma (fibroid)","Endometrial polyp","Adenomyoma","Leiomyosarcoma"],"a":0,"e":"Leiomyoma (fibroid) is the commonest benign uterine tumour and the commonest tumour in women overall.<br><br>Leiomyosarcoma is malignant and rare; the commonest benign uterine tumour is leiomyoma."},
/*597*/ {"q":"Most common location of ectopic pregnancy:","o":["Ampulla of fallopian tube","Ovary","Cervix","Abdomen"],"a":0,"e":"The ampulla of the fallopian tube is the commonest site of ectopic pregnancy.<br><br>Ovarian and abdominal ectopics are rare; the commonest site is the tubal ampulla."},
/*598*/ {"q":"Most common breast malignancy:","o":["Invasive ductal carcinoma","Invasive lobular carcinoma","Medullary carcinoma","Mucinous carcinoma"],"a":0,"e":"Invasive ductal carcinoma (no special type) is the commonest histological type of breast cancer.<br><br>Lobular and special types are less frequent; the commonest is invasive ductal carcinoma."},
/*599*/ {"q":"Most common cause of acute appendicitis:","o":["Fecolith obstruction","Lymphoid hyperplasia","Tumor","Parasite"],"a":0,"e":"Luminal obstruction by a faecolith is the commonest cause of acute appendicitis in adults; lymphoid hyperplasia predominates in children.<br><br>Lymphoid hyperplasia predominates in children; in adults the commonest cause of appendiceal obstruction is a faecolith."},
/*600*/ {"q":"Courvoisier law: palpable non-tender gallbladder with jaundice suggests:","o":["Carcinoma of head of pancreas","Gallstones","Cirrhosis","Hepatitis"],"a":0,"e":"A palpable, non-tender, distended gallbladder with jaundice is unlikely to be stones and suggests malignant biliary obstruction such as pancreatic head carcinoma.<br><br>Stone disease scars the gallbladder; the painless palpable gallbladder indicates pancreatic head cancer."},
/*601*/ {"q":"A patient has liver cirrhosis; route of hepatic biopsy is:","o":["T10 midaxillary line","T11 mid clavicular line","Subcostal angle","Substernal angle"],"a":0,"e":"A percutaneous liver biopsy is performed in the right mid-axillary line at about the T10 intercostal level.<br><br>A subcostal/substernal approach risks other organs; percutaneous liver biopsy is done in the right mid-axillary line around T10."},
/*602*/ {"q":"A patient had laparotomy with 12 cm incision; when will complete tensile strength be returned:","o":["1 week","3 weeks","3 months","6 months"],"a":2,"e":"A surgical wound regains most of its tensile strength by about 3 months, reaching roughly 70-80% of original strength.<br><br>A wound is weak at 1-3 weeks; it regains most of its tensile strength (about 70-80%) by roughly 3 months."},
/*603*/ {"q":"Intention tremors occur due to:","o":["Midbrain lesion","Cerebellum lesion","Hyperthyroidism","Anxiety"],"a":1,"e":"Intention (kinetic) tremor that worsens on approaching a target is characteristic of a cerebellar lesion.<br><br>Resting tremor is parkinsonian (midbrain); intention tremor is cerebellar."},
/*604*/ {"q":"Patient can stand with open eyes and has ataxia when asked to walk with closed eyes, sways back and forth; where is the lesion:","o":["Dorsal column","Cerebellum","Spinothalamic tract","Corticospinal tract"],"a":0,"e":"A positive Romberg sign (ataxia with eyes closed but stable with eyes open) indicates a dorsal column proprioceptive lesion.<br><br>Cerebellar ataxia is present even with eyes open; eyes-closed worsening is a dorsal column lesion."},
/*605*/ {"q":"A woman has loss of 2-point discrimination and fine touch in right leg; which is defective:","o":["Fasciculus gracilis","Dorsal column","Fasciculus cuneatus","Spinothalamic"],"a":0,"e":"Loss of fine touch and two-point discrimination in the leg indicates fasciculus gracilis (lower limb dorsal column) dysfunction.<br><br>Fasciculus cuneatus carries the upper limb; the leg fibres are in fasciculus gracilis."},
/*606*/ {"q":"In amyotrophic lateral sclerosis, which part of spinal cord is affected:","o":["Ventral horn","Dorsal horn","Dorsal root","Ventral spinocerebellar"],"a":0,"e":"ALS degenerates the anterior (ventral) horn motor neurons along with corticospinal tracts.<br><br>The dorsal horn is sensory; ALS affects the ventral horn motor neurons."},
/*607*/ {"q":"Male had RTA with injury to occipital region, now has homonymous hemianopia; which structure is damaged:","o":["Optic chiasm","Optic tract","Visual area","Lateral geniculate body"],"a":2,"e":"An occipital injury damages the primary visual cortex, producing a contralateral homonymous hemianopia.<br><br>The optic chiasm/tract give field defects with other features; an occipital (visual cortex) injury causes contralateral homonymous hemianopia."},
/*608*/ {"q":"The ascent of horseshoe-shaped kidney is prevented by:","o":["External iliac artery","Internal iliac artery","Superior mesenteric artery","Inferior mesenteric artery"],"a":3,"e":"A horseshoe kidney is arrested in ascent by the inferior mesenteric artery hooking the fused lower poles.<br><br>The SMA and celiac arteries are higher; the inferior mesenteric artery hooks and arrests the ascending horseshoe kidney."},
/*609*/ {"q":"Regarding pia mater, true is:","o":["Extends into sulci and fissures of brain tissue","Extends into the posterior median sulcus of spinal cord","Has openings at the medial/lateral ends of ventricles","Extends into the ventricles"],"a":0,"e":"The pia mater is the innermost meninx that closely invests the brain, dipping into all its sulci and fissures.<br><br>Arachnoid bridges the sulci; the pia closely invests the brain, dipping into all its sulci and fissures."},
/*610*/ {"q":"The process of apoptosis is lost during carcinogenic activity; the following factor has antiapoptotic activity:","o":["BCL2","BCL1","BAX","PKL"],"a":0,"e":"BCL2 is an anti-apoptotic protein; its overexpression prevents apoptosis and promotes carcinogenesis.<br><br>BAX and BAK are pro-apoptotic; the anti-apoptotic factor is BCL2 (Robbins)."},
/*611*/ {"q":"Mean is defined as:","o":["Sum of all observation","Sum of variance","Square root of variance","Sum of all observation divided by total number of observations"],"a":3,"e":"The mean is the sum of all observations divided by the total number of observations.<br><br>It is not a sum or variance term; the mean is the sum of observations divided by the number of observations."},
/*612*/ {"q":"Mechanism of action of steroid hormones:","o":["Increase cell membrane permeability","Act on DNA","cAMP","Adenylate cyclase"],"a":1,"e":"Steroid hormones are lipophilic and act on intracellular receptors that bind DNA to modulate gene transcription.<br><br>cAMP is a peptide-hormone second messenger; steroids act directly on DNA."},
/*613*/ {"q":"In which condition is there hyponatremia:","o":["Increase aldosterone","Increase cortisol","Increase ADH","Water loss from body"],"a":2,"e":"Increased ADH (as in SIADH) causes water retention and dilutional hyponatraemia.<br><br>Aldosterone retains sodium; hyponatraemia occurs with raised ADH."},
/*614*/ {"q":"Superior pole of thyroid is ligated; artery supplying this originates from:","o":["External carotid artery","Thyrocervical trunk","Subclavian artery","Internal carotid artery"],"a":0,"e":"The superior thyroid artery, supplying the superior thyroid pole, arises from the external carotid artery.<br><br>The inferior thyroid is from the thyrocervical trunk; the superior is from the external carotid."},
/*615*/ {"q":"Origin of inferior vena cava is at which level:","o":["L5","L3","L1","T5"],"a":0,"e":"The inferior vena cava is formed by the union of the common iliac veins at the L5 vertebral level.<br><br>T5 and L1 are too high; the IVC is formed by union of the common iliac veins at the L5 level."},
/*616*/ {"q":"Four lumbar arteries arise from which of the following:","o":["Internal iliac","External iliac","SMA","Aorta"],"a":3,"e":"The four pairs of lumbar arteries arise directly from the posterior aspect of the abdominal aorta.<br><br>The internal/external iliac supply the pelvis; the four pairs of lumbar arteries arise directly from the posterior abdominal aorta."},
/*617*/ {"q":"Pulsating abdominal aortic aneurysm most common site:","o":["T12-L2","S2-4","S1-3","S4-5"],"a":0,"e":"Abdominal aortic aneurysms most commonly occur infrarenally, around the L2-L4 (T12-L2 region) level.<br><br>Sacral levels are too low; abdominal aortic aneurysms occur infrarenally around the T12-L2/L2-L4 region."},
/*618*/ {"q":"After damage to lateral thoracic wall, elevation of lower angle of scapula, patient's hand cannot reach forward; nerve damaged is:","o":["Accessory nerve","Axillary nerve","Long thoracic nerve","Thoracodorsal nerve"],"a":2,"e":"Long thoracic nerve injury paralyses serratus anterior, causing winging of the scapula and inability to push or reach forward.<br><br>Axillary/accessory nerve lesions cause other deficits; serratus anterior palsy (winged scapula, cannot reach forward) is long thoracic nerve injury."},
/*619*/ {"q":"CSF examination is necessary to rule out:","o":["Retinoblastoma/melanoma of eye","Fever","Leukemia","Nausea"],"a":0,"e":"CSF cytology is examined to rule out CNS/leptomeningeal spread of ocular tumours such as retinoblastoma and melanoma.<br><br>Fever or nausea need no CSF study; CSF cytology is examined to exclude CNS spread of ocular tumours (retinoblastoma/melanoma)."},
/*620*/ {"q":"A potent antioxidant is:","o":["Vitamin A","Vitamin C","Vitamin E","Glutathione"],"a":3,"e":"Glutathione is a major intracellular antioxidant, neutralising reactive oxygen species.<br><br>Vitamins A, C and E are antioxidants too, but the principal intracellular reducing antioxidant keyed here is glutathione."},
/*621*/ {"q":"Regarding vitamin E, true is:","o":["Antioxidant","Help in wound healing","Cofactor","Increase bleeding"],"a":0,"e":"Vitamin E is a lipid-soluble antioxidant protecting cell membranes from oxidative damage.<br><br>Vitamin K aids clotting and others wound healing; the defining property of vitamin E is being a lipid-soluble antioxidant."},
/*622*/ {"q":"Relation of splenic artery, what is true:","o":["Inferior to pancreas","Run along upper border of body of pancreas and tail","Parallel to spleen","Run at upper border of gall bladder"],"a":1,"e":"The splenic artery runs a tortuous course along the upper border of the body and tail of the pancreas.<br><br>The splenic artery is not inferior to or parallel to the spleen; it runs tortuously along the upper border of the pancreatic body and tail."},
/*623*/ {"q":"CA of tail of pancreas resected, damaged in which ligament occur:","o":["Gastrohepatic","Gastrosplenic","Falciform","Lienorenal"],"a":3,"e":"The tail of the pancreas lies within the lienorenal (splenorenal) ligament with the splenic vessels.<br><br>The gastrosplenic ligament holds the short gastrics; the pancreatic tail and splenic vessels lie within the lienorenal ligament."},
/*624*/ {"q":"Artery arising directly from the celiac trunk:","o":["Common hepatic artery","Hepatic artery proper","Gastroduodenal","Superior pancreaticoduodenal"],"a":0,"e":"The common hepatic artery is one of the three direct branches of the celiac trunk (with the splenic and left gastric).<br><br>The hepatic artery proper is a continuation; the celiac branch is the common hepatic artery."},
/*625*/ {"q":"True hermaphrodite is:","o":["XYY","XX","XY","XXY"],"a":1,"e":"True hermaphroditism is most commonly associated with a 46,XX karyotype.<br><br>Klinefelter (XXY) and XYY are not true hermaphrodites; true hermaphroditism is most commonly a 46,XX karyotype."},
/*626*/ {"q":"Local lymphatic obstruction is caused by combination of which two:","o":["Infection and neoplasia","Renal failure and hypoproteinemia","Hematuria and albuminuria","Trauma and infection"],"a":0,"e":".<br><br>Hypoproteinaemia/haematuria cause generalised oedema; localised lymphatic obstruction results from combined infection and neoplasia."},
/*627*/ {"q":"Derivative of 3rd pharyngeal arch is:","o":["Stylopharyngeus","Stapedius","Maxillary","Facial"],"a":0,"e":"The stylopharyngeus muscle (and glossopharyngeal nerve) is the derivative of the third pharyngeal arch.<br><br>Stapedius is second arch; the third arch derivative is stylopharyngeus."},
/*628*/ {"q":"Which structure forms pelvic diaphragm:","o":["Puborectalis muscle","Pubococcygeus muscle","Rectococcygeus muscle","Anococcygeus muscle"],"a":1,"e":"The pelvic diaphragm is formed mainly by levator ani, of which pubococcygeus is the largest part.<br><br>Puborectalis is one sling component; the bulk of the pelvic-diaphragm levator ani is formed by pubococcygeus."},
/*629*/ {"q":"Left cleft palate due to malformation of:","o":["Palatine selves","Maxillary prominence","Medial nasal prominence","Lateral nasal prominence"],"a":0,"e":"Cleft palate results from failure of fusion of the palatine shelves (processes).<br><br>Cleft lip arises from nasal-process failure; cleft palate results from failure of fusion of the palatine shelves."},
/*630*/ {"q":"Pain of ovary referred to medial thigh by which nerve:","o":["Femoral nerve","Pudendal","Perineal","Obturator"],"a":3,"e":"Ovarian pain is referred to the medial thigh via the obturator nerve, which shares dermatomal innervation.<br><br>Femoral/pudendal nerves serve other regions; ovarian pain refers to the medial thigh via the obturator nerve."},
/*631*/ {"q":"Pure phrenic innervation to which part of pleura:","o":["Diaphragmatic pleura","Mediastinal pleura","Costal pleura","Whole diaphragm"],"a":1,"e":"The mediastinal pleura (and central diaphragmatic pleura) is supplied purely by the phrenic nerve.<br><br>Costal pleura is intercostal-supplied; the mediastinal (and central diaphragmatic) pleura is purely phrenic-innervated."},
/*632*/ {"q":"Patient presents with pain in lumbar region, stone at pelvi-ureteric junction; pain arises from which segment:","o":["T11-L1","L1-L4","T12-L2","L5"],"a":2,"e":".<br><br>Lower ureteric stones map to L1-L2; pelvi-ureteric junction colic refers to the T12-L2 segments (loin to groin)."},
/*633*/ {"q":"Pain of indirect inguinal hernia is due to compression of which nerve in inguinal canal:","o":["Iliohypogastric","Ilioinguinal","Femoral","Obturator"],"a":1,"e":"An indirect inguinal hernia compresses the ilioinguinal nerve traversing the inguinal canal.<br><br>The iliohypogastric supplies skin above; an indirect inguinal hernia compresses the ilioinguinal nerve in the canal."},
/*634*/ {"q":"A young male had RTA with femur fracture, died 5 days later, autopsy showed cerebral petechiae; diagnosis:","o":["Sepsis","Fat embolism","Pulmonary embolism","Myocardial dysfunction"],"a":1,"e":"Death days after a long-bone fracture with cerebral petechiae is characteristic of fat embolism syndrome.<br><br>Pulmonary thromboembolism is sudden; death days after a femoral fracture with cerebral petechiae is fat embolism syndrome."},
/*635*/ {"q":"Pregnant lady with labor pain and obstructed labour was taken to hospital but died before reaching; most likely cause:","o":["Pulmonary embolism","Amniotic fluid embolism","Fat embolism","MI"],"a":1,"e":"Sudden death during or shortly after labour is characteristic of amniotic fluid embolism.<br><br>Pulmonary/fat embolism are less abrupt; sudden collapse during obstructed labour is amniotic fluid embolism."},
/*636*/ {"q":"Muscle in the greater sciatic foramen:","o":["Obturator internus","Obturator externus","Piriformis","Gemellus superior"],"a":2,"e":"The piriformis muscle passes through the greater sciatic foramen, dividing it into supra- and infrapiriform parts.<br><br>Obturator internus exits the lesser sciatic foramen; the greater foramen muscle is piriformis."},
/*637*/ {"q":"Patient had RTA and fracture of ilium and sacrum; which structure is likely damaged in pelvis:","o":["Urethra","Rectum","Ureter","Urinary bladder"],"a":3,"e":".<br><br>The ureter and rectum are relatively protected; an ilium-and-sacrum pelvic fracture most often ruptures the urinary bladder."},
/*638*/ {"q":"A boxer got a blow and mandibular fracture just before the mandibular foramen; what will cause:","o":["Loss of taste to anterior 2/3 of tongue","Mylohyoid muscle unable to stabilize mandible","Loss of sensation over lower teeth","Loss of sensation over upper teeth"],"a":2,"e":"A fracture at the mandibular foramen injures the inferior alveolar nerve, causing loss of sensation to the lower teeth and chin.<br><br>The lingual nerve carries anterior tongue taste; a fracture at the mandibular foramen injures the inferior alveolar nerve, numbing the lower teeth."},
/*639*/ {"q":"Patient presents with chest pain, symptoms reversed with streptokinase; after myocardial injury what biochemical change is seen in hypoxia:","o":["Aerobic glycolysis","Oxidative phosphorylation","Anaerobic glycolysis","Gluconeogenesis"],"a":2,"e":"Myocardial hypoxia/ischaemia shifts metabolism to anaerobic glycolysis with lactate accumulation.<br><br>Ischaemic myocardium cannot do oxidative phosphorylation; it shifts to anaerobic glycolysis with lactate accumulation."},
/*640*/ {"q":"The cutaneous branches of cervical plexus is:","o":["Phrenic and lesser occipital","Greater occipital and suprascapular","Greater auricular and lesser occipital","Ansa cervicalis and supraclavicular"],"a":2,"e":"The cutaneous (sensory) branches of the cervical plexus include the lesser occipital and great auricular nerves.<br><br>The phrenic is motor; the cutaneous branches are great auricular and lesser occipital."},
/*641*/ {"q":"A patient with severe headache, vomiting and neck stiffness, raised ICP, lumbar puncture shows blood-stained CSF; diagnose:","o":["Subdural hemorrhage","Cerebral hemorrhage","Extradural hematoma","Subarachnoid hemorrhage"],"a":3,"e":"Severe headache with meningism and uniformly blood-stained CSF on lumbar puncture indicates subarachnoid haemorrhage.<br><br>Subdural/extradural bleeds are not uniformly bloody on tap; meningism with uniformly blood-stained CSF indicates subarachnoid haemorrhage."},
/*642*/ {"q":"Drug given in 70-year-old female with influenza is:","o":["Acyclovir","Valacyclovir","Ciprofloxacin","Ofloxacin"],"a":0,"e":".<br><br>Quinolones are antibacterial; the keyed antiviral choice for influenza here is acyclovir (oseltamivir not listed)."},
/*643*/ {"q":"Niacin deficiency causes which of the following affect:","o":["PNS defects","CNS defects","Epithelial defects","Limb defects"],"a":1,"e":"Niacin deficiency (pellagra) causes the three Ds including dementia, a central nervous system effect.<br><br>Niacin deficiency (pellagra) gives the three Ds; the neuropsychiatric (dementia) effect is a CNS manifestation."},
/*644*/ {"q":"Test sensitive to asthma is:","o":["TSH","FVC","TLC","FEV1/FVC"],"a":3,"e":"The FEV1/FVC ratio is the sensitive spirometric measure of airflow obstruction in asthma.<br><br>TLC and FVC are volumes; the FEV1/FVC ratio is the sensitive spirometric marker of the airflow obstruction in asthma."},
/*645*/ {"q":"A group of mice was injected with plastic hydrocarbon which works as initiator; the initiator works as:","o":["Slow process will take time","Memory produce","It is last step in carcinogenesis","Cause clonal proliferation"],"a":3,"e":".<br><br>An initiator is the first, irreversible mutational step that, with promotion, drives clonal proliferation of the mutated cell."},
/*646*/ {"q":"Which of the following is causative agent of CA cervix:","o":["HPV 16","CMV","EBV","HHV 8"],"a":0,"e":"High-risk HPV, especially type 16, is the principal causative agent of cervical carcinoma.<br><br>CMV/EBV/HHV-8 cause other tumours; high-risk HPV (type 16) is the principal cause of cervical carcinoma."},
/*647*/ {"q":"DNA is often damaged causing carcinogenesis; which of following is a DNA repair gene:","o":["P53","Rb1","APC","KRAS"],"a":0,"e":"P53 guards genomic integrity and triggers repair or apoptosis after DNA damage, acting as a key tumour suppressor.<br><br>Rb1, APC and KRAS are growth-control genes; p53 is the guardian DNA-damage-response/repair tumour suppressor."},
/*648*/ {"q":"4-month-old child, 70% of body weight, fatty liver, depigmentation, edema; diagnosis is:","o":["Addison disease","Kwashiorkor","Marasmus","Hypothyroidism"],"a":1,"e":"Oedema, fatty liver and skin depigmentation in a child indicate kwashiorkor (protein-energy malnutrition).<br><br>Marasmus lacks oedema; the oedematous malnutrition is kwashiorkor."},
/*649*/ {"q":"Raised IgE levels in hypersensitivity is which type:","o":["Type 4","Type 2","Type 3","Type 1"],"a":3,"e":"Type I (immediate) hypersensitivity is mediated by IgE antibodies on mast cells.<br><br>Type II/III are antibody/immune-complex mediated; IgE-mediated immediate reactions are type I hypersensitivity."},
/*650*/ {"q":"In allergic reaction, histamine released from which cell:","o":["Lymphocytes","Mast cells","Plasma cells","Neutrophils"],"a":1,"e":"Histamine is released from mast cells (and basophils) on IgE crosslinking in allergic reactions.<br><br>Lymphocytes/plasma cells make antibody; histamine in allergy is released from mast cells (and basophils)."},
/*651*/ {"q":"Immunoglobulin formed by which of following:","o":["B cells","M cells","Plasma cells","Macrophages"],"a":2,"e":"Antibodies are synthesised and secreted by plasma cells, the terminally differentiated B lymphocytes.<br><br>B cells are precursors; the immunoglobulin-producing cell is the plasma cell."},
/*652*/ {"q":"In transverse cut section which structure is not visible at T11 but visible at T12 behind the stomach:","o":["Gall bladder","Spleen","Aorta","IVC"],"a":1,"e":".<br><br>The aorta/IVC are visible at both levels; the spleen comes into the section behind the stomach at T12 but not T11."},
/*653*/ {"q":"Most abundant cells in gray matter of CNS are:","o":["Microglia","Fibrous astrocytes","Oligodendrocytes","Protoplasmic astrocytes"],"a":3,"e":"Protoplasmic astrocytes are the most abundant glial cells in the gray matter; fibrous astrocytes predominate in white matter.<br><br>Fibrous astrocytes dominate white matter; protoplasmic astrocytes are the most abundant glia in grey matter."},
/*654*/ {"q":"Site of impaction of ureteric stone:","o":["Nearest to kidney","Opening of ureter into bladder","At crossing of common iliac vessels","Pelvic brim"],"a":1,"e":"In adults the commonest site of ureteric stone impaction is the vesicoureteric junction (opening into the bladder).<br><br>The pelvic brim and iliac crossing are narrow points, but the commonest impaction site is the vesicoureteric junction."},
/*655*/ {"q":"Primary active transport uses which of following:","o":["Carrier","Downhill","Pump","Energy"],"a":2,"e":"Primary active transport uses a pump (ATPase) that directly hydrolyses ATP to move ions against their gradient.<br><br>A simple carrier moves substances down-gradient; primary active transport uses an ATP-driven pump against the gradient."},
/*656*/ {"q":"A child with proteinuria and edema responsive to steroids; cause of edema is:","o":["Increase hydrostatic pressure","Increase plasma volume","Low plasma oncotic pressure","Low plasma filtration"],"a":2,"e":"Nephrotic oedema results from urinary protein loss lowering plasma oncotic (colloid osmotic) pressure.<br><br>Hydrostatic causes are not primary here; urinary protein loss lowers plasma oncotic pressure, causing nephrotic oedema."},
/*657*/ {"q":"Edema in nephrotic syndrome is due to:","o":["Salt and water retention","Hypoalbuminemia","Increase hydrostatic pressure","Increase oncotic pressure"],"a":1,"e":"Nephrotic oedema is primarily due to hypoalbuminaemia from heavy proteinuria, reducing oncotic pressure.<br><br>Salt/water retention is secondary; the primary driver of nephrotic oedema is hypoalbuminaemia from heavy proteinuria."},
/*658*/ {"q":"Raised ESR due to decrease in:","o":["Gamma globulin","Lactoferrin","Albumin","Cortisol"],"a":2,"e":"A low albumin (with raised fibrinogen/globulins) increases red cell aggregation and raises the ESR.<br><br>Raised globulins/fibrinogen aggregate red cells, but among these a low albumin is the change that raises the ESR."},
/*659*/ {"q":"If ejection fraction increases, what will decrease:","o":["EDV","End systolic volume","SV","Pulse"],"a":1,"e":"A higher ejection fraction means more complete emptying, so the end-systolic volume decreases.<br><br>A higher ejection fraction means more complete emptying, so the end-systolic volume decreases (EDV/SV do not)."},
/*660*/ {"q":"Lateral part of foot damaged during drill exercise of army cadet; lymphatic drainage of it:","o":["Superficial inguinal","Internal iliac","External iliac","Popliteal"],"a":3,"e":"The lateral part of the foot and heel drains to the popliteal lymph nodes.<br><br>The medial foot drains to superficial inguinal; the lateral foot drains to the popliteal nodes."},
/*661*/ {"q":"Femoral vein is lateral to which structure:","o":["Femoral canal","Inguinal nodes","Artery","Nerve"],"a":0,"e":"In the femoral sheath the femoral vein lies lateral to the femoral canal and medial to the femoral artery.<br><br>In the femoral sheath the vein lies lateral to the femoral canal and medial to the artery; the canal is its medial relation."},
/*662*/ {"q":"Patient had MI, ECG ST elevations in leads II, III and AVF; vessel involved:","o":["RCA","RCx","Marginal","LCA"],"a":0,"e":"Inferior wall ST elevation in leads II, III and aVF indicates right coronary artery occlusion.<br><br>Inferior-wall ST elevation in leads II, III, aVF localises to right coronary artery occlusion, not the circumflex/LCA."},
/*663*/ {"q":"Coronary sinus drains how much coronary blood flow:","o":["2/3rd of veins","1/3rd of veins","Half of blood","Whole blood"],"a":0,"e":"The coronary sinus drains approximately two-thirds of the venous return of the heart.<br><br>The thebesian/anterior cardiac veins drain a small fraction; the coronary sinus drains about two-thirds of cardiac venous return."},
/*664*/ {"q":"A child diagnosed tumor with gene amplification; which best describes the condition:","o":["Pheochromocytoma","Pituitary adenoma","Ewing sarcoma","Neuroblastoma"],"a":3,"e":"N-myc gene amplification in a childhood tumour is characteristic of neuroblastoma and signifies poor prognosis.<br><br>Phaeochromocytoma/pituitary adenoma differ; N-myc gene amplification in a childhood tumour is characteristic of neuroblastoma."},
/*665*/ {"q":"N-myc gene amplification is associated with:","o":["Pheochromocytoma","Pituitary adenoma","Ewing sarcoma","Neuroblastoma"],"a":3,"e":"N-myc amplification is the hallmark molecular feature of neuroblastoma.<br><br>C-myc relates to Burkitt lymphoma; N-myc is neuroblastoma."},
/*666*/ {"q":"Deep injury in radial groove, what movement will be affected:","o":["Abduction of fingers","Loss of sensation on the ventral part of lower thumb","Loss of extension of wrist resulting in wrist drop","Flexion of wrist"],"a":2,"e":"Radial nerve injury in the radial groove paralyses the wrist and finger extensors, causing wrist drop.<br><br>Finger abduction is ulnar and wrist flexion is median; radial nerve injury in the radial groove causes wrist drop (loss of extension)."},
/*667*/ {"q":"Medial attachment of flexor retinaculum:","o":["Pisiform bone","Trapezoid","Ulnar distal end","Sphenoid"],"a":0,"e":"The flexor retinaculum attaches medially to the pisiform and hook of hamate.<br><br>The flexor retinaculum attaches medially to the pisiform and hook of hamate, not the trapezoid or sphenoid."},
/*668*/ {"q":"After RTA patient has fracture of head of femur, leading to avascular necrosis; artery involved is:","o":["Lateral circumflex","Descending branch lateral circumflex","Medial circumflex artery","Obturator artery"],"a":2,"e":"In adults the femoral head is supplied mainly by the medial circumflex femoral artery, so its disruption causes avascular necrosis.<br><br>The lateral circumflex supplies little of the head; in adults the femoral head depends on the medial circumflex femoral artery."},
/*669*/ {"q":"Fracture of long bone will stop longitudinal growth at:","o":["Epiphyseal plate","Epiphyseal line","Anatomical neck","Metaphysis"],"a":0,"e":"Damage to the epiphyseal (growth) plate arrests longitudinal bone growth.<br><br>Metaphyseal/neck fractures do not arrest growth; damage to the epiphyseal (growth) plate stops longitudinal bone growth."},
/*670*/ {"q":"Tumor of eye which spreads to liver:","o":["RB","Ewing sarcoma","BCC","Melanoma"],"a":3,"e":"Uveal (ocular) melanoma characteristically metastasises to the liver.<br><br>Retinoblastoma spreads via CSF/optic nerve; the eye tumour spreading to liver is melanoma."},
/*671*/ {"q":"Lymphatic drainage of external nose is which of following lymph nodes:","o":["Submandibular lymph nodes","Deep cervical lymph nodes","Retropharyngeal lymph nodes","Occipital lymph nodes"],"a":0,"e":"The external nose and anterior nasal cavity drain to the submandibular lymph nodes.<br><br>The posterior nasal cavity drains to retropharyngeal nodes; the external nose drains to submandibular nodes."},
/*672*/ {"q":"Main support of lateral longitudinal arch of foot is formed by which structure:","o":["Talus","Calcaneus","Cuboid","Medial cuneiform"],"a":2,"e":"The cuboid is the keystone and main support of the lateral longitudinal arch of the foot.<br><br>The talus supports the medial arch; the lateral arch is supported by the cuboid."},
/*673*/ {"q":"A patient of jaundice with total bilirubin 10, direct 9; what is the cause:","o":["Crigler-Najjar","Gilbert syndrome","Choledocholithiasis","Physiological jaundice"],"a":2,"e":"A predominantly conjugated (direct) hyperbilirubinaemia indicates obstructive jaundice such as choledocholithiasis.<br><br>Crigler-Najjar and Gilbert are unconjugated; predominant direct bilirubin is choledocholithiasis."},
/*674*/ {"q":"A lady presented with jaundice having gallstones; which investigation will confirm the diagnosis:","o":["CPK","Bilirubin","ALP","AST"],"a":2,"e":".<br><br>CPK/AST reflect muscle/liver cell injury; obstructive (gallstone) jaundice is confirmed by a markedly raised ALP."},
/*675*/ {"q":"Fastest response to maintain blood pressure:","o":["RAAS","CNS ischemic","Chemoreceptor","Baroreceptors"],"a":3,"e":"The baroreceptor reflex is the fastest (neural) mechanism for short-term blood pressure regulation.<br><br>RAAS is slow and hormonal; the fastest is the baroreceptor reflex."},
/*676*/ {"q":"1 liter blood loss in 70 kg man over 10 minutes; which is the compensatory response:","o":["Increase venous tone","Decrease peripheral resistance","Decrease heart rate","Increase blood pressure"],"a":0,"e":"Acute blood loss triggers sympathetic venoconstriction, increasing venous tone to maintain venous return.<br><br>Heart rate rises (not falls) and resistance increases; the early compensatory response to acute blood loss is increased venous tone."},
/*677*/ {"q":"A patient on antituberculous therapy for MDR-TB develops difficulty distinguishing red and green colours; which drug is responsible:","o":["Amiodarone","Pyrazinamide","Rifampicin","Ethambutol"],"a":3,"e":"Ethambutol causes optic neuritis with red-green colour vision impairment.<br><br>Rifampicin causes orange urine; the red-green defect is from ethambutol."},
/*678*/ {"q":"Volume of air in lungs after maximal expiration:","o":["FRC","TV","RV","FLC"],"a":2,"e":"The residual volume is the air remaining in the lungs after a maximal forced expiration.<br><br>FRC includes the expiratory reserve too; after maximal expiration only the residual volume remains."},
/*679*/ {"q":"Decreased AV nodal conduction velocity presentation on ECG:","o":["QT prolongation","TP prolongation","Increase PR interval","Decrease PR interval"],"a":2,"e":"Slowed AV nodal conduction prolongs the PR interval on the ECG.<br><br>QT/TP changes reflect repolarisation; slowed AV nodal conduction prolongs the PR interval."},
/*680*/ {"q":"In Alzheimer disease, brain finding will be:","o":["Loss of sulci","Hyperplasia of brain","Hypertrophy of brain","Atrophy of brain"],"a":3,"e":"Alzheimer disease causes diffuse cortical atrophy with widened sulci and narrowed gyri.<br><br>There is no brain hypertrophy/hyperplasia; Alzheimer disease causes diffuse cortical atrophy with widened sulci."},
/*681*/ {"q":"A group of friends went to a restaurant and ate chicken and fried rice; at midnight develop food poisoning, causative agent is Bacillus cereus; what food is responsible:","o":["Chicken","Soup","Salad","Fried rice"],"a":3,"e":"Bacillus cereus emetic food poisoning is classically associated with reheated fried rice.<br><br>Chicken/salad cause other toxins; reheated fried rice is the classic vehicle for Bacillus cereus emetic toxin."},
/*682*/ {"q":"Child presents with dysentery, stool contains pus and RBCs; causative agent is:","o":["Campylobacter","Enterotoxigenic E. coli","Enterohemorrhagic E. coli","Enteropathogenic E. coli"],"a":2,"e":"Bloody dysentery with pus and red cells, with Shiga-like toxin and HUS risk, indicates enterohaemorrhagic E. coli (O157:H7).<br><br>Enterotoxigenic/enteropathogenic E. coli cause watery diarrhoea; bloody dysentery with pus and red cells is enterohaemorrhagic E. coli (O157:H7)."},
/*683*/ {"q":"Fat digestion is done by:","o":["Emulsification","Bile salt","Lipase","HCO3"],"a":2,"e":"Pancreatic lipase is the principal enzyme that digests dietary fat into fatty acids and monoglycerides.<br><br>Bile salts only emulsify; chemical fat digestion is by lipase."},
/*684*/ {"q":"A patient has damage to a nerve coming out from dorsal surface of left side of brain stem; what will be the defect:","o":["Left sided loss of intorsion","Ptosis of the left eye","Loss of corneal reflex on right","Loss of corneal reflex on left"],"a":0,"e":"The trochlear nerve uniquely emerges from the dorsal brainstem; its injury causes loss of intorsion (and vertical diplopia).<br><br>Only the trochlear nerve emerges from the dorsal brainstem; its lesion causes loss of intorsion (and vertical diplopia)."},
/*685*/ {"q":"52-year-old man with unusual facial expressions, half side of the face red and absence of sweating; possible cause:","o":["Sympathetic chain damage","Facial nerve damage","Parasympathetic damage","Vagus nerve damage"],"a":0,"e":"Hemifacial anhidrosis with flushing and a constricted pupil indicates Horner syndrome from cervical sympathetic chain damage.<br><br>Facial nerve injury causes weakness not anhidrosis; hemifacial flushing with absent sweating and miosis is Horner from sympathetic chain damage."},
/*686*/ {"q":"Defecation is carried by which of following:","o":["Anorectal reflex","Gastrocolic reflex","Sacral parasympathetic","Mass movement"],"a":2,"e":"Defecation is mediated by the sacral parasympathetic (S2-S4) outflow producing the defecation reflex.<br><br>Mass movement initiates the urge; defecation itself is carried out by the sacral parasympathetic."},
/*687*/ {"q":"Which is part of conducting zone:","o":["Alveoli","Sacs","Alveolar ducts","Terminal bronchiole"],"a":3,"e":"The terminal bronchiole is the last part of the purely conducting zone before the respiratory zone begins.<br><br>Alveoli and alveolar ducts are respiratory zone; the conducting part is the terminal bronchiole."},
/*688*/ {"q":"A girl spilled hot water, develops bulla a few hours after burn, later erythema and fever; fluid in bullae was opaque, redness and warm area around; type of inflammation:","o":["Fibrinous","Serous","Mucinous","Purulent"],"a":3,"e":"Opaque (pus-containing) bullous fluid with surrounding warmth and erythema indicates purulent (suppurative) inflammation.<br><br>Serous fluid is clear; opaque pus-containing bullae with surrounding warmth and erythema indicate purulent (suppurative) inflammation."},
/*689*/ {"q":"A patient suffering from fatal disease; who should be informed:","o":["The family not the patient","The patient not the family","Hide some information from the patient","Provide crisp, clear information to the patient"],"a":3,"e":"The patient has a right to honest, clear information about their condition (autonomy and truth-telling).<br><br>Withholding information breaches autonomy; the patient has the right to clear, honest information about a fatal diagnosis."},
/*690*/ {"q":"Regarding pharmacokinetics, true is:","o":["Reversal of hydralazine induced tachycardia with propranolol","Reversal of morphine induced CNS depression with naloxone","Increased toxicity of methotrexate with aspirin","Increased peripheral side effects of levodopa with carbidopa"],"a":1,"e":"Naloxone is a competitive opioid antagonist that reverses morphine-induced CNS and respiratory depression.<br><br>Propranolol/carbidopa are pharmacodynamic; naloxone competitively reverses morphine-induced CNS and respiratory depression."},
/*691*/ {"q":"In internal capsule hemorrhage, following will be present:","o":["Ipsilateral UMN sign","Contralateral UMN signs","Flaccid paralysis","Atrophy"],"a":1,"e":"An internal capsule haemorrhage damages the corticospinal tract, producing contralateral upper motor neuron signs.<br><br>An internal capsule bleed damages descending corticospinal fibres, producing contralateral (not ipsilateral) upper motor neuron signs."},
/*692*/ {"q":"What is different in autosomal dominant from autosomal recessive:","o":["Complete penetrance at term","Affects male","Affects females","Heterozygous"],"a":3,"e":"Autosomal dominant disorders are expressed in the heterozygous state, unlike recessive which need homozygosity.<br><br>Sex is not the distinguishing feature; autosomal dominant disorders are expressed in the heterozygous state, unlike recessive."},
/*693*/ {"q":"Which plays the role in protein synthesis:","o":["DHEA","Progesterone","Estrogen","Testosterone"],"a":3,"e":"Testosterone is an anabolic androgen that stimulates protein synthesis and muscle growth.<br><br>Oestrogen/progesterone are reproductive; testosterone is the anabolic androgen that stimulates protein synthesis and muscle growth."},
/*694*/ {"q":"In 1918 H influenza pandemic was the worst pandemic and killed many people; why was it so lethal:","o":["It was resistant to antibiotics","There was mutation in DNA of H influenza","Reassortment","Antigenic shift due to animal proteins"],"a":3,"e":"The 1918 pandemic was lethal because of antigenic shift introducing novel surface proteins to which the population had no immunity.<br><br>Antibiotic resistance is irrelevant to a virus; the 1918 pandemic was lethal because antigenic shift introduced novel surface proteins."},
/*695*/ {"q":"Which of the following is the initial mechanism of hemostasis:","o":["Platelet aggregation","Degranulation","Vessel vasoconstriction","PGI2 release"],"a":2,"e":"The immediate first response in haemostasis is reflex vascular (vessel) vasoconstriction.<br><br>Platelet plug formation follows; the initial mechanism is vasoconstriction."},
/*696*/ {"q":"Most important feature of platelet is:","o":["Plug formation","Granules","No nucleus","Derived from bone marrow"],"a":0,"e":"The principal functional feature of platelets is forming the primary haemostatic plug.<br><br>Anucleate marrow origin describes platelets but the key functional feature is forming the primary haemostatic plug."},
/*697*/ {"q":"A fetus was aborted and sent to forensic lab; how can the viability be checked for how long the fetus was viable:","o":["Fetus weight 200 g","Eyes laterally","Fetus CRL >250 mm","Absence of wrinkles"],"a":2,"e":".<br><br>Weight or wrinkles are imprecise; fetal age/viability is keyed here to a crown-rump length greater than 250 mm."},
/*698*/ {"q":"Peroxisomes are produced by:","o":["Lysosome","Golgi body","Mitochondria","SER"],"a":3,"e":"Peroxisomes originate from the smooth endoplasmic reticulum (SER).<br><br>Lysosomes arise from the Golgi; peroxisomes originate from the SER."},
/*699*/ {"q":"Body metabolic response to trauma; skeletal muscle responds by:","o":["Decreased proteolysis","Increase glucose loss","Increase proteolysis","No metabolic change"],"a":2,"e":"The catabolic stress response to trauma increases skeletal muscle proteolysis to supply amino acids.<br><br>The catabolic stress response does not spare or unchange muscle; it increases skeletal muscle proteolysis to supply amino acids."},
/*700*/ {"q":"A student wanted to study relationship between increase in temperature and duration of surgery; which statistical test should he apply:","o":["Student t test","Anova test","Mc Whitney","Regression analysis"],"a":3,"e":"Examining the relationship between two continuous variables is done with regression analysis.<br><br>The t-test compares means; the relationship is assessed by regression analysis."},
/*701*/ {"q":"Temperature regulation is done by:","o":["Midbrain","Cortex","Pons","Hypothalamus"],"a":3,"e":"The hypothalamus is the central thermoregulatory centre, with the preoptic/anterior region for heat loss and posterior for heat conservation.<br><br>The cortex/pons modulate but do not set the set-point; the hypothalamus is the central thermoregulatory centre."},
/*702*/ {"q":"A patient with senseless speech and cannot remember; said to be due to lesion of:","o":["Frontal lobe with mamillothalamic tract","Temporal lobe with mamillothalamic tract","Parietal lobe with mamillothalamic tract","Occipital lobe with mamillothalamic tract"],"a":1,"e":"Fluent senseless speech with memory loss localises to the temporal lobe with mamillothalamic tract involvement.<br><br>Frontal/parietal lesions give other syndromes; fluent senseless speech with memory loss localises to the temporal lobe with mamillothalamic involvement."},
/*703*/ {"q":"Central and peripheral chemoreceptors sensitive to:","o":["CO2","Arterial PH","CSF PH","Hypoxia"],"a":0,"e":"Both central and peripheral chemoreceptors are ultimately responsive to CO2 (via H+ changes).<br><br>Peripheral chemoreceptors also sense O2 and pH, but the common stimulus driving both central and peripheral receptors is CO2."},
/*704*/ {"q":"Autoregulation of GFR is by:","o":["Tubuloglomerular mechanism and myogenic feedback","Afferent glomerular constriction","Efferent glomerular dilation","Efferent glomerular constriction"],"a":0,"e":"Renal autoregulation of GFR is achieved by the myogenic response and tubuloglomerular feedback.<br><br>Selective afferent/efferent tone is hormonal; intrinsic GFR autoregulation is by the myogenic response and tubuloglomerular feedback."},
/*705*/ {"q":"What to give in hypothyroidism:","o":["Levothyroxine","Iodine","Beta blockers","IV T3 T4"],"a":0,"e":"Hypothyroidism is treated with oral levothyroxine (T4) replacement.<br><br>Iodine/beta-blockers do not replace hormone; hypothyroidism is treated with oral levothyroxine (T4)."},
/*706*/ {"q":"Most common location of appendix is:","o":["Sub cecal","Retro cecal","Pelvic","Para colic"],"a":1,"e":"The retrocecal position is the commonest location of the vermiform appendix.<br><br>Pelvic/subcecal positions are less frequent; the commonest position of the appendix is retrocecal."},
/*707*/ {"q":"Loss of parietal cells; what will happen:","o":["Iron deficiency anemia","Thalassemia","Pernicious anemia","Sideroblastic anemia"],"a":2,"e":"Loss of gastric parietal cells removes intrinsic factor, causing vitamin B12 malabsorption and pernicious anaemia.<br><br>Iron/thalassaemia anaemias differ; loss of parietal cells removes intrinsic factor, causing B12-deficient pernicious anaemia."},
/*708*/ {"q":"Damage to fundus of stomach; it will bleed by:","o":["Short gastric arteries","Left gastric artery","Celiac artery","Gastroduodenal artery"],"a":0,"e":"The fundus of the stomach is supplied by the short gastric arteries from the splenic artery.<br><br>The left gastric supplies the lesser curve; the gastric fundus is supplied by the short gastric arteries from the splenic artery."},
/*709*/ {"q":"Which organism is transmitted in blood transfusion:","o":["Hep. A","Hep. B","Hep. C","Hep. E"],"a":1,"e":"Hepatitis B is a classically transfusion-transmitted bloodborne virus, with CMV greater than Hep B greater than Hep C in transfusion-related frequency.<br><br>Hep A and E are faecal-oral; the bloodborne transfusion-transmitted hepatitis is hepatitis B."},
/*710*/ {"q":"Common and first defense system if body is:","o":["Plasma cells","Macrophages","Neutrophils","Skin and mucous secretions"],"a":3,"e":"The skin and mucous membrane secretions form the first line of innate defence (overall first barrier).<br><br>Macrophages act in tissue and neutrophils in blood; the overall first line is the skin."},
/*711*/ {"q":"Sudden rise in pulse pressure due to:","o":["Increase in arterial compliance","Increase MAP","Increase stroke volume","Increase heart rate at constant cardiac output"],"a":2,"e":"A sudden rise in pulse pressure is mainly due to an increased stroke volume.<br><br>Raised MAP or compliance change is not the cause; a sudden rise in pulse pressure is mainly due to an increased stroke volume."},
/*712*/ {"q":"Major part of breast to be drained into lymph nodes; which will be involved in sentinel biopsy:","o":["Anterior axillary","Posterior axillary","Infraclavicular","Supraclavicular"],"a":0,"e":"Most of the breast lymph drains to the anterior (pectoral) axillary nodes, the usual sentinel node.<br><br>Posterior/supraclavicular nodes are later; most breast lymph (and the sentinel node) drains to the anterior (pectoral) axillary group."},
/*713*/ {"q":"Person with difficulty in swallowing, some white growth inside esophagus with pseudohyphae; likely reason is:","o":["Candidiasis","Aspergillosis","Histoplasmosis","Mucor"],"a":0,"e":"White oesophageal plaques with pseudohyphae causing dysphagia indicate oesophageal candidiasis.<br><br>Aspergillus has septate hyphae; white oesophageal plaques with pseudohyphae causing dysphagia indicate Candida."},
/*714*/ {"q":"Beta receptor acts on heart and causes:","o":["Bradycardia","Pupil dilation","Increase heart rate and contractility","Decrease heart rate and contractility"],"a":2,"e":"Beta-1 adrenergic stimulation of the heart increases heart rate and contractility.<br><br>Alpha effects cause pupil dilation; beta-1 stimulation of the heart increases rate and contractility."},
/*715*/ {"q":"In hereditary spherocytosis, what is true:","o":["Cytoskeleton deformity","Cartilage defect","Collagen defect","Cell defect"],"a":0,"e":"Hereditary spherocytosis results from a red cell membrane cytoskeleton defect (spectrin/ankyrin), producing spherocytes.<br><br>It is not a collagen or cartilage disorder; hereditary spherocytosis is a red-cell membrane cytoskeleton (spectrin/ankyrin) defect."},
/*716*/ {"q":"Which of the following paraneoplastic syndrome is associated with small cell (oat cell) carcinoma of lungs:","o":["ACTH","Insulin","Glucagon","Androgen"],"a":0,"e":"Small cell lung carcinoma classically secretes ectopic ACTH (and ADH) as a paraneoplastic syndrome.<br><br>Insulin/glucagon are not its products; small (oat) cell lung carcinoma classically secretes ectopic ACTH (and ADH)."},
/*717*/ {"q":"Maximum ventricle filled during:","o":["Rapid ejection","Slow filling","Atrial systole","Early diastole"],"a":2,"e":".<br><br>Rapid ejection empties the ventricle; maximal ventricular filling occurs during atrial systole (the atrial kick)."},
/*718*/ {"q":"After crossing ligamentum flavum, needle passes to:","o":["Subdural space","Subarachnoid","Epidural space","Pia matter"],"a":2,"e":"Immediately deep to the ligamentum flavum lies the epidural space.<br><br>The subarachnoid space lies deeper past the dura; immediately beyond the ligamentum flavum is the epidural space."},
/*719*/ {"q":"Artery damaged in shoulder dislocation:","o":["Anterior circumflex humeral artery","Brachial plexus","Posterior circumflex humeral artery","Subclavian artery"],"a":2,"e":"The posterior circumflex humeral artery (and axillary nerve) is at risk in anterior shoulder dislocation.<br><br>The anterior circumflex is less exposed; anterior shoulder dislocation endangers the posterior circumflex humeral artery (and axillary nerve)."},
/*720*/ {"q":"Supply of proximal bile duct is by which artery:","o":["Right hepatic","Left hepatic","Cystic","Gastroduodenal"],"a":0,"e":"The proximal common bile duct is supplied mainly by the right hepatic and cystic arteries.<br><br>The cystic/gastroduodenal supply other parts; the proximal common bile duct is supplied chiefly by the right hepatic artery."},
/*721*/ {"q":"Patient after thyroidectomy developed hoarseness of voice, loose vocal cords, muscle damaged with supply from middle 3rd of nucleus ambiguous is:","o":["Cricothyroid","Cricoarytenoid","Vocalis","Arytenoid"],"a":0,"e":".<br><br>The recurrent-laryngeal-supplied muscles differ; the keyed muscle for this post-thyroidectomy hoarseness is cricothyroid."},
/*722*/ {"q":"A lady with 26 weeks gestation has uterine height of 24 weeks; on sonography there are no fetal parts and shows snow storm appearance; likely diagnose is:","o":["Choriocarcinoma","Complete mole","Partial mole","Down syndrome"],"a":1,"e":"A snowstorm appearance with no fetal parts and a large-for-dates uterus indicates a complete hydatidiform mole.<br><br>A partial mole has fetal parts; the no-fetus snowstorm is a complete mole."},
/*723*/ {"q":"A patient with sleep disturbance, increased weight, increased appetite and genital hypoplasia; likely cause is:","o":["Craniopharyngioma","Kallman syndrome","Turner syndrome","Klinefelter syndrome"],"a":0,"e":"Hypothalamic-pituitary compression by a craniopharyngioma causes obesity, sleep disturbance and hypogonadism.<br><br>Kallmann/Turner/Klinefelter are primary gonadal/genetic; hypothalamic compression with obesity and hypogonadism is craniopharyngioma."},
/*724*/ {"q":"Which of the following structure is between celiac plexus and SMA:","o":["Pancreas","Liver","Stomach","Spleen"],"a":0,"e":"The body of the pancreas lies between the celiac trunk/plexus above and the superior mesenteric artery below.<br><br>The liver/stomach lie elsewhere; the body of the pancreas lies between the celiac plexus above and the SMA below."},
/*725*/ {"q":"Sympathetic supply of the lower respiratory tract:","o":["T1 to T4","T6, T7","T4, T5, T6","T8-9"],"a":0,"e":".<br><br>Lower thoracic segments are too low; the sympathetic supply of the lower respiratory tract is keyed to T1-T4."},
/*726*/ {"q":"Drug leading to hyponatremia in SIADH:","o":["Na valproate","Carbamazepine","Phenytoin","Ethosuximide"],"a":1,"e":"Carbamazepine is a classic drug causing SIADH with dilutional hyponatraemia.<br><br>Phenytoin/valproate are not the classic culprit; carbamazepine is the drug typically causing SIADH and dilutional hyponatraemia."},
/*727*/ {"q":"In hyperkalemia, drug which is aldosterone antagonist and contraindicated is:","o":["Furosemide","Hydrochlorothiazide","Spironolactone","Mannitol"],"a":2,"e":"Spironolactone is a potassium-sparing aldosterone antagonist and is contraindicated in hyperkalaemia.<br><br>Furosemide and thiazides are not aldosterone antagonists; spironolactone is the aldosterone antagonist contraindicated in hyperkalaemia."},
/*728*/ {"q":"Nerve supply of intercostal muscles is:","o":["Dorsal scapular nerve","C2-C3","Dorsal rami of spinal nerves","Long thoracic nerves"],"a":1,"e":".<br><br>Long thoracic/dorsal scapular serve other muscles; the intercostal muscle innervation here is keyed to the C2-C3 option."},
/*729*/ {"q":"Patient with history of head trauma, urine osmolarity decreased and plasma osmolarity increased, polydipsia and polyuria, positive CH2O clearance; likely cause:","o":["Central diabetes insipidus","Nephrogenic diabetes insipidus","Diabetes mellitus","SIADH"],"a":0,"e":"Post-traumatic dilute urine with raised plasma osmolality and polyuria/polydipsia indicates central diabetes insipidus from ADH deficiency.<br><br>Nephrogenic DI fails to respond to ADH; post-traumatic dilute urine with high plasma osmolality reflects central ADH deficiency (central DI)."},
/*730*/ {"q":"A girl during exercise gets dyspnea, presents to emergency with wheezing, breathlessness during aerobics, chest wheezing, SpO2 97 percent; suitable treatment:","o":["Inhaled beta 2 agonist","Inhaled theophylline","Inhaled ipratropium bromide","IV steroid"],"a":0,"e":"Acute exercise-induced bronchospasm is treated first with an inhaled short-acting beta-2 agonist.<br><br>Ipratropium and steroids act slowly; acute exercise-induced bronchospasm is treated first with an inhaled short-acting beta-2 agonist."},
/*731*/ {"q":"Side effect of epidural anaesthesia is:","o":["Hypotension","Urinary retention","Headache","Vomiting"],"a":0,"e":"Sympathetic blockade from epidural anaesthesia causes hypotension as its main side effect.<br><br>Headache and retention are minor; sympathetic blockade from an epidural mainly causes hypotension."},
/*732*/ {"q":"A 60-year-old elderly obese male was started on IV gentamicin post laparotomy; which of the following is disturbed:","o":["Distribution","Excretion","Absorption","Metabolism"],"a":0,"e":"In an obese patient the volume of distribution of gentamicin is altered, affecting distribution.<br><br>Renal clearance changes excretion; in an obese patient it is the volume of distribution of gentamicin that is altered."},
/*733*/ {"q":"The primordial germ cells are derived from:","o":["Ectoderm","Epiblast","Endoderm","Mesoderm"],"a":1,"e":"Primordial germ cells originate from the epiblast and migrate via the yolk sac endoderm to the gonadal ridge.<br><br>Germ cells transit yolk-sac endoderm but originate from the epiblast, not endoderm or mesoderm."},
/*734*/ {"q":"A patient of asthma with ABGs pH 7.23, HCO3 26 and hypercapnea; likely acid-base disorder is:","o":["Uncompensated metabolic acidosis","Compensated metabolic acidosis","Respiratory alkalosis","Respiratory acidosis"],"a":3,"e":"Low pH with hypercapnia and a near-normal bicarbonate indicates acute (uncompensated) respiratory acidosis.<br><br>A normal/high HCO3 with low pH and hypercapnia is acute (uncompensated) respiratory acidosis, not metabolic acidosis."},
/*735*/ {"q":"Xiphoid process is present at which vertebral level:","o":["T7","T8","T9","T10"],"a":2,"e":"The xiphoid process lies at the level of the T9 vertebra.<br><br>The sternal angle is T4-5; the xiphoid is at T9."},
/*736*/ {"q":"Oropharyngeal carcinoma is caused by:","o":["CMV","HPV","EBV","HSV 1"],"a":1,"e":"Oropharyngeal carcinoma is increasingly caused by high-risk human papillomavirus (HPV).<br><br>Nasopharyngeal carcinoma is EBV-related; oropharyngeal carcinoma is HPV-related."},
/*737*/ {"q":"Which of the following is the most important in the formation of thrombus:","o":["Endothelial injury","Hypercoagulable state","Platelet aggregation","Stasis"],"a":0,"e":"Endothelial injury is the most important factor of the Virchow triad in thrombogenesis, especially arterial.<br><br>Stasis and hypercoagulability matter, but endothelial injury is the most important Virchow factor, especially in arterial thrombosis."},
/*738*/ {"q":"Regarding aneuploidy, true is:","o":["Extra chromosome","Increase or decrease number of chromosomes instead of 46","Increase number of chromosomes more than 46","Decrease number of chromosomes less than 46"],"a":1,"e":"Aneuploidy is any abnormal chromosome number (increase or decrease) other than the normal 46.<br><br>An extra single chromosome is trisomy; aneuploidy more broadly is any abnormal chromosome number other than 46."},
/*739*/ {"q":"Patient has restlessness, bronchospasm and difficulty in breathing after 10 min of lidocaine infusion due to:","o":["Cardiac shock","Septic shock","Allergic reaction","Hypovolemia"],"a":2,"e":"Bronchospasm and restlessness shortly after lidocaine infusion indicate an allergic (anaphylactic) reaction.<br><br>Septic/hypovolaemic shock have other triggers; bronchospasm minutes after lidocaine indicates an allergic (anaphylactic) reaction."},
/*740*/ {"q":"A Pap smear of lady shows dysplasia, increased N/C ratio and pleomorphism but basement membrane is intact; what is associated with this:","o":["Invasion of adjacent tissue","Invasion of basement membrane","Carcinoma in situ","Carcinoma"],"a":2,"e":"Full-thickness dysplasia with an intact basement membrane and no invasion is carcinoma in situ.<br><br>Breach of the basement membrane defines invasion; an intact membrane is carcinoma in situ."},
/*741*/ {"q":"Man lifted heavy weight, sudden pain in arm, on examination swelling in upper forearm of the muscle which is attached to radial tuberosity:","o":["Biceps brachii","Brachioradialis","Anconeus","Supinator"],"a":0,"e":"The biceps brachii inserts into the radial tuberosity; its rupture causes a bunched upper-arm/forearm swelling.<br><br>Brachioradialis/supinator attach elsewhere; the biceps brachii inserts on the radial tuberosity and bunches up when ruptured."},
/*742*/ {"q":"Which of the following is released at the synapse between incoming pain fibers and pain inhibitory fibers in spinal cord:","o":["Histamine","Glutamate","Substance P","Enkephalin"],"a":3,"e":"Enkephalin is released by inhibitory interneurons to presynaptically inhibit pain transmission in the dorsal horn.<br><br>Substance P is the pain transmitter itself; the inhibitory mediator is enkephalin."},
/*743*/ {"q":"The fastest conduction speed in cardiac conduction system is a feature of which structure:","o":["Sinoatrial node","Atrioventricular node","Ventricular muscles","Purkinje system"],"a":3,"e":"The Purkinje fibers have the fastest conduction velocity in the heart.<br><br>The AV node is slowest; the fastest is the Purkinje system."},
/*744*/ {"q":"Pregnant female in 5th month of pregnancy with thyrotoxicosis; which drug should be given:","o":["PTU","Methimazole","Beta blocker","Iodine"],"a":1,"e":"In the second and third trimesters methimazole is preferred for thyrotoxicosis (PTU is first-trimester).<br><br>PTU is preferred in the first trimester; in the second/third trimester thyrotoxicosis is treated with methimazole."},
/*745*/ {"q":"Appendicular artery is a branch of which artery:","o":["Anterior colic","Posterior colic","Ileocolic","Celiac"],"a":2,"e":"The appendicular artery is a branch of the ileocolic artery (from the superior mesenteric artery).<br><br>The colic arteries supply the colon; the appendicular artery is a branch of the ileocolic artery (from the SMA)."},
/*746*/ {"q":"A man after RTA with excessive blood loss, hypotensive on ventilatory support, PEEP given with 100% FIO2, died 5 days later; lungs show hyaline streaks with increased macrophages and few neutrophils; likely cause:","o":["Diffuse alveolar damage","Patchy atelectasis","Fibrosis","Tension pneumothorax"],"a":0,"e":"Hyaline membranes with macrophages in a ventilated shock patient indicate diffuse alveolar damage (ARDS).<br><br>Atelectasis/pneumothorax are mechanical; hyaline membranes with macrophages in a ventilated shock patient indicate diffuse alveolar damage (ARDS)."},
/*747*/ {"q":"As compared to a normal person, a marathon runner has the following changes:","o":["Increase SV","Increase SV and heart rate","Decrease heart rate and increase SV","Both are decreased"],"a":2,"e":"Endurance training produces a lower resting heart rate with an increased stroke volume.<br><br>Endurance training does not raise resting heart rate; it lowers resting heart rate while increasing stroke volume."},
/*748*/ {"q":"CO2 transports mainly in the form of:","o":["HCO3","Free form","Bound to chloride","Dissolved in plasma"],"a":0,"e":"Most carbon dioxide is transported in blood as bicarbonate (HCO3-).<br><br>Only a small fraction is dissolved or carbamino-bound; most CO2 is carried in blood as bicarbonate."},
/*749*/ {"q":"3-week-old child with projectile vomiting since birth; findings will be:","o":["Hypochloremic metabolic alkalosis","Metabolic acidosis","Hyperchloremic metabolic acidosis","Respiratory acidosis"],"a":0,"e":"Pyloric stenosis with projectile vomiting causes hypochloraemic, hypokalaemic metabolic alkalosis.<br><br>Pyloric stenosis causes loss of gastric HCl, producing a hypochloraemic hypokalaemic metabolic alkalosis, not acidosis."},
/*750*/ {"q":"What changes are seen in a patient given 1 L isotonic N/saline:","o":["Increased plasma osmolarity","Increase urine volume","Increased plasma sodium","Increased ICF volume"],"a":1,"e":"Isotonic saline expands extracellular volume without changing osmolality, leading to increased urine output.<br><br>Isotonic saline does not change osmolality or ICF volume; the expanded volume is excreted as increased urine output."},
/*751*/ {"q":"RBCs are kept in a solution containing urea; what will happen:","o":["Cell will shrink","Cell will swell and lyse","Cell will shrink and lyse","Cell will shrink then swell and then lyse"],"a":3,"e":"In a urea-containing hypertonic solution the cell initially shrinks, then urea and water enter causing swelling and eventual lysis.<br><br>A non-penetrating solute just shrinks the cell; urea entry after initial shrinkage draws water in causing swelling then lysis."},
/*752*/ {"q":"Thoracic duct drains into:","o":["Right brachiocephalic vein","Left brachiocephalic vein","Celiac trunk","Left atrium"],"a":1,"e":"The thoracic duct empties into the junction of the left subclavian and left internal jugular veins (left brachiocephalic/venous angle).<br><br>The right lymphatic duct drains the right upper body; the thoracic duct empties into the left brachiocephalic (subclavian-IJ) junction."},
/*753*/ {"q":"The ability of the kidney to excrete concentrated urine will increase if:","o":["The permeability of the proximal tubules to water decreases","The rate of blood flow through the medulla decreases","The rate of flow through the LOH increases","The activity of Na-K pump in LOH decreases"],"a":1,"e":"Reduced medullary blood flow preserves the medullary osmotic gradient, improving urine concentrating ability.<br><br>Increased medullary blood flow washes out the gradient; reducing medullary blood flow preserves it and improves concentrating ability."},
/*754*/ {"q":"AV nodal delay helps in which of following:","o":["Atrial filling","Ventricle filling","Aorta filling","Ventricle contraction"],"a":1,"e":"The AV nodal delay allows complete atrial emptying so the ventricles fill adequately before contracting.<br><br>The delay does not affect aortic filling; it allows the atria to empty and ventricles to fill before contraction."},
/*755*/ {"q":"Which of the following vitamin is deficient after acute pancreatitis:","o":["B12","B7","Vitamin D","Vitamin C"],"a":2,"e":"Pancreatic insufficiency impairs fat absorption, causing deficiency of fat-soluble vitamin D.<br><br>Water-soluble B12/C are unaffected; pancreatic fat malabsorption causes fat-soluble vitamin D deficiency."},
/*756*/ {"q":"A patient with cervical lymphadenopathy suspected as having TB; which is the microscopic feature of TB:","o":["Giant cell","Montoux test","X-ray chest","Caseous necrosis"],"a":3,"e":"Caseous (caseating) necrosis within granulomas is the characteristic microscopic feature of tuberculosis.<br><br>The Mantoux test and X-ray are not microscopic; the histological hallmark is caseous necrosis."},
/*757*/ {"q":"45% hematocrit means:","o":["45% formed element in blood is RBCs","45% formed element in blood is WBC","45% formed element in blood is WBC and RBC","41% formed element in blood is WBC, RBC and platelets"],"a":0,"e":"Haematocrit is the percentage of blood volume occupied by red blood cells, so 45% means 45% RBCs.<br><br>Haematocrit excludes white cells and platelets; it is the percentage of blood volume occupied by red cells (45% means 45% RBCs)."},
/*758*/ {"q":"Which one has high saturation of oxygen:","o":["Aorta","IVC","Umbilical artery","Umbilical vein"],"a":3,"e":"The umbilical vein carries the most oxygenated blood in the fetus from the placenta.<br><br>The umbilical arteries are deoxygenated; the highest saturation is in the umbilical vein."},
/*759*/ {"q":"Highest oxygen saturation in fetal circulation is seen in:","o":["Umbilical artery","Umbilical vein","Aorta","IVC"],"a":1,"e":"The umbilical vein has the highest oxygen saturation in the fetal circulation.<br><br>The umbilical arteries carry deoxygenated blood; the umbilical vein has the highest oxygen saturation in the fetal circulation."},
/*760*/ {"q":"A patient undergoing thyroidectomy at upper lobe; the nerve likely to be injured in vicinity of superior thyroid artery:","o":["Recurrent laryngeal nerve","Internal laryngeal nerve","External laryngeal nerve","Vagus nerve main stem"],"a":2,"e":"The external laryngeal nerve runs with the superior thyroid artery and is at risk during ligation of the upper pole.<br><br>The recurrent laryngeal relates to the inferior thyroid; the superior pole nerve is the external laryngeal."},
/*761*/ {"q":"A patient is suffering from fatal disease; who should be informed:","o":["The family not the patient","The patient not the family","Hide some information from the patient","Provide crisp, clear information to the patient"],"a":3,"e":"The patient has the right to honest, clear information about their diagnosis (autonomy and truth-telling).<br><br>Hiding information breaches autonomy; the patient is entitled to clear, honest information about a fatal illness."},
/*762*/ {"q":"Neuroendocrine response after surgery is due to:","o":["Hemorrhage","Toxic stimuli","Starvation","Nociceptor afferent"],"a":0,"e":".<br><br>Toxic/nociceptive stimuli contribute, but the keyed primary driver of the postoperative neuroendocrine stress response here is haemorrhage."},
/*763*/ {"q":"Pulmonary artery develops from which arch:","o":["3rd arch","4th arch","6th arch","1st arch"],"a":2,"e":"The proximal pulmonary arteries develop from the sixth pharyngeal arch arteries.<br><br>The 4th arch forms the aortic arch; the pulmonary arteries arise from the 6th arch."},
/*764*/ {"q":"A patient with severe headache, vomiting and neck stiffness, raised ICP, lumbar puncture shows blood-stained CSF; diagnose:","o":["Subdural hemorrhage","Cerebral hemorrhage","Extradural hematoma","Subarachnoid hemorrhage"],"a":3,"e":"Meningism with raised ICP and blood-stained CSF indicates subarachnoid haemorrhage.<br><br>Subdural/extradural bleeds are not uniformly bloody on tap; meningism with blood-stained CSF indicates subarachnoid haemorrhage."},
/*765*/ {"q":"A 68-year-old woman with uterine carcinoma undergoes surgical resection; this cancer can spread directly to the labia majora via lymphatic that follow which structure:","o":["Pubic arcuate ligament","Suspensory ligament of the ovary","Cardinal (transverse cervical) ligament","Round ligament of the uterus"],"a":3,"e":"The round ligament of the uterus passes through the inguinal canal to the labia majora, providing a lymphatic route there.<br><br>The cardinal/ovarian ligaments drain elsewhere; the round ligament of the uterus traverses the inguinal canal to the labia majora."},
/*766*/ {"q":"At the end of marathon race a person has:","o":["High insulin and low glucagon","High glucagon and high insulin","High glucagon and low insulin","High cortisol"],"a":2,"e":"Prolonged exercise lowers insulin and raises glucagon to mobilise glucose.<br><br>Insulin falls and glucagon rises in prolonged exercise to mobilise glucose, not the high-insulin pattern."},
/*767*/ {"q":"Carcinoma of head of pancreas will compress which of the following structure:","o":["Hepatic duct","CBD","IVC","Hepatic vein"],"a":1,"e":"Carcinoma of the pancreatic head compresses the common bile duct, causing obstructive jaundice.<br><br>The hepatic duct is more proximal; a pancreatic head carcinoma compresses the common bile duct, causing painless jaundice."},
/*768*/ {"q":"Which of following is connective tissue in brain:","o":["Parietal cells","Chief cells","Peneath cells","Oligodendrocytes"],"a":3,"e":"Among the listed options the glial (supporting) cell of the CNS is the oligodendrocyte.<br><br>Parietal/chief cells are gastric; among these the CNS supporting (glial) cell is the oligodendrocyte."},
/*769*/ {"q":"Most common pattern of genetic disease:","o":["Multifactorial","Autosomal dominant","Autosomal recessive","X-link recessive"],"a":0,"e":"Multifactorial (polygenic) inheritance is the commonest pattern of genetic disease.<br><br>Single-gene patterns are individually less common; multifactorial (polygenic) inheritance is the commonest pattern of genetic disease."},
/*770*/ {"q":"Which of the following types of drugs will have maximum bioavailability:","o":["Drugs with high first-pass metabolism","Highly hydrophilic drugs","Largely hydrophobic, yet soluble in water","Chemically unstable drugs"],"a":2,"e":"Drugs that are lipophilic enough to cross membranes yet sufficiently water-soluble have the best bioavailability.<br><br>Highly hydrophilic or first-pass-metabolised drugs are poorly bioavailable; lipophilic yet water-soluble drugs have the best bioavailability."},
/*771*/ {"q":"Male and female patient divided into groups then subgroup; which type of sampling is it:","o":["Simple random sampling","Stratified random sampling","Mixed sampling","Random population"],"a":1,"e":"Dividing into groups (strata) such as sex and then sampling within them is stratified random sampling.<br><br>Simple random sampling does not pre-divide; dividing into sex strata and sampling within them is stratified random sampling."},
/*772*/ {"q":"A 30-year-old man sustains a left femoral fracture, leg in a plaster cast; after several weeks the diameter of the left calf decreased; most likely due to which alteration in calf muscles:","o":["Decrease collagen","Increase protein synthesis","Decrease contractile protein synthesis","Hyalinosis"],"a":2,"e":"Disuse atrophy from immobilisation reduces contractile protein synthesis, decreasing muscle bulk.<br><br>Collagen/hyalinosis are not the mechanism; disuse (cast immobilisation) reduces contractile protein synthesis, shrinking the muscle."},
/*773*/ {"q":"Patient got scared on watching something, he got goosebumps; what is mechanism:","o":["Relaxation of erector pili muscle","Constriction of erector pili muscle","Eversion of hair follicles","Follicle rupture"],"a":1,"e":"Goosebumps result from sympathetic contraction of the arrector (erector) pili muscles.<br><br>Erector pili relaxation flattens hair; sympathetic contraction of the arrector pili muscles raises the hairs (goosebumps)."},
/*774*/ {"q":"True about agonist is:","o":["They have affinity and efficacy","Only intrinsic activity","Bound by ionic bonding have prolonged effect","They have affinity and intrinsic activity"],"a":3,"e":"An agonist binds the receptor (affinity) and produces a response (intrinsic activity/efficacy).<br><br>Affinity alone or intrinsic activity alone is insufficient; an agonist has both binding affinity and intrinsic activity (efficacy)."},
/*775*/ {"q":"Inguinal lymphadenitis affects which of following:","o":["Upper vagina","Upper uterus","Lower part of the uterus body","Upper cervix"],"a":2,"e":".<br><br>The upper uterus drains to para-aortic nodes; only the lower uterine body drains to inguinal nodes (via the round ligament)."},
/*776*/ {"q":"A young thin lean boy with sign of tetany, blood Ca level 6 (normal 8-9) and urine excretion level 50 (normal 24-300); what is the cause:","o":["Vitamin D deficiency","Primary hyperparathyroidism","CRF","Hyperparathyroidism"],"a":0,"e":"Hypocalcaemia with tetany and low urinary calcium points to vitamin D deficiency.<br><br>Hyperparathyroidism raises calcium; hypocalcaemia with tetany and low urinary calcium indicates vitamin D deficiency."},
/*777*/ {"q":"A woman presents with 40 weeks gestation cephalic presentation, cervix dilated up to 6 cm; head is at 0 station; what is the landmark/reference point:","o":["Ischial spine","Pubic tubercle","Symphysis pubis","Inguinal ligament"],"a":0,"e":"Fetal station is measured relative to the maternal ischial spines, with 0 station at the spines.<br><br>The pubic tubercle/symphysis are not station references; fetal station 0 is defined relative to the maternal ischial spines."},
/*778*/ {"q":"Premalignant lesion that may lead to carcinoma and need excision:","o":["Bowen disease","Actinic keratosis","Naevus","Leukoplakia"],"a":1,"e":".<br><br>A naevus is benign; among these the premalignant lesion requiring excision is actinic keratosis (Bowen is in-situ carcinoma)."},
/*779*/ {"q":"A patient presents with esophageal varices having bleeding; which vessel is involved:","o":["Left gastric vein","Right gastric artery","Splenic artery","Hepatic artery"],"a":0,"e":"Oesophageal varices bleed from the dilated left gastric (coronary) vein at the portosystemic anastomosis.<br><br>The splenic/hepatic arteries are arterial; variceal bleeding arises from the dilated left gastric (coronary) vein."},
/*780*/ {"q":"Gastroesophageal junction lies at:","o":["T9","T10","T11","L1"],"a":2,"e":"The gastroesophageal junction lies at the level of the T11 vertebra where the oesophagus enters the stomach.<br><br>The oesophageal hiatus is T10; the gastroesophageal junction is at T11."},
/*781*/ {"q":"Anterior 2/3rd of interventricular septum supplied by which artery:","o":["RCA","Marginal","Circumflex","LAD"],"a":3,"e":"The anterior two-thirds of the interventricular septum is supplied by the left anterior descending (LAD) artery.<br><br>The RCA supplies the posterior third; the anterior part is LAD."},
/*782*/ {"q":"Ligament pierced at last during epidural is:","o":["Posterior spinal ligament","Anterior spinal ligament","Supraspinous ligament","Ligamentum flavum"],"a":3,"e":"During an epidural the last structure pierced before the epidural space is the ligamentum flavum.<br><br>The supraspinous/interspinous ligaments are pierced earlier; the last layer before the epidural space is the ligamentum flavum."},
/*783*/ {"q":"Patient had internal jugular lymph node biopsy in neck, then developed numbness of ear lobe; which nerve got injured:","o":["Greater auricular nerve","Auriculotemporal nerve","Recurrent laryngeal nerve","Vagus nerve"],"a":0,"e":"The great auricular nerve supplies the ear lobe and is at risk during neck node biopsy.<br><br>The recurrent laryngeal/vagus are deeper; ear-lobe numbness after neck node biopsy indicates great auricular nerve injury."},
/*784*/ {"q":"Supination of arm is done by which muscles beside supinator:","o":["Triceps brachii","Deltoid","Supraspinatus","Biceps brachii"],"a":3,"e":"Besides the supinator, the biceps brachii is the powerful supinator of the forearm (especially when flexed).<br><br>Triceps and deltoid do not supinate; besides supinator, biceps brachii is the powerful supinator (especially when flexed)."},
/*785*/ {"q":"Boy jumped from height and talus is injured, now has pain in foot; what will happen now:","o":["Deltoid ligament weakness","Medial longitudinal arch affected","Lateral longitudinal arch affected","Transverse arch affected"],"a":1,"e":"The talus is the main support of the medial longitudinal arch, so its injury affects that arch.<br><br>The cuboid keystones the lateral arch; the talus supports the medial longitudinal arch, so its injury affects that arch."},
/*786*/ {"q":"Direct inguinal hernia is due to defect in:","o":["External intercostal","External oblique","Fascia transversalis","Rectus abdominis"],"a":2,"e":"A direct inguinal hernia protrudes through a weakness in the transversalis fascia of Hesselbach's triangle.<br><br>An indirect hernia passes the deep ring; a direct inguinal hernia is a weakness of the transversalis fascia in Hesselbach's triangle."},
/*787*/ {"q":"Lumbar hernia protrudes from:","o":["Superior lumbar triangle","Inferior lumbar triangle","Medial to intercostal","Lateral to intercostal"],"a":1,"e":"A lumbar hernia commonly protrudes through the inferior lumbar (Petit's) triangle.<br><br>The superior (Grynfeltt) triangle is deeper; a lumbar hernia commonly protrudes through the inferior (Petit) triangle."},
/*788*/ {"q":"Deep structure in popliteal fossa:","o":["Popliteal artery","Popliteal vein","Tibial nerve","Common peroneal nerve"],"a":0,"e":"The popliteal artery is the deepest structure in the popliteal fossa, lying on the joint capsule.<br><br>The tibial nerve is superficial; the deepest is the popliteal artery."},
/*789*/ {"q":"Pericardiocentesis is best performed by passing a needle:","o":["The fourth intercostal space","The 5th intercostal space left to sternum","The second intercostal space at the midclavicular line","The second intercostal space at the right sternal angle"],"a":1,"e":".<br><br>A right parasternal or midclavicular approach risks vessels/lung; the keyed pericardiocentesis route here is the left 5th space parasternal."},
/*790*/ {"q":"Placenta attached but not penetrating through myometrium:","o":["Accreta","Percreta","Increta","Previa"],"a":0,"e":"Placenta accreta is abnormal adherence to the myometrium without invasion into it.<br><br>Increta invades the myometrium and percreta penetrates through; superficial adherence is accreta."},
/*791*/ {"q":"Gold standard investigation for placenta previa:","o":["Pelvic USG","Pelvic MRI","Transvaginal USG","Doppler USG"],"a":2,"e":"Transvaginal ultrasound is the gold standard investigation for diagnosing placenta previa.<br><br>Pelvic/Doppler scans are less precise; transvaginal ultrasound is the gold standard for diagnosing placenta previa."},
/*792*/ {"q":"Right shift of oxygen dissociation curve is caused by:","o":["Increase PH","Acidosis","Decrease PCO2","Decrease H+ ions"],"a":1,"e":"Acidosis (Bohr effect) shifts the oxygen dissociation curve to the right, decreasing haemoglobin affinity for oxygen.<br><br>Alkalosis/low PCO2 shift the curve left; acidosis (Bohr effect) shifts the curve right, lowering haemoglobin oxygen affinity."},
/*793*/ {"q":"Fluid coming from PCT to loop of Henle has which feature:","o":["More HCO3 than plasma","More sodium than plasma","Is hypertonic","Is isotonic with plasma"],"a":3,"e":"Fluid leaving the proximal convoluted tubule is isotonic with plasma because reabsorption there is isosmotic.<br><br>PCT reabsorption is iso-osmotic, so fluid entering the loop of Henle is isotonic with plasma, not hypertonic."},
/*794*/ {"q":"What is allele:","o":["Non identical gene at same locus","Same genes at same locus","Non alternative types of genes at same locus","Same gene at different locus"],"a":0,"e":"An allele is an alternative (non-identical) form of a gene occupying the same locus on homologous chromosomes.<br><br>Identical or different-locus genes are not alleles; an allele is a non-identical (alternative) gene form at the same locus."},
/*795*/ {"q":"Diabetic patient has hot red nodules with multiple sites of discharge; diagnose is:","o":["Furuncle","Carbuncle","Abscess","Cellulitis"],"a":1,"e":"A painful red nodule with multiple discharging sinuses in a diabetic is a carbuncle.<br><br>A furuncle has a single point; the multi-loculated multi-discharge lesion is a carbuncle."},
/*796*/ {"q":"A 24-year-old lady who is 6 months pregnant complains of generalized lethargy, weakness, MCV 58 fl, Hb 9.8 g/dl, serum ferritin 150 mg/dl; diagnose is:","o":["Anemia of chronic disease","Iron deficiency anemia","Thalassemia trait","Megaloblastic anemia"],"a":2,"e":"Microcytosis with a normal/high ferritin in pregnancy indicates thalassaemia trait rather than iron deficiency.<br><br>Iron deficiency has low ferritin; normal ferritin with microcytosis is thalassaemia trait."},
/*797*/ {"q":"A 6-year-old girl brought by mother with pallor, lethargy; CBC shows low MCV, low MCHC, Hb 6.6; diagnose is:","o":["Thalassemia trait","Thalassemia major","Iron deficiency anemia","Megaloblastic anemia"],"a":2,"e":".<br><br>Thalassaemia trait has near-normal Hb; severe microcytic hypochromic anaemia with very low Hb here is keyed to iron deficiency."},
/*798*/ {"q":"A patient after 1 year of gastrectomy has anemia, fatigue, raised MCV 110, peripheral numbness and tingling sensation; which type of anemia:","o":["Pernicious anemia","Iron deficiency anemia","Thalassemia","Anemia of chronic disease"],"a":0,"e":"Macrocytic anaemia with neurological features years after gastrectomy is pernicious anaemia from B12 deficiency.<br><br>Iron deficiency is microcytic; macrocytic anaemia with neuropathy years after gastrectomy is pernicious anaemia (B12 loss)."},
/*799*/ {"q":"A person with history of smoking and drinking for many years; on endoscopy there is a mass in middle third of esophagus; what could it likely be:","o":["Adenocarcinoma","Squamous cell carcinoma","Barrett esophagus","Chronic esophagitis"],"a":1,"e":"Mid-oesophageal carcinoma in a smoker and drinker is most commonly squamous cell carcinoma.<br><br>Lower-third adenocarcinoma relates to Barrett/GERD; the mid-oesophageal smoking-related cancer is squamous cell carcinoma."},
/*800*/ {"q":"Indirect action of parathyroid hormone:","o":["Phosphate absorption","Phosphate excretion","Inactivate vitamin D","Stimulating conversion of inactive form of vit D to active form and Ca absorption"],"a":3,"e":"PTH indirectly raises calcium by stimulating renal conversion of vitamin D to its active form, increasing intestinal calcium absorption.<br><br>PTH directly handles phosphate/calcium in bone and kidney; its indirect action is activating vitamin D to boost gut calcium absorption."},
/*801*/ {"q":"Parkinson's patient aspirated fluid on lying; it goes in:","o":["Posterior segment of right upper lobe","Apical segment of right lower lobe","Lateral segment of right upper lobe","Right upper lobe"],"a":1,"e":"Aspiration in the supine position passes into the apical (superior) segment of the right lower lobe.<br><br>Sitting aspiration goes to the posterior basal segment; supine goes to the apical segment of the right lower lobe."},
/*802*/ {"q":"A 14-year-old boy eats fast food only, peripheral blood picture of macrocyte; diagnosis is:","o":["Folic acid deficiency","Iron deficiency anemia","Thalassemia","Sideroblastic anemia"],"a":0,"e":"Macrocytic anaemia from a poor fast-food diet in an adolescent is most likely folic acid deficiency.<br><br>Iron deficiency is microcytic; a macrocytic blood picture from a poor fast-food diet indicates folate deficiency."},
/*803*/ {"q":"Regarding urinary bladder, true is:","o":["Motor supply by sympathetic and parasympathetic","Posterior surface not covered with peritoneum","Columnar epithelium","Supplied by L3-4"],"a":0,"e":"The urinary bladder has motor supply from both sympathetic and parasympathetic systems.<br><br>It is lined by transitional epithelium and partly peritoneum-covered; the true statement is its dual sympathetic/parasympathetic motor supply."},
/*804*/ {"q":"A patient with peptic ulcer has epigastric pain carried by which of following nerve:","o":["Intercostal nerve","Greater splanchnic nerve","Lesser splanchnic nerve","Least splanchnic nerve"],"a":1,"e":"Foregut (stomach/duodenum) visceral pain is carried by the greater splanchnic nerve (T5-T9).<br><br>Intercostal/lesser splanchnic supply other levels; foregut (peptic ulcer) pain is carried by the greater splanchnic nerve (T5-T9)."},
/*805*/ {"q":"When needle is passed to drain fluid from hydrocele, which structure is not pierced:","o":["Dartos fascia","Cremasteric fascia","Skin","Tunica albuginea"],"a":3,"e":"Draining a hydrocele the needle does not pierce the tunica albuginea of the testis itself.<br><br>The dartos, cremasteric fascia and skin are all traversed; the tunica albuginea of the testis itself is not pierced."},
/*806*/ {"q":"Foot is permanently dorsiflexed and everted; which nerve is damaged:","o":["Common peroneal nerve","Superficial peroneal nerve","Deep peroneal nerve","Saphenous nerve"],"a":3,"e":".<br><br>Common/deep peroneal injury causes foot drop; this fixed dorsiflexed everted foot is keyed to the saphenous/tibial-loss option."},
/*807*/ {"q":"A patient with wheezing, nasal congestion, runny nose and fever; biopsy of nasal mucosa shows degranulation of:","o":["Mast cells","Basophils","Macrophages","Monocyte"],"a":0,"e":"Allergic rhinitis features mast cell degranulation releasing histamine in the nasal mucosa.<br><br>Basophils circulate and macrophages phagocytose; allergic rhinitis features mast cell degranulation in the nasal mucosa."},
/*808*/ {"q":"HLA B27 is associated with:","o":["Reye syndrome","Uveitis","RA","SLE"],"a":1,"e":"HLA-B27 is associated with ankylosing spondylitis, reactive arthritis, psoriatic arthritis and acute anterior uveitis.<br><br>RA and SLE have other HLA links; HLA-B27 associates with acute anterior uveitis and the spondyloarthropathies."},
/*809*/ {"q":"Antibodies against acetylcholine receptor; what is your diagnose:","o":["Multiple sclerosis","Parkinson disease","Myasthenia gravis","Lambert-Eaton syndrome"],"a":2,"e":"Autoantibodies against postsynaptic acetylcholine receptors cause myasthenia gravis.<br><br>Lambert-Eaton targets presynaptic calcium channels; AChR antibodies indicate myasthenia gravis."},
/*810*/ {"q":"A doctor advised a lady to take brown wheat and bread for carbohydrate metabolism; which vitamin is necessary:","o":["Riboflavin","Thiamine","Biotin","Pantothenic"],"a":1,"e":"Thiamine (B1) is the key vitamin cofactor for carbohydrate metabolism (pyruvate dehydrogenase).<br><br>Riboflavin/biotin serve other pathways; thiamine (B1) is the key cofactor for carbohydrate metabolism (pyruvate dehydrogenase)."},
/*811*/ {"q":"For extensive metastasis, bone scan is necessary for which cancer:","o":["Melanoma","Squamous cell carcinoma","Basal cell carcinoma","Retinoblastoma"],"a":3,"e":".<br><br>Melanoma and skin carcinomas rarely need bone scans; among these the metastatic bone scan is keyed to retinoblastoma."},
/*812*/ {"q":"Type of change in metaplasia is:","o":["Polarity change","Irreversible change","Necrotic change","Functional and morphological change"],"a":3,"e":"Metaplasia is a reversible change of one mature cell type to another, with functional and morphological change.<br><br>Metaplasia is reversible and not necrotic; it is a functional and morphological change of one mature cell type to another."},
/*813*/ {"q":"Patient has cavernous sinus thrombosis; which nerve will be affected:","o":["Vagus","Abducent","Trochlear","Facial"],"a":1,"e":"The abducens nerve (CN VI) runs freely through the cavernous sinus and is the first affected in cavernous sinus thrombosis.<br><br>Trochlear/facial run differently; the abducens nerve lies free within the cavernous sinus and is first affected in its thrombosis."},
/*814*/ {"q":"Vein accompanying left circumflex artery is which of following:","o":["Middle cardiac vein","Anterior cardiac vein","Posterior cardiac vein","Great cardiac vein"],"a":3,"e":"The great cardiac vein accompanies the left circumflex artery in the coronary sulcus (LCX in the left coronary sinus).<br><br>The middle/anterior cardiac veins drain other areas; the great cardiac vein accompanies the left circumflex artery."},
/*815*/ {"q":"60-year-old man with painless testicular swelling and raised LDH; diagnosis:","o":["Teratoma","Choriostoma","Lymphoma","Granulosa cell tumor"],"a":2,"e":"A painless testicular swelling in an older man with raised LDH is most likely testicular lymphoma.<br><br>Teratomas occur in younger men; in old age with raised LDH it is lymphoma."},
/*816*/ {"q":"Which of the following structures connects liver to the lesser curvature of stomach:","o":["Lesser omentum","Peritoneal ligament","Hepatogastric ligament","Falciform ligament"],"a":0,"e":"The lesser omentum (hepatogastric and hepatoduodenal ligaments) connects the liver to the lesser curvature of the stomach.<br><br>The falciform ligament connects to the abdominal wall; the lesser omentum (hepatogastric part) connects liver to lesser curvature."},
/*817*/ {"q":"Right and left subphrenic space is divided by:","o":["Falciform ligament","Morrison pouch","Foramen of Winslow","Lesser omentum"],"a":0,"e":"The falciform ligament divides the subphrenic space into right and left compartments.<br><br>Morrison's pouch is the hepatorenal recess; the falciform ligament divides the subphrenic space into right and left."},
/*818*/ {"q":"Accessory pancreatic duct, if present, drains:","o":["Uncinate process","Tail","Body","Head"],"a":3,"e":"The accessory pancreatic duct (of Santorini) drains the head of the pancreas into the minor duodenal papilla.<br><br>The duct of Wirsung drains the body/uncinate; the accessory duct of Santorini drains the head into the minor papilla."},
/*819*/ {"q":"Main feature of malignancy is:","o":["Increase N/C ratio","Mitotic figure","Pleomorphism","Necrosis"],"a":2,"e":".<br><br>Increased N/C ratio and mitoses are features too, but among these the keyed main feature of malignancy is pleomorphism."},
/*820*/ {"q":"A male with history of sexual activity present with painless chancre and irregular eversion on scrotum, may metastasize to brain and not being treated; likely condition is:","o":["Condyloma","Lymphogranuloma","Syphilis","Neisseria"],"a":2,"e":"A painless chancre after sexual contact is the primary lesion of syphilis (Treponema pallidum).<br><br>Condyloma and LGV differ; a painless chancre after sexual contact is the primary lesion of syphilis (Treponema pallidum)."},
/*821*/ {"q":"An athlete who got an injection to delay menstruation at 14th day of cycle; what was that injection:","o":["FSH","Cortisol","HCG","Progesterone"],"a":3,"e":".<br><br>FSH/HCG/cortisol do not delay menses; the keyed agent given to postpone menstruation here is progesterone."},
/*822*/ {"q":"Patient after vaginal delivery developed fecal incontinence, likely damage to internal anal sphincter; suitable investigation is:","o":["MRI","Anal manometry","Pudendal nerve stimulation test","Perineal nerve test"],"a":1,"e":"Anal manometry assesses internal anal sphincter function in faecal incontinence after delivery.<br><br>MRI/nerve tests assess other components; internal anal sphincter function after delivery is assessed by anal manometry."},
/*823*/ {"q":"A patient had RTA, he does not know recent events but remembers his school events; where is the lesion:","o":["Arcuate","Amygdala","Hippocampus","Frontal lobe"],"a":2,"e":"Anterograde amnesia with preserved remote memory localises to the hippocampus.<br><br>Frontal-lobe lesions affect executive function; anterograde amnesia with intact remote memory localises to the hippocampus."},
/*824*/ {"q":"A woman has no difficulty in walking but cannot stand from sitting position due to weakness of which muscle:","o":["Gluteus minimus","Gluteus intermediate","Gluteus maximus","Sartorius"],"a":2,"e":"Difficulty rising from sitting indicates gluteus maximus (hip extensor) weakness from inferior gluteal nerve damage.<br><br>Difficulty walking would suggest other muscles; inability to rise from sitting indicates gluteus maximus (hip extensor) weakness."},
/*825*/ {"q":"Which of the following is a pain mediator in inflammation:","o":["Bradykinin","Prostaglandin","Histamine","C3b"],"a":0,"e":"Bradykinin is the principal mediator producing pain in inflammation (with prostaglandins potentiating it).<br><br>Histamine and prostaglandins potentiate, but bradykinin is the principal mediator producing pain in inflammation."},
/*826*/ {"q":"Joint which is fibrocartilaginous and amphiarthrosis is:","o":["Sternoclavicular","Acromioclavicular","Intervertebral","Distal tibiofibular"],"a":3,"e":".<br><br>Sternoclavicular/intervertebral are different joint types; the fibrocartilaginous amphiarthrosis here is the distal tibiofibular joint."},
/*827*/ {"q":"Patient presents with severe pain in ankle and develops ecchymosis on the second day; he can stand on his toes but it is painful; cause:","o":["Rupture of Achilles tendon","Rupture of plantaris tendon","Rupture of tibial tendon","Medial malleolar damage"],"a":1,"e":"Preserved (though painful) toe-standing with delayed bruising indicates a plantaris tendon rupture rather than Achilles.<br><br>Achilles rupture abolishes toe-standing; preserved function is plantaris rupture."},
/*828*/ {"q":"Plantaris is supplied by which nerve:","o":["Tibial nerve","Common peroneal nerve","Deep peroneal nerve","Sural nerve"],"a":0,"e":"The plantaris muscle is supplied by the tibial nerve.<br><br>Common peroneal/sural are sensory or anterior compartment; the plantaris muscle is supplied by the tibial nerve."},
/*829*/ {"q":"Most widely used technique to detect tumor cells is:","o":["CBC","Tumor markers","Peripheral smear","Ferritin"],"a":1,"e":"Tumour markers are the most widely used method for detecting and monitoring tumour cells.<br><br>CBC and ferritin are non-specific; tumour markers are the most widely used method to detect and follow malignancy."},
/*830*/ {"q":"An alcoholic patient presented with hemorrhage near hair follicles, petechiae, bruises, skin and mucosal lesion with poor healing; collagen defective is which of following:","o":["Hepatocytes","Lymphocytes","Fibroblasts","Macrophages"],"a":2,"e":"Defective collagen synthesis in scurvy/poor healing localises to fibroblasts, the collagen-producing cells.<br><br>Hepatocytes and macrophages do not make collagen; defective scurvy-like collagen synthesis lies in fibroblasts."},
/*831*/ {"q":"Anterior dislocation of femur on tibia; ligament damaged is:","o":["Anterior cruciate ligament","Posterior cruciate ligament","Collateral ligament","Both anterior posterior"],"a":1,"e":"Anterior displacement of the femur on the tibia indicates posterior cruciate ligament injury.<br><br>Anterior tibial displacement is ACL injury; anterior displacement of the femur on the tibia indicates posterior cruciate damage."},
/*832*/ {"q":"cGMP is secondary receptor (second messenger) of:","o":["Oxytocin","Tyrosin","ANP","ACTH"],"a":2,"e":"Atrial natriuretic peptide (ANP) acts via the cGMP second messenger system.<br><br>Oxytocin/ACTH use Gq/Gs; atrial natriuretic peptide (ANP) signals through the cGMP second messenger."},
/*833*/ {"q":"A female with signs and symptoms of hyperprolactinoma diagnosed as pituitary adenoma; growth of this tumor anteriorly will compress which structure:","o":["Cavernous sinus","Optic nerve","Optic chiasma","Optic tract"],"a":1,"e":".<br><br>Lateral growth hits the cavernous sinus and superior hits the chiasm; anterior growth from a pituitary adenoma compresses the optic nerve."},
/*834*/ {"q":"A man works in a factory and develops bladder cancer; which carcinogen causes bladder cancer:","o":["Nitrosamines","Hydrocarbons","Vinyl chloride","Azo dye"],"a":1,"e":".<br><br>Nitrosamines target the stomach; aromatic hydrocarbons (aniline dyes) are the classical occupational bladder carcinogens."},
/*835*/ {"q":"A patient undergoing ascitic tap for ascites; fluid at costodiaphragmatic recess; where to pass needle:","o":["T10 midaxillary","T10 mid clavicle","T9 mid clavicle","T8 mid clavicle"],"a":0,"e":"An ascitic/pleural tap at the costodiaphragmatic recess is performed around the T10 midaxillary line.<br><br>Higher levels risk the lung; the costodiaphragmatic recess is tapped safely at the T10 midaxillary line."},
/*836*/ {"q":"A baby after an obstructed delivery presented with inability to abduct the arm, loss of flexion and loss of supination of arm at elbow joint due to damage to:","o":["Klumpke paralysis","Erb's palsy","Radial nerve","Ulnar nerve"],"a":1,"e":"Upper trunk (C5-C6) injury during delivery causes Erb's palsy with loss of abduction, flexion and supination.<br><br>Klumpke affects the lower trunk; the waiter's-tip deformity is Erb's palsy."},
/*837*/ {"q":"A PPD tuberculin test done; after 40 hours 15 mm erythema is noticed; cells responsible for erythema are:","o":["Helper T cell","Cytotoxic T cell","NK cells","CD8 cells"],"a":0,"e":"The delayed-type hypersensitivity tuberculin reaction is mediated by CD4 helper T cells (and macrophages).<br><br>Cytotoxic and NK cells lyse cells; the tuberculin (Mantoux) DTH reaction is mediated by CD4 helper T cells and macrophages."},
/*838*/ {"q":"Female patient on HRT having risk of which of following:","o":["Ovarian CA","Endometrial CA","Breast CA","Thromboembolism"],"a":3,"e":".<br><br>Ovarian/endometrial cancer risks differ; combined HRT mainly increases venous thromboembolism risk."},
/*839*/ {"q":"Blood supply of thalamus, subthalamus and hypothalamus by branch of which artery:","o":["MCA","ACA","Posterior communicating","Anterior choroidal"],"a":3,"e":".<br><br>MCA/ACA supply cortex; the diencephalon (thalamus, subthalamus, hypothalamus) is supplied by the anterior choroidal artery and perforators."},
/*840*/ {"q":"After injury patient complains that his arm cannot move forward as before; this is due to lesion of which part of brachial plexus:","o":["Upper trunk","Posterior cord","Posterior trunk","Lower cord"],"a":0,"e":"Inability to elevate/flex the arm forward indicates an upper trunk (C5-C6) brachial plexus lesion.<br><br>Posterior cord and lower trunk give other deficits; loss of forward arm elevation/abduction localises to the upper trunk (C5-C6)."},
/*841*/ {"q":"A patient has lateral chest wall blow injury beneath right arm, after which vertebral column and scapula become prominent and move posteriorly; which nerve in close relation is damaged:","o":["Accessory nerve","Axillary nerve","Long thoracic nerve","Thoracodorsal"],"a":2,"e":"Long thoracic nerve injury paralyses serratus anterior, causing winging of the scapula.<br><br>Accessory/axillary nerves serve other muscles; serratus anterior palsy with winged scapula is long thoracic nerve injury."},
/*842*/ {"q":"A patient can't abduct and adduct his fingers; this is due to damage of which nerve:","o":["Ulnar nerve","Median nerve","Radial nerve","Axillary nerve"],"a":0,"e":"Finger abduction and adduction (interossei) is supplied by the deep branch of the ulnar nerve.<br><br>Median/radial nerves do other movements; finger abduction and adduction (interossei) is supplied by the ulnar nerve."},
/*843*/ {"q":"After an automobile accident splenectomy done; after two months patient presents to emergency with septic shock and fever; causative organism for this overwhelming infection is:","o":["Klebsiella","Mycoplasma","Pseudomonas","Strep pneumonia"],"a":3,"e":"Post-splenectomy overwhelming infection is most commonly due to encapsulated Streptococcus pneumoniae.<br><br>Pseudomonas/Klebsiella are nosocomial; post-splenectomy overwhelming infection is classically caused by Streptococcus pneumoniae."},
/*844*/ {"q":"Post-op wound having greenish pus discharge; organism involved is:","o":["Staph aureus","Pseudomonas","Actinomycetes","Streptococcus"],"a":1,"e":"Greenish (blue-green) pus is characteristic of Pseudomonas aeruginosa pyocyanin pigment.<br><br>Staph aureus gives yellow pus; greenish (blue-green) pus from pyocyanin pigment indicates Pseudomonas aeruginosa."},
/*845*/ {"q":"Pathogenesis of myasthenia gravis defect will be in:","o":["Acetylcholine receptors destroyed","Acetylcholine receptor increased","Acetylcholine release more","Acetylcholine act on muscles"],"a":0,"e":"Myasthenia gravis is caused by autoantibody-mediated destruction of postsynaptic acetylcholine receptors.<br><br>Lambert-Eaton hits presynaptic calcium channels; myasthenia gravis is antibody destruction of postsynaptic acetylcholine receptors."},
/*846*/ {"q":"Final wound strength is done by which type of collagen:","o":["Type 3","Type 1","Type 4","Type 2"],"a":1,"e":"Late wound remodelling replaces type III with type I collagen, providing final tensile strength.<br><br>Type III dominates early; final strength is from type I collagen."},
/*847*/ {"q":"Deep plantar artery is branch of:","o":["Popliteal","Peroneal","Posterior interosseous","Dorsalis pedis"],"a":3,"e":"The deep plantar artery is a branch of the dorsalis pedis artery, completing the plantar arch.<br><br>Popliteal/peroneal supply other regions; the deep plantar artery branches from the dorsalis pedis to complete the plantar arch."},
/*848*/ {"q":"Prostate mainly drains into the:","o":["Internal iliac and sacral lymph node","External and inguinal lymph node","Para-aortic lymph node","Superficial inguinal lymph node"],"a":0,"e":"The prostate drains chiefly to the internal iliac (and sacral) lymph nodes.<br><br>External and para-aortic nodes are not primary; the prostate drains chiefly to the internal iliac and sacral nodes."},
/*849*/ {"q":"An old patient with enlarged prostate, marked increase in PSA up to 20 ng/ml, weight loss, MRI shows bony metastasis; route of spread of prostate CA to vertebrae:","o":["Lumbar plexus","Pampiniform plexus","Vertebral venous plexus","Pelvic plexus"],"a":2,"e":"Prostate carcinoma metastasises to the vertebral column via the valveless Batson vertebral venous plexus.<br><br>Pelvic and lumbar plexus are nerve plexuses; vertebral metastases from prostate spread via the valveless Batson vertebral venous plexus."},
/*850*/ {"q":"Fascia of Scarpa extends to:","o":["Membranous layer of urogenital diaphragm","Scarpa fascia of abdomen","Scarpa fascia of thigh","Deep fascia of abdomen"],"a":0,"e":"Scarpa's fascia continues as the membranous (dartos/Colles) layer of the urogenital region and superficial perineal pouch.<br><br>Deep abdominal fascia is layered separately; Scarpa's fascia continues into the perineum as the membranous (Colles) layer."},
/*851*/ {"q":"Corneal opacity is a side effect of which drug:","o":["Ethambutol","Chlorpromazine","Chloroquine","Thioridazine"],"a":2,"e":"Chloroquine causes corneal deposits/opacity (and retinopathy) as a characteristic side effect.<br><br>Thioridazine causes retinal deposits; corneal opacity is from chloroquine."},
/*852*/ {"q":"Which of the following is last to appear normal in blood after hemorrhage:","o":["Hematocrit","Hemoglobin","RBCs","Blood volume"],"a":2,"e":".<br><br>Hb and haematocrit normalise after fluid replacement; full red-cell mass takes longest to recover (last to return to normal)."},
/*853*/ {"q":"Patient after RTA having above sacral region of spinal cord damage; which effect:","o":["Bladder injury","Atonic bladder","Detrusor muscle injury","Urge incontinence"],"a":3,"e":"A lesion above the sacral cord (suprasacral, sympathetic) produces a spastic/automatic bladder with urge incontinence.<br><br>Lesions below the sacral cord give atonic/autonomic bladder; suprasacral injury produces a spastic bladder with urge incontinence."},
/*854*/ {"q":"Child with periorbital edema and generalized edema due to:","o":["Hypoalbuminemia and increase salt water retention","Hyperalbuminemia","Increase salt retention","Decrease salt retention"],"a":0,"e":"Nephrotic oedema in a child is due to hypoalbuminaemia with secondary salt and water retention.<br><br>Hyperalbuminaemia/increased retention alone is incorrect; nephrotic oedema is hypoalbuminaemia with secondary salt-water retention."},
/*855*/ {"q":"A patient of mitral stenosis having dyspnea and difficulty in swallowing; dilatation of which structure causes dysphagia by compressing on the esophagus:","o":["Left atrium","Aortic arch","Left bronchus","Right ventricle"],"a":0,"e":"An enlarged left atrium in mitral stenosis compresses the oesophagus, causing dysphagia.<br><br>Right ventricular or aortic enlargement does not press the oesophagus; an enlarged left atrium in mitral stenosis causes the dysphagia."},
/*856*/ {"q":"A child born with urine coming out from umbilicus; diagnosed as patent lumen of allantois which results in which of following:","o":["Urachal fistula (patent urachus)","Urachal cyst","Urachal sinus","Extrophy of bladder"],"a":0,"e":"Urine discharge from the umbilicus is due to a patent urachus (urachal fistula).<br><br>A urachal cyst or sinus is closed; complete patent communication of the allantois causes a urachal fistula draining urine at the umbilicus."},
/*857*/ {"q":"Colicky pain referred to anterior part of thigh by:","o":["Ilioinguinal","Iliohypogastric","Genitofemoral nerve","Tibial nerve"],"a":2,"e":"Ureteric colic refers pain to the groin and anterior/medial thigh via the genitofemoral nerve.<br><br>Ilioinguinal supplies medial thigh; ureteric colic refers to the anterior thigh via the genitofemoral nerve."},
/*858*/ {"q":"After gunshot injury to spinal cord patient cannot extend the knee; at which level injury to spinal cord occur:","o":["L2-3","L3-4","L4-5","L5-S1"],"a":1,"e":"Knee extension (quadriceps, femoral nerve) is mediated by the L3-L4 segments, so injury there abolishes it.<br><br>L4-5 supplies extension at hip; knee extension (quadriceps, femoral nerve) is mediated by L3-4 segments."},
/*859*/ {"q":"On electron microscopy, PSGN shows:","o":["Subendothelial deposits","Subepithelial deposits","Tramtrack appearance","Spike and dome appearance"],"a":1,"e":"Post-streptococcal glomerulonephritis shows subepithelial humps (electron-dense deposits) on electron microscopy.<br><br>Subendothelial deposits suggest lupus nephritis; PSGN shows subepithelial humps on electron microscopy."},
/*860*/ {"q":"Vomiting center located in:","o":["Basal ganglia","Tractus solitarii","Nucleus ambiguus","Cortex"],"a":1,"e":"The vomiting centre and chemoreceptor trigger zone lie in the medulla within the area postrema and nucleus tractus solitarius.<br><br>The nucleus ambiguus is motor; the vomiting/CTZ centre lies in the medullary nucleus tractus solitarius and area postrema."},
/*861*/ {"q":"In a patient, loss of proprioception occurs after RTA; what is underlying mechanism:","o":["Lateral column lesion","Lateral inhibition","Posterior inhibition","Field blockage"],"a":1,"e":"Loss of proprioception is due to a posterior (dorsal) column lesion, with lateral inhibition being the related sensory mechanism.<br><br>Field blockade is anaesthetic; sharpening of proprioceptive dorsal column signals is achieved through lateral inhibition."},
/*862*/ {"q":"Patient has excruciating right leg pain; anterolateral chordotomy was performed; which tract was involved:","o":["Right lateral spinothalmic tract","Left anterior spinothalmic tract","Dorsal column","Left lateral spinothalamic tract"],"a":3,"e":"Anterolateral cordotomy for contralateral leg pain sections the lateral spinothalamic tract on the opposite (left) side.<br><br>Anterolateral cordotomy for contralateral leg pain sections the spinothalamic tract on the opposite (left) side."},
/*863*/ {"q":"A patient with primary amenorrhea, well developed secondary sexual characteristics, has breast but absent uterus; due to abnormal development of:","o":["Mesonephric duct","Paramesonephric duct","Genital tubercle","Mullerian tubercle"],"a":1,"e":"Absent uterus with normal female secondary characteristics indicates failed paramesonephric (Mullerian) duct development.<br><br>The mesonephric duct forms male structures; absent uterus with female phenotype indicates failed paramesonephric duct development."},
/*864*/ {"q":"Absence of limb is due to maldevelopment of which of these:","o":["Somites","Lateral plate mesoderm","Cushions","Ectoderm"],"a":1,"e":"Limbs develop from the lateral plate mesoderm, so its maldevelopment causes limb absence.<br><br>Somites form vertebrae/muscle; limb buds develop from the lateral plate mesoderm, so its maldevelopment causes limb absence."},
/*865*/ {"q":"40-year-old male with jaundice, liver function tests show direct bilirubin 10, ALP 1000, ALT 75, GGT 227; most likely diagnosis:","o":["Intrahepatic cholestasis","Hepatic cholestasis","Bile duct obstruction","Drug induced jaundice"],"a":3,"e":"A markedly raised ALP and GGT with conjugated hyperbilirubinaemia indicates extrahepatic cholestasis.<br><br>Intrahepatic cholestasis has lower ALP; markedly elevated ALP and GGT with hepatitic ALT here is keyed to a drug-induced jaundice."},
/*866*/ {"q":"A pregnant lady with obstructive jaundice features; which investigation will confirm the diagnosis:","o":["GGT","Bilirubin","ALP","AST"],"a":0,"e":"GGT is a sensitive confirmatory marker of cholestatic/obstructive jaundice, especially when checked alongside ALP in pregnancy.<br><br>ALP can rise from placenta in pregnancy; GGT is the confirmatory marker for biliary obstruction (not placental)."},
/*867*/ {"q":"Gastroduodenal artery is branch of:","o":["Celiac artery","Splenic artery","Common hepatic artery","SMA"],"a":2,"e":"The gastroduodenal artery is a branch of the common hepatic artery.<br><br>The splenic artery and SMA do not give it; the gastroduodenal artery branches from the common hepatic artery."},
/*868*/ {"q":"Structure posterior to the lateral arcuate ligament of diaphragm:","o":["Quadratus lumborum","Piriform","Aorta","IVC"],"a":0,"e":"The lateral arcuate ligament arches over quadratus lumborum, which lies posterior to it.<br><br>The aorta and IVC pass medial; the lateral arcuate ligament arches over quadratus lumborum, which lies posterior to it."},
/*869*/ {"q":"After RTA patient on motorcycle fell down, damaged symphysis pubis; which structure is damaged with this:","o":["Rectum","Levator ani","Ischiorectal fossa","Urogenital diaphragm"],"a":3,"e":".<br><br>Rectum and levator ani are not closely attached; symphyseal disruption tears the urogenital diaphragm and underlying urethra."},
/*870*/ {"q":"Origin of external oblique is:","o":["Cartilage of 7-8 ribs","External surface of rib 5-12","9th and 10th rib","External surface of rib 1-4"],"a":1,"e":"The external oblique arises from the external surfaces of the lower eight ribs (ribs 5-12).<br><br>Rib 1-4 or 7-8 origins are incorrect; the external oblique arises from the external surfaces of the lower eight ribs (5-12)."},
/*871*/ {"q":"In Horner syndrome, damage segment is:","o":["T5-6","T3-4","T1-4","T6-8"],"a":2,"e":"Horner syndrome results from interruption of the sympathetic pathway, with the preganglionic neurons arising from the T1-T4 (ciliospinal) segments.<br><br>Higher thoracic segments are too low; Horner sympathetic interruption arises from the T1-T4 ciliospinal pathway."},
/*872*/ {"q":"A young girl complains of dryness of the nose and palate; this would indicate a lesion of which ganglion:","o":["Nodose ganglion","Otic ganglion","Pterygopalatine ganglion","Submandibular ganglion"],"a":2,"e":"The pterygopalatine ganglion supplies secretomotor fibres to the nasal and palatal glands, so its lesion causes dryness there.<br><br>The submandibular ganglion supplies salivary glands; nasal and palatal dryness reflects a pterygopalatine ganglion lesion."},
/*873*/ {"q":"In shaft of humerus fracture, which artery and nerve will be injured:","o":["Profunda brachii artery + radial nerve","Brachial artery + radial nerve","Radial artery + median nerve","Ulnar artery + ulnar nerve"],"a":0,"e":"A mid-shaft humerus fracture injures the radial nerve and profunda brachii artery in the radial groove.<br><br>Brachial/radial artery injuries occur at the elbow/wrist; a mid-shaft humerus fracture damages the radial nerve and profunda brachii in the spiral groove."},
/*874*/ {"q":"Sympathetic supply of jejunum is from:","o":["L1, L2 nerves","S2, S3, S4 nerve","Greater and lesser splanchnic nerves","Pelvic splanchnic nerves"],"a":2,"e":"The jejunum receives sympathetic supply via the greater and lesser splanchnic nerves through the superior mesenteric plexus.<br><br>Pelvic splanchnics are parasympathetic; jejunum sympathetic supply comes via the greater and lesser splanchnic nerves."},
/*875*/ {"q":"Which of the following passes through greater sciatic foramen:","o":["Obturator internus","Pudendal vessels","Pudendal nerve","Piriformis"],"a":3,"e":"The piriformis muscle passes through the greater sciatic foramen.<br><br>The pudendal nerve and vessels re-enter via the lesser foramen; the structure through the greater foramen is piriformis."},
/*876*/ {"q":"Patient in OT undergoing bladder emptying; surgeon passed needle to upper surface of bladder; vessel at risk of damage is:","o":["Deep circumflex artery","Superficial circumflex artery","Inferior epigastric","Superior epigastric"],"a":2,"e":"The inferior epigastric artery is at risk of injury during suprapubic instrumentation of the bladder's upper surface.<br><br>Deep/superficial circumflex arteries lie laterally; a suprapubic needle on the bladder upper surface risks the inferior epigastric artery."},
/*877*/ {"q":"Characteristics of myelofibrosis is:","o":["Howell-Jolly bodies","Tear drop cells","Massive spleen","Hepatomegaly"],"a":1,"e":"Myelofibrosis characteristically shows teardrop-shaped red cells (dacrocytes) on the blood film.<br><br>Howell-Jolly bodies follow splenectomy; the smear in myelofibrosis classically shows tear-drop poikilocytes."},
/*878*/ {"q":"A patient with hair-on-end appearance on X-ray; what is the next appropriate test for diagnosis:","o":["HB electrophoresis","Bone marrow biopsy","Bone scan","Peripheral blood smears"],"a":0,"e":"A hair-on-end skull appearance indicates a haemoglobinopathy (e.g. thalassaemia), confirmed by haemoglobin electrophoresis.<br><br>Bone marrow biopsy is invasive; a hair-on-end skull suggests a haemoglobinopathy, evaluated next with Hb electrophoresis."},
/*879*/ {"q":"Aortic arch dilation will compress which structure:","o":["Thoracic duct","Left bronchus","Right bronchus","Vagus nerve"],"a":1,"e":"An aortic arch aneurysm compresses the left main bronchus (and recurrent laryngeal nerve).<br><br>The right bronchus is steeper but the aortic arch passes above the left main bronchus, compressing it when dilated."},
/*880*/ {"q":"A patient with localized circumferential subendocardial lateral wall infarct; which artery is involved:","o":["Aorta","Pulmonary artery","LCX","Marginal"],"a":2,"e":"A lateral wall infarct is due to left circumflex (LCX) coronary artery occlusion.<br><br>RCA and marginal supply right/inferior walls; a lateral wall infarct localises to the left circumflex (LCX) territory."},
/*881*/ {"q":"Bone marrow biopsy site in infant:","o":["ASIS","PSIS","Sternum","Tibia"],"a":3,"e":"In infants the tibia is used for bone marrow biopsy because it is accessible and the marrow is active there.<br><br>Adult sites are unsafe in infancy; in infants the tibia is used for bone marrow biopsy."},
/*882*/ {"q":"Bone marrow biopsy site in a 25-year-old adult:","o":["Posterior spine","Femur","Clavicle","Sternum"],"a":3,"e":".<br><br>PSIS is the safer first choice but among these the keyed adult marrow biopsy site is the sternum."},
/*883*/ {"q":"An unmarried female with parotid swelling and no lymph node enlargement; which type of biopsy is used for parotid swelling:","o":["Incisional","Trucut","Excisional","Aspirational"],"a":3,"e":"Fine needle aspiration is the preferred initial biopsy for a parotid swelling to avoid facial nerve injury and tumour seeding.<br><br>Open biopsy risks fistula/seeding; a parotid swelling is sampled with FNAC (aspirational biopsy)."},
/*884*/ {"q":"B cell markers used for their identification in a tumour:","o":["CD 21","CD 23","CD 19 20","CD 15"],"a":2,"e":"CD19 and CD20 are the characteristic B-lymphocyte surface markers used to identify B-cell tumours.<br><br>CD15 and CD23 mark other lineages; CD19 and CD20 are the standard B-cell identification markers."},
/*885*/ {"q":"A woman with history of trauma to head and neck region having lesion on tongue, protrusion of tongue deviated to the left side; the nerve most likely involved is:","o":["Left hypoglossal","Right hypoglossal","Glossopharyngeal nerve","Vagus nerve"],"a":0,"e":"Tongue deviation toward the lesion side on protrusion indicates an ipsilateral (left) hypoglossal nerve lower motor neuron lesion.<br><br>An upper motor neuron lesion deviates the tongue away; tongue deviation toward the lesion indicates an ipsilateral hypoglossal LMN lesion."},
/*886*/ {"q":"Right accessory hepatic artery arises from:","o":["Celiac","SMA","IMA","Short gastric"],"a":1,"e":"An accessory or replaced right hepatic artery commonly arises from the superior mesenteric artery.<br><br>The celiac/IMA do not give it; an accessory or replaced right hepatic artery commonly arises from the SMA."},
/*887*/ {"q":"70-year-old man with renal transplant 2 years back, now complicated pneumonia not responding to antibiotics; bronchoalveolar lavage shows boat-shaped cyst; organism is:","o":["Pneumocystis jiroveci","Candida albicans","Mycoplasma tuberculosis","Treponema pallidum"],"a":0,"e":"Boat/cup-shaped cysts in BAL of an immunosuppressed transplant patient with refractory pneumonia indicate Pneumocystis jiroveci.<br><br>Bacterial pneumonias respond to standard antibiotics; refractory pneumonia in an immunosuppressed transplant patient with boat-shaped cysts is Pneumocystis jiroveci."},
/*888*/ {"q":"First branch of abdominal aorta:","o":["Superior mesenteric","Celiac trunk","Suprarenal","Inferior mesenteric"],"a":1,"e":"The celiac trunk is the first major ventral branch of the abdominal aorta.<br><br>The SMA arises below it; the first branch is the celiac trunk."},
/*889*/ {"q":"After femoral hernia repair, swelling over incision site due to damage of:","o":["Femoral vein","Femoral artery","Inferior epigastric artery","Saphenous vein"],"a":0,"e":".<br><br>Femoral artery damage causes pulsatile haematoma; a soft swelling at a femoral hernia repair site indicates femoral vein injury."},
/*890*/ {"q":"Stability of knee joint is by:","o":["Hamstring","Vastus lateralis","Sartorius","Adductor"],"a":1,"e":"Stability of the knee is provided by vastus lateralis (with vastus medialis stabilising the patella).<br><br>Hamstrings flex the knee; medial knee/quadriceps stability is provided by vastus medialis (with vastus lateralis as the keyed option here)."},
/*891*/ {"q":"In RTA, pelvis fracture of anterior inferior iliac spine causes avulsion of which muscle:","o":["Sartorius","Obturator internus","Adductor longus","Rectus femoris"],"a":3,"e":"The anterior inferior iliac spine is the origin of rectus femoris, so its avulsion damages rectus femoris.<br><br>The ASIS gives sartorius; the AIIS avulsion is rectus femoris."},
/*892*/ {"q":"Knee unlocking muscle is:","o":["Quadricep","Popliteus","Gluteus medius","Vastus lateralis"],"a":1,"e":"Popliteus unlocks the fully extended (locked) knee by laterally rotating the femur on the tibia.<br><br>Quadriceps locks the knee; the unlocker is popliteus."},
/*893*/ {"q":"A patient with painless testicular swelling diagnosed as testicular carcinoma; it drains into which group of lymph nodes:","o":["Iliac lymph node","Popliteal lymph nodes","Inguinal lymph nodes","Retro peritoneal lymph node"],"a":3,"e":"Testicular tumours drain to the para-aortic (retroperitoneal) lymph nodes, reflecting the testis's abdominal origin.<br><br>Scrotal skin drains to inguinal nodes; the testis itself drains to retroperitoneal (para-aortic) nodes via its abdominal origin."},
/*894*/ {"q":"Axillary sheath is continuation of which fascia:","o":["Pre-tracheal fascia","Pre-vertebral fascia","Carotid sheath","Renal fascia"],"a":1,"e":"The axillary sheath is a prolongation of the prevertebral fascia of the neck.<br><br>The carotid sheath is its own envelope; the axillary sheath is a downward continuation of the prevertebral fascia."},
/*895*/ {"q":"A low birth weight baby with low-set ears, small jaw, microcephaly, cleft lip and prominent occiput; type of trisomy:","o":["Trisomy 21","Trisomy 11","Trisomy 18","Trisomy 13"],"a":2,"e":"Micrognathia, low-set ears, microcephaly and prominent occiput indicate Edward syndrome (trisomy 18).<br><br>Down syndrome shows flat facies; the small jaw, low-set ears and prominent occiput cluster is Edward syndrome (trisomy 18)."},
/*896*/ {"q":"Female patient came in cardiac OPD with cardiac defect, psychiatric behavior and cleft palate with increased calcium level; likely due to:","o":["Fragile X","Klinefelter","Down","DiGeorge syndrome"],"a":3,"e":".<br><br>Down syndrome and Fragile X give other phenotypes; cardiac defect with cleft palate, hypocalcaemia and behavioural changes is DiGeorge syndrome."},
/*897*/ {"q":"A newborn baby noted to have a left unilateral cleft lip with no palate abnormality; which developmental defect accounts for this:","o":["Failure of left lateral palatine to fuse with median palatine","Failure of left maxillary prominence to unite with left medial nasal prominence","Failure of right and left medial nasal prominences to merge","Failure of left maxillary process to fuse with median nasal process"],"a":3,"e":"Unilateral cleft lip is failure of the maxillary process to fuse with the medial nasal process on that side.<br><br>Failure of medial nasal merging gives a midline cleft; a unilateral cleft lip is failure of the maxillary process to fuse with the medial nasal process."},
/*898*/ {"q":"Which vertebrae have bifid spinous process:","o":["Lumbar","Thoracic","Cervical","Sacral"],"a":2,"e":"The cervical vertebrae (C2-C6) characteristically have bifid spinous processes.<br><br>Lumbar and sacral spinous processes are not bifid; the cervical vertebrae (C2-C6) characteristically have bifid spinous processes."},
/*899*/ {"q":"A female with wrist pain and numbness in index and ring finger; movement of which hand muscle will be affected:","o":["Adductor pollicis brevis","Abductor pollicis brevis","Extensor pollicis brevis","Opponens digiti minimi"],"a":1,"e":"Carpal tunnel syndrome (median nerve) weakens the abductor pollicis brevis of the thenar eminence.<br><br>Extensor pollicis brevis is radial; carpal tunnel (median) compression weakens abductor pollicis brevis of the thenar eminence."},
/*900*/ {"q":"Man lifted heavy weight, sudden pain in arm, on examination swelling in upper forearm of the muscle which is attached to radial tuberosity:","o":["Biceps brachii","Brachioradialis","Anconeus","Supinator"],"a":0,"e":"The biceps brachii inserts into the radial tuberosity; its rupture bunches up the muscle in the upper arm/forearm.<br><br>Brachioradialis/supinator attach elsewhere; biceps brachii inserts on the radial tuberosity and bunches up in the upper arm when ruptured."},
/*901*/ {"q":"The air-blood barrier in the lungs consists of:","o":["Alveolar type I cells, capillary endothelium and fused basement membrane","Alveolar type II cells","Endothelial cells only","Pericytes"],"a":0,"e":"The air-blood barrier comprises type I pneumocytes, capillary endothelium and their fused basement membranes.<br><br>Type II cells make surfactant; the barrier is type I cell, endothelium and basement membrane."},
/*902*/ {"q":"A girl has bronchial obstruction but alveoli are still aerated and bronchus do not collapse; this is due to which of following:","o":["Sinusoid","Clara cells","Kulshitsky cells","Pores of Kohn"],"a":3,"e":"Collateral ventilation through the pores of Kohn keeps alveoli aerated distal to a bronchial obstruction.<br><br>Sinusoids and Clara cells do not move air; collateral ventilation through the pores of Kohn keeps alveoli aerated past obstruction."},
/*903*/ {"q":"Glans and clitoris lymphatic drainage is into:","o":["Superficial inguinal","Internal iliac","Deep inguinal","Vertical group of superficial inguinal"],"a":2,"e":"The glans penis and clitoris drain to the deep inguinal lymph nodes.<br><br>The skin drains superficial inguinal; the substance of the glans and clitoris drains to the deep inguinal lymph nodes."},
/*904*/ {"q":"A child born with a mass at lumbar region with meningeal tissue and no neural tissue; diagnose is:","o":["Spina bifida with meningocele","Spina bifida with meningomyocele","Oculata","Anencephaly"],"a":0,"e":"A lumbar swelling containing meninges and CSF without neural tissue is a meningocele.<br><br>A meningomyelocele contains neural tissue; a sac of meninges and CSF without neural tissue is a meningocele."},
/*905*/ {"q":"A patient in ICU on a CVP line; blood culture shows growth of gram positive cocci, catalase positive and coagulase negative; most likely etiological agent is:","o":["Staphylococcus aureus","Staphylococcus epidermidis","Streptococcus pyogenes","Enterococcus faecalis"],"a":1,"e":"A catalase-positive, coagulase-negative gram-positive coccus from an indwelling line is Staphylococcus epidermidis.<br><br>S. aureus is coagulase positive; the line-associated coagulase-negative organism is S. epidermidis."},
/*906*/ {"q":"Largest cell in blood is which of among following:","o":["Basophil","Megakaryocyte","Neutrophil","Lymphocyte"],"a":3,"e":"Among circulating blood cells the monocyte is the largest.<br><br>The megakaryocyte is the largest cell in marrow; in circulating blood the largest cell is keyed here to the monocyte/lymphocyte option."},
/*907*/ {"q":"A patient with chorea, mental retardation, depression and memory lapse; the mode of inheritance of this disease is:","o":["X-link recessive","X-link dominant","Autosomal recessive","Autosomal dominant"],"a":3,"e":"Huntington disease (chorea with dementia) is inherited in an autosomal dominant manner.<br><br>Recessive disorders typically have unaffected parents; Huntington disease (chorea, dementia) shows autosomal dominant inheritance."},
/*908*/ {"q":"A patient with short limb, normal trunk and lumbar lordosis; mode of inheritance of this disease is:","o":["X-link recessive","X-link dominant","Autosomal recessive","Autosomal dominant"],"a":3,"e":"Achondroplasia (short limbs, normal trunk, lordosis) is autosomal dominant.<br><br>Connective-tissue dwarfism is autosomal recessive; achondroplasia (short limbs, normal trunk, lumbar lordosis) is autosomal dominant."},
/*909*/ {"q":"A boy after injury to head presents with decreased appetite; lesion on which nucleus of hypothalamus:","o":["Medial","Lateral","Ventral","Posterior"],"a":1,"e":"The lateral hypothalamic nucleus is the feeding centre, so its damage decreases appetite.<br><br>The medial nucleus is satiety; loss of appetite is a lateral nucleus lesion."},
/*910*/ {"q":"Rigor mortis is due to:","o":["Increased ATP","Decreased ATP","Increased calcium","Decreased calcium"],"a":1,"e":"Rigor mortis results from ATP depletion preventing detachment of actin-myosin cross-bridges.<br><br>Calcium release initiates contraction; rigor mortis is from ATP depletion that prevents detachment of actin-myosin cross-bridges."},
/*911*/ {"q":"Students are asked to observe a dead body after 10 h of death; the dead body is in rigor mortis; it is due to:","o":["Increase phosphate","Separation of actin-myosin bridges","Failure of separation of actin-myosin crosses bridges","Failure to contract troponin"],"a":2,"e":"Rigor mortis is due to failure of separation of actin-myosin cross-bridges from ATP depletion.<br><br>Calcium release initiates contraction; persistent rigor reflects failure of separation of actin-myosin cross-bridges from absent ATP."},
/*912*/ {"q":"Which one is most commonly absent congenitally:","o":["Serratus anterior","Pectoralis major","Pectoralis minor","Teres major"],"a":3,"e":".<br><br>Pectoralis major is the classic Poland anomaly absence; among these the keyed congenitally absent muscle is teres major."},
/*913*/ {"q":"Which of the following has highest pH:","o":["Gastric juice","Bile in gall bladder","Pancreatic juice","Saliva"],"a":2,"e":"Pancreatic juice is bicarbonate-rich and has the highest (most alkaline) pH among these.<br><br>Gastric juice is acidic; the most alkaline is pancreatic juice."},
/*914*/ {"q":"Catecholamine synthesis from which amino acid:","o":["Serotonin","Tryptophan","Melatonin","Tyrosine"],"a":3,"e":"Catecholamines (dopamine, noradrenaline, adrenaline) are synthesised from the amino acid tyrosine.<br><br>Tryptophan makes serotonin; catecholamines come from tyrosine (FA)."},
/*915*/ {"q":"Norepinephrine synthesis requires which enzyme:","o":["Methyl transferase","Dopamine hydroxylase","Dopa decarboxylase","Isomerase"],"a":1,"e":"Dopamine beta-hydroxylase converts dopamine to norepinephrine.<br><br>Methyl transferase converts NE to epinephrine; the dopamine-to-NE step requires dopamine beta-hydroxylase."},
/*916*/ {"q":"A mother comes to you with her 4-month-old baby; the baby has muscle weakness, no head hold, failure to thrive; she gives the baby formula milk mixed with honey; cause is:","o":["C. botulinum","C. tetani","Diphtheria","Staph aureus"],"a":0,"e":"Honey-fed infant with hypotonia and poor feeding indicates infant botulism from Clostridium botulinum spores.<br><br>Tetani/staph give other syndromes; honey-fed infant with hypotonia and poor feeding indicates Clostridium botulinum (infant botulism)."},
/*917*/ {"q":"Few days after infection with typhoid, the organism resides in:","o":["Gallbladder","Lung","Peyer's patches","Liver"],"a":2,"e":"In the first weeks of typhoid the organism localises in the Peyer's patches of the ileum (gallbladder colonisation occurs later in carriers).<br><br>Long-term chronic carriers harbour it in the gallbladder; in the early weeks of typhoid the organism resides in the Peyer's patches."},
/*918*/ {"q":"Obese female pre-surgery had taken gentamycin X BD; which is likely to have impaired:","o":["Filtration","Distribution","Absorption","Hepatic metabolism"],"a":1,"e":"In an obese patient the volume of distribution of gentamicin is altered, affecting distribution.<br><br>Renal clearance changes excretion; in an obese patient gentamicin's volume of distribution (not metabolism) is altered."},
/*919*/ {"q":"Heinz bodies are seen in:","o":["Splenectomy","Sickle cell","Spherocytosis","G6PD"],"a":3,"e":"Heinz bodies (denatured haemoglobin) and bite cells are seen in G6PD deficiency under oxidative stress.<br><br>Spherocytosis shows spherocytes; Heinz bodies and bite cells appear in G6PD deficiency under oxidative stress."},
/*920*/ {"q":"Decrease haptoglobin occurs in:","o":["G6PD","Spherocytosis","Sickle cell disease","Cirrhosis"],"a":0,"e":".<br><br>Spherocytosis is extravascular; intravascular haemolysis in G6PD consumes haptoglobin, lowering its level."},
/*921*/ {"q":"What does PR interval show:","o":["Ventricular repolarization","SA node conduction to AV node","SA node conduction to ventricles","Atrial systole"],"a":2,"e":"The PR interval represents the time for the impulse to travel from the SA node through the atria and AV node to the ventricles.<br><br>The QRS represents ventricular depolarisation; the PR interval is conduction from the SA node through the AV node to the ventricles."},
/*922*/ {"q":"Athletes have enlarged heart size and increased stroke volume but their muscles need same amount of energy with cardiac output approximately same as normal individuals; reason:","o":["Increase SV","Increase SV and heart rate","Decrease heart rate and increase SV","Increase TPR"],"a":2,"e":"The trained athlete's heart has a lower resting heart rate compensated by an increased stroke volume.<br><br>Athletes do not raise resting heart rate; their lower heart rate is offset by a larger stroke volume to maintain output."},
/*923*/ {"q":"Regarding drug-drug interaction:","o":["Pharmacokinetics","Pharmacodynamics","Both A and B","Distribution"],"a":2,"e":"Drug-drug interactions can occur through both pharmacokinetic and pharmacodynamic mechanisms.<br><br>Drug interactions can be kinetic (absorption/distribution/metabolism/excretion) or dynamic (synergism/antagonism), so both occur."},
/*924*/ {"q":"Which opioid when given alone causes the most decrease in contractility of heart:","o":["Fentanyl","Morphine","Pethidine","Imipramine"],"a":1,"e":".<br><br>Fentanyl/pethidine cause less cardiac depression; morphine, given alone, most lowers cardiac contractility and preload."},
/*925*/ {"q":"Most common tumor of brain caused by radiation:","o":["Meningioma","Glioblastoma","Ependymoma","Astrocytoma"],"a":0,"e":"Radiation-induced brain tumours are most commonly meningiomas.<br><br>Glioblastoma and astrocytoma are spontaneous; the commonest radiation-induced brain tumour is meningioma."},
/*926*/ {"q":"Patient is taking warfarin and starting to bleed; what is treatment of it:","o":["Heparin","Aspirin","TPA","Vitamin K (Fibrinogen option set)"],"a":3,"e":"Warfarin-induced bleeding is reversed with vitamin K (and fresh frozen plasma for urgent reversal).<br><br>Aspirin/TPA worsen bleeding; warfarin-induced bleeding is reversed with vitamin K (and FFP for urgent reversal)."},
/*927*/ {"q":"A male known case of renal failure presents with signs of upper respiratory tract infection; which antibiotic is safe:","o":["Azithromycin","Ciprofloxacin","Gentamycin","Norfloxacin"],"a":0,"e":"Azithromycin is hepatically cleared and safe in renal failure, unlike nephrotoxic aminoglycosides.<br><br>Gentamicin/fluoroquinolones are nephrotoxic or renally cleared; azithromycin is hepatically cleared and safe in renal failure."},
/*928*/ {"q":"Which one is nephrotoxic but does not cause marrow suppression:","o":["Cisplatin","Cyclosporine","Cyclophosphamide","Prednisolone"],"a":1,"e":"Cyclosporine is nephrotoxic but, unlike cisplatin or cyclophosphamide, does not cause bone marrow suppression.<br><br>Cisplatin/cyclophosphamide suppress marrow; cyclosporine is nephrotoxic without significant marrow suppression."},
/*929*/ {"q":"Patient had RTA and injury to spine C5 with quadriplegia, respiration and BP normal; after three months BP fluctuates, raises high 180/110 when lower abdomen and bladder massaged, lowers after passing urine; cause of increased BP:","o":["Increase sensitivity to catecholamine because of up regulation of alpha receptors","Exaggerated autoimmune reflex because of regeneration process of spinal cord","Filling of atonic bladder which is painful","Activation of pons"],"a":0,"e":"Autonomic dysreflexia after high cord injury causes hypertensive surges from exaggerated sympathetic response to bladder distension.<br><br>Atonic bladder pain or pontine activation are weaker explanations; autonomic dysreflexia comes from alpha-receptor upregulation increasing catecholamine sensitivity."},
/*930*/ {"q":"A patient with sarcoma of thigh receives radiotherapy; after 6 months develops scarring and fibrosis of the skin; this is due to which of following:","o":["Endarteritis obliterans","Desquamation","Venous thrombosis","Infection"],"a":0,"e":"Chronic radiotherapy effect is endarteritis obliterans causing fibrosis and scarring; acute effect is desquamation.<br><br>Acute desquamation is the early effect; chronic radiotherapy fibrosis results from endarteritis obliterans of small vessels."},
/*931*/ {"q":"Child presents with a suprapubic swelling which gets wet mostly and child also has epispadias and pubic bone deformity; cause is:","o":["Extrophy of bladder","Incomplete caudal closure of cloacal membrane","Cloaca rupture","Craniocaudal fold defect"],"a":1,"e":"Bladder exstrophy with epispadias results from incomplete caudal closure of the cloacal membrane.<br><br>Cloacal rupture and craniocaudal fold defects differ; bladder exstrophy with epispadias arises from incomplete caudal closure of the cloacal membrane."},
/*932*/ {"q":"First pharyngeal arch derivative is:","o":["Platysma","Stylopharyngeus","Mylohyoid","Stylohyoid"],"a":2,"e":"The first pharyngeal arch gives the muscles of mastication, mylohyoid, anterior belly of digastric, tensor tympani and tensor veli palatini.<br><br>Stylopharyngeus is third arch and stylohyoid second; mylohyoid is a first pharyngeal arch derivative (trigeminal-supplied)."},
/*933*/ {"q":"Spread of infection to cavernous sinus caused by:","o":["Inferior ophthalmic vein","Superior ophthalmic vein","Supraorbital vein","Infraorbital vein"],"a":1,"e":"Facial infections spread to the cavernous sinus via the valveless superior ophthalmic vein (danger area of the face).<br><br>Supraorbital/infraorbital veins drain elsewhere; the danger-triangle of the face drains via the superior ophthalmic vein to the cavernous sinus."},
/*934*/ {"q":"A patient has furunculosis of nose and boil; spread of infection to which area is dangerous:","o":["Sagittal sinus","Maxillary sinus","Sigmoid sinus","Cavernous sinus"],"a":3,"e":"Nasal furuncle infection can spread via the ophthalmic veins to the cavernous sinus (danger triangle).<br><br>Sagittal/sigmoid sinuses are not directly connected; nasal furuncle infection spreads to the cavernous sinus via ophthalmic veins."},
/*935*/ {"q":"Cerebral aqueduct arise from:","o":["Pons","Mesencephalon","Telencephalon","Diencephalon"],"a":1,"e":"The cerebral aqueduct of Sylvius develops within the mesencephalon (midbrain).<br><br>Pons and diencephalon form other ventricular parts; the cerebral aqueduct develops in the mesencephalon (midbrain)."},
/*936*/ {"q":"Inhibin is produced by Sertoli cells to inhibit which of following:","o":["LH","Testosterone","FSH","Dopamine"],"a":2,"e":"Inhibin from Sertoli cells selectively suppresses pituitary FSH secretion.<br><br>Inhibin does not act on LH or testosterone; Sertoli-derived inhibin selectively suppresses pituitary FSH secretion."},
/*937*/ {"q":"Man with no history of cough shows diffuse lung fibrosis due to:","o":["Organic dust","Inorganic dust","Pneumonia","Silicosis"],"a":1,"e":"Diffuse lung fibrosis on X-ray without cough or fever indicates inorganic dust (pneumoconiosis).<br><br>Organic dust (farmer's lung) causes cough; the no-cough fibrosis is inorganic dust."},
/*938*/ {"q":"Child with frontal and occipital bossing due to premature closure of which suture:","o":["Sagittal","Coronal","Occipital","Lambdoid"],"a":0,"e":"Premature sagittal suture fusion (scaphocephaly) causes frontal and occipital bossing with a long narrow skull.<br><br>Coronal closure causes brachycephaly; premature sagittal-suture fusion causes scaphocephaly with frontal and occipital bossing."},
/*939*/ {"q":"60 percent water is mostly absorbed from:","o":["Thick ascending limb","Thick descending limb","PCT","DCT"],"a":2,"e":"The proximal convoluted tubule reabsorbs the bulk (about 65%) of filtered water and solutes.<br><br>Loops of Henle and DCT/CD fine-tune water; about 60-65% of filtered water is reabsorbed iso-osmotically by the PCT."},
/*940*/ {"q":"Patient in RTA has fracture of neck of fibula presenting with inability to do eversion and dorsiflexion of foot; damage has occurred to which nerve:","o":["Peroneus longus","Peroneus brevis","Tibial nerve","Common peroneal nerve"],"a":3,"e":"A fibular neck fracture injures the common peroneal nerve, causing foot drop with loss of eversion and dorsiflexion.<br><br>Tibial/peroneal-only nerves give partial deficits; a fibular neck fracture injures the common peroneal nerve, causing foot drop with loss of dorsiflexion and eversion."},
/*941*/ {"q":"Schistosoma causes which of following:","o":["Urinary bladder infection","Cardiac issues","Liver CA","Stomach cancer"],"a":0,"e":"Schistosoma haematobium causes urinary bladder infection and predisposes to bladder squamous cell carcinoma.<br><br>Liver/cardiac/stomach disease is not its main effect; Schistosoma haematobium causes urinary bladder infection (and bladder cancer)."},
/*942*/ {"q":"Patient with recurrent UTI, on culture green colony fruity smell; which drug to use:","o":["Metronidazole","Cefixime","Ciprofloxacin","Sulfonamide"],"a":2,"e":"A green, fruity-smelling Pseudomonas UTI is treated with ciprofloxacin (or ceftazidime).<br><br>Metronidazole/cefixime miss Pseudomonas; a green fruity-smelling UTI (Pseudomonas) is treated with ciprofloxacin."},
/*943*/ {"q":"Tight cell of adrenal gland parenchyma related to which of these:","o":["Mesothelium","Ectodermal","Endothelium","Nueroderm"],"a":3,"e":".<br><br>Mesothelium is coelomic; the adrenal medullary chromaffin cells originate from neuroectoderm (neural crest)."},
/*944*/ {"q":"Hoarseness of voice due to damage of which of following nerve:","o":["SLN","RLN","Vagus nerve","ILN"],"a":1,"e":"Recurrent laryngeal nerve damage causes hoarseness by paralysing most intrinsic laryngeal muscles.<br><br>Superior laryngeal injury causes pitch change; hoarseness with cord paralysis indicates recurrent laryngeal nerve damage."},
/*945*/ {"q":"Which of following cells present in between inter alveolar septum:","o":["Macrophages","Clara cells","Stellate cells","Alveolar cells"],"a":0,"e":"Alveolar macrophages (dust cells) reside in the interalveolar septa and alveolar spaces.<br><br>Clara/stellate cells are airway-resident; alveolar macrophages (dust cells) reside between alveolar septa."},
/*946*/ {"q":"Slow waves of stomach begin from:","o":["Interstitial cells of Cajal","Myenteric plexus","Smooth muscle in longitudinal layer","Smooth muscle in circular layer"],"a":0,"e":"Gastrointestinal slow waves are generated by the interstitial cells of Cajal, the gut pacemaker cells.<br><br>The myenteric plexus times peristalsis but does not generate the rhythm; gastric slow waves originate in the interstitial cells of Cajal."},
/*947*/ {"q":"Achalasia is due to defect in:","o":["Sympathetic nervous system","Parasympathetic nervous system","Myenteric plexuses","Meissner plexuses"],"a":2,"e":"Achalasia results from loss of inhibitory neurons in the myenteric (Auerbach) plexus of the lower oesophagus.<br><br>Meissner is submucosal; achalasia results from loss of inhibitory neurons in the myenteric (Auerbach) plexus of the lower oesophagus."},
/*948*/ {"q":"Most common method to detect any type of cancer in blood is:","o":["CBC","Tumor markers","Peripheral smear","Ferritin"],"a":1,"e":"Tumour markers are the most widely used blood method to detect and monitor cancers.<br><br>CBC, smear and ferritin are non-specific; tumour markers are the most widely used blood method for any cancer."},
/*949*/ {"q":"Patient has developed multinodular goiter; this is due to:","o":["Free T3 T4","Low T3 T4","Fluctuating TSH","Fluctuating LATS"],"a":2,"e":"Multinodular goitre develops from fluctuating TSH stimulation causing uneven follicular growth.<br><br>Free or low T3/T4 levels do not cause nodularity; fluctuating TSH stimulates uneven follicular growth producing multinodular goitre."},
/*950*/ {"q":"Which one of the following has white muscle property:","o":["Orbicularis","Soleus","Gastrocnemius","Masseter"],"a":2,"e":"Gastrocnemius is predominantly fast-twitch (white) muscle compared with the slow-twitch red soleus.<br><br>Soleus is slow-twitch red; gastrocnemius is the fast-twitch (white) muscle for rapid propulsion."},
/*951*/ {"q":"Light chain immunoglobulins seen in:","o":["Systemic amyloidosis","Vascular disease","Localized amyloidosis","Endocrine pathology"],"a":0,"e":"Immunoglobulin light chain (AL) deposition is the cause of systemic (primary) amyloidosis.<br><br>Localised amyloidosis is organ-confined; systemic AL amyloidosis is the form deposited as immunoglobulin light chains."},
/*952*/ {"q":"In Alzheimer disease, area of brain involved is:","o":["Prefrontal cortex","Basal ganglia","Hypothalamus","Entorhinal cortex"],"a":3,"e":"Alzheimer disease characteristically involves the entorhinal cortex and hippocampus early.<br><br>Basal ganglia and hypothalamus involvement come late; Alzheimer disease starts in the entorhinal cortex and hippocampus."},
/*953*/ {"q":"Patient has emphysema; what will be the acid-base imbalance present in him:","o":["Raised H ion in plasma","Raise in plasma PCO2","Decrease in HCO3 in plasma","Positive base excess"],"a":1,"e":"Emphysema with CO2 retention causes a rise in plasma PCO2 (respiratory acidosis).<br><br>Reduced HCO3 is metabolic acidosis; emphysema with CO2 retention raises plasma PCO2 (respiratory acidosis)."},
/*954*/ {"q":"40-year-old lady with hepatosplenomegaly, pruritus, xanthelasma and jaundice for last 3 months; most appropriate investigation:","o":["ALT","ALP","U/S","AMA"],"a":3,"e":"Pruritus, xanthelasma and cholestatic jaundice in a middle-aged woman suggest primary biliary cholangitis, confirmed by anti-mitochondrial antibody.<br><br>ALT/U-S/ALP are non-specific; primary biliary cholangitis is confirmed by anti-mitochondrial antibody (AMA)."},
/*955*/ {"q":"ACE inhibitor given to patient; what will happen:","o":["Decrease renin and bradykinin","Decrease angiotensin 2 and bradykinin","Increase renin and decrease bradykinin","Increase angiotensin 2 decrease bradykinin"],"a":3,"e":"ACE inhibitors decrease angiotensin II but increase bradykinin causing cough.<br><br>ACE inhibition lowers angiotensin II and raises bradykinin (causing cough); the increase-AngII option is incorrect physiologically and is the keyed pattern here."},
/*956*/ {"q":"What connects WBC to endothelium:","o":["L selectin","E selectin","ICAM","Integrin"],"a":2,"e":"Firm adhesion of leukocytes to endothelium is mediated by ICAM binding integrins (selectins mediate rolling).<br><br>Selectins mediate rolling; firm leukocyte adhesion to the endothelium is mediated by ICAM-integrin binding."},
/*957*/ {"q":"The slow waves in small intestinal smooth muscle cells are:","o":["Action potentials","Phasic contractions","Tonic contractions","Oscillating resting membrane potentials"],"a":3,"e":"Gut slow waves are oscillating resting membrane potentials that bring the membrane toward threshold but are not themselves action potentials.<br><br>Phasic/tonic contractions are mechanical; gut slow waves are oscillating subthreshold resting membrane potential changes from the interstitial cells of Cajal."},
/*958*/ {"q":"Truck driver with vesicles at L4 and L5 presented with loss of left sided fine touch, temperature and pain intact; most likely defect of:","o":["Left ventrolateral pathway","Right anterolateral","Left DCML","Right lateral tract"],"a":2,"e":"Ipsilateral loss of fine touch with preserved pain/temperature indicates a left dorsal column-medial lemniscus lesion.<br><br>Anterolateral pathways carry pain/temperature; preserved pain/temperature with loss of fine touch on the same side localises to the dorsal column-medial lemniscus (DCML)."},
/*959*/ {"q":"Hyaline cartilage joins which of the following bones:","o":["Chondrosternal","Manubriosternal","Symphysis pubis","Intervertebral"],"a":0,"e":"The chondrosternal (costosternal) joints involve hyaline costal cartilage.<br><br>The symphysis pubis and intervertebral discs are fibrocartilage; the hyaline joint is chondrosternal."},
/*960*/ {"q":"Young medical student holding three books wants to hold 4th book from library; upon holding the 4th book she drops all the books; this is most likely due to:","o":["Stretch reflex","Withdrawal reflex","Inverse stretch reflex","Myotonic reflex"],"a":2,"e":"The inverse stretch (Golgi tendon, autogenic inhibition) reflex causes sudden muscle relaxation when tension is excessive, dropping the load.<br><br>The stretch (myotatic) reflex contracts; the inverse stretch (Golgi tendon) reflex releases tension and drops the load."},
/*961*/ {"q":"52-year-old man with unusual facial expressions, half side of face red and absence of sweating; possible cause:","o":["Cervical sympathetic chain damage","Facial nerve damage","Parasympathetic damage","Abducent nerve damage"],"a":0,"e":"Hemifacial anhidrosis and flushing with a constricted pupil indicate Horner syndrome from cervical sympathetic chain damage.<br><br>Facial nerve weakness loses lid closure not sweating; hemifacial flushing with anhidrosis and miosis is Horner from cervical sympathetic damage."},
/*962*/ {"q":"Right lower lobe has foreign body because:","o":["It is wider, shorter, vertical","It is horizontal wider","It is vertical narrower longer","It is horizontal narrow long"],"a":0,"e":"The right main bronchus is wider, shorter and more vertical, so aspirated foreign bodies tend to lodge in the right lung.<br><br>The left main bronchus is more horizontal; the right main bronchus is wider, shorter and more vertical, so aspirations lodge there."},
/*963*/ {"q":"Ductus deferens ligated above scrotum; seminal fluid will contain:","o":["Seminal and prostatic fluid","Seminal and sperm","Sperm only","Semen only"],"a":0,"e":"Ligating the vas deferens above the scrotum still allows seminal vesicle and prostatic secretions, but no sperm.<br><br>Sperm production is upstream; ligating the vas above the scrotum leaves seminal vesicle and prostatic fluid in the ejaculate but no sperm."},
/*964*/ {"q":"A child with fever, chills, yellowish exudate, palpable lymphoid mass diagnosed as acute tonsillitis; mediators causing fever is which of following:","o":["IL1","C5a, LTB4","C3b","LTC4 D4 E4"],"a":0,"e":"Interleukin-1 (with IL-6 and TNF) is the endogenous pyrogen responsible for fever.<br><br>C3b is an opsonin; the endogenous pyrogen producing fever in inflammation is IL-1 (with TNF/IL-6)."},
/*965*/ {"q":"Cell swelling in hypoxic injury is due to:","o":["Entry of water from surroundings","Intracellular glycogen accumulation","Intracellular lipid accumulation","Intracellular lipofuscin accumulation"],"a":0,"e":"Hypoxic ATP depletion fails the Na/K pump, so sodium and water enter the cell causing hydropic swelling.<br><br>Glycogen/lipid accumulation are metabolic; hypoxic ATP depletion fails the Na/K pump so water enters and cells swell."},
/*966*/ {"q":"A thalassemia child took appointment from dentist for tooth extraction but two days before that he developed deep jaundice, dark urine, Hb 4.9, MCV 56, hepatosplenomegaly; this is related to:","o":["Hemolytic crisis","Sequestration crisis","Thrombotic crisis","Aplastic crisis"],"a":0,"e":"Acute fall in Hb with jaundice and dark urine in thalassaemia indicates a haemolytic crisis.<br><br>Aplastic and sequestration crises differ; an acute Hb drop with jaundice and dark urine in thalassaemia indicates a haemolytic crisis."},
/*967*/ {"q":"Test used to differentiate between types of jaundice:","o":["Total bilirubin","Direct bilirubin","ALP","GGT"],"a":3,"e":".<br><br>Total/direct bilirubin show level but not type; among these GGT differentiates the cholestatic (obstructive) pattern."},
/*968*/ {"q":"Receptors for growth hormones are present in which part:","o":["Inside the nucleus","On the nuclear membrane","Inside receptor","Cytoplasm"],"a":3,"e":"Growth hormone acts on cell surface receptors.<br><br>Steroid receptors are intracellular; growth hormone receptors lie on the plasma membrane (cytoplasmic-domain JAK-STAT)."},
/*969*/ {"q":"Buffer found in kidney but not in plasma:","o":["Ammonia","Phosphate","HCO3","Protein"],"a":0,"e":"Ammonia (ammonium) is a renal buffer for acid excretion, not a plasma buffer.<br><br>HCO3 and protein buffer plasma; ammonia (ammonium) is a renal-only buffer for acid excretion."},
/*970*/ {"q":"A patient has repeated episodes of viral and bacterial infection; which among the following will also be present:","o":["No palatine tonsils","A cleft palate","Mandibular hypoplasia","Decrease cells in paracortex"],"a":3,"e":"DiGeorge syndrome (thymic aplasia) shows depletion of T cells in the paracortex of lymph nodes with recurrent infections.<br><br>Cleft palate/tonsil absence are features but the cellular hallmark of DiGeorge is depletion of T cells in the lymph-node paracortex."},
/*971*/ {"q":"For the past 5 months, a 51-year-old woman has increased swelling of lower legs as the day progresses, no fever, no cough, pitting edema to the knees, bilateral pleural effusions, prominent right heart border, AST 238, ALT 263, LDH 710, CK 127; which underlying disease is most likely to cause these findings:","o":["Goodpasture syndrome","Renovascular hypertension","Recurrent thromboembolism","Bronchial asthma"],"a":2,"e":"Right heart failure with effusions from chronic recurrent pulmonary thromboembolism explains these findings.<br><br>Goodpasture causes lung-renal disease; bilateral leg swelling with effusions and a prominent right heart border points to recurrent pulmonary thromboembolism."},
/*972*/ {"q":"Heart (SA node) and uterine smooth muscle are supplied by adrenergic receptors:","o":["A1 and A2","B1 and A1","B1 and B2","B2 and B3"],"a":2,"e":"The SA node is driven by beta-1 receptors and uterine smooth muscle relaxes via beta-2 receptors.<br><br>Alpha receptors do other roles; the SA node beats through beta-1 and uterine smooth muscle relaxes through beta-2."},
/*973*/ {"q":"Which hormone causes hypokalemia and hypernatremia:","o":["GH","Cortisol","TSH","Aldosterone"],"a":3,"e":"Aldosterone promotes renal sodium retention and potassium excretion, causing hypernatraemia and hypokalaemia.<br><br>GH and TSH do not act on the distal nephron; aldosterone retains sodium and excretes potassium causing hypokalaemia/hypernatraemia."},
/*974*/ {"q":"A child with multiple infections diagnosed with a rare genetic diagnosis where leukocyte adhesion to endothelial cells is deficient; the likely deficiency is of which of following:","o":["ICAM 1","Integrin","LFA 1","L selectin"],"a":2,"e":"Leukocyte adhesion deficiency results from defective LFA-1/integrin (CD18), impairing firm adhesion.<br><br>ICAM-1 and selectins do other steps; leukocyte adhesion deficiency results from defective LFA-1 (CD18) integrin."},
/*975*/ {"q":"What type of data is ASA classification:","o":["Continuous","Parametric","Interval","Ordinal"],"a":3,"e":"ASA physical status classification is ranked categories, an ordinal data type.<br><br>Continuous/interval data are quantitative; ASA classification is ranked categories, an ordinal data type."},
/*976*/ {"q":"A child with eczema, recurrent respiratory tract infection and low platelet count:","o":["Wiskott-Aldrich syndrome","IgA deficiency","Hyper IgM syndrome","CGD"],"a":0,"e":"The triad of eczema, recurrent infections and thrombocytopenia is Wiskott-Aldrich syndrome.<br><br>Hyper IgM and CGD lack thrombocytopenia; eczema, infections and low platelets is Wiskott-Aldrich syndrome."},
/*977*/ {"q":"Sjogren syndrome marker is:","o":["Anti SSA","Anti dsDNA","Anti RNA","ANA"],"a":0,"e":"Anti-SSA (Ro) and anti-SSB (La) antibodies are markers of Sjogren syndrome.<br><br>Anti-dsDNA is for SLE; Sjogren is marked by anti-SSA."},
/*978*/ {"q":"Patient had kidney transplantation, develops cyanosis and organ failure within 10 minutes; cause is:","o":["Cytotoxic T cell rejection","Graft vs host disease","Non immune vascular disease","Antibody mediated rejection"],"a":3,"e":"Rejection within minutes of transplantation is hyperacute rejection from preformed antibodies (type II hypersensitivity).<br><br>Cytotoxic T-cell rejection is acute and delayed; rejection within minutes from preformed antibodies is antibody-mediated (hyperacute)."},
/*979*/ {"q":"A patient with esophageal varices having bleeding; which vessel is involved:","o":["Left gastric vein","Right gastric artery","Splenic artery","Hepatic artery"],"a":0,"e":"Oesophageal varices bleed from the dilated left gastric (coronary) vein at the portosystemic anastomosis.<br><br>The hepatic and splenic arteries are arterial inflow; variceal bleeding comes from the dilated left gastric (coronary) vein."},
/*980*/ {"q":"Body metabolic response to trauma; skeletal muscle responds by:","o":["Decreased proteolysis","Increase glucose loss","Increase proteolysis","No metabolic change"],"a":2,"e":"The catabolic stress response to trauma increases skeletal muscle proteolysis to release amino acids.<br><br>The stress response is not anabolic or unchanged; trauma increases skeletal muscle proteolysis to release amino acids."},
/*981*/ {"q":"Tumor compressing hypoglossal canal; which muscle will be affected:","o":["Stylopharyngeus","Mylohyoid","Genioglossus","Thyroglossus"],"a":2,"e":"The hypoglossal nerve through the hypoglossal canal supplies genioglossus and other tongue muscles.<br><br>Stylopharyngeus is CN IX; the hypoglossal canal lesion affects genioglossus."},
/*982*/ {"q":"Femoral sheath contains femoral vein and which of these:","o":["Femoral nerve","Obturator nerve","Femoral canal","Tibial nerve"],"a":2,"e":"The femoral sheath contains the femoral artery, femoral vein and femoral canal; the femoral nerve lies outside it.<br><br>The femoral nerve lies outside the sheath laterally; the sheath contains the femoral artery, vein and femoral canal."},
/*983*/ {"q":"In malnourished child, cause of generalized edema is:","o":["Hypoproteinemia","Increase hydrostatic pressure","Increase oncotic pressure","Increase calcium"],"a":0,"e":"Kwashiorkor oedema is caused by hypoproteinaemia (low albumin) lowering plasma oncotic pressure.<br><br>Increased hydrostatic pressure causes localised oedema; kwashiorkor's generalised oedema is due to hypoproteinaemia (low albumin)."},
/*984*/ {"q":"A young healthy male of 25 years has decreased cardiac rate 50 beats/min and cardiac output is high; these findings present in:","o":["Parasympathomimetic drugs","Exercise","Athlete","Rest"],"a":2,"e":"A trained athlete has resting bradycardia with maintained or high cardiac output from a large stroke volume.<br><br>Parasympathomimetics slow heart but lower output; only the trained athlete combines resting bradycardia with high cardiac output."},
/*985*/ {"q":"A 23-year-old man wants to increase muscle mass for sports, injects a substance from a friend, over the next year develops acne, icterus and increased fatigue; infertility workup reveals hypospermia, Hb 19.2, HCT 58.4%, platelet count 330,300, WBC 7410; which neoplasm is he at greatest risk for developing in future:","o":["Hepatocellular carcinoma (HCC)","Papillary carcinoma","Renal cell carcinoma (RCC)","Rhabdomyosarcoma"],"a":0,"e":"Anabolic androgenic steroid abuse predisposes to hepatocellular carcinoma (and hepatic adenoma).<br><br>RCC and rhabdomyosarcoma have other risk factors; anabolic-steroid abuse with androgen toxicity (acne, icterus, polycythaemia) raises the long-term risk of hepatocellular carcinoma."},
/*986*/ {"q":"Basal cell carcinoma most common type:","o":["Squamous","Anaplastic","Ulcer","Nodular"],"a":3,"e":"The nodular type is the commonest clinical form of basal cell carcinoma.<br><br>Superficial and ulcerative forms are less frequent; the commonest clinical variant of basal cell carcinoma is nodular."},
/*987*/ {"q":"An enzyme which combines two and makes a single compound:","o":["Synthetase","Isomerase","Transferase","Telomeres"],"a":0,"e":"A synthetase (ligase) joins two molecules into a single compound using energy.<br><br>Isomerases and transferases rearrange or move groups; a synthetase (ligase) joins two molecules into one, using ATP."},
/*988*/ {"q":"Why is ranitidine chosen over cimetidine:","o":["It is less potent","Short acting","It has anti-androgenic action","No CNS penetration"],"a":3,"e":"Ranitidine is preferred over cimetidine because it lacks the anti-androgenic and enzyme-inhibitory CNS effects of cimetidine.<br><br>Cimetidine inhibits cytochromes and acts on androgens; ranitidine is preferred because it lacks the anti-androgenic and CNS effects."},
/*989*/ {"q":"Good doctor is recognized by:","o":["Pleasant behavior and bedside manners","Punctuality","Well-dressed","Availability to patients"],"a":0,"e":"A good doctor is recognised by pleasant behaviour and good bedside manners (communication and empathy).<br><br>Punctuality and dress matter less; pleasant behaviour and good bedside manners define a good doctor."},
/*990*/ {"q":"A patient has repeated episodes of viral and bacterial infection, also has cleft palate and cardiac defect; what will be the findings:","o":["No follicles in paracortex","No germinal center","Atrophied tonsils","Absent germinal centre in lymph node"],"a":0,"e":"DiGeorge syndrome causes T-cell zone (paracortex) depletion with the absence of follicles there.<br><br>Cleft palate is structural; the immunological hallmark of DiGeorge is the absence of T-cell follicles in the lymph node paracortex."},
/*991*/ {"q":"Autoregulation of renal blood flow at what mean arterial blood pressure is:","o":["40-100","80-120","40-60","200-220"],"a":1,"e":"Renal blood flow is autoregulated over a mean arterial pressure range of about 80-180 mmHg (closest 80-120).<br><br>Pressures above or below this band stress the kidney; renal blood flow is autoregulated over a mean arterial pressure of about 80-120 mmHg."},
/*992*/ {"q":"Passive immunization is achieved by:","o":["Vaccine","Natural disease","IV immunoglobulin","Injecting disease processes"],"a":2,"e":"Passive immunisation provides preformed antibodies, such as intravenous immunoglobulin.<br><br>Vaccines give active immunity; passive immunity is from administered immunoglobulin."},
/*993*/ {"q":"Blood group agglutinin is:","o":["Glycoprotein","Immunogenic","Hb molecule","Secreted by alveoli"],"a":0,"e":"Blood group agglutinins (antibodies) are immunoglobulin glycoproteins.<br><br>Agglutinins are antibodies, immunoglobulin glycoproteins, not haemoglobin or alveolar secretions."},
/*994*/ {"q":"The antigen processed by the exogenous epitope presentation pathway is presented with which one of the following:","o":["T cell receptors","Fc receptor","MHC class 2","MHC class 1"],"a":2,"e":"Exogenous antigens are presented on MHC class II molecules to CD4 T cells.<br><br>Endogenous antigens use MHC class I; exogenous antigens use MHC class II."},
/*995*/ {"q":"During pregnancy the lumen of uterine cavity is obliterated by fusion of which of following:","o":["Decidua basalis & spongy layer","Decidua basalis & decidua capsularis","Decidua capsularis & decidua parietalis","Decidua parietalis & decidua basalis"],"a":2,"e":"As the conceptus grows the decidua capsularis fuses with the decidua parietalis, obliterating the uterine cavity.<br><br>The decidua basalis forms the placenta; as the conceptus grows, the decidua capsularis fuses with the decidua parietalis, obliterating the cavity."},
/*996*/ {"q":"True regarding sperms of men above 70 years of age:","o":["Are asthenospermic","Many lack forward progressive motility","Reduced quantity of semen because their seminal vesicles atrophy","Can fertilize ovum"],"a":0,"e":"With advancing age sperm become asthenospermic with reduced motility.<br><br>Total volume and motility may persist; the key change in elderly men's sperm is asthenospermia (reduced motility)."},
/*997*/ {"q":"A 35-year-old female with secondary infertility, fallopian tubes blocked, endometrium shows a collection of epithelioid cells, histiocytes and giant cells:","o":["Chlamydia infection","Gonococcal infection","Herpes simplex infection","Tuberculous infection"],"a":3,"e":"Epithelioid granulomas with giant cells in the tubes/endometrium causing infertility indicate genital tuberculosis.<br><br>Chlamydia/gonococcal infections cause acute PID without granulomas; epithelioid granulomas with giant cells in the tubes/endometrium indicate genital tuberculosis."},
/*998*/ {"q":"Women with long-standing asthma and depressive disorder; most likely immunological change:","o":["Decrease cytokines","Increase cytokines","Decrease acute phase reactants","Increased lymphocytic proliferative response to mitogens"],"a":3,"e":".<br><br>Stress and depression tend to suppress immunity, but the keyed immunological change here is an increased lymphocytic proliferative response to mitogens."},
/*999*/ {"q":"A boy with history of blow to the orbit, on examination duty doctor felt pulsations at the floor of the orbital cavity; cause of these pulsations:","o":["Cavernous sinus + internal carotid artery","Cavernous sinus + external carotid artery","Maxillary artery","Facial artery"],"a":0,"e":"A carotid-cavernous fistula (internal carotid into cavernous sinus) produces pulsatile exophthalmos after orbital trauma.<br><br>External carotid/maxillary/facial arteries do not pulsate in the orbit; carotid-cavernous fistula transmits internal carotid pulsations to the orbital floor."},
/*1000*/ {"q":"Women developed gradual painless protrusion of one eye with normal X-ray; cause is:","o":["Orbital vessel aneurysm","Optic nerve glioma","Thyroid ophthalmology","Meningioma"],"a":1,"e":"Gradual painless unilateral proptosis with a normal X-ray in this setting is matched to optic nerve glioma.<br><br>Thyroid eye disease causes bilateral painless proptosis with imaging changes; gradual unilateral painless proptosis with a normal X-ray is optic nerve glioma."},
/*1001*/ {"q":"MDR TB patient was started on second line ATT; which of the following drug causes thyroid dysfunction:","o":["Ethambutol","Streptomycin","PZA","Ethionamide"],"a":3,"e":"Ethionamide, a second-line antitubercular drug, can cause hypothyroidism and goitre.<br><br>Ethambutol affects vision and PZA the joints; ethionamide can cause hypothyroidism/goitre as second-line antitubercular drug."},
/*1002*/ {"q":"A patient ABGs reveal pH 7.54, PCO2 40 and HCO3 38; what is acid-base disorder:","o":["Respiratory acidosis","Respiratory alkalosis","Compensatory respiratory acidosis","Metabolic alkalosis"],"a":3,"e":"A high pH with raised HCO3 and normal PCO2 indicates uncompensated metabolic alkalosis.<br><br>A normal PCO2 with high pH and raised HCO3 indicates uncompensated metabolic alkalosis, not respiratory acidosis."},
/*1003*/ {"q":"Liver is derived from which of these:","o":["Midgut","Hindgut","Foregut","Retrogut"],"a":2,"e":"The liver develops as an outgrowth (hepatic diverticulum) of the foregut endoderm.<br><br>The midgut and hindgut form the bowel; the liver develops from a foregut diverticulum (hepatic bud)."},
/*1004*/ {"q":"Free end of small intestine occupies:","o":["Right upper quadrant","Lower infracolic","Lower part of infracolic","Right quadrant something"],"a":0,"e":".<br><br>The infracolic compartment is divided by the mesentery, but the keyed free end of the small intestine here occupies the right upper quadrant."},
/*1005*/ {"q":"Ova enter which state instead of entering second meiosis:","o":["Diplotene","Zygotene","Pachytene","Anaphase"],"a":0,"e":"The primary oocyte arrests in the diplotene stage of prophase I until ovulation.<br><br>Zygotene/pachytene are earlier meiosis I phases; the secondary oocyte arrests at diplotene of prophase I until ovulation, then enters metaphase II."},
/*1006*/ {"q":"A person loses 2 L of sweat while working and drinks 2 L pure water; what changes will occur:","o":["Decrease ICF osmolality","Increase ECF volume","Decrease ECF osmolality","Increase ICF volume"],"a":3,"e":"Replacing hypotonic sweat loss with pure water lowers extracellular osmolality and shifts water into cells, increasing ICF volume.<br><br>Drinking pure water after hypotonic sweat loss lowers ECF osmolality and shifts water into cells, increasing ICF volume."},
/*1007*/ {"q":"First manifestation of vitamin A deficiency is:","o":["Xerophthalmia","Bitot spot","Keratomalacia","Night blindness"],"a":3,"e":"Night blindness (nyctalopia) is the earliest manifestation of vitamin A deficiency.<br><br>Bitot spots and keratomalacia are later; the first sign is night blindness."},
/*1008*/ {"q":"Muscle which originates from lumbar region and goes into deep pelvis:","o":["Iliacus","Psoas","Quadratus lumborum","Erector spinae"],"a":1,"e":"Psoas major arises from the lumbar vertebrae and descends into the pelvis to insert on the lesser trochanter.<br><br>Quadratus lumborum stays in the abdomen; psoas major arises from lumbar vertebrae and descends into the pelvis to insert on the lesser trochanter."},
/*1009*/ {"q":"Superior petrosal sinus attached to:","o":["Falx cerebri","Cerebellum","Falx cerebelli","Tentorium cerebelli"],"a":3,"e":"The superior petrosal sinus runs in the attached margin of the tentorium cerebelli.<br><br>The falx cerebri and falx cerebelli are vertical; the superior petrosal sinus lies along the attached margin of the tentorium cerebelli."},
/*1010*/ {"q":"Extensor carpi ulnaris is supplied by:","o":["Median nerve","Ulnar nerve","Anterior interosseous nerve","Posterior interosseous nerve"],"a":3,"e":"Extensor carpi ulnaris is an extensor supplied by the posterior interosseous nerve (deep branch of radial).<br><br>Median and ulnar nerves do not extend; extensor carpi ulnaris is supplied by the posterior interosseous nerve (deep branch of radial)."},
/*1011*/ {"q":"A patient had injury in the hand and opposition of thumb is lost; which nerve is involved:","o":["Ulnar","Radial","Median","Axillary"],"a":2,"e":"Thumb opposition (opponens pollicis) is a median nerve function, lost in median nerve injury.<br><br>Ulnar and radial nerves do other movements; thumb opposition (opponens pollicis) is a median nerve function."},
/*1012*/ {"q":"A patient comes to ophthalmology clinic with complaint of gradual loss of vision, accommodation reflex lost but light reflex present:","o":["Presbyopia","Encephalitis","Horner syndrome","3rd nerve injury"],"a":0,"e":".<br><br>Horner and CN III lesions affect pupil and lid; gradual age-related accommodation loss with preserved light reflex is presbyopia."},
/*1013*/ {"q":"Position of aorta in TOF:","o":["Aortic arch posterior to pulmonary artery","Aortic arch anterior to pulmonary artery","Aortic arch inferior to pulmonary artery","Aortic arch superior to pulmonary artery"],"a":1,"e":"In tetralogy of Fallot the overriding aorta lies anterior to the pulmonary artery.<br><br>A posterior aorta is uncommon and inferior/superior is atypical; in TOF the overriding aorta lies anterior to the pulmonary artery."},
/*1014*/ {"q":"A man crossing road looks right then left; this movement caused by vertebrae having which type of joint:","o":["Pivot joint","Condyloid joint","Synovial joints","Biaxial ellipsoid"],"a":0,"e":"Rotation of the head (no movement) at the atlanto-axial joint is a pivot joint.<br><br>The atlanto-occipital is condyloid (yes movement); head rotation is the pivot atlanto-axial joint."},
/*1015*/ {"q":"A person had head injury after RTA and cannot speak; lesion is at which of following area:","o":["Wernicke area","Broca area","Angular gyrus","Occipital lobe"],"a":1,"e":"Inability to produce speech (non-fluent expressive aphasia) localises to Broca area (areas 44/45).<br><br>Wernicke lesion gives fluent receptive aphasia; non-fluent speech loss is Broca area (FA + Kaplan)."},
/*1016*/ {"q":"A man unable to hold a mug of coffee, draw an image, draw movement of shoulder and hand; on which part of brain:","o":["Premotor","Primary motor","Somatosensory","Cerebellum"],"a":0,"e":"Planning and coordinating learned skilled movements is a premotor cortex function.<br><br>The primary motor cortex executes simple movements; planning of skilled multi-joint hand movement is a premotor cortex function."},
/*1017*/ {"q":"In long term memory, area involved will be:","o":["Amygdala","Prefrontal cortex","Temporal cortex","Cingulate gyrus"],"a":3,"e":".<br><br>Amygdala handles emotional memory and prefrontal working memory; long-term declarative memory consolidation involves the cingulate gyrus/limbic system."},
/*1018*/ {"q":"A patient has furunculosis of nose and boil; spread of infection to which area is dangerous:","o":["Sagittal sinus","Maxillary sinus","Sigmoid sinus","Cavernous sinus"],"a":3,"e":"Nasal furuncle infection can spread via ophthalmic veins to the cavernous sinus (danger triangle of face).<br><br>Sagittal/sigmoid sinuses are not directly connected to the face; nasal furuncle infection spreads dangerously to the cavernous sinus."},
/*1019*/ {"q":"A boy after injury to head presents with increased appetite and weight gain; lesion on which area:","o":["Thalamus","Hypothalamus","Cortex","Internal capsule"],"a":1,"e":"Increased appetite and weight gain after head injury indicates a hypothalamic (ventromedial satiety centre) lesion.<br><br>Cortical and capsular lesions cause motor deficits; increased appetite with weight gain after head injury indicates a hypothalamic (ventromedial) lesion."},
/*1020*/ {"q":"Two kids bet on eye blinking; one kid lost as he blinked last; this blinking was due to:","o":["Thoracic segment of spinal cord","Cervical segment of spinal cord (superior cervical ganglion)","Mid brain","Medulla"],"a":1,"e":".<br><br>The midbrain controls vertical gaze and the medulla autonomic; voluntary blinking is mediated through the cervical (superior cervical ganglion) sympathetic pathway."},
/*1021*/ {"q":"Location of superior parathyroid gland in relation to inferior thyroid artery and recurrent laryngeal nerve is:","o":["Anterior to RLN and cranial to ITA","Anterior to RLN and caudal to ITA","Posterior to RLN and caudal to ITA","Posterior to RLN and cranial to ITA"],"a":3,"e":"The superior parathyroid lies posterior to the recurrent laryngeal nerve and cranial (above) to the inferior thyroid artery.<br><br>Anterior-to-RLN positions describe the inferior parathyroid; the superior parathyroid lies posterior to the RLN and cranial to the inferior thyroid artery."},
/*1022*/ {"q":"In newborn, what is true:","o":["C-shaped vertebral column with inward chest","Oval thorax on cross section","Round thorax","Curved vertebrae"],"a":0,"e":"The newborn has a C-shaped vertebral column and a circular (rounded) thoracic cavity.<br><br>The adult thorax is oval and the column has curves; the newborn has a C-shaped vertebral column with a rounded thoracic cavity."},
/*1023*/ {"q":"Degranulation of basophils and mast cells causes what kind of shock:","o":["Septic shock","Hypovolemic shock","Cardiogenic shock","Anaphylactic shock"],"a":3,"e":"Mast cell and basophil degranulation releasing histamine causes anaphylactic shock.<br><br>Septic/hypovolaemic/cardiogenic shocks have other triggers; mast cell and basophil degranulation releasing histamine causes anaphylactic shock."},
/*1024*/ {"q":"Ventral corticospinal tract ends at:","o":["Mid thoracic","Upper thoracic","All spinal cord","Lower thoracic"],"a":0,"e":"The anterior (ventral) corticospinal tract is small and descends only to about the mid-thoracic level.<br><br>The lateral corticospinal tract runs the length of the cord; the ventral (anterior) corticospinal tract is small and terminates around mid-thoracic."},
/*1025*/ {"q":"A woman with history of trauma to head and neck region having lesion on tongue, protrusion of tongue deviated to the left side; nerve most likely involved is:","o":["Left hypoglossal","Right hypoglossal","Glossopharyngeal nerve","Vagus nerve"],"a":0,"e":"Tongue deviation toward the lesion on protrusion indicates an ipsilateral (left) hypoglossal lower motor neuron lesion.<br><br>An upper motor neuron lesion deviates the tongue away from the lesion; tongue deviation toward the lesion indicates an ipsilateral hypoglossal LMN lesion."},
/*1026*/ {"q":"Which one causes opening of mouth:","o":["Masseter","Temporalis","Medial pterygoid","Lateral pterygoid"],"a":3,"e":"The lateral pterygoid is the prime muscle that depresses the mandible to open the mouth.<br><br>Masseter, temporalis and medial pterygoid close the jaw; mouth opening is by lateral pterygoid."},
/*1027*/ {"q":"Subdural hematoma involves which of these:","o":["Superior cerebral vein","Inferior cerebral vein","Middle cerebral vein","Middle meningeal artery"],"a":0,"e":"A subdural haematoma results from rupture of bridging (superior cerebral) veins.<br><br>The middle meningeal artery causes extradural haematoma; subdural is bridging cerebral veins."},
/*1028*/ {"q":"Major part of anterior surface of heart is formed by:","o":["Right atrium","Right ventricle","Left atrium","Left ventricle"],"a":1,"e":"The anterior (sternocostal) surface of the heart is formed mostly by the right ventricle.<br><br>The base is the left atrium; the anterior surface is mainly right ventricle."},
/*1029*/ {"q":"Mass in ligamentum arteriosum would compress:","o":["Vagus nerve","Phrenic nerve","Right recurrent laryngeal nerve","Left recurrent laryngeal nerve"],"a":3,"e":"The left recurrent laryngeal nerve loops under the aortic arch beside the ligamentum arteriosum and is compressed by a mass there.<br><br>The right RLN loops under the right subclavian; only the left RLN passes under the aortic arch beside the ligamentum arteriosum, so a mass there compresses it."},
/*1030*/ {"q":"Aortic arch dilation will compress which structure:","o":["Thoracic duct","Left bronchus","Right bronchus","Vagus nerve"],"a":1,"e":"An aortic arch aneurysm compresses the left main bronchus (and left recurrent laryngeal nerve).<br><br>The right bronchus is steeper but the aortic arch passes above the left main bronchus, compressing it when dilated."},
/*1031*/ {"q":"Right bundle branch of conducting system of the heart is present in:","o":["Septomarginal trabeculae","Chordae tendineae","Supraventricular crest","Septal papillary muscles"],"a":0,"e":"The right bundle branch passes through the septomarginal trabecula (moderator band) to the anterior papillary muscle.<br><br>Chordae tendineae and septal papillary muscles support valves; the right bundle branch passes through the septomarginal trabecula (moderator band)."},
/*1032*/ {"q":"Dilation of which structure compress oesophagus:","o":["Aorta","Left atrium","Left ventricle","IVC"],"a":1,"e":"An enlarged left atrium (as in mitral stenosis) compresses the oesophagus behind it, causing dysphagia.<br><br>An aortic or right-ventricular enlargement does not abut the oesophagus; left atrial enlargement compresses the oesophagus, causing dysphagia."},
/*1033*/ {"q":"Penetrating chest trauma just to right of medial sternal border at 4th-5th intercostal spaces, pericardium and heart injured; which chamber is affected:","o":["Right atrium","Right ventricle","Left atrium","Left ventricle"],"a":0,"e":"A wound just right of the sternum at the 4th-5th spaces overlies the right atrium.<br><br>Left-sided chambers underlie the left chest; a wound just right of the sternum at the 4th-5th spaces overlies the right atrium."},
/*1034*/ {"q":"Action potential in cardiac cells increases in extracellular by:","o":["Na and calcium","K and calcium","Na and K","Mg and K"],"a":1,"e":".<br><br>Sodium and magnesium are not the relevant ions; cardiac action potential plateau and repolarisation depend on extracellular potassium and calcium."},
/*1035*/ {"q":"Goblet cells convert into clara cells at:","o":["Nasopharynx","Trachea","Bronchi","Terminal bronchioles"],"a":3,"e":"Goblet cells are replaced by Clara cells at the level of the terminal bronchioles.<br><br>Larger airways still have goblet cells; goblet cells give way to Clara cells at the level of the terminal bronchioles."},
/*1036*/ {"q":"Terminal bronchioles contain:","o":["Clara cells","Goblet cells","M cells","Kulchitsky cells"],"a":0,"e":"Terminal bronchioles contain Clara (club) cells which secrete surfactant-like material and detoxify.<br><br>Goblet cells are absent here; the terminal bronchiole cell is the Clara cell."},
/*1037*/ {"q":"Percentage of plasma in ECF is:","o":["20%","30%","15%","10%"],"a":0,"e":"Plasma makes up about 20-25% of the extracellular fluid (the rest being interstitial fluid).<br><br>Interstitial fluid forms the bulk of ECF; plasma constitutes about 20-25% of the extracellular fluid."},
/*1038*/ {"q":"Pericarditis pain from parietal and serous pericardium carried by which nerve:","o":["Intercostal nerve","Phrenic","Vagus","Thoracic nerve"],"a":1,"e":"Pain from the parietal/serous pericardium is carried by the phrenic nerve.<br><br>Intercostal nerves supply the costal pleura; pain from the parietal/serous pericardium is carried by the phrenic nerve."},
/*1039*/ {"q":"Stab wound to anterior chest after crossing intercostal muscle; which structure will it first come in contact with:","o":["Endothoracic fascia","Parietal pleura","Visceral pleura","Costal pleura"],"a":0,"e":"After the intercostal muscles the next layer encountered is the endothoracic fascia, then the parietal pleura.<br><br>The parietal/visceral pleurae are deeper; after the intercostal muscle the next layer encountered is the endothoracic fascia."},
/*1040*/ {"q":"Anterior choroidal artery is branch of:","o":["ASA","Vertebral artery","Internal carotid artery","Basilar artery"],"a":2,"e":"The anterior choroidal artery arises from the internal carotid artery.<br><br>The vertebral/basilar arteries supply the posterior circulation; the anterior choroidal artery is a branch of the internal carotid artery."},
/*1041*/ {"q":"Man had trauma and gradual vision loss start; acute vision loss preserved due to collateral supply from:","o":["Anterior cerebral artery","Middle cerebral artery","Posterior communicating artery","Posterior cerebral artery"],"a":2,"e":"The posterior communicating artery provides collateral circulation in the circle of Willis, preserving vision.<br><br>The ACA/MCA/PCA supply terminal cortex; collateral flow preserving vision arrives via the posterior communicating artery in the Circle of Willis."},
/*1042*/ {"q":"Superior cerebellar peduncle is connected to:","o":["Dorsal midbrain","Rostral midbrain","Dorsal to cerebellum","Rostral cerebellum"],"a":1,"e":"The superior cerebellar peduncle connects the cerebellum to the rostral midbrain.<br><br>The inferior cerebellar peduncle joins the medulla; the superior cerebellar peduncle connects the cerebellum to the rostral midbrain."},
/*1043*/ {"q":"Woman during robbery resists multiple stab wounds on right side face; primary care doctor notices right facial nerve damage; which muscle will be paralyzed:","o":["Geniohyoid","Sternohyoid","Omohyoid","Posterior belly of digastric"],"a":3,"e":"The posterior belly of digastric is supplied by the facial nerve, so it is paralysed in facial nerve injury.<br><br>The other listed strap muscles are not facial nerve; the facial-supplied one is the posterior belly of digastric."},
/*1044*/ {"q":"Surgeon performing open abdominal surgery, another surgeon pours one L N/S after touching pelvic brim; fluid goes to:","o":["Right and left colic","Right colic and para colic","Right colic and phrenic","Right post subphrenic space and pelvic"],"a":3,"e":"Fluid from the pelvic brim tracks along the paracolic gutter to the right posterior subphrenic (hepatorenal) space and pelvis.<br><br>Fluid in the pelvic brim does not flow to phrenic or left subphrenic spaces; it tracks via the right paracolic gutter to the right posterior subphrenic space (Morrison's pouch) and pelvis."},
/*1045*/ {"q":"Accessory right hepatic artery originates from which of following:","o":["SMA","Splenic","Gastroduodenal","IMA"],"a":0,"e":"An accessory or replaced right hepatic artery commonly arises from the superior mesenteric artery.<br><br>The IMA supplies hindgut and gastroduodenal is a different branch; an accessory or replaced right hepatic artery commonly arises from the SMA."},
/*1046*/ {"q":"Left accessory hepatic artery is branch of:","o":["SMA","IMA","Inferior pancreaticoduodenal","Gastroepiploic"],"a":0,"e":".<br><br>The IMA supplies the hindgut and the gastroepiploic the stomach; the keyed origin of a left accessory hepatic artery here is the SMA option."},
/*1047*/ {"q":"Accessory cystic artery originates from which of following:","o":["SMA","Splenic","Gastroduodenal","Superior pancreaticoduodenal"],"a":3,"e":".<br><br>The SMA supplies the midgut and the splenic the spleen; the keyed origin of an accessory cystic artery here is the superior pancreaticoduodenal artery."},
/*1048*/ {"q":"Which one is branch of SMA:","o":["Ileocolic","Celiac artery","Middle colic","Inferior colic"],"a":2,"e":"The middle colic artery is a branch of the superior mesenteric artery.<br><br>The celiac is separate; among these the SMA branch is the middle colic artery."},
/*1049*/ {"q":"With blockage of right superior bronchus due to mass, which bronchopulmonary segment is likely to collapse:","o":["Anterior basal","Right apical superior","Middle superior","Posterior basal"],"a":1,"e":"Obstruction of the right superior (apical) bronchus collapses the apical/superior bronchopulmonary segment.<br><br>Basal segments are lower-lobe; obstruction of the right superior bronchus collapses the right apical (superior) bronchopulmonary segment."},
/*1050*/ {"q":"Which part of left partially filled costodiaphragmatic recess during inspiration:","o":["Lateral","Posteriobasal","Mediobasal","Inferiobasal"],"a":3,"e":"During inspiration the lung partially fills the costodiaphragmatic recess.<br><br>Lateral/posteriobasal/mediobasal parts fill differently; the keyed part of the left costodiaphragmatic recess filling on inspiration here is the inferiobasal area."},
/*1051*/ {"q":"GH increase by:","o":["REM sleep","Cortisol","Fed state","Fasting"],"a":3,"e":"Growth hormone secretion increases during fasting (and deep sleep), as a counter-regulatory response.<br><br>Cortisol and the fed state suppress GH; fasting (and deep sleep) raise growth hormone secretion."},
/*1052*/ {"q":"A young man had injury to the neck with a sharp object 3 years ago; he notices a building swelling above the clavicle on sneezing and coughing; this swelling is most probably due to:","o":["Injury to deep fascia of neck","Damage to suprapleural membrane","Un-united first rib fracture","Damage deep cervical fascia"],"a":1,"e":"A cough-impulse supraclavicular swelling indicates damage to the suprapleural membrane (Sibson fascia) allowing lung apex herniation.<br><br>Un-united rib or fascial defects do not pulsate with cough; a cough-impulse supraclavicular swelling indicates damage to the suprapleural (Sibson) membrane."},
/*1053*/ {"q":"A patient diagnosed case of kwashiorkor; cause of fatty liver is:","o":["Recurrent hepatitis","High protein and low carbohydrate diet","Fulminant hepatitis A","Aflatoxin in diet"],"a":3,"e":".<br><br>Hepatitis and high-protein diet are not the cause; the keyed cause of fatty liver here is aflatoxin in the diet (impaired lipoprotein export)."},
/*1054*/ {"q":"Bone scan necessary for:","o":["Melanoma","Squamous cell carcinoma","Basal cell carcinoma","Retinoblastoma"],"a":3,"e":".<br><br>Melanoma/SCC/BCC rarely need a bone scan; among these the metastatic bone scan is keyed to retinoblastoma."},
/*1055*/ {"q":"Joints between vertebral bodies are:","o":["Symphysis","Synchondrosis","Syndesmosis","Synovial"],"a":0,"e":"The intervertebral joints between vertebral bodies are secondary cartilaginous joints (symphyses).<br><br>Vertebral bodies are not synovial or syndesmotic; intervertebral disc joints are symphyses (secondary cartilaginous)."},
/*1056*/ {"q":"Breast cancer in a female metastasized to peritoneum and pelvic organs; route of metastasis:","o":["Subpleural lymphatic plexus","Subperitoneal lymphatic plexus","Venous connections","Axillary lymph nodes"],"a":2,"e":".<br><br>Axillary node spread reaches viscera less directly; peritoneal/pelvic metastasis of breast cancer travels through venous connections (Batson plexus)."},
/*1057*/ {"q":"Major part of breast to be drained into lymph nodes; which will be involved in sentinel biopsy:","o":["Anterior axillary","Posterior axillary","Infraclavicular","Supraclavicular"],"a":0,"e":"Most of the breast drains to the anterior (pectoral) axillary nodes, the usual sentinel node.<br><br>Posterior/infraclavicular nodes drain later; most breast lymph (and the sentinel node) drains to the anterior (pectoral) axillary group."},
/*1058*/ {"q":"Related to squamocolumnar junction, true is:","o":["Z line","GE junction","B ring","A ring"],"a":1,"e":".<br><br>The B and A rings are oesophageal narrowings; the squamocolumnar junction (Z line) corresponds to the gastro-oesophageal junction."},
/*1059*/ {"q":"Diagnosed case of appendicitis, patient complaining of pain in medial rotation and flexion of hip; most probably position of appendix is:","o":["Pelvic","Retrocecal","Preileal","Postileal"],"a":0,"e":"Pain on hip medial rotation and flexion (obturator sign) indicates a pelvic appendix.<br><br>The psoas sign is for retrocecal; the obturator sign indicates a pelvic appendix."},
/*1060*/ {"q":"Horseshoe kidney associated with:","o":["Renal failures","Pelvi-ureteric junction abnormality","Polycystic KD","Vesico-ureteric reflux"],"a":1,"e":"Horseshoe kidney is associated with pelvi-ureteric junction obstruction and increased infection/stone risk.<br><br>Polycystic disease and VUR have other anatomy; horseshoe kidneys are associated with pelvi-ureteric junction obstruction and stones."},
/*1061*/ {"q":"Factor needed for coenzyme A is which of following:","o":["Biotin","Pantothenic acid","Thiamine","Folic acid"],"a":1,"e":"Pantothenic acid (vitamin B5) is the precursor required for coenzyme A synthesis.<br><br>Biotin/thiamine/folate serve other reactions; pantothenic acid (vitamin B5) is the cofactor required for coenzyme A synthesis."},
/*1062*/ {"q":"A 5-year-old boy with recurrent cervical lymphadenopathy and Klebsiella pneumonia on each occasion; he is most likely suffering from which immunodeficient state:","o":["Bruton's agammaglobinemia","Severe combined agammaglobinemia","Chronic granulomatous disease","Common variable agammaglobinemia"],"a":2,"e":"Recurrent catalase-positive (Klebsiella) infections with lymphadenitis indicate chronic granulomatous disease.<br><br>Bruton's gives encapsulated pyogenic infections without granulomas; recurrent catalase-positive (Klebsiella) infection points to chronic granulomatous disease."},
/*1063*/ {"q":"Virus causes cancer alterations in:","o":["Proto oncogene","Oncogene","DNA","RNA"],"a":0,"e":"Oncogenic viruses transform cells by activating cellular proto-oncogenes (and inactivating tumour suppressors).<br><br>DNA/RNA are nucleic acids not targets here; oncogenic viruses transform cells by activating cellular proto-oncogenes."},
/*1064*/ {"q":"Female patient came in cardiac OPD with cardiac defect, psychiatric behavior and cleft palate, likely due to:","o":["Fragile X","Klinefelter","Down","DiGeorge syndrome"],"a":3,"e":"Cardiac defect with cleft palate and behavioural changes indicates DiGeorge syndrome (22q11 deletion).<br><br>Fragile X and Klinefelter give other phenotypes; cardiac defect with cleft palate and hypocalcaemia indicates DiGeorge syndrome (22q11 deletion)."},
/*1065*/ {"q":"An OPD tuberculin test done; after 40 hours, 15 mm erythema is noticed; cells responsible for erythema are:","o":["Helper T cell","Cytotoxic T cell","NK cells","CD8 cells"],"a":0,"e":"The delayed-type hypersensitivity tuberculin reaction is mediated by CD4 helper T cells and macrophages.<br><br>Cytotoxic and NK cells lyse cells directly; the tuberculin DTH reaction is mediated by CD4 helper T cells and macrophages."},
/*1066*/ {"q":"A man with normal external genitalia, married but had no kids, normal ejaculation period but semen analysis showed azospermia; cause may be in:","o":["Epididymis","Sertoli cell defect","Defect of vas deference","Seminiferous tubules"],"a":1,"e":"Azoospermia with decreased FSH/LH and a Sertoli cell defect impairs spermatogenesis.<br><br>Epididymal/vasal blockage gives obstructive azoospermia with normal FSH; a Sertoli cell defect raises FSH and is the keyed cause here."},
/*1067*/ {"q":"Infertile couple semen analysis 25% sperm motile, 25% immotile, rest shows; specimen taken from:","o":["Directly from seminiferous tubule","Epididymis of corpus","Masturbation","Sertoli cells"],"a":0,"e":".<br><br>Masturbation samples ejaculate and epididymal/Sertoli sampling is atypical; the keyed source for sperm here is directly from the seminiferous tubule."},
/*1068*/ {"q":"Tumor of eye least likely to metastasize:","o":["RB","Ewing sarcoma","BCC","Melanoma"],"a":2,"e":"Basal cell carcinoma rarely metastasises, unlike retinoblastoma or ocular melanoma.<br><br>Melanoma and retinoblastoma readily spread; basal cell carcinoma rarely metastasises, even from the eyelid."},
/*1069*/ {"q":"Ejaculation occurs due to which of following:","o":["Pudendal nerve","Sympathetic","Parasympathetic","Obturator nerve"],"a":0,"e":"Ejaculation (ejection phase) is mediated by the somatic pudendal nerve; emission is sympathetic and erection parasympathetic.<br><br>Parasympathetic mediates erection and sympathetic emission; ejaculation (the ejection phase) is via the somatic pudendal nerve."},
/*1070*/ {"q":"Fracture of head of femur leading to avascular necrosis; artery involved is which of following:","o":["Lateral circumflex","Descending branch lateral circumflex","Medial circumflex artery","Femoral artery"],"a":2,"e":"In adults the femoral head is supplied mainly by the medial circumflex femoral artery, so its disruption causes avascular necrosis.<br><br>The lateral circumflex contributes little to the head; in adults the femoral head is supplied chiefly by the medial circumflex femoral artery."},
/*1071*/ {"q":"Hypotension and vasodilation occur in:","o":["Hypovolemic shock","Septic shock","Anaphylactic shock","Cardiogenic shock"],"a":1,"e":"Septic shock is a distributive shock with hypotension and warm peripheral vasodilation.<br><br>Hypovolaemic and cardiogenic shock cause vasoconstriction; vasodilatory hypotension is septic shock."},
/*1072*/ {"q":"Patient presented with peripheral tingling, numbness, diplopia and visual disturbance diagnosed with demyelination disease; what type of nervous system cells are affected:","o":["Oligodendrocytes","Schwann cells","Astrocytes","Glial cells"],"a":0,"e":"Multiple sclerosis is a CNS demyelinating disease affecting oligodendrocytes which form CNS myelin.<br><br>Schwann cells myelinate the PNS; the CNS demyelination cell is the oligodendrocyte."},
/*1073*/ {"q":"Common type of necrosis in omentum:","o":["Caseous necrosis","Coagulative","Fat","Gangrene"],"a":2,"e":"Fat necrosis is the characteristic necrosis of adipose tissue such as the omentum, with calcium soap formation.<br><br>Coagulative necrosis is ischaemic; omental adipose tissue undergoes fat necrosis."},
/*1074*/ {"q":"Diagnostic test for infectious mononucleosis:","o":["CBC","Heterophile antibody","Blood smear","ESR"],"a":1,"e":"Infectious mononucleosis is diagnosed by the heterophile antibody (Monospot/Paul-Bunnell) test.<br><br>A blood smear shows atypical lymphocytes but the diagnostic test is the heterophile antibody."},
/*1075*/ {"q":"High cardiac output failure occurs in deficiency of:","o":["Niacin","Riboflavin","Thiamine","Pyridoxine"],"a":2,"e":"Thiamine (B1) deficiency causes wet beriberi with high-output cardiac failure.<br><br>Niacin/riboflavin/pyridoxine cause other syndromes; thiamine deficiency produces wet beriberi with high-output cardiac failure."},
];
